package.preload["engine.armor"] = function()
-- engine/armor.lua
-- Armor before-effect interceptor. Reduces inflict_injury damage based on
-- worn items' materials, coverage, fit, and degradation state.
--
-- Ownership: Smithers (UI/Parser Engineer) — implementation
--            Bart (Architect) — design (D-ARMOR-SYSTEM)
--
-- Registration: armor.register(effects)  installs the before-interceptor.
-- The interceptor only touches effects with type == "inflict_injury".

local materials = require("engine.materials")

local armor = {}

---------------------------------------------------------------------------
-- Constants (from architecture doc §3.1)
---------------------------------------------------------------------------
local HARDNESS_WEIGHT   = 1.0
local FLEXIBILITY_WEIGHT = 1.0
local DENSITY_WEIGHT    = 0.5
local DENSITY_CAP       = 3000  -- kg/m³ — beyond this, density stops scaling

-- Fit multipliers (architecture doc §3.2)
local FIT_MULTIPLIER = {
    makeshift  = 0.5,
    fitted     = 1.0,
    masterwork = 1.2,
}

-- Degradation state → protection multiplier (architecture doc §5.2)
local STATE_MULTIPLIER = {
    intact    = 1.0,
    cracked   = 0.7,
    shattered = 0.0,
}

-- Degradation transitions
local DEGRADE_NEXT = {
    intact  = "cracked",
    cracked = "shattered",
}

-- Impact type → degradation multiplier (architecture doc §5.1)
local IMPACT_TYPE_FACTOR = {
    piercing = 0.5,
    slashing = 1.0,
    blunt    = 1.5,
}
local DEFAULT_IMPACT_FACTOR = 1.0

---------------------------------------------------------------------------
-- Helpers
---------------------------------------------------------------------------

--- Calculate base protection from a material property table.
local function base_protection(mat)
    local hardness    = mat.hardness or 0
    local flexibility = mat.flexibility or 0
    local density     = mat.density or 0
    local density_factor = math.min(1.0, density / DENSITY_CAP)
    return hardness * HARDNESS_WEIGHT
         + flexibility * FLEXIBILITY_WEIGHT
         + density_factor * DENSITY_WEIGHT
end

--- Get the effective protection for a single worn item.
-- Returns 0 if the item has no valid material or is shattered.
local function item_protection(item)
    -- State check
    local state = item._state or "intact"
    local state_mult = STATE_MULTIPLIER[state]
    if not state_mult or state_mult == 0 then return 0 end

    -- Material lookup
    local mat = materials.get(item.material)
    if not mat then return 0 end

    -- Base from material
    local prot = base_protection(mat)

    -- Coverage (default 1.0)
    local coverage = item.coverage or 1.0
    prot = prot * coverage

    -- Fit multiplier (default "fitted" = 1.0)
    local fit = item.fit or "fitted"
    local fit_mult = FIT_MULTIPLIER[fit] or 1.0
    prot = prot * fit_mult

    -- Degradation state multiplier
    prot = prot * state_mult

    return prot
end

--- Check whether a worn item covers a given injury location.
-- Checks explicit `covers` array first, then falls back to
-- `wear.slot` or `wear_slot` for items that declare a single slot.
local function covers_location(item, location)
    -- Explicit covers array (highest priority)
    if item.covers then
        for _, loc in ipairs(item.covers) do
            if loc == location then return true end
        end
        return false
    end
    -- Fall back to wear.slot or wear_slot (single-slot items)
    local slot = (item.wear and item.wear.slot) or item.wear_slot
    if slot and slot == location then return true end
    return false
end

--- Build narration for armor absorbing damage.
local function narrate_absorption(item, reduction)
    if reduction <= 0 then return end
    local name = item.name or item.id or "your armor"
    if reduction >= 5 then
        print("Your " .. name .. " absorbs much of the blow.")
    else
        print("Your " .. name .. " absorbs some of the blow.")
    end
end

--- Check degradation and apply state transition.
local function check_degradation(item, original_damage, impact_type)
    local state = item._state or "intact"
    local next_state = DEGRADE_NEXT[state]
    if not next_state then return end  -- already shattered or unknown

    local mat = materials.get(item.material)
    if not mat then return end

    local fragility = mat.fragility or 0
    if fragility <= 0 then return end  -- material never breaks

    local impact_factor = IMPACT_TYPE_FACTOR[impact_type] or DEFAULT_IMPACT_FACTOR
    local break_chance = fragility * (original_damage / 20) * impact_factor

    if math.random() < break_chance then
        item._state = next_state
        local name = item.name or item.id or "your armor"
        if next_state == "cracked" then
            print("Your " .. name .. " develops a hairline crack.")
        elseif next_state == "shattered" then
            print("Your " .. name .. " shatters into pieces!")
        end
    end
end

--- Degrade worn armor covering a given location (called by hit verb).
-- @param player       table   Player state (must have .worn)
-- @param location     string  Body location that was hit
-- @param damage       number  Original damage of the hit
-- @param impact_type  string  "blunt", "slashing", "piercing", or nil
function armor.degrade_covering_armor(player, location, damage, impact_type)
    local worn = player.worn
    if not worn or #worn == 0 then return end
    for _, item in ipairs(worn) do
        if type(item) == "table" and covers_location(item, location) then
            check_degradation(item, damage, impact_type)
        end
    end
end

---------------------------------------------------------------------------
-- Registration
---------------------------------------------------------------------------

--- Install the armor before-interceptor on the effects pipeline.
-- @param effects_module  The effects module (engine.effects)
function armor.register(effects_module)
    effects_module.add_interceptor("before", function(effect, ctx)
        -- Only intercept injury effects
        if effect.type ~= "inflict_injury" then return end
        if not effect.location then return end
        if not ctx or not ctx.player then return end

        local worn = ctx.player.worn
        if not worn or #worn == 0 then return end

        -- Gather worn items covering this injury location
        local covering = {}
        for _, item in ipairs(worn) do
            if covers_location(item, effect.location) then
                covering[#covering + 1] = item
            end
        end
        if #covering == 0 then return end

        -- Sum protection from all covering layers
        local total_protection = 0
        for _, item in ipairs(covering) do
            total_protection = total_protection + item_protection(item)
        end

        local original_damage = effect.damage
        local protection_int = math.floor(total_protection)

        -- Reduce damage (minimum 1 — armor never fully negates)
        if protection_int > 0 then
            effect.damage = math.max(1, effect.damage - protection_int)
        end

        -- Narrate
        local reduction = original_damage - effect.damage
        for _, item in ipairs(covering) do
            if item_protection(item) > 0 then
                narrate_absorption(item, reduction)
                break  -- one narration line is enough
            end
        end

        -- Degradation check per item
        local impact_type = effect.damage_type or nil
        for _, item in ipairs(covering) do
            check_degradation(item, original_damage, impact_type)
        end
    end)
end

return armor

end

package.preload["engine.combat"] = function()
local resolution = require("engine.combat.resolution")
local narration = require("engine.combat.narration")
local presentation_ok, presentation = pcall(require, "engine.ui.presentation")
local creatures_ok, creatures_mod = pcall(require, "engine.creatures")
if not creatures_ok then creatures_mod = nil end
local npc_behavior_ok, npc_behavior = pcall(require, "engine.combat.npc-behavior")
if not npc_behavior_ok then npc_behavior = nil end

local M = {}

-- Re-export from resolution for backward compatibility
M.SEVERITY = resolution.SEVERITY

M.PHASE = {
    INITIATE = 1,
    DECLARE = 2,
    RESPOND = 3,
    RESOLVE = 4,
    NARRATE = 5,
    UPDATE = 6,
}

local SIZE_MODIFIERS = resolution.SIZE_MODIFIERS
local is_player = resolution.is_player
local normalize_weapon = resolution.normalize_weapon
local pick_weapon = resolution.pick_weapon

function M.initiate(attacker, defender)
    local a_speed = attacker and attacker.combat and attacker.combat.speed or 0
    local d_speed = defender and defender.combat and defender.combat.speed or 0
    if a_speed ~= d_speed then
        return a_speed > d_speed and attacker or defender,
            a_speed > d_speed and defender or attacker
    end
    local a_size = attacker and attacker.combat and attacker.combat.size or "medium"
    local d_size = defender and defender.combat and defender.combat.size or "medium"
    local a_mod = SIZE_MODIFIERS[a_size] or 1.0
    local d_mod = SIZE_MODIFIERS[d_size] or 1.0
    if a_mod ~= d_mod then
        return a_mod < d_mod and attacker or defender,
            a_mod < d_mod and defender or attacker
    end
    return attacker, defender
end

function M.declare(attacker, weapon, target_zone, opts)
    local attack_weapon = normalize_weapon(weapon) or pick_weapon(attacker)
    return {
        weapon = attack_weapon,
        target_zone = target_zone,
        stance = opts and opts.stance or "balanced",
    }
end

function M.respond(defender, response, opts)
    local r = response
    if type(r) == "table" then r = r.type end
    return {
        type = r,
        stance = opts and opts.stance or "balanced",
    }
end

function M.resolve_exchange(attacker, defender, weapon, target_zone, response, opts)
    local attack_action = M.declare(attacker, weapon, target_zone, opts)
    local defense_action = M.respond(defender, response, opts)
    local result = resolution.resolve_damage(attacker, defender, attack_action.weapon, attack_action.target_zone, defense_action.type, opts)

    result.phase_log = {
        M.PHASE.INITIATE,
        M.PHASE.DECLARE,
        M.PHASE.RESPOND,
        M.PHASE.RESOLVE,
        M.PHASE.NARRATE,
        M.PHASE.UPDATE,
    }

    result.narration = M.narrate(result, result.light ~= false)
    result.text = result.narration

    local update_result = resolution.update(result, opts)
    if update_result then
        for k, v in pairs(update_result) do result[k] = v end
    end

    return result
end

function M.resolve(attacker, defender, weapon, target_zone, response, opts)
    return resolution.resolve_damage(attacker, defender, normalize_weapon(weapon), target_zone, response, opts)
end

function M.narrate(result, light)
    if narration and narration.generate then
        return narration.generate(result, light)
    end
    if narration and narration.narrate then
        return narration.narrate(result, light)
    end
    return ""
end

-- Delegate to resolution module
M.update = resolution.update
M.interrupt_check = resolution.interrupt_check

---------------------------------------------------------------------------
-- Active fights tracking (Track 3A)
---------------------------------------------------------------------------

local active_fights = {}
local fight_counter = 0

function M.get_active_fights()
    return active_fights
end

function M.find_fight_by_room(room_id)
    for _, fight in pairs(active_fights) do
        if fight.room_id == room_id then return fight end
    end
    return nil
end

function M.find_fight_for_combatant(combatant)
    local cid = combatant.id or combatant.guid
    for _, fight in pairs(active_fights) do
        for _, c in ipairs(fight.combatants) do
            if (c.id or c.guid) == cid then return fight end
        end
    end
    return nil
end

function M.start_fight(context, combatants, room_id)
    fight_counter = fight_counter + 1
    local fight = {
        id = fight_counter,
        combatants = {},
        room_id = room_id,
        round = 0,
    }
    for _, c in ipairs(combatants) do
        fight.combatants[#fight.combatants + 1] = c
    end
    active_fights[fight.id] = fight
    if context then context.active_fights = active_fights end
    return fight
end

function M.end_fight(context, fight_id)
    active_fights[fight_id] = nil
    if context then context.active_fights = active_fights end
end

function M.join_fight(fight, combatant)
    for _, c in ipairs(fight.combatants) do
        if (c.id or c.guid) == (combatant.id or combatant.guid) then
            return fight
        end
    end
    fight.combatants[#fight.combatants + 1] = combatant
    return fight
end

function M.remove_combatant(fight, combatant)
    local cid = combatant.id or combatant.guid
    for i = #fight.combatants, 1, -1 do
        if (fight.combatants[i].id or fight.combatants[i].guid) == cid then
            table.remove(fight.combatants, i)
            break
        end
    end
    if #fight.combatants < 2 then return true end
    return false
end

-- Sort combatants: speed desc → size asc → player last among equals
function M.sort_combatants(combatants)
    local sorted = {}
    for _, c in ipairs(combatants) do sorted[#sorted + 1] = c end
    table.sort(sorted, function(a, b)
        local a_speed = a.combat and a.combat.speed or 0
        local b_speed = b.combat and b.combat.speed or 0
        if a_speed ~= b_speed then return a_speed > b_speed end
        local a_size = SIZE_MODIFIERS[a.combat and a.combat.size or "medium"] or 1.0
        local b_size = SIZE_MODIFIERS[b.combat and b.combat.size or "medium"] or 1.0
        if a_size ~= b_size then return a_size < b_size end
        -- Player goes last among equals
        local a_player = is_player(a) and 1 or 0
        local b_player = is_player(b) and 1 or 0
        return a_player < b_player
    end)
    return sorted
end

-- NPC target selection: prey list first, then aggression threshold fallback
function M.select_npc_target(attacker, combatants)
    local prey_list = attacker.behavior and attacker.behavior.prey
    local attacker_id = attacker.id or attacker.guid

    -- Priority: prey list targets
    if prey_list and #prey_list > 0 then
        for _, prey_id in ipairs(prey_list) do
            for _, c in ipairs(combatants) do
                local cid = c.id or c.guid
                if cid ~= attacker_id and c._state ~= "dead" and c.animate ~= false then
                    if c.id == prey_id then return c end
                end
            end
        end
    end

    -- Fallback: attack highest-aggression target (non-self, alive)
    local aggression = attacker.behavior and attacker.behavior.aggression or 0
    if aggression > 20 then
        local best, best_size = nil, math.huge
        for _, c in ipairs(combatants) do
            local cid = c.id or c.guid
            if cid ~= attacker_id and c._state ~= "dead" and c.animate ~= false then
                local c_size = SIZE_MODIFIERS[c.combat and c.combat.size or "medium"] or 1.0
                if c_size < best_size then
                    best, best_size = c, c_size
                end
            end
        end
        return best
    end
    return nil
end

-- Resolve one full round of multi-combatant combat
function M.resolve_round(context, fight)
    if not fight or #fight.combatants < 2 then return {} end

    fight.round = (fight.round or 0) + 1
    local ordered = M.sort_combatants(fight.combatants)
    local results = {}

    local light = true
    if context and context.player and presentation_ok and presentation
       and presentation.get_light_level then
        light = presentation.get_light_level(context) ~= "dark"
    end

    -- Pairwise: each combatant attacks once per round in turn order
    for _, attacker in ipairs(ordered) do
        if attacker._state == "dead" or attacker.animate == false then
            goto continue_attacker
        end

        local target
        if is_player(attacker) then
            -- Player attacks their declared target (from context)
            target = context and context.combat_target
            if not target or target._state == "dead" then
                target = nil
                for _, c in ipairs(fight.combatants) do
                    if not is_player(c) and c._state ~= "dead" and c.animate ~= false then
                        target = c
                        break
                    end
                end
            end
        else
            target = M.select_npc_target(attacker, fight.combatants)
        end

        if not target or target._state == "dead" then
            goto continue_attacker
        end

        local weapon = pick_weapon(attacker)
        local target_zone = nil
        if not is_player(attacker) and npc_behavior then
            target_zone = npc_behavior.select_target_zone(attacker, target)
        end
        local response = nil
        if not is_player(target) and npc_behavior then
            response = npc_behavior.select_response(target, attacker)
        end

        -- Cornered stance: attack × 1.5 applied via opts
        local stance = context and context.combat_stance or "balanced"
        local opts = { light = light, stance = stance }
        if attacker._cornered then
            opts.cornered_bonus = 1.5
        end

        local result = M.resolve_exchange(attacker, target, weapon, target_zone, response, opts)
        results[#results + 1] = result

        -- Remove dead combatants
        if result.defender_dead then
            M.remove_combatant(fight, target)
        end

        ::continue_attacker::
    end

    -- End fight if fewer than 2 alive combatants remain
    local alive_count = 0
    for _, c in ipairs(fight.combatants) do
        if c._state ~= "dead" and c.animate ~= false then
            alive_count = alive_count + 1
        end
    end
    if alive_count < 2 then
        M.end_fight(context, fight.id)
    end

    return results
end

-- Reset active fights (for testing)
function M.reset_fights()
    active_fights = {}
    fight_counter = 0
end

-- Context-aware target selection: finds same-room creatures via registry
function M.select_target(context, attacker)
    if not context or not attacker then return nil end
    local attacker_loc = attacker.location
    if not attacker_loc then return nil end
    -- Build combatants list from registry (all animate creatures in same room)
    local combatants = {}
    if creatures_mod and creatures_mod.get_creatures_in_room then
        combatants = creatures_mod.get_creatures_in_room(context.registry, attacker_loc)
    else
        -- Fallback: scan registry directly
        local all = {}
        if context.registry and type(context.registry.list) == "function" then
            all = context.registry:list()
        elseif context.registry and type(context.registry.all) == "function" then
            all = context.registry:all()
        end
        for _, obj in ipairs(all) do
            if obj.animate and obj.location == attacker_loc then
                combatants[#combatants + 1] = obj
            end
        end
    end
    return M.select_npc_target(attacker, combatants)
end

function M.run_combat(context, attacker, defender)
    local light = true
    if context and context.player and presentation_ok and presentation and presentation.get_light_level then
        light = presentation.get_light_level(context) ~= "dark"
    end

    -- C14: Signal combat mode to the game loop
    if context then context.combat_active = true end

    local stance = context and context.combat_stance or "balanced"
    local weapon = pick_weapon(attacker)

    -- NPC target zone: use combat.behavior.target_priority for zone selection
    local target_zone = nil
    if not is_player(attacker) and npc_behavior then
        target_zone = npc_behavior.select_target_zone(attacker, defender)
    end

    -- NPC defense response: auto-select from defender's combat.behavior.defense
    local response = nil
    if not is_player(defender) and npc_behavior then
        response = npc_behavior.select_response(defender, attacker)
    end

    local result = M.resolve_exchange(attacker, defender, weapon, target_zone, response, { light = light, stance = stance })

    -- WAVE-4: Emit combat sound stimulus for creature reactions
    if creatures_mod and creatures_mod.emit_stimulus then
        local room_id = defender.location
            or (context and context.current_room and context.current_room.id)
        if room_id then
            local intensity = 3  -- unarmed
            if weapon and weapon.id and weapon.id ~= "fist" then intensity = 6 end
            if result.defender_dead then intensity = 8 end
            creatures_mod.emit_stimulus(room_id, "loud_noise", {
                intensity = intensity,
                source = attacker.id or attacker.guid or "combat",
            })
        end
    end

    -- C12: Emit creature_died stimulus and capture death narration
    if result.defender_dead then
        if creatures_mod and creatures_mod.emit_stimulus then
            local room_id = defender.location
                or (context and context.current_room and context.current_room.id)
            if room_id then
                creatures_mod.emit_stimulus(room_id, "creature_died", {
                    creature_id = defender.id or defender.guid,
                    creature_name = defender.name,
                })
            end
        end
    end

    -- C14: Clear combat mode when combat resolves
    if result.defender_dead or result.fled or result.combat_over then
        if context then context.combat_active = nil end
    end

    -- WAVE-3: Near-death trauma hook — player health dropped below 10% max
    if context and context.player then
        local player = context.player
        local max_hp = player.max_health or 100
        local cur_hp = player.health or max_hp
        if cur_hp > 0 and cur_hp < max_hp * 0.1 then
            local inj_ok, inj = pcall(require, "engine.injuries")
            if inj_ok and inj and inj.add_stress then
                inj.add_stress(player, "near_death_combat")
            end
        end
    end

    return result
end

return M

end

package.preload["engine.combat.narration"] = function()
local M = {}

local SEVERITY = {
    DEFLECT = 0,
    GRAZE = 1,
    HIT = 2,
    SEVERE = 3,
    CRITICAL = 4,
}

local function pick(list)
    return list[math.random(#list)]
end

local zone_words = {
    head = { "head", "skull", "cranium" },
    body = { "body", "torso", "flank", "side", "belly", "chest", "ribs" },
    torso = { "torso", "chest", "ribs", "gut" },
    arms = { "arm", "forearm", "shoulder" },
    hands = { "hand", "fingers", "knuckles" },
    legs = { "leg", "thigh", "shin", "knee", "haunch" },
    feet = { "foot", "ankle" },
    tail = { "tail", "tail" },
}

local tissue_words = {
    skin = "skin",
    hide = "hide",
    flesh = "flesh",
    bone = "bone",
    organ = "organ",
}

local function zone_text(zone, body_tree)
    if not zone then return "body" end
    -- #369/#337: Use creature-specific zone names when available (Principle 8)
    if body_tree and body_tree[zone] and body_tree[zone].names then
        return pick(body_tree[zone].names)
    end
    local list = zone_words[zone]
    if list then return pick(list) end
    return zone
end

local function tissue_text(tissue)
    if not tissue then return "flesh" end
    return tissue_words[tissue] or tissue:gsub("-", " ")
end

local function material_text(material_name)
    if not material_name then return "weapon" end
    -- #338: Natural weapon materials should use weapon names, not raw material names
    if material_name == "tooth-enamel" then
        return pick({ "tooth", "fang" })
    end
    if material_name == "keratin" then
        return pick({ "keratin claws", "claws", "keratin" })
    end
    return material_name:gsub("-", " ")
end

local function actor_name(actor)
    -- #366: nil attacker in player-initiated combat defaults to "You"
    if not actor then return "You" end
    if actor.id == "player" or actor.is_player then return "You" end
    local name = actor.name or actor.id or "someone"
    if name:lower() == "you" then return "You" end
    return name:sub(1, 1):upper() .. name:sub(2)
end

local function possessive(name)
    if not name then return "their" end
    local lower = name:lower()
    if lower == "you" or lower == "the player" then return "your" end
    if name:sub(-1) == "s" then return name .. "'" end
    return name .. "'s"
end

local function action_verb(result)
    return result.action_verb
        or (result.weapon and result.weapon.combat and result.weapon.combat.message)
        or (result.weapon and result.weapon.message)
        or "hits"
end

local LIGHT_TEMPLATES = {
    [SEVERITY.DEFLECT] = {
        "{attacker} {verb} {target_possessive} {zone}, but the {material} glances off.",
        "The {material} skitters off {target_possessive} {zone} as {attacker} {verb}.",
        "{attacker} {verb} toward {target_possessive} {zone}; the {material} fails to bite.",
    },
    [SEVERITY.GRAZE] = {
        "{attacker} {verb} {target_possessive} {zone}, leaving a shallow mark in the {tissue}.",
        "The {material} edge nicks {target_possessive} {zone}, a thin line across the {tissue}.",
        "A quick strike across {target_possessive} {zone} scratches the {tissue}.",
    },
    [SEVERITY.HIT] = {
        "{attacker} {verb} into {target_possessive} {zone}, cutting into the {tissue}.",
        "The {material} bites at {target_possessive} {zone}, parting {tissue}.",
        "{attacker} drives the {material} into {target_possessive} {zone}, drawing blood from the {tissue}.",
    },
    [SEVERITY.SEVERE] = {
        "{attacker} hacks into {target_possessive} {zone}; the {tissue} cracks under the {material}.",
        "A brutal blow to {target_possessive} {zone} fractures the {tissue}.",
        "The {material} tears through {target_possessive} {zone}, splintering {tissue}.",
    },
    [SEVERITY.CRITICAL] = {
        "{attacker} plunges the {material} into {target_possessive} {zone}, hitting something vital.",
        "A devastating strike to {target_possessive} {zone} — the {tissue} gives way.",
        "{attacker} drives the {material} deep into {target_possessive} {zone}; a fatal wound opens.",
    },
}

local DARK_TEMPLATES = {
    [SEVERITY.DEFLECT] = {
        "You hear a sharp clack as the {material} glances off in the dark.",
        "A dull thud at {target_possessive} {zone}; the {material} doesn't bite.",
        "In the dark, a scrape and a miss — the {material} skitters away.",
    },
    [SEVERITY.GRAZE] = {
        "You feel a quick sting at {target_possessive} {zone}; a light scratch in the {tissue}.",
        "A faint rip and warmth on {target_possessive} {zone} — the {material} just grazes.",
        "In the dark you hear a soft hiss and feel a nick on {target_possessive} {zone}.",
    },
    [SEVERITY.HIT] = {
        "A wet thud and sharp pain in {target_possessive} {zone}; the {material} bites into {tissue}.",
        "You hear a crack and feel the {material} sink into {target_possessive} {zone}.",
        "A heavy impact on {target_possessive} {zone} — warm blood and torn {tissue}.",
    },
    [SEVERITY.SEVERE] = {
        "A sickening crunch from {target_possessive} {zone}; the {tissue} fractures.",
        "You hear bone snap as the {material} smashes {target_possessive} {zone}.",
        "A brutal crack and tearing sound — {target_possessive} {zone} is wrecked.",
    },
    [SEVERITY.CRITICAL] = {
        "A deep, wet squelch and a scream — the blow to {target_possessive} {zone} is fatal.",
        "In the dark, a violent crunch and sudden stillness at {target_possessive} {zone}.",
        "You hear a piercing shriek and feel the {material} drive deep; something vital gives way.",
    },
}

local function render(template, data)
    local text = template:gsub("{(.-)}", function(key)
        return data[key] or ""
    end)
    -- #290/#338: Collapse preposition overlap when verb phrase already ends
    -- with a preposition that clashes with the template's following preposition
    text = text:gsub("into into", "into")
    text = text:gsub("into toward", "toward")
    text = text:gsub("into at", "at")
    text = text:gsub("onto into", "into")
    text = text:gsub("onto toward", "toward")
    text = text:gsub("onto at", "at")
    text = text:gsub("across across", "across")
    text = text:gsub("across toward", "toward")
    -- #338: Remove dangling prepositions before sentence-ending punctuation
    text = text:gsub(" into%.", ".")
    text = text:gsub(" into;", ";")
    text = text:gsub(" into,", ",")
    text = text:gsub(" onto%.", ".")
    text = text:gsub(" onto;", ";")
    text = text:gsub(" onto,", ",")
    text = text:gsub(" across%.", ".")
    text = text:gsub(" across;", ";")
    -- #338: Fix mid-sentence capitalization after conjunctions/prepositions
    text = text:gsub(" as A ", " as a ")
    text = text:gsub(" as The ", " as the ")
    return text
end

function M.generate(result, light)
    result = result or {}
    local severity = result.severity or SEVERITY.HIT
    local is_light = light ~= false
    local templates = is_light and LIGHT_TEMPLATES or DARK_TEMPLATES
    local list = templates[severity] or templates[SEVERITY.HIT]

    local defender = result.defender or {}
    local defender_name = defender.name or defender.id or "someone"

    local data = {
        attacker = actor_name(result.attacker),
        verb = action_verb(result),
        target_possessive = possessive(defender_name),
        zone = zone_text(result.zone, defender.body_tree),
        material = material_text(result.material_name or (result.weapon and result.weapon.material)),
        tissue = tissue_text(result.tissue_hit),
    }

    return render(pick(list), data)
end

M.narrate = M.generate

-- Expose SEVERITY for external use (budget logic, witness tests)
M.SEVERITY = SEVERITY

---------------------------------------------------------------------------
-- Witness narration — NPC-vs-NPC combat observed by the player
---------------------------------------------------------------------------

-- Third-person visual templates (same room + light)
local WITNESS_LIGHT_TEMPLATES = {
    [SEVERITY.DEFLECT] = {
        "{attacker} swipes at {defender}, but misses entirely.",
        "{attacker} lunges at {defender}; the blow glances harmlessly off.",
        "{defender} sidesteps as {attacker} strikes at empty air.",
    },
    [SEVERITY.GRAZE] = {
        "{attacker} scratches {defender} across the {zone}, barely drawing blood.",
        "{attacker} nicks {defender}'s {zone} with a light scratch.",
        "A quick swipe from {attacker} leaves a shallow mark on {defender}'s {zone}.",
    },
    [SEVERITY.HIT] = {
        "{attacker} strikes {defender} in the {zone}, drawing blood.",
        "{attacker} drives into {defender}'s {zone} with a solid hit.",
        "{attacker} lands a vicious blow to {defender}'s {zone}.",
    },
    [SEVERITY.SEVERE] = {
        "{attacker} savages {defender}'s {zone}; you hear bone crack.",
        "A brutal strike from {attacker} tears into {defender}'s {zone}.",
        "{attacker} smashes into {defender}'s {zone} with terrible force.",
    },
    [SEVERITY.CRITICAL] = {
        "{attacker} lunges at {defender}, claws extended — a killing blow to the {zone}.",
        "{attacker} drives deep into {defender}'s {zone}; {defender} crumples.",
        "A devastating strike from {attacker} to {defender}'s {zone} — the fight is over.",
    },
}

-- Audio-only templates (same room + dark)
local WITNESS_DARK_TEMPLATES = {
    [SEVERITY.DEFLECT] = {
        "You hear a brief scuffle nearby.",
        "Something shifts in the darkness — a scrape, then nothing.",
        "A quick shuffling sound nearby, then silence.",
    },
    [SEVERITY.GRAZE] = {
        "You hear a brief scuffle nearby.",
        "A small creature yelps softly in the darkness.",
        "You hear claws skitter across something in the dark.",
    },
    [SEVERITY.HIT] = {
        "Something yelps in pain in the darkness.",
        "You hear a wet thud and a yelp of pain in the dark.",
        "You hear a wet impact and a pained squeal nearby.",
    },
    [SEVERITY.SEVERE] = {
        "A terrible shriek pierces the darkness.",
        "You hear a sickening crunch in the dark, then whimpering.",
        "Something screams in agony nearby — bone snaps in the dark.",
    },
    [SEVERITY.CRITICAL] = {
        "A piercing shriek rips through the darkness, then silence.",
        "A violent thrashing in the dark ends with a final, wet crunch.",
        "A piercing shriek tears through the darkness, then nothing.",
    },
}

-- Adjacent room templates (distant audio, 1 line max)
local ADJACENT_TEMPLATES = {
    "You hear sounds of a struggle from the {direction}.",
    "Distant snarling and scuffling echo from the {direction}.",
    "Something fights in the {direction} — you hear muffled thuds.",
}

--- Generate third-person visual witness narration (same room + lit).
-- @param result  combat result table
-- @return string  narration text
local function witness_visual(result)
    result = result or {}
    local severity = result.severity or SEVERITY.HIT
    local list = WITNESS_LIGHT_TEMPLATES[severity] or WITNESS_LIGHT_TEMPLATES[SEVERITY.HIT]

    local attacker = result.attacker or {}
    local defender = result.defender or {}

    local data = {
        attacker = actor_name(attacker),
        defender = actor_name(defender),
        zone = zone_text(result.zone, defender.body_tree),
        material = material_text(result.material_name or (result.weapon and result.weapon.material)),
        tissue = tissue_text(result.tissue_hit),
    }

    return render(pick(list), data)
end

--- Generate audio-only witness narration (same room + dark).
-- @param result  combat result table
-- @return string  narration text
local function witness_dark(result)
    result = result or {}
    local severity = result.severity or SEVERITY.HIT
    local list = WITNESS_DARK_TEMPLATES[severity] or WITNESS_DARK_TEMPLATES[SEVERITY.HIT]
    return pick(list)
end

--- Generate distant narration for adjacent room combat.
-- @param direction  string direction label (e.g. "north", "above")
-- @return string  narration text
local function witness_adjacent(direction)
    local dir = direction or "nearby"
    local template = pick(ADJACENT_TEMPLATES)
    return render(template, { direction = dir })
end

--- Unified witness narration dispatcher.
-- Selects narration tier based on opts.light and opts.distance.
--
-- Called by tests as: describe_exchange(result, opts)
-- Called by Bart as:  describe_exchange(result, { light = bool, distance = str })
--
-- @param result  combat result table (attacker, defender, severity, zone, etc.)
-- @param opts    table  { light = bool, distance = "adjacent"|"out_of_range"|nil }
-- @return string|nil  narration text (nil for out-of-range)
function M.describe_exchange(result, opts)
    result = result or {}
    opts = opts or {}

    local distance = opts.distance
    if distance == "out_of_range" or distance == "distant" then
        return nil
    end

    if distance == "adjacent" then
        local direction = opts.direction or "nearby"
        return witness_adjacent(direction)
    end

    -- Same room: light-dependent
    if opts.light == false then
        return witness_dark(result)
    end
    return witness_visual(result)
end

-- Keep standalone helpers accessible for Bart's emit_witness pathway
M.describe_exchange_visual = witness_visual
M.describe_exchange_dark = witness_dark
M.describe_adjacent = witness_adjacent

---------------------------------------------------------------------------
-- Narration budget — caps NPC narration per combat round
---------------------------------------------------------------------------

--- Create a new budget tracker for one combat round.
-- @param cap  number  max NPC narration lines per round (default 6)
-- @return table  budget state object
function M.new_budget(cap)
    return { count = 0, cap = cap or 6, overflow_emitted = false }
end

M.create_budget = M.new_budget

-- Module-level budget for simple callers (reset_budget / get_budget)
local budget_state = M.new_budget(6)

--- Reset the module-level narration budget for a new combat round.
function M.reset_budget()
    budget_state.count = 0
    budget_state.overflow_emitted = false
end

--- Get current module-level budget state (for testing/inspection).
-- @return table  { count, cap, overflow_emitted }
function M.get_budget()
    return {
        count = budget_state.count,
        cap = budget_state.cap,
        overflow_emitted = budget_state.overflow_emitted,
    }
end

--- Check whether a narration line should be emitted under budget rules.
-- @param budget           table   budget state (count, cap, overflow_emitted)
-- @param severity         number  severity level from SEVERITY enum
-- @param is_player_combat boolean true if player's own fight (exempt)
-- @return boolean  true if the line should be emitted
local function budget_allows(budget, severity, is_player_combat)
    if is_player_combat then return true end
    if budget.count < budget.cap then return true end
    -- Over budget: only critical-tier narration (HIT+) passes
    if severity and severity >= SEVERITY.HIT then return true end
    return false
end

--- Emit a witness narration line, respecting the budget protocol.
--
-- Supports two calling conventions:
--   emit(result, budget, opts)  — budget-aware (test/engine API)
--   emit(text, severity, is_player_combat) — simple (legacy/internal)
--
-- @return string|nil  the line to show, or nil if suppressed
function M.emit(result_or_text, budget_or_severity, opts_or_player)
    -- Detect calling convention: budget-aware vs simple
    if type(result_or_text) == "table" then
        -- Budget-aware call: emit(result, budget, opts)
        local result = result_or_text
        local budget = budget_or_severity
        local opts = opts_or_player or {}

        if not budget or type(budget) ~= "table" then
            budget = budget_state
        end

        local severity = result.severity or SEVERITY.HIT
        local is_player_combat = opts.player_combat

        -- Generate text through describe_exchange
        local text = M.describe_exchange(result, opts)
        if not text then return nil end

        if not budget_allows(budget, severity, is_player_combat) then
            return nil
        end

        if not is_player_combat then
            budget.count = budget.count + 1
        end

        return text
    else
        -- Simple call: emit(text, severity, is_player_combat)
        local text = result_or_text
        local severity = budget_or_severity
        local is_player_combat = opts_or_player

        if not text then return nil end

        if not budget_allows(budget_state, severity, is_player_combat) then
            return nil
        end

        if not is_player_combat then
            budget_state.count = budget_state.count + 1
        end

        return text
    end
end

--- Returns overflow marker text if budget was exceeded this round.
-- Call after a full combat round to display the deferred indicator.
-- @param budget  table  budget state (optional, uses module-level if nil)
-- @return string|nil  "[The melee continues...]" if overflow occurred, nil otherwise
function M.overflow_text(budget)
    local b = budget or budget_state
    if b.count >= b.cap and not b.overflow_emitted then
        b.overflow_emitted = true
        return "[The melee continues...]"
    end
    return nil
end

---------------------------------------------------------------------------
-- Unified witness dispatcher — called by combat engine per exchange
---------------------------------------------------------------------------

--- Determine proximity tier between the player and a combat room.
-- @param player_room_id  string  the room the player is currently in
-- @param combat_room_id  string  the room where combat is happening
-- @param exits           table   exits table from the player's current room
-- @return string  "same", "adjacent", or "distant"
function M.proximity(player_room_id, combat_room_id, exits)
    if not player_room_id or not combat_room_id then return "distant" end
    if player_room_id == combat_room_id then return "same" end
    if exits then
        for _, exit in pairs(exits) do
            local target = type(exit) == "table" and exit.target or exit
            if target == combat_room_id then return "adjacent" end
        end
    end
    return "distant"
end

--- Find the direction label for an adjacent room exit.
-- @param exits           table   exits from the player's room
-- @param combat_room_id  string  the room where combat is happening
-- @return string  direction label (e.g. "north") or "nearby"
local function find_direction(exits, combat_room_id)
    if not exits or not combat_room_id then return "nearby" end
    for dir, exit in pairs(exits) do
        local target = type(exit) == "table" and exit.target or exit
        if target == combat_room_id then return dir end
    end
    return "nearby"
end

--- Generate witness narration for NPC combat based on proximity and light.
-- Full-context entry point for Bart's combat engine integration.
--
-- @param result           table   combat result (attacker, defender, severity, zone, etc.)
-- @param player_room_id   string  current room of the player
-- @param combat_room_id   string  room where the combat occurs
-- @param light            boolean whether the player's room is lit
-- @param exits            table   exits from the player's current room
-- @param is_player_combat boolean true if the player is a combatant
-- @return string|nil      narration text to display (nil = nothing to show)
function M.emit_witness(result, player_room_id, combat_room_id, light, exits, is_player_combat)
    result = result or {}
    local prox = M.proximity(player_room_id, combat_room_id, exits)

    if prox == "distant" then
        return nil
    end

    local severity = result.severity or SEVERITY.HIT
    local text

    if prox == "same" then
        if light then
            text = witness_visual(result)
        else
            text = witness_dark(result)
        end
    elseif prox == "adjacent" then
        local direction = find_direction(exits, combat_room_id)
        text = witness_adjacent(direction)
    end

    -- Use simple emit with module-level budget
    return M.emit(text, severity, is_player_combat)
end

--- Emit a morale break narration line (counts toward budget).
-- @param creature_name  string  name of the fleeing creature
-- @param direction      string  direction it flees toward (optional)
-- @param light          boolean whether the room is lit
-- @return string|nil    narration text or nil if suppressed
function M.emit_morale_break(creature_name, direction, light)
    local name = creature_name or "Something"
    local text
    if light then
        if direction then
            text = name .. " panics and bolts " .. direction .. "!"
        else
            text = name .. " panics and flees!"
        end
    else
        if direction then
            text = "You hear something scramble away to the " .. direction .. "."
        else
            text = "You hear something scramble away in the dark."
        end
    end
    return M.emit(text, SEVERITY.GRAZE, false)
end

---------------------------------------------------------------------------
-- Combat sound propagation narration API (WAVE-4)
---------------------------------------------------------------------------

--- Emit combat sound narration for the player based on distance from combat.
-- Same room: nil (combat narration already covers it).
-- Adjacent room: directional sound text.
-- 2+ exits away: nil (sound doesn't propagate that far).
--
-- @param room       string  room id where combat occurs
-- @param intensity  number  0-10 scale (unarmed=3, weapon=6, death=8)
-- @param witness_text string template override (unused in Phase 3; reserved)
-- @param opts       table   { player_room_id, exits, light }
-- @return string|nil  narration text for the player
function M.emit_combat_sound(room, intensity, witness_text, opts)
    opts = opts or {}
    local prox = M.proximity(opts.player_room_id, room, opts.exits)

    if prox == "same" then return nil end
    if prox == "distant" then return nil end

    -- Adjacent: directional sound narration
    local direction = find_direction(opts.exits, room)
    return "You hear violent sounds from the " .. direction .. ". Something crashes."
end

--- Narrate a creature fleeing from combat noise (visible to player only).
-- @param creature_name string  display name of the creature
-- @param light         boolean whether the player can see
-- @return string|nil   narration text, or nil if dark
function M.creature_flee_sound(creature_name, light)
    if not light then return nil end
    return (creature_name or "Something") .. " skitters away from the noise."
end

--- Narrate a predator investigating combat noise (visible to player only).
-- @param creature_name string  display name of the creature
-- @param light         boolean whether the player can see
-- @return string|nil   narration text, or nil if dark
function M.creature_investigate_sound(creature_name, light)
    if not light then return nil end
    return (creature_name or "Something") .. " perks up, drawn toward the sounds."
end

return M

end

package.preload["engine.combat.npc-behavior"] = function()
-- engine/combat/npc-behavior.lua
-- NPC combat decision-making: response selection, stance, target zone.
-- Reads creature combat.behavior metadata (Principle 8).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

-- Map creature attack_pattern → engine stance
local PATTERN_TO_STANCE = {
    aggressive  = "aggressive",
    sustained   = "aggressive",
    ambush      = "aggressive",
    hit_and_run = "defensive",
    defensive   = "defensive",
    opportunistic = "balanced",
    random      = "balanced",
    cornered    = "aggressive",
}

---------------------------------------------------------------------------
-- select_response(creature, attacker, combat_state) -> response_type
-- Reads defender's combat.behavior.defense (dodge/block/flee/counter/none).
-- Cornered creatures never select "flee" — they fight.
---------------------------------------------------------------------------
function M.select_response(creature, attacker, combat_state)
    local cb = creature and creature.combat and creature.combat.behavior
    if not cb then return nil end
    local defense = cb.defense
    -- Cornered creatures cannot flee
    if creature._cornered and defense == "flee" then
        return "counter"
    end
    if defense and defense ~= "none" then return defense end
    return nil
end

---------------------------------------------------------------------------
-- select_stance(creature, combat_state) -> stance_string
-- Maps creature's combat.behavior.attack_pattern to engine stance.
-- Cornered creatures always use aggressive stance.
---------------------------------------------------------------------------
function M.select_stance(creature, combat_state)
    if creature._cornered then return "aggressive" end
    local cb = creature and creature.combat and creature.combat.behavior
    if not cb then return "balanced" end
    local pattern = cb.attack_pattern or cb.stance
    if pattern and PATTERN_TO_STANCE[pattern] then
        return PATTERN_TO_STANCE[pattern]
    end
    return "balanced"
end

---------------------------------------------------------------------------
-- select_target_zone(creature, defender, combat_state) -> zone_string|nil
-- Uses combat.behavior.target_priority to bias zone selection.
-- "weakest" → vital zones, "threatening" → largest zone, else nil (random).
---------------------------------------------------------------------------
function M.select_target_zone(creature, defender, combat_state)
    local cb = creature and creature.combat and creature.combat.behavior
    if not cb or not cb.target_priority then return nil end
    local bt = defender and defender.body_tree
    if not bt then return nil end

    local priority = cb.target_priority
    if priority == "weakest" then
        -- Target vital zones (head preferred)
        for zone, info in pairs(bt) do
            if info and info.vital then return zone end
        end
    elseif priority == "threatening" then
        -- Target largest zone
        local best_zone, best_size = nil, 0
        for zone, info in pairs(bt) do
            local sz = (info and info.size) or 1
            if sz > best_size then
                best_zone, best_size = zone, sz
            end
        end
        return best_zone
    end
    -- "closest" or unknown → nil (engine uses random weighted)
    return nil
end

return M

end

package.preload["engine.combat.resolution"] = function()
-- engine/combat/resolution.lua
-- Damage resolution: resolve_damage(), layer penetration, severity mapping,
-- update (health/injury application), interrupt_check.
--
-- Ownership: Bart (Architect) — split from combat/init.lua in Phase 3 WAVE-0.

local materials = require("engine.materials")
local presentation_ok, presentation = pcall(require, "engine.ui.presentation")
local injuries_ok, injuries = pcall(require, "engine.injuries")
if not injuries_ok then injuries = nil end
local npc_behavior_ok, npc_behavior = pcall(require, "engine.combat.npc-behavior")
if not npc_behavior_ok then npc_behavior = nil end

local R = {}

R.SEVERITY = {
    DEFLECT = 0,
    GRAZE = 1,
    HIT = 2,
    SEVERE = 3,
    CRITICAL = 4,
}

R.SIZE_MODIFIERS = {
    tiny = 0.5,
    small = 1.0,
    medium = 2.0,
    large = 4.0,
    huge = 8.0,
}

R.STANCE_MODIFIERS = {
    aggressive = { attack = 1.3, defense = 1.3 },
    defensive = { attack = 0.7, defense = 0.7 },
    balanced = { attack = 1.0, defense = 1.0 },
}

local FORCE_SCALE = 0.1
-- Tissue-layer penetration resistance. Tuned so unarmed blunt (force=2, bone)
-- can penetrate soft tissue (hide/flesh) at GRAZE level while bone/organ stay
-- protected.  See #275 — old value of 1000 made fists deal zero damage.
local THICKNESS = 200

local function ensure_material_defaults()
    if not materials or not materials.registry then return end
    for _, mat in pairs(materials.registry) do
        if mat.max_edge == nil then
            if type(mat.hardness) == "number" then
                mat.max_edge = math.max(1, math.floor(mat.hardness))
            else
                mat.max_edge = 1
            end
        end
    end
end

ensure_material_defaults()

function R.is_player(obj)
    return obj and (obj.id == "player" or obj.is_player == true)
end

local function size_modifier(combat)
    local size = combat and combat.size or "medium"
    return R.SIZE_MODIFIERS[size] or 1.0
end

local function get_material(name)
    if materials and materials.get then
        local mat = materials.get(name)
        if mat then
            if mat.max_edge == nil then
                mat.max_edge = type(mat.hardness) == "number" and math.max(1, math.floor(mat.hardness)) or 1
            end
            return mat
        end
    end
    return { density = 1000, hardness = 1, flexibility = 0.5, max_edge = 1 }
end

function R.normalize_weapon(weapon)
    if not weapon then return nil end
    if weapon.combat then return weapon end
    if weapon.type then
        return {
            id = weapon.id,
            name = weapon.name or weapon.id,
            material = weapon.material,
            combat = {
                type = weapon.type,
                force = weapon.force or 1,
                message = weapon.message or "hits",
                two_handed = weapon.two_handed or false,
            },
            on_hit = weapon.on_hit,
            _natural_weapon = true,
        }
    end
    return weapon
end

function R.pick_weapon(attacker)
    if attacker and attacker.combat and attacker.combat.natural_weapons then
        local list = attacker.combat.natural_weapons
        if #list > 0 then
            return R.normalize_weapon(list[math.random(#list)])
        end
    end
    return R.normalize_weapon({
        id = "fist",
        name = "bare fist",
        material = "bone",
        combat = { type = "blunt", force = 2, message = "punches", two_handed = false },
    })
end

local function zone_weights(body_tree, exclude)
    local zones = {}
    local total = 0
    for zone, info in pairs(body_tree or {}) do
        if zone ~= exclude then
            local weight = (info and info.size) or 1
            zones[#zones + 1] = { id = zone, weight = weight }
            total = total + weight
        end
    end
    return zones, total
end

local function weighted_zone(body_tree, exclude)
    local zones, total = zone_weights(body_tree, exclude)
    if #zones == 0 then return nil end
    local roll = math.random() * total
    local acc = 0
    for _, entry in ipairs(zones) do
        acc = acc + entry.weight
        if roll <= acc then return entry.id end
    end
    return zones[#zones].id
end

local function select_zone(body_tree, target_zone, allow_target, accuracy)
    if not body_tree or next(body_tree) == nil then return target_zone or "body" end
    local target_accuracy = accuracy or 0.6
    if target_zone and allow_target and body_tree[target_zone] then
        math.random()
        if math.random() <= target_accuracy then
            return target_zone
        end
        return weighted_zone(body_tree, target_zone) or target_zone
    end
    return weighted_zone(body_tree, nil) or target_zone
end

local function map_severity(layer)
    if not layer then return R.SEVERITY.DEFLECT end
    if layer == "organ" then return R.SEVERITY.CRITICAL end
    if layer == "bone" then return R.SEVERITY.SEVERE end
    if layer == "flesh" then return R.SEVERITY.HIT end
    return R.SEVERITY.GRAZE
end

---------------------------------------------------------------------------
-- Core damage resolution: layer penetration + severity calculation
---------------------------------------------------------------------------
function R.resolve_damage(attacker, defender, weapon, target_zone, response, opts)
    local result = {
        attacker = attacker,
        defender = defender,
        weapon = weapon,
    }

    local light = true
    if opts and opts.light ~= nil then
        light = opts.light
    elseif opts and presentation_ok and presentation and presentation.get_light_level then
        light = presentation.get_light_level(opts) ~= "dark"
    end

    local stance = opts and opts.stance or "balanced"
    local stance_mod = R.STANCE_MODIFIERS[stance] or R.STANCE_MODIFIERS.balanced

    -- NPC stance: if attacker is NPC, read combat.behavior via npc-behavior
    if not R.is_player(attacker) and npc_behavior then
        local npc_stance = npc_behavior.select_stance(attacker)
        if npc_stance and R.STANCE_MODIFIERS[npc_stance] then
            stance = npc_stance
            stance_mod = R.STANCE_MODIFIERS[npc_stance]
        end
    end

    local weapon_type = weapon and weapon.combat and weapon.combat.type or "blunt"
    if weapon_type == "slash" then weapon_type = "edged" end

    local weapon_force = weapon and weapon.combat and weapon.combat.force or 1
    local weapon_material = weapon and (weapon.material or weapon.combat and weapon.combat.material) or "flesh"
    local mat = get_material(weapon_material)
    local base_force = (mat.density or 1000) * size_modifier(attacker and attacker.combat) * weapon_force * FORCE_SCALE
    local accuracy = weapon_force >= 7 and 1.0 or 0.6

    if R.is_player(attacker) then
        base_force = base_force * (stance_mod.attack or 1.0)
        -- WAVE-3: Stress attack_penalty — each -1 reduces force by 15%
        if injuries and injuries.get_stress_effects then
            local effects = injuries.get_stress_effects(attacker)
            local penalty = effects.attack_penalty or 0
            if penalty < 0 then
                base_force = base_force * math.max(0.3, 1.0 + penalty * 0.15)
            end
        end
    elseif stance ~= "balanced" then
        base_force = base_force * (stance_mod.attack or 1.0)
    end

    -- Cornered bonus: attack × 1.5 when creature has no escape
    if opts and opts.cornered_bonus then
        base_force = base_force * opts.cornered_bonus
    end

    local defense_multiplier = 1.0
    local response_type = response
    if type(response_type) == "table" then response_type = response_type.type end

    -- NPC response auto-select: if no response provided, read defender's behavior
    if not response_type and not R.is_player(defender) and npc_behavior then
        response_type = npc_behavior.select_response(defender, attacker)
    end
    if response_type == "block" then
        defense_multiplier = 0.3
    elseif response_type == "flee" then
        defense_multiplier = 0.5
        result.fled = true
        result.combat_over = true
    elseif response_type == "dodge" then
        if math.random() <= 0.4 then
            result.severity = R.SEVERITY.DEFLECT
            result.zone = select_zone(defender and defender.body_tree, target_zone, light, accuracy)
            result.tissue_hit = defender and defender.body_tree
                and defender.body_tree[result.zone]
                and defender.body_tree[result.zone].tissue
                and defender.body_tree[result.zone].tissue[1]
            result.material_name = weapon_material
            result.action_verb = weapon and weapon.combat and weapon.combat.message or "hits"
            result.dodged = true
            result.light = light
            return result
        end
    elseif response_type == "counter" then
        result.counter = true
    end

    if R.is_player(defender) then
        defense_multiplier = defense_multiplier * (stance_mod.defense or 1.0)
    elseif stance ~= "balanced" then
        defense_multiplier = defense_multiplier * (stance_mod.defense or 1.0)
    end

    base_force = base_force * defense_multiplier
    if base_force <= 0 then
        result.severity = R.SEVERITY.DEFLECT
        result.zone = select_zone(defender and defender.body_tree, target_zone, light, accuracy)
        result.tissue_hit = defender and defender.body_tree
            and defender.body_tree[result.zone]
            and defender.body_tree[result.zone].tissue
            and defender.body_tree[result.zone].tissue[1]
        result.material_name = weapon_material
        result.action_verb = weapon and weapon.combat and weapon.combat.message or "hits"
        result.light = light
        return result
    end

    local zone = select_zone(defender and defender.body_tree, target_zone, light, accuracy)
    local zone_info = defender and defender.body_tree and defender.body_tree[zone] or nil
    local layers = zone_info and zone_info.tissue or { "flesh" }

    local deepest = nil
    if weapon_type == "edged" or weapon_type == "pierce" then
        local edge_force = base_force * (mat.max_edge or 1)
        for _, layer in ipairs(layers) do
            local layer_mat = get_material(layer)
            edge_force = edge_force - ((layer_mat.hardness or 1) * THICKNESS)
            if edge_force > 0 then
                deepest = layer
            else
                break
            end
        end
    else
        local remaining = base_force
        for _, layer in ipairs(layers) do
            local layer_mat = get_material(layer)
            local transfer = remaining * (1.0 - (layer_mat.flexibility or 0))
            local layer_damage = transfer - ((layer_mat.hardness or 1) * THICKNESS * 0.5)
            if layer_damage > 0 then
                deepest = layer
            end
            remaining = transfer * 0.8
            if remaining <= 0 then break end
        end
    end

    result.zone = zone
    result.tissue_hit = deepest or layers[1]
    result.severity = map_severity(deepest)
    result.material_name = weapon_material
    result.action_verb = weapon and weapon.combat and weapon.combat.message or "hits"
    result.light = light
    return result
end

---------------------------------------------------------------------------
-- Severity → injury type mapping
---------------------------------------------------------------------------
local SEVERITY_INJURY_MAP = {
    edged = {
        [1] = "minor-cut",       -- GRAZE
        [2] = "bleeding",        -- HIT
        [3] = "bleeding",        -- SEVERE
        [4] = "bleeding",        -- CRITICAL
    },
    pierce = {
        [1] = "minor-cut",
        [2] = "bleeding",
        [3] = "bleeding",
        [4] = "bleeding",
    },
    blunt = {
        [1] = "bruised",
        [2] = "bruised",
        [3] = "crushing-wound",
        [4] = "crushing-wound",
    },
}

function R.map_severity_to_injury(severity, weapon_type)
    if not severity or severity <= 0 then return nil end
    local wtype = weapon_type or "blunt"
    if wtype == "slash" then wtype = "edged" end
    local map = SEVERITY_INJURY_MAP[wtype] or SEVERITY_INJURY_MAP.blunt
    return map[severity] or "bruised"
end

---------------------------------------------------------------------------
-- Update: apply damage to defender, inflict injuries, handle death
---------------------------------------------------------------------------
function R.update(result, _opts)
    local defender = result.defender
    if not defender or not defender.health then return result end

    local damage_map = {
        [R.SEVERITY.DEFLECT] = 0,
        [R.SEVERITY.GRAZE] = 1,
        [R.SEVERITY.HIT] = 3,
        [R.SEVERITY.SEVERE] = 6,
        [R.SEVERITY.CRITICAL] = 10,
    }
    local damage = damage_map[result.severity or R.SEVERITY.DEFLECT] or 0
    defender.health = math.max(0, defender.health - damage)
    result.damage = damage
    result.target_health = defender.health

    -- C11: Inflict injury via the injury subsystem when damage lands
    if injuries and damage > 0 and defender.injuries then
        local weapon = result.weapon
        local weapon_type = weapon and weapon.combat and weapon.combat.type or "blunt"
        local injury_type = R.map_severity_to_injury(result.severity, weapon_type)
        if injury_type then
            local source = weapon and weapon.id or "unknown"
            local zone = result.zone
            pcall(injuries.inflict, defender, injury_type, source, zone, damage)
            result.injury_type = injury_type
        end
    end

    -- Track 4C: on_hit disease delivery — severity >= HIT triggers weapon's
    -- on_hit effect (e.g. venom, rabies). Fully generic: no creature-specific
    -- code (Principle 8). Symmetric for player-vs-NPC and NPC-vs-NPC.
    if injuries and (result.severity or 0) >= R.SEVERITY.HIT then
        local weapon = result.weapon
        local on_hit = weapon and weapon.on_hit
        if on_hit and on_hit.inflict and on_hit.probability then
            if math.random() <= on_hit.probability then
                local source = weapon.id or "unknown"
                local zone = result.zone
                pcall(injuries.inflict, defender, on_hit.inflict, source, zone)
                result.disease_inflicted = on_hit.inflict
            end
        end
    end

    -- C12: Creature death mutation
    if defender.health <= 0 then
        defender._state = "dead"
        defender.animate = false
        defender.portable = true
        defender.alive = false
        result.defender_dead = true

        -- #345/#370: Use "The" + id for death narration (capitalized, definite article)
        local death_id = defender.id or "creature"
        local default_death = "The " .. death_id .. " is dead."

        -- Pull death description from creature's dead state definition
        local dead_state = defender.states and defender.states.dead
        if dead_state then
            if dead_state.room_presence then
                defender.room_presence = dead_state.room_presence
            end
            result.death_narration = dead_state.description or default_death
        else
            result.death_narration = default_death
        end
    end

    return result
end

---------------------------------------------------------------------------
-- Interrupt check: detect stance-ineffective streaks
---------------------------------------------------------------------------
function R.interrupt_check(result, combat_state)
    if not combat_state then return nil end
    if result.weapon_broke then return "weapon_break" end
    if result.armor_failed then return "armor_fail" end
    if result.severity == R.SEVERITY.DEFLECT then
        combat_state.deflect_streak = (combat_state.deflect_streak or 0) + 1
    else
        combat_state.deflect_streak = 0
    end
    if (combat_state.deflect_streak or 0) >= 2 then
        return "stance_ineffective"
    end
    return nil
end

return R

end

package.preload["engine.containment"] = function()
-- engine/containment/init.lua
-- Four-layer containment validator with weight checking and multi-surface support.
--
-- Layers:
--   1. Container identity -- is the target a container at all?
--   2. Physical size -- does the item physically fit?
--   3. Capacity -- is there room (by size and weight)?
--   4. Category accept/reject -- does the container allow this type of item?
--
-- Multi-surface: when a container has `surfaces`, the validator targets a
-- specific surface (top, inside, underneath, etc.) instead of root-level fields.

local containment = {}

-- Helper: get the containment zone (surface or root) for a container.
-- Returns the zone table and nil, or nil and an error string.
local function get_zone(container_obj, surface_name)
  if container_obj.surfaces and surface_name then
    local zone = container_obj.surfaces[surface_name]
    if not zone then
      return nil, "there is no '" .. surface_name .. "' on " .. (container_obj.name or container_obj.id)
    end
    if zone.accessible == false then
      return nil, "the " .. surface_name .. " of " .. (container_obj.name or container_obj.id) .. " is not accessible"
    end
    return zone, nil
  end

  -- No surfaces defined or no surface specified -- fall back to root-level fields
  if container_obj.surfaces and not surface_name then
    return nil, "you need to specify where on " .. (container_obj.name or container_obj.id) .. " (e.g. top, inside)"
  end

  -- Root-level container fields
  -- #79: check accessible on root-level containers (e.g. closed drawer)
  if container_obj.accessible == false then
    return nil, (container_obj.name or container_obj.id) .. " is not accessible"
  end
  return {
    capacity = container_obj.capacity or 0,
    max_item_size = container_obj.max_item_size,
    weight_capacity = container_obj.weight_capacity,
    contents = container_obj.contents or {},
    accept = container_obj.accept,
    reject = container_obj.reject,
  }, nil
end

-- Helper: sum weights of contents in a zone, using the registry to look up each item.
local function contents_weight(zone, registry)
  local total = 0
  if not zone.contents or not registry then return total end
  for _, item_id in ipairs(zone.contents) do
    local obj = registry:get(item_id)
    if obj then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

-- Helper: sum sizes of contents in a zone, using the registry.
local function contents_size(zone, registry)
  local total = 0
  if not zone.contents or not registry then return total end
  for _, item_id in ipairs(zone.contents) do
    local obj = registry:get(item_id)
    if obj then
      total = total + (obj.size or 0)
    end
  end
  return total
end

-- can_contain(item, container_obj, surface_name, registry)
--   -> true, nil  |  false, reason_string
--
-- Validates all four layers. `surface_name` is optional (nil for root-level).
-- `registry` is optional but required for weight checking.
function containment.can_contain(item, container_obj, surface_name, registry)
  -- Layer 0: Self-containment guard (BUG-036b)
  if item == container_obj then
    return false, "You can't put something inside itself."
  end

  -- Layer 1: Container identity
  if container_obj.surfaces then
    -- Multi-surface objects are containers by definition
  elseif not container_obj.container then
    return false, (container_obj.name or container_obj.id) .. " is not a container"
  end

  -- Get the target zone
  local zone, zone_err = get_zone(container_obj, surface_name)
  if not zone then
    return false, zone_err
  end

  -- Layer 2: Physical size
  local item_size = item.size or 1
  if zone.max_item_size and item_size > zone.max_item_size then
    return false, (item.name or item.id) .. " is too large to fit"
  end

  -- Layer 3a: Size capacity
  local used_size = contents_size(zone, registry)
  local capacity = zone.capacity or 0
  if capacity > 0 and (used_size + item_size) > capacity then
    local prep = container_obj.container_preposition or "on"
    return false, "There is not enough room " .. prep .. " " .. (container_obj.name or "that") .. "."
  end

  -- Layer 3b: Weight capacity
  local item_weight = item.weight or 0
  if zone.weight_capacity and zone.weight_capacity > 0 then
    local used_weight = contents_weight(zone, registry)
    if (used_weight + item_weight) > zone.weight_capacity then
      return false, (item.name or item.id) .. " is too heavy"
    end
  end

  -- Layer 4: Category accept/reject
  if item.categories and type(item.categories) == "table" then
    -- Reject list: if item has any rejected category, deny
    if zone.reject and type(zone.reject) == "table" then
      for _, cat in ipairs(item.categories) do
        for _, rejected in ipairs(zone.reject) do
          if cat == rejected then
            return false, (item.name or item.id) .. " cannot be placed there"
          end
        end
      end
    end

    -- Accept list: if specified, item must have at least one accepted category
    if zone.accept and type(zone.accept) == "table" and #zone.accept > 0 then
      local accepted = false
      for _, cat in ipairs(item.categories) do
        for _, allowed in ipairs(zone.accept) do
          if cat == allowed then
            accepted = true
            break
          end
        end
        if accepted then break end
      end
      if not accepted then
        return false, (item.name or item.id) .. " does not belong there"
      end
    end
  end

  return true, nil
end

return containment

end

package.preload["engine.creatures.actions"] = function()
-- engine/creatures/actions.lua
-- Action scoring + execution for creature behavior engine.
-- Extracted from init.lua to keep module under 500 LOC ceiling.
--
-- Ownership: Bart (Architecture Lead)

local M = {}

local predator_prey = require("engine.creatures.predator-prey")
local respawn = require("engine.creatures.respawn")
local combat_ok, combat = pcall(require, "engine.combat")
if not combat_ok then combat = nil end

---------------------------------------------------------------------------
-- Behavior selection (utility scoring)
---------------------------------------------------------------------------

-- score_actions(creature, context, helpers) -> sorted array of { action, score }
-- helpers: { get_location, get_creatures_in_room }
function M.score_actions(creature, context, helpers)
    local behavior = creature.behavior or {}
    local drives = creature.drives or {}
    local scores = {}

    scores[#scores + 1] = { action = "idle", score = 10 }

    -- C14: Suppress wander during active combat
    local wander_score = 0
    if not (context and context.combat_active) then
        if drives.curiosity then
            wander_score = wander_score + (drives.curiosity.value or 0) * 0.3
        end
        wander_score = wander_score + (behavior.wander_chance or 0) * 0.2
    end
    scores[#scores + 1] = { action = "wander", score = wander_score }

    local fear_val = drives.fear and drives.fear.value or 0
    local flee_threshold = behavior.flee_threshold or 50
    if fear_val >= flee_threshold then
        scores[#scores + 1] = { action = "flee", score = fear_val * 1.5 }
    end

    local vocal_score = 0
    if fear_val > 10 and fear_val < flee_threshold then
        vocal_score = fear_val * 0.3
    end
    if drives.curiosity then
        vocal_score = vocal_score + (drives.curiosity.value or 0) * 0.1
    end
    scores[#scores + 1] = { action = "vocalize", score = vocal_score }

    -- Attack: score when prey is present in the same room
    if predator_prey.has_prey_in_room(creature, context, helpers.get_creatures_in_room, helpers.get_location) then
        local aggression = behavior.aggression or 0
        local hunger_val = drives.hunger and drives.hunger.value or 0
        local attack_score = aggression * 0.5 + hunger_val * 0.5
        -- Territorial boost: creature in home territory gets aggression bonus
        if behavior.territorial then
            local territory = behavior.territory or behavior.home_territory
            local loc = helpers.get_location(context.registry, creature)
            if territory and loc == territory then
                attack_score = attack_score + aggression * 0.3
            end
        end
        scores[#scores + 1] = { action = "attack", score = attack_score }
    end

    -- Create object: score when creature has creates_object behavior
    if behavior.creates_object then
        local create_score = behavior.creates_object.priority or 15
        scores[#scores + 1] = { action = "create_object", score = create_score }
    end

    for _, entry in ipairs(scores) do
        entry.score = entry.score + math.random() * 2
    end

    table.sort(scores, function(a, b) return a.score > b.score end)
    return scores
end

---------------------------------------------------------------------------
-- Movement
---------------------------------------------------------------------------

-- move_creature(context, creature, target_room_id, helpers)
-- helpers: { get_location, get_room, set_location }
function M.move_creature(context, creature, target_room_id, helpers)
    local old_loc = helpers.get_location(context.registry, creature)

    -- Update room.contents arrays (real game uses these)
    local old_room = helpers.get_room(context, old_loc)
    if old_room and old_room.contents then
        for i = #old_room.contents, 1, -1 do
            if old_room.contents[i] == creature.id then
                table.remove(old_room.contents, i)
                break
            end
        end
    end
    local new_room = helpers.get_room(context, target_room_id)
    if new_room then
        new_room.contents = new_room.contents or {}
        new_room.contents[#new_room.contents + 1] = creature.id
    end

    -- Update location (both obj.location and mock registry tracker)
    helpers.set_location(context.registry, creature, target_room_id)
end

---------------------------------------------------------------------------
-- Food-as-bait behavior (Track 5C; R-5 boundary: no cooking/recipes/spoilage)
---------------------------------------------------------------------------

local function find_bait(ctx, room_id, cid, helpers)
    local r = {}
    for _, o in ipairs(helpers.list_objects(ctx.registry)) do
        if o.food and o.food.bait_targets and helpers.get_location(ctx.registry, o) == room_id then
            for _, t in ipairs(o.food.bait_targets) do if t == cid then r[#r+1]=o; break end end
        end
    end
    table.sort(r, function(a,b) return (a.food.bait_value or 0) > (b.food.bait_value or 0) end)
    return r
end

function M.try_bait(ctx, creature, helpers)
    local h = creature.drives and creature.drives.hunger
    if not h or (h.value or 0) < (h.satisfy_threshold or 80) then return nil end
    if ctx.combat_active or (combat and combat.find_fight_for_combatant and combat.find_fight_for_combatant(creature)) then return nil end
    local loc = helpers.get_location(ctx.registry, creature); if not loc then return nil end
    local cn = creature.name or "a creature"
    local pr, CN, msgs = helpers.get_player_room_id(ctx), cn:sub(1,1):upper()..cn:sub(2), {}
    local food = find_bait(ctx, loc, creature.id, helpers)
    if #food > 0 then
        ctx.registry:remove(food[1].id); h.value = h.min or 0
        if loc == pr then local m = CN.." scurries toward "..(food[1].name or "the food").." and devours it."; msgs[1] = m; print(m) end
        return msgs end
    local best, bv = nil, -1
    for _, ex in ipairs(helpers.get_valid_exits(ctx, loc, creature)) do
        local a = find_bait(ctx, ex.target, creature.id, helpers)
        if #a > 0 and (a[1].food.bait_value or 0) > bv then best, bv = ex.target, a[1].food.bait_value or 0 end end
    if not best then return nil end; M.move_creature(ctx, creature, best, helpers)
    if loc == pr then msgs[1] = CN.." scurries away, drawn by a scent." end
    if best == pr then msgs[1] = CN.." arrives, sniffing hungrily." end
    return msgs
end

---------------------------------------------------------------------------
-- Action execution
---------------------------------------------------------------------------

-- execute_action(context, creature, action, helpers) -> messages[]
-- helpers: { get_player_room_id, get_location, get_valid_exits, get_room,
--            emit_stimulus, handle_creature_death, attempt_flee }
function M.execute_action(context, creature, action, helpers)
    local messages = {}
    local player_room = helpers.get_player_room_id(context)
    local creature_loc = helpers.get_location(context.registry, creature)

    if action == "idle" then
        if creature._state and creature._state ~= "alive-idle"
           and creature._state ~= "dead" then
            creature._state = "alive-idle"
        end

    elseif action == "wander" then
        local exits = helpers.get_valid_exits(context, creature_loc, creature)

        -- Territory leash (#400): restrict wander to patrol_rooms or territory
        local behavior = creature.behavior or {}
        if behavior.territory then
            local patrol = behavior.patrol_rooms
            if not patrol then
                patrol = { behavior.territory }
            end
            local allowed = {}
            for _, ex in ipairs(exits) do
                for _, room_id in ipairs(patrol) do
                    if ex.target == room_id then
                        allowed[#allowed + 1] = ex
                        break
                    end
                end
            end
            exits = allowed
        end

        if #exits > 0 then
            local choice = exits[math.random(#exits)]
            local old_loc = creature_loc

            if creature._state and creature._state ~= "dead" then
                creature._state = "alive-wander"
            end

            M.move_creature(context, creature, choice.target, helpers)

            if old_loc == player_room then
                local name = creature.name or "a creature"
                local Name = name:sub(1,1):upper() .. name:sub(2)
                -- #401: Add prepositions for non-cardinal exit directions
                local CARDINAL = {
                    north=true, south=true, east=true, west=true,
                    up=true, down=true, northeast=true, northwest=true,
                    southeast=true, southwest=true,
                }
                local dir = choice.direction
                if CARDINAL[dir] then
                    messages[#messages + 1] = Name .. " scurries " .. dir .. "."
                else
                    messages[#messages + 1] = Name .. " scurries through the " .. dir .. "."
                end
            elseif choice.target == player_room then
                local name = creature.name or "a creature"
                local st = creature.states and creature.states[creature._state]
                local arrival = st and st.room_presence
                messages[#messages + 1] = arrival or
                    (name:sub(1,1):upper() .. name:sub(2) .. " arrives.")
            end
            creature._last_exit = choice.direction
        else
            if creature._state and creature._state ~= "dead" then
                creature._state = "alive-idle"
            end
        end

    elseif action == "flee" then
        local exits = helpers.get_valid_exits(context, creature_loc, creature)
        if #exits > 0 then
            local choice = exits[math.random(#exits)]
            local old_loc = creature_loc

            if creature._state and creature._state ~= "dead" then
                creature._state = "alive-flee"
            end

            M.move_creature(context, creature, choice.target, helpers)

            if old_loc == player_room then
                local name = creature.name or "a creature"
                messages[#messages + 1] = name:sub(1,1):upper() .. name:sub(2) ..
                    " bolts " .. choice.direction .. "!"
            elseif choice.target == player_room then
                local name = creature.name or "a creature"
                messages[#messages + 1] = name:sub(1,1):upper() .. name:sub(2) ..
                    " darts into the room, eyes wide with fear!"
            end
            creature._last_exit = choice.direction
        else
            if creature._state and creature._state ~= "dead" then
                creature._state = "alive-flee"
            end
        end

    elseif action == "vocalize" then
        if creature_loc == player_room then
            local st = creature.states and creature.states[creature._state]
            local sound = st and st.on_listen
            if sound then
                messages[#messages + 1] = sound
            end
        end

    elseif action == "create_object" then
        local obj_spec = (creature.behavior or {}).creates_object
        if obj_spec then
            -- Cooldown check (os.time-based; avoids coupling to presentation layer)
            if obj_spec.cooldown then
                local now = os.time()
                if creature._last_creation and (now - creature._last_creation) < obj_spec.cooldown then
                    obj_spec = nil
                end
            end
            if obj_spec then
                -- max_per_room cap (declarative metadata — Principle 8)
                local proceed = true
                if obj_spec.max_per_room and obj_spec.template then
                    local room = helpers.get_room(context, creature_loc)
                    if room and room.contents then
                        local tpl = obj_spec.template
                        local count = 0
                        for _, ref in ipairs(room.contents) do
                            local obj = context.registry and type(context.registry.get) == "function"
                                and context.registry:get(ref) or nil
                            if obj and obj.id and (obj.id == tpl or obj.id:sub(1, #tpl) == tpl) then
                                count = count + 1
                            end
                        end
                        if count >= obj_spec.max_per_room then
                            proceed = false
                        end
                    end
                end
                -- Custom condition check
                if proceed and obj_spec.condition then
                    proceed = obj_spec.condition(creature, context, helpers)
                end
                if proceed then
                    local instance
                    -- Prefer registry:instantiate(template) for proper deep-copy + GUID
                    if obj_spec.template and context.registry
                        and type(context.registry.instantiate) == "function" then
                        instance = context.registry:instantiate(obj_spec.template)
                    else
                        local spec = obj_spec.object_def or {}
                        instance = {}
                        for k, v in pairs(spec) do instance[k] = v end
                        local uid = (creature.id or "creature") .. "-obj-" .. tostring(os.time()) .. "-" .. tostring(math.random(1000, 9999))
                        instance.id = instance.id and (instance.id .. "-" .. uid) or uid
                        -- Register manually when not using instantiate
                        if context.registry then
                            if type(context.registry.register) == "function" then
                                context.registry:register(instance.id, instance)
                            elseif type(context.registry.add) == "function" then
                                context.registry:add(instance)
                            end
                        end
                    end
                    instance.creator = creature.guid or creature.id
                    local room = helpers.get_room(context, creature_loc)
                    if room then
                        room.contents = room.contents or {}
                        room.contents[#room.contents + 1] = instance.guid or instance.id
                    end
                    instance.location = creature_loc
                    creature._last_creation = os.time()
                    -- Narration (only if player is present)
                    if obj_spec.narration and creature_loc == player_room then
                        messages[#messages + 1] = obj_spec.narration
                    end
                end
            end
        end

    elseif action == "attack" then
        local target = predator_prey.select_prey_target(
            context, creature, helpers.get_creatures_in_room, helpers.get_location)
        if target and combat then
            if creature._state and creature._state ~= "dead" then
                creature._state = "alive-hunt"
            end
            local result = combat.run_combat(context, creature, target)
            local room_id = creature_loc or player_room
            -- Emit creature_attacked stimulus via helpers for testability
            if room_id then
                helpers.emit_stimulus(room_id, "creature_attacked", {
                    attacker_id = creature.id or creature.guid,
                    defender_id = target.id or target.guid,
                    attacker_name = creature.name,
                    defender_name = target.name,
                })
            end
            -- Creature death: register respawn, reshape, emit stimulus
            if result and result.defender_dead and room_id then
                local dead_name = target.name
                respawn.register(target)
                local death_room = helpers.get_room(context, room_id)
                helpers.handle_creature_death(target, context, death_room)
                helpers.emit_stimulus(room_id, "creature_died", {
                    creature_id = target.id or target.guid,
                    creature_name = dead_name,
                    killer_id = creature.id or creature.guid,
                    killer_name = creature.name,
                })
            end
            -- Narrate if player is in the same room
            if creature_loc == player_room then
                local atk_name = creature.name or "a creature"
                local def_name = target.name or "a creature"
                if result and result.text and result.text ~= "" then
                    messages[#messages + 1] = result.text
                else
                    messages[#messages + 1] = atk_name:sub(1,1):upper() ..
                        atk_name:sub(2) .. " attacks " .. def_name .. "!"
                end
                if result and result.death_narration then
                    messages[#messages + 1] = result.death_narration
                end
            end

            -- Track 3B: Morale check on the DEFENDER after combat resolves
            if result and not result.defender_dead then
                local morale_result = helpers.attempt_flee(context, target)
                if target._morale_message then
                    messages[#messages + 1] = target._morale_message
                    target._morale_message = nil
                end
                -- If defender fled, remove from any active fight
                if morale_result == "flee" and combat.find_fight_for_combatant then
                    local fight = combat.find_fight_for_combatant(target)
                    if fight then combat.remove_combatant(fight, target) end
                end
            end

            -- Track 3B: Morale check on the ATTACKER too
            helpers.attempt_flee(context, creature)
            if creature._morale_message then
                messages[#messages + 1] = creature._morale_message
                creature._morale_message = nil
            end
        end
    end

    return messages
end

return M

end

package.preload["engine.creatures.death"] = function()
-- engine/creatures/death.lua
-- Creature death reshape: transforms creature instances in-place (D-14).
-- When a creature's health reaches 0 and death_state is declared,
-- the instance metamorphoses into a dead object — same GUID, different shape.
--
-- Ownership: Bart (Architecture Lead)

local M = {}

local inventory_ok, inventory = pcall(require, "engine.creatures.inventory")
if not inventory_ok then inventory = nil end
local loot_ok, loot_engine = pcall(require, "engine.creatures.loot")
if not loot_ok then loot_engine = nil end
local fsm_ok, fsm_mod = pcall(require, "engine.fsm")
if not fsm_ok then fsm_mod = nil end

---------------------------------------------------------------------------
-- Helpers
---------------------------------------------------------------------------

local function normalize_guid(guid)
    if type(guid) ~= "string" then return guid end
    return guid:gsub("^%{(.-)%}$", "%1")
end

local function deep_copy(orig)
    if type(orig) ~= "table" then return orig end
    local copy = {}
    for k, v in pairs(orig) do copy[k] = deep_copy(v) end
    return copy
end

-- Resolve a byproduct object by id, loading on-demand if needed (#281).
local function resolve_byproduct(bp_id, context)
    local reg = context and context.registry
    if reg and type(reg.get) == "function" then
        local obj = reg:get(bp_id)
        if obj then return obj end
    end

    -- On-demand: load from object_sources (keyed by id)
    local sources = context and context.object_sources
    local ldr = context and context.loader
    if sources and sources[bp_id] and ldr and type(ldr.load_source) == "function" then
        local def = ldr.load_source(sources[bp_id])
        if def then
            if reg then reg:register(bp_id, def) end
            return def
        end
    end

    -- Fallback: search base_classes for matching id
    local base_classes = context and context.base_classes
    if base_classes then
        for _, def in pairs(base_classes) do
            if def.id == bp_id then
                local copy = deep_copy(def)
                if reg then reg:register(bp_id, copy) end
                return copy
            end
        end
    end

    return nil
end

-- reshape_instance(instance, death_state, registry, room)
-- Transforms a live creature instance into a dead object instance in-place.
-- The creature table is modified directly: template switches, sensory/identity
-- overwrite, creature metadata cleared. GUID is preserved.
function M.reshape_instance(instance, death_state, registry, room)
    -- Switch template (creature -> small-item or furniture)
    instance.template = death_state.template

    -- Overwrite identity
    instance.name = death_state.name
    instance.description = death_state.description
    instance.keywords = death_state.keywords
    instance.room_presence = death_state.room_presence

    -- Overwrite sensory (on_feel is primary dark sense)
    instance.on_feel = death_state.on_feel
    instance.on_smell = death_state.on_smell
    instance.on_listen = death_state.on_listen
    instance.on_taste = death_state.on_taste

    -- Physical properties
    instance.portable = death_state.portable
    instance.size = death_state.size or instance.size
    instance.weight = death_state.weight or instance.weight
    instance.animate = false
    instance.alive = false

    -- Optional metadata overlays
    if death_state.food then instance.food = death_state.food end
    if death_state.crafting then instance.crafting = death_state.crafting end
    if death_state.container then instance.container = death_state.container end

    -- Spoilage FSM (fresh -> bloated -> rotten -> bones)
    if death_state.states then
        instance.states = death_state.states
        instance.initial_state = death_state.initial_state or "fresh"
        instance._state = instance.initial_state
        instance.transitions = death_state.transitions
        -- Start the spoilage timer so timed_events fire
        if fsm_mod and registry then
            fsm_mod.start_timer(registry, instance.id or instance.guid)
        end
    end

    -- Ensure reshaped creature is in room.contents exactly once (#285).
    -- The creature may already be present from initial placement; avoid duplicates.
    if room then
        room.contents = room.contents or {}
        local entry_id = instance.id or instance.guid
        local already_present = false
        for _, eid in ipairs(room.contents) do
            if eid == entry_id then
                already_present = true
                break
            end
        end
        if not already_present then
            room.contents[#room.contents + 1] = entry_id
        end
    end

    -- Clear creature-only metadata (no longer animate)
    instance.behavior = nil
    instance.drives = nil
    instance.reactions = nil
    instance.movement = nil
    instance.awareness = nil
    instance.health = nil
    instance.max_health = nil
    instance.body_tree = nil
    instance.combat = nil
end

-- handle_creature_death(creature, context, room) -> bool
-- Orchestrates reshape + byproducts + narration when a creature dies.
-- Returns true if reshape occurred, false if creature has no death_state.
-- Does NOT emit creature_died stimulus — callers handle that separately.
function M.handle_creature_death(creature, context, room)
    if not creature or not creature.death_state then return false end
    local ds = creature.death_state

    -- Capture loot_table before reshape (reshape preserves it, but capture
    -- defensively so the engine never depends on field survival order).
    local creature_loot_table = creature.loot_table

    M.reshape_instance(creature, ds, context and context.registry, room)

    -- Instantiate byproducts to room floor, loading on-demand if needed (#281)
    if ds.byproducts and room then
        room.contents = room.contents or {}
        for _, bp_id in ipairs(ds.byproducts) do
            local bp_obj = resolve_byproduct(bp_id, context)
            if bp_obj then
                bp_obj.location = room.id
                room.contents[#room.contents + 1] = bp_obj.id or bp_id
            end
        end
    end

    -- WAVE-2: drop inventory items to room floor (#280)
    if inventory then
        inventory.drop_on_death(creature, room, context)
    end

    -- WAVE-2: roll loot table and place drops on room floor
    if loot_engine and creature_loot_table and room then
        local death_context = {
            kill_method = context and (context.kill_method or context.last_combat_method),
        }
        local drops = loot_engine.roll_loot_table(
            { loot_table = creature_loot_table }, death_context)
        if #drops > 0 then
            loot_engine.instantiate_drops(drops, room, context)
        end
    end

    -- Clear loot_table from reshaped corpse (no longer relevant)
    creature.loot_table = nil

    -- Reshape narration (printed after combat death text)
    if ds.reshape_narration then print(ds.reshape_narration) end

    -- WAVE-3: Trauma hook — player witnessing creature death gains stress
    if context and context.player then
        local player = context.player
        local player_room = player.location
            or (context.current_room and (type(context.current_room) == "table"
                and context.current_room.id or context.current_room))
        local creature_room = creature.location
            or (room and room.id)
        if player_room and creature_room and player_room == creature_room then
            local inj_ok, inj = pcall(require, "engine.injuries")
            if inj_ok and inj and inj.add_stress then
                inj.add_stress(player, "witness_creature_death")
            end
        end
    end

    return true
end

return M

end

package.preload["engine.creatures"] = function()
-- engine/creatures/init.lua
-- Creature behavior engine: drives, reactions, utility-scored actions, movement.
-- Evaluates metadata on animate objects generically (Principle 8).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

local stimulus = require("engine.creatures.stimulus")
local predator_prey = require("engine.creatures.predator-prey")
local morale = require("engine.creatures.morale")
local navigation = require("engine.creatures.navigation")
local death = require("engine.creatures.death")
local creature_inventory = require("engine.creatures.inventory")
local respawn = require("engine.creatures.respawn")
local combat_ok, combat = pcall(require, "engine.combat")
if not combat_ok then combat = nil end
local creature_actions = require("engine.creatures.actions")
local pack_tactics = require("engine.creatures.pack-tactics")
local territorial = require("engine.creatures.territorial")

---------------------------------------------------------------------------
-- Registry abstraction: works with both real registry (:list) and test mocks (:all)
---------------------------------------------------------------------------

local function list_objects(registry)
    if type(registry.list) == "function" then return registry:list() end
    if type(registry.all) == "function" then return registry:all() end
    if registry._objects then
        local result = {}
        for _, obj in pairs(registry._objects) do result[#result + 1] = obj end
        return result
    end
    return {}
end

local function get_location(registry, creature)
    if creature.location then return creature.location end
    if type(registry.get_location) == "function" then
        return registry:get_location(creature.guid)
    end
    return nil
end

local function set_location(registry, creature, room_id)
    creature.location = room_id
    if type(registry.set_location) == "function" then
        registry:set_location(creature.guid, room_id)
    end
end

local function get_room(context, room_id)
    if context.rooms and context.rooms[room_id] then
        return context.rooms[room_id]
    end
    local reg = context.registry
    if type(reg.get_room) == "function" then return reg:get_room(room_id) end
    if type(reg.get) == "function" then
        local obj = reg:get(room_id)
        if obj then return obj end
    end
    for _, obj in ipairs(list_objects(reg)) do
        if obj.id == room_id and (obj.template == "room" or obj.exits) then
            return obj
        end
    end
    return nil
end

local function get_player_room_id(context)
    local cr = context.current_room
    if type(cr) == "table" then return cr.id end
    if type(cr) == "string" then return cr end
    return nil
end

---------------------------------------------------------------------------
-- Stimulus / creatures API
---------------------------------------------------------------------------
function M.emit_stimulus(room_id, stimulus_type, data)
    stimulus.emit(room_id, stimulus_type, data)
end

function M.clear_stimuli() stimulus.clear() end

function M.get_creatures_in_room(registry, room_id)
    local result = {}
    for _, obj in ipairs(list_objects(registry)) do
        if obj.animate then
            local loc = get_location(registry, obj)
            if loc == room_id then
                result[#result + 1] = obj
            end
        end
    end
    return result
end

-- Drive system: update_drives(creature)
local function update_drives(creature)
    if type(creature.drives) ~= "table" then return end
    for _, drive in pairs(creature.drives) do
        if type(drive) == "table" and type(drive.value) == "number" then
            local rate = drive.decay_rate or 0
            drive.value = drive.value + rate
            local max_val = drive.max or 100
            local min_val = drive.min or 0
            if drive.value > max_val then drive.value = max_val end
            if drive.value < min_val then drive.value = min_val end
        end
    end
end

---------------------------------------------------------------------------
-- Reaction system
---------------------------------------------------------------------------

-- Navigation helpers delegated to navigation module
local function get_room_distance(context, from_id, to_id)
    return navigation.get_room_distance(context, from_id, to_id, get_room)
end

local function get_valid_exits(context, room_id, creature)
    return navigation.get_valid_exits(context, room_id, creature, get_room)
end

local stimulus_helpers = {
    get_location = get_location,
    get_room_distance = get_room_distance,
}

local function process_stimuli(context, creature)
    return stimulus.process(context, creature, stimulus_helpers)
end

---------------------------------------------------------------------------
-- Death reshape API (delegated to engine/creatures/death.lua)
-- Placed early so action_helpers can reference M.handle_creature_death.
---------------------------------------------------------------------------
M.reshape_instance = death.reshape_instance
M.handle_creature_death = death.handle_creature_death

---------------------------------------------------------------------------
-- Action helpers table (dependencies for creatures/actions.lua)
---------------------------------------------------------------------------
local action_helpers = {
    get_location = get_location,
    set_location = set_location,
    get_room = get_room,
    get_player_room_id = get_player_room_id,
    list_objects = list_objects,
    get_valid_exits = get_valid_exits,
    -- Wrappers resolve M.* at call time so test monkey-patching works
    get_creatures_in_room = function(reg, room_id)
        return M.get_creatures_in_room(reg, room_id)
    end,
    emit_stimulus = function(room_id, st, data)
        return M.emit_stimulus(room_id, st, data)
    end,
    handle_creature_death = function(target, ctx, room)
        return M.handle_creature_death(target, ctx, room)
    end,
}

-- Morale helpers: move_creature delegates to extracted actions module
local morale_helpers = {
    get_location = get_location,
    get_valid_exits = get_valid_exits,
    get_player_room_id = get_player_room_id,
    move_creature = function(ctx, creature, target)
        creature_actions.move_creature(ctx, creature, target, action_helpers)
    end,
}

local function check_morale(context, creature, combat_result)
    return morale.check(context, creature, combat_result, morale_helpers)
end

function M.attempt_flee(context, creature)
    return morale.check(context, creature, nil, morale_helpers)
end

-- attempt_flee added after definition so action_helpers captures it
action_helpers.attempt_flee = function(ctx, creature)
    return M.attempt_flee(ctx, creature)
end

---------------------------------------------------------------------------
-- creature_tick(context, creature) -> messages[]
-- Evaluates one creature's behavior: drives → reactions → action selection.
---------------------------------------------------------------------------
function M.creature_tick(context, creature)
    local messages = {}

    if not creature.animate or creature._state == "dead" then
        return messages
    end

    -- 0. Territorial evaluation: reduce fear, boost effective aggression
    local behavior = creature.behavior or {}
    local creature_loc = get_location(context.registry, creature)
    if behavior.territorial then
        local territory = behavior.territory or behavior.home_territory
        if territory and creature_loc == territory then
            if creature.drives and creature.drives.fear then
                local fear = creature.drives.fear
                fear.value = math.max(fear.min or 0, (fear.value or 0) - 10)
            end
        end
    end

    -- 0a. Territory marking: place marker when creature enters a new room
    if behavior.territorial and behavior.marks_territory ~= false then
        if creature_loc and creature_loc ~= creature._last_marked_room then
            local existing = territorial.find_markers_in_room(context.registry, creature_loc)
            local already_marked = false
            for _, m in ipairs(existing) do
                local m_owner = (m.territory and m.territory.owner) or m.owner or m.creator
                if m_owner == creature.guid then
                    already_marked = true; break
                end
            end
            if not already_marked then
                local marker = territorial.mark_territory(creature, context)
                if marker then
                    creature._last_marked_room = creature_loc
                end
            end
        end
    end

    -- 0b. Territorial marker response: evaluate foreign markers in room
    if behavior.territorial and creature_loc then
        local markers = territorial.find_markers_in_room(context.registry, creature_loc)
        for _, marker in ipairs(markers) do
            local m_owner = (marker.territory and marker.territory.owner) or marker.owner or marker.creator
            if m_owner and m_owner ~= creature.guid then
                local response = territorial.evaluate_marker(creature, marker, context)
                if response == "avoid" then
                    -- Flee from foreign territory
                    local exits = get_valid_exits(context, creature_loc, creature)
                    if #exits > 0 then
                        local choice = exits[math.random(#exits)]
                        creature_actions.move_creature(context, creature, choice.target, action_helpers)
                        creature._last_exit = choice.direction
                    end
                    return messages
                elseif response == "challenge" then
                    creature._state = "alive-aggressive"
                end
                break
            end
        end
    end

    -- 0c. Pack tactics: defensive retreat when health < 20%
    if pack_tactics.should_retreat(creature, context) then
        local exits = get_valid_exits(context, creature_loc, creature)
        if #exits > 0 then
            local choice = exits[math.random(#exits)]
            creature_actions.move_creature(context, creature, choice.target, action_helpers)
            creature._state = "alive-flee"
            local player_room = get_player_room_id(context)
            if creature_loc == player_room then
                local cn = creature.name or "a creature"
                messages[#messages + 1] = cn:sub(1,1):upper() .. cn:sub(2) .. " limps away, seeking cover."
            end
            return messages
        end
    end

    -- 1. Update drives
    update_drives(creature)

    -- 2. Process stimuli
    local reaction_msgs = process_stimuli(context, creature)
    for _, msg in ipairs(reaction_msgs) do
        messages[#messages + 1] = msg
    end
    local bait = creature_actions.try_bait(context, creature, action_helpers)
    if bait then for _, m in ipairs(bait) do messages[#messages+1] = m end; return messages end

    -- 2a. Ambush check: creature with behavior.ambush stays hidden until trigger
    if behavior.ambush and not creature._ambush_sprung then
        local ambush = behavior.ambush
        local should_spring = false
        if type(ambush.condition) == "function" then
            should_spring = ambush.condition(creature, context)
        elseif ambush.trigger_on_proximity then
            local player_room = get_player_room_id(context)
            should_spring = creature_loc == player_room
        end
        if not should_spring then
            return messages
        end
        creature._ambush_sprung = true
        local player_room = get_player_room_id(context)
        if creature_loc == player_room and ambush.narration then
            messages[#messages + 1] = ambush.narration
        end
    end

    -- 2b. Web ambush (spider-specific via metadata — Principle 8)
    if behavior.web_ambush and not creature._ambush_sprung then
        local web_ambush = behavior.web_ambush
        local should_spring = false
        if type(web_ambush.condition) == "function" then
            should_spring = web_ambush.condition(creature, context)
        end
        if should_spring then
            creature._ambush_sprung = true
        else
            return messages
        end
    end

    -- 3. Score and select best action (with pack stagger)
    local scored = creature_actions.score_actions(creature, context, action_helpers)
    local best = scored[1]
    if best then
        -- Pack stagger: if attacking and pack present, only alpha attacks this turn
        if best.action == "attack" and creature_loc then
            local pack = pack_tactics.get_pack_in_room(context.registry, creature_loc, creature)
            if #pack > 1 then
                local alpha = pack_tactics.select_alpha(pack, context)
                if alpha and alpha.guid ~= creature.guid then
                    -- Non-alpha: skip attack this turn (stagger delay)
                    if not creature._pack_waited then
                        creature._pack_waited = true
                        best = { action = "idle", score = 0 }
                    else
                        creature._pack_waited = nil
                    end
                end
            end
        end

        local action_msgs = creature_actions.execute_action(context, creature, best.action, action_helpers)
        for _, msg in ipairs(action_msgs) do
            messages[#messages + 1] = msg
        end
    end

    return messages
end

---------------------------------------------------------------------------
-- tick(context) -> messages[]
-- Master tick: iterates all animate objects, runs creature_tick for each,
-- advances respawn timers, then drains the stimulus queue.
---------------------------------------------------------------------------
function M.tick(context)
    local messages = {}
    if not context or not context.registry then return messages end

    local creatures = {}
    for _, obj in ipairs(list_objects(context.registry)) do
        if obj.animate then
            creatures[#creatures + 1] = obj
        end
    end

    for _, creature in ipairs(creatures) do
        local ok, result = pcall(M.creature_tick, context, creature)
        if ok and type(result) == "table" then
            for _, msg in ipairs(result) do
                messages[#messages + 1] = msg
            end
        end
    end

    -- Advance respawn timers (spawns new creatures when ready)
    respawn.tick(context, list_objects, get_room, get_player_room_id(context))

    M.clear_stimuli()
    return messages
end

---------------------------------------------------------------------------
-- Public API: expose internal functions for testing and cross-module use
---------------------------------------------------------------------------
function M.has_prey_in_room(c, ctx) return predator_prey.has_prey_in_room(c, ctx, M.get_creatures_in_room, get_location) end
function M.select_prey_target(ctx, c) return predator_prey.select_prey_target(ctx, c, M.get_creatures_in_room, get_location) end

-- Delegate to actions module, preserving original public signatures
function M.score_actions(creature, context)
    return creature_actions.score_actions(creature, context, action_helpers)
end
function M.execute_action(context, creature, action)
    return creature_actions.execute_action(context, creature, action, action_helpers)
end

-- check_morale(creature) -> true if health/max_health < flee_threshold
function M.check_morale(creature)
    if not creature then return nil end
    local health = creature.health
    local max_health = creature.max_health
    if not health or not max_health or max_health <= 0 then return nil end
    local threshold = creature.combat and creature.combat.behavior
        and creature.combat.behavior.flee_threshold
    if not threshold then
        local raw = creature.behavior and creature.behavior.flee_threshold
        if raw and raw > 1 then threshold = raw / 100 else threshold = raw end
    end
    if not threshold then return nil end
    return (health / max_health) < threshold
end

---------------------------------------------------------------------------
-- Respawn API (delegated to engine/creatures/respawn.lua)
---------------------------------------------------------------------------
M.register_for_respawn = respawn.register
M.respawn_pending = respawn.count_pending
M.respawn_clear = respawn.clear

---------------------------------------------------------------------------
-- Inventory API (delegated to engine/creatures/inventory.lua)
---------------------------------------------------------------------------
M.validate_inventory = creature_inventory.validate
M.drop_inventory_on_death = creature_inventory.drop_on_death
M.inventory_presence_hint = creature_inventory.presence_hint

---------------------------------------------------------------------------
-- Pack Tactics API (delegated to engine/creatures/pack-tactics.lua)
---------------------------------------------------------------------------
M.pack_tactics = pack_tactics

---------------------------------------------------------------------------
-- Territorial API (delegated to engine/creatures/territorial.lua)
---------------------------------------------------------------------------
