package.preload["engine.creatures.inventory"] = function()
-- engine/creatures/inventory.lua
-- Creature inventory: validation, death drops, sensory integration.
-- WAVE-2 implementation (Phase 3).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

local VALID_WORN_SLOTS = { head = true, torso = true, arms = true, legs = true, feet = true }
local MAX_HANDS = 2

---------------------------------------------------------------------------
-- Helpers
---------------------------------------------------------------------------

local function normalize_guid(guid)
    if type(guid) ~= "string" then return guid end
    return guid:gsub("^%{(.-)%}$", "%1")
end

local function deep_copy(orig)
    if type(orig) ~= "table" then return orig end
    local copy = {}
    for k, v in pairs(orig) do copy[k] = deep_copy(v) end
    return copy
end

-- Resolve an inventory item GUID to a live object, instantiating from
-- base_classes on demand if the item isn't pre-registered (#280).
local function resolve_item_guid(guid, context)
    local registry = context and context.registry

    -- Try registry GUID index first
    if registry and type(registry.find_by_guid) == "function" then
        local obj = registry:find_by_guid(guid)
        if obj then return obj end
    end

    -- On-demand: instantiate from base_classes (keyed by normalized GUID)
    local base_classes = context and context.base_classes
    if base_classes then
        local norm = normalize_guid(guid)
        local base = base_classes[norm]
        if base then
            local instance = deep_copy(base)
            if registry and type(registry.register) == "function" then
                local item_id = instance.id or norm
                registry:register(item_id, instance)
            end
            return instance
        end
    end

    return nil
end

---------------------------------------------------------------------------
-- Validation (INV-01 through INV-03)
---------------------------------------------------------------------------

function M.validate(creature, registry)
    if not creature then return false, { "creature is nil" } end
    local inv = creature.inventory
    if not inv then return true, {} end
    if type(inv) ~= "table" then return false, { "inventory must be a table" } end

    local errs = {}
    local id = creature.id or creature.guid or "unknown"

    -- INV-01: hands max 2
    if inv.hands then
        if type(inv.hands) ~= "table" then
            errs[#errs + 1] = "inventory.hands must be a table"
        elseif #inv.hands > MAX_HANDS then
            errs[#errs + 1] = string.format(
                "INV-01: creature %s has %d items in hands; max is %d",
                id, #inv.hands, MAX_HANDS)
        end
    end

    -- INV-02: worn slots valid
    if inv.worn then
        if type(inv.worn) ~= "table" then
            errs[#errs + 1] = "inventory.worn must be a table"
        else
            for slot, _ in pairs(inv.worn) do
                if not VALID_WORN_SLOTS[slot] then
                    errs[#errs + 1] = string.format(
                        "INV-02: creature %s has invalid worn slot '%s'; valid slots are: head, torso, arms, legs, feet",
                        id, tostring(slot))
                end
            end
        end
    end

    -- INV-03: GUID resolution
    if registry and type(registry.get) == "function" then
        local function check_guid(guid)
            if guid and not registry:get(guid) then
                errs[#errs + 1] = string.format(
                    "INV-03: creature %s inventory references non-existent GUID %s",
                    id, tostring(guid))
            end
        end
        if inv.hands then
            for _, guid in ipairs(inv.hands) do check_guid(guid) end
        end
        if inv.worn then
            for _, guid in pairs(inv.worn) do
                if guid then check_guid(guid) end
            end
        end
        if inv.carried then
            for _, guid in ipairs(inv.carried) do check_guid(guid) end
        end
    end

    return #errs == 0, errs
end

---------------------------------------------------------------------------
-- Death drop: scatter inventory items to room floor (#280)
---------------------------------------------------------------------------

function M.drop_on_death(creature, room, context)
    local inv = creature.inventory
    if not inv then return {} end

    local dropped = {}

    -- Collect all item GUIDs from hands, worn, carried
    if inv.hands then
        for _, guid in ipairs(inv.hands) do
            dropped[#dropped + 1] = guid
        end
    end
    if inv.worn then
        for _, guid in pairs(inv.worn) do
            if guid then dropped[#dropped + 1] = guid end
        end
    end
    if inv.carried then
        for _, guid in ipairs(inv.carried) do
            dropped[#dropped + 1] = guid
        end
    end

    -- Resolve each GUID and place item on the room floor
    if room and #dropped > 0 then
        room.contents = room.contents or {}
        for _, guid in ipairs(dropped) do
            local item = resolve_item_guid(guid, context)
            if item then
                item.location = room.id
                room.contents[#room.contents + 1] = item.id or guid
            end
        end
    end

    -- Clear creature inventory (items now on floor)
    creature.inventory = nil

    return dropped
end

---------------------------------------------------------------------------
-- Sensory integration: inventory presence hint
---------------------------------------------------------------------------

function M.presence_hint(creature)
    local inv = creature.inventory
    if not inv then return nil end

    local has_items = false
    if inv.hands and #inv.hands > 0 then has_items = true end
    if not has_items and inv.carried and #inv.carried > 0 then has_items = true end
    if not has_items and inv.worn then
        for _, v in pairs(inv.worn) do
            if v then has_items = true; break end
        end
    end

    if not has_items then return nil end
    return creature.inventory_presence or "something glinting at its feet"
end

---------------------------------------------------------------------------
-- Constants exposed for tests
---------------------------------------------------------------------------
M.VALID_WORN_SLOTS = VALID_WORN_SLOTS
M.MAX_HANDS = MAX_HANDS

return M

end

package.preload["engine.creatures.loot"] = function()
-- engine/creatures/loot.lua
-- Loot table engine: probabilistic drops from creature metadata.
-- Reads loot_table blocks declared in creature definitions (Principle 8).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

local _loot_counter = 0

---------------------------------------------------------------------------
-- Helpers
---------------------------------------------------------------------------

local function deep_copy(orig)
    if type(orig) ~= "table" then return orig end
    local copy = {}
    for k, v in pairs(orig) do copy[k] = deep_copy(v) end
    return copy
end

-- Resolve a template definition by id, following the same 3-tier pattern
-- used by resolve_byproduct in death.lua: registry → object_sources → base_classes.
local function resolve_template(template_id, context)
    if not template_id or not context then return nil end

    local reg = context.registry
    if reg and type(reg.get) == "function" then
        local obj = reg:get(template_id)
        if obj then return deep_copy(obj) end
    end

    local sources = context.object_sources
    local ldr = context.loader
    if sources and sources[template_id] and ldr and type(ldr.load_source) == "function" then
        local def = ldr.load_source(sources[template_id])
        if def then return deep_copy(def) end
    end

    local base_classes = context.base_classes
    if base_classes then
        for _, def in pairs(base_classes) do
            if def.id == template_id then
                return deep_copy(def)
            end
        end
    end

    return nil
end

---------------------------------------------------------------------------
-- weighted_select(options) -> option | nil
-- Weighted random selection from array of {weight, ...} entries.
-- Sum weights, roll random, walk cumulative. Return selected option.
---------------------------------------------------------------------------
function M.weighted_select(options)
    if not options or #options == 0 then return nil end

    local total = 0
    for _, opt in ipairs(options) do
        total = total + (opt.weight or 0)
    end
    if total == 0 then return nil end

    local roll = math.random() * total
    local cumulative = 0
    for _, opt in ipairs(options) do
        cumulative = cumulative + (opt.weight or 0)
        if roll <= cumulative then
            return opt
        end
    end

    return options[#options]
end

---------------------------------------------------------------------------
-- roll_loot_table(creature, death_context) -> drops[]
-- Main entry point. Reads creature.loot_table metadata and returns array
-- of {template, quantity} drop descriptors.
---------------------------------------------------------------------------
function M.roll_loot_table(creature, death_context)
    local loot = creature and creature.loot_table
    if not loot then return {} end

    local drops = {}

    -- 1. Always drops (100% guaranteed)
    for _, item in ipairs(loot.always or {}) do
        drops[#drops + 1] = { template = item.template, quantity = item.quantity or 1 }
    end

    -- 2. Weighted roll (pick ONE from on_death)
    if loot.on_death then
        local selected = M.weighted_select(loot.on_death)
        if selected and selected.item then
            drops[#drops + 1] = { template = selected.item.template, quantity = 1 }
        end
    end

    -- 3. Variable quantity rolls
    for _, v in ipairs(loot.variable or {}) do
        local qty = math.random(v.min, v.max)
        if qty > 0 then
            drops[#drops + 1] = { template = v.template, quantity = qty }
        end
    end

    -- 4. Conditional drops (based on kill method)
    if death_context and death_context.kill_method then
        local cond = loot.conditional and loot.conditional[death_context.kill_method]
        if cond then
            for _, item in ipairs(cond) do
                drops[#drops + 1] = { template = item.template, quantity = item.quantity or 1 }
            end
        end
    end

    return drops
end

---------------------------------------------------------------------------
-- instantiate_drops(drops, room, context) -> instances[]
-- Takes drops array from roll_loot_table, instantiates each item via
-- context resolution, places on room floor. Handles quantity > 1.
---------------------------------------------------------------------------
function M.instantiate_drops(drops, room, context)
    if not drops or #drops == 0 then return {} end

    local instances = {}
    local reg = context and context.registry

    for _, drop in ipairs(drops) do
        for _ = 1, drop.quantity do
            local obj = resolve_template(drop.template, context)
            if obj then
                _loot_counter = _loot_counter + 1
                local instance_id = drop.template .. "-loot-" .. _loot_counter
                obj.id = instance_id

                if reg and type(reg.register) == "function" then
                    reg:register(instance_id, obj)
                end

                if room then
                    obj.location = room.id
                    room.contents = room.contents or {}
                    room.contents[#room.contents + 1] = instance_id
                end

                instances[#instances + 1] = obj
            end
        end
    end

    return instances
end

-- Reset counter (for deterministic testing)
function M._reset_counter()
    _loot_counter = 0
end

return M

end

package.preload["engine.creatures.morale"] = function()
-- engine/creatures/morale.lua
-- Creature morale system: flee_threshold checks and cornered fallback.
-- Extracted from creatures/init.lua for WAVE-3 (Phase 2).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

---------------------------------------------------------------------------
-- check(context, creature, combat_result, helpers) -> "flee"|"cornered"|nil
-- Called after combat RESOLVE phase. If health/max_health < flee_threshold,
-- creature attempts to flee. If no valid exits, enters cornered stance.
--
-- helpers must provide:
--   helpers.get_location(registry, creature) -> room_id
--   helpers.get_valid_exits(context, room_id, creature) -> exits[]
--   helpers.get_player_room_id(context) -> room_id|nil
--   helpers.move_creature(context, creature, target_room_id)
---------------------------------------------------------------------------
function M.check(context, creature, combat_result, helpers)
    if not creature or creature._state == "dead" then return nil end

    local health = creature.health
    local max_health = creature.max_health
    if not health or not max_health or max_health <= 0 then return nil end

    -- Read from combat.behavior.flee_threshold (decimal ratio 0.0-1.0)
    local threshold = creature.combat and creature.combat.behavior
        and creature.combat.behavior.flee_threshold
    -- Fallback to behavior.flee_threshold, normalizing integer to ratio
    if not threshold then
        local raw = creature.behavior and creature.behavior.flee_threshold
        if raw and raw > 1 then
            threshold = raw / 100
        else
            threshold = raw
        end
    end
    if not threshold then return nil end

    local health_ratio = health / max_health
    if health_ratio >= threshold then
        creature._cornered = nil
        return nil
    end

    -- Below threshold: attempt to flee
    local creature_loc = helpers.get_location(context.registry, creature)
    if not creature_loc then return nil end

    local exits = helpers.get_valid_exits(context, creature_loc, creature)
    if #exits > 0 then
        local choice = exits[math.random(#exits)]
        local player_room = helpers.get_player_room_id(context)

        if creature._state and creature._state ~= "dead" then
            creature._state = "alive-flee"
        end
        creature._cornered = nil

        helpers.move_creature(context, creature, choice.target)
        creature._last_exit = choice.direction

        if creature_loc == player_room then
            local name = creature.name or "a creature"
            creature._morale_message = name:sub(1,1):upper() .. name:sub(2) ..
                " panics and flees " .. choice.direction .. "!"
        end

        return "flee"
    else
        -- Cornered: no valid exits — fight harder
        creature._cornered = true
        if creature._state and creature._state ~= "dead" then
            creature._state = "alive-cornered"
        end

        local player_room = helpers.get_player_room_id(context)
        if creature_loc == player_room then
            local name = creature.name or "a creature"
            creature._morale_message = name:sub(1,1):upper() .. name:sub(2) ..
                ", cornered, bares its teeth!"
        end

        return "cornered"
    end
end

return M

end

package.preload["engine.creatures.navigation"] = function()
-- engine/creatures/navigation.lua
-- Creature navigation helpers: exit resolution, room distance, movement.
-- Extracted from creatures/init.lua for WAVE-3 (Phase 2).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

---------------------------------------------------------------------------
-- get_exit_target(context, exit) -> target_room_id or nil
---------------------------------------------------------------------------
function M.get_exit_target(context, exit)
    if type(exit) == "string" then exit = { portal = exit } end
    if type(exit) ~= "table" then return nil end
    if exit.target then return exit.target end
    if exit.portal and context.registry then
        local reg = context.registry
        if type(reg.get) == "function" then
            local portal = reg:get(exit.portal)
            if portal and portal.portal then return portal.portal.target end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- get_room_distance(context, from_id, to_id, get_room_fn) -> number
-- BFS distance between two rooms. Returns 999 if unreachable.
---------------------------------------------------------------------------
function M.get_room_distance(context, from_id, to_id, get_room_fn)
    if from_id == to_id then return 0 end
    local visited = { [from_id] = true }
    local frontier = { from_id }
    local depth = 0
    while #frontier > 0 and depth < 10 do
        depth = depth + 1
        local next_frontier = {}
        for _, rid in ipairs(frontier) do
            local room = get_room_fn(context, rid)
            if room and room.exits then
                for _, exit in pairs(room.exits) do
                    local target_id = M.get_exit_target(context, exit)
                    if target_id and not visited[target_id] then
                        if target_id == to_id then return depth end
                        visited[target_id] = true
                        next_frontier[#next_frontier + 1] = target_id
                    end
                end
            end
        end
        frontier = next_frontier
    end
    return 999
end

---------------------------------------------------------------------------
-- is_exit_passable(context, exit, creature) -> bool, target_room_id
---------------------------------------------------------------------------
function M.is_exit_passable(context, exit, creature)
    if type(exit) == "string" then exit = { portal = exit } end
    if type(exit) ~= "table" then return false, nil end

    if exit.target then
        if exit.open == false then
            if not (creature.movement and creature.movement.can_open_doors) then
                return false, nil
            end
        end
        return true, exit.target
    end

    if exit.portal and context.registry and type(context.registry.get) == "function" then
        local portal = context.registry:get(exit.portal)
        if not portal then return false, nil end
        local state = portal.states and portal.states[portal._state]
        if not state or not state.traversable then
            if not (creature.movement and creature.movement.can_open_doors) then
                return false, nil
            end
        end
        local target = portal.portal and portal.portal.target
        if not target then return false, nil end
        return true, target
    end

    return false, nil
end

---------------------------------------------------------------------------
-- room_has_npc_obstacle(context, room_id, get_room_fn) -> bool
-- Checks if a room contains any object with obstacle.blocks_npc_movement.
-- Used to prevent NPC movement into rooms with blocking obstacles (webs, etc).
---------------------------------------------------------------------------
function M.room_has_npc_obstacle(context, room_id, get_room_fn)
    local room = get_room_fn(context, room_id)
    if not room or not room.contents then return false end
    local reg = context.registry
    if not reg then return false end
    local get = type(reg.get) == "function" and reg.get or nil
    for _, obj_id in ipairs(room.contents) do
        local obj = get and reg:get(obj_id)
        if obj and obj.obstacle and obj.obstacle.blocks_npc_movement then
            return true
        end
    end
    return false
end

---------------------------------------------------------------------------
-- get_valid_exits(context, room_id, creature, get_room_fn) -> exits[]
---------------------------------------------------------------------------
function M.get_valid_exits(context, room_id, creature, get_room_fn)
    local room = get_room_fn(context, room_id)
    if not room or not room.exits then return {} end

    local valid = {}
    for dir, exit in pairs(room.exits) do
        local passable, target = M.is_exit_passable(context, exit, creature)
        if passable and target then
            -- NPC obstacle check: block entry into rooms with NPC-blocking obstacles
            if not M.room_has_npc_obstacle(context, target, get_room_fn) then
                valid[#valid + 1] = { direction = dir, target = target }
            end
        end
    end
    return valid
end

return M

end

package.preload["engine.creatures.pack-tactics"] = function()
-- engine/creatures/pack-tactics.lua
-- Simplified pack awareness: stagger attacks, alpha selection, defensive retreat.
-- Phase 4 WAVE-5 — full alpha/beta/omega roles deferred to Phase 5.
-- Q4 resolved: alpha = highest health wolf (not highest aggression).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

---------------------------------------------------------------------------
-- select_alpha(pack, ctx) -> creature
-- Alpha is the wolf with highest current health. Ties broken by max_health.
---------------------------------------------------------------------------
function M.select_alpha(pack, ctx)
    if not pack or #pack == 0 then return nil end
    if #pack == 1 then return pack[1] end

    local alpha = pack[1]
    for i = 2, #pack do
        local c = pack[i]
        local c_hp = c.health or 0
        local a_hp = alpha.health or 0
        if c_hp > a_hp or (c_hp == a_hp and (c.max_health or 0) > (alpha.max_health or 0)) then
            alpha = c
        end
    end
    return alpha
end

---------------------------------------------------------------------------
-- plan_attack(pack, ctx) -> array of { creature, attacker, delay }
-- Alpha attacks on turn 0; others stagger by 1 game-turn each.
-- Single wolf: no stagger, immediate attack (delay 0).
---------------------------------------------------------------------------
function M.plan_attack(pack, ctx)
    if not pack or #pack == 0 then return {} end
    if #pack == 1 then
        return { { creature = pack[1], attacker = pack[1].guid, delay = 0 } }
    end

    local alpha = M.select_alpha(pack, ctx)
    local plan = {}
    local delay_counter = 0

    -- Alpha attacks first
    plan[#plan + 1] = { creature = alpha, attacker = alpha.guid, delay = 0 }

    -- Others stagger by 1 turn each
    for _, c in ipairs(pack) do
        if c ~= alpha then
            delay_counter = delay_counter + 1
            plan[#plan + 1] = { creature = c, attacker = c.guid, delay = delay_counter }
        end
    end

    return plan
end

---------------------------------------------------------------------------
-- should_retreat(creature, ctx) -> bool
-- Defensive retreat when health < 20% of max.
---------------------------------------------------------------------------
function M.should_retreat(creature, ctx)
    if not creature then return false end
    local hp = creature.health or 0
    local max_hp = creature.max_health or 1
    if max_hp <= 0 then return false end
    return (hp / max_hp) < 0.20
end

---------------------------------------------------------------------------
-- get_pack_in_room(registry, room_id, creature_id) -> array of same-species creatures
-- Finds all alive creatures sharing the same base id (e.g. "wolf") in a room.
---------------------------------------------------------------------------
function M.get_pack_in_room(registry, room_id, creature)
    if not registry or not room_id or not creature then return {} end
    local base_id = creature.id or ""
    local list_fn = registry.list or registry.all
    if not list_fn then return {} end

    local pack = {}
    for _, obj in ipairs(list_fn(registry)) do
        if obj.animate and obj._state ~= "dead"
           and obj.id == base_id
           and obj.location == room_id then
            pack[#pack + 1] = obj
        end
    end
    return pack
end

---------------------------------------------------------------------------
-- prefers_doorway(creature, ctx, get_room_fn) -> bool
-- Smart positioning: creature near an exit blocks player escape.
-- Returns true if creature is in a room with exits (positional advantage).
---------------------------------------------------------------------------
function M.prefers_doorway(creature, ctx, get_room_fn)
    if not creature or not ctx then return false end
    local loc = creature.location
    if not loc then return false end
    local room = get_room_fn and get_room_fn(ctx, loc)
    if not room or not room.exits then return false end

    local exit_count = 0
    for _ in pairs(room.exits) do exit_count = exit_count + 1 end
    return exit_count > 0
end

return M

end

package.preload["engine.creatures.predator-prey"] = function()
-- engine/creatures/predator-prey.lua
-- Predator-prey subsystem: prey detection, target selection, source_filter.
-- Fleshed out in WAVE-2 (Phase 2). Reads creature.behavior.prey metadata.
--
-- Ownership: Bart (Architecture Lead)

local M = {}

---------------------------------------------------------------------------
-- has_prey_in_room(creature, context, get_creatures_fn, get_location_fn)
-- Returns true if any alive creature matching creature.behavior.prey is
-- in the same room. Skips dead creatures and self.
---------------------------------------------------------------------------
function M.has_prey_in_room(creature, context, get_creatures_fn, get_location_fn)
    local prey_list = creature.behavior and creature.behavior.prey
    if not prey_list or #prey_list == 0 then return false end

    local registry = context.registry
    local creature_loc = get_location_fn(registry, creature)
    if not creature_loc then return false end

    -- Check registry creatures
    local others = get_creatures_fn(registry, creature_loc)
    for _, other in ipairs(others) do
        if other ~= creature and other._state ~= "dead" and other.animate ~= false then
            for _, prey_id in ipairs(prey_list) do
                if other.id == prey_id then return true end
            end
        end
    end

    -- Check player (lives at context.player, not in registry)
    local player = context.player
    if player and player.location == creature_loc then
        for _, prey_id in ipairs(prey_list) do
            if prey_id == "player" then return true end
        end
    end

    return false
end

---------------------------------------------------------------------------
-- select_prey_target(context, creature, get_creatures_fn, get_location_fn)
-- Returns first alive creature matching prey list in same room, or nil.
-- Iterates prey list first (priority order) then creatures.
---------------------------------------------------------------------------
function M.select_prey_target(context, creature, get_creatures_fn, get_location_fn)
    local prey_list = creature.behavior and creature.behavior.prey
    if not prey_list or #prey_list == 0 then return nil end

    local registry = context.registry
    local creature_loc = get_location_fn(registry, creature)
    if not creature_loc then return nil end

    local others = get_creatures_fn(registry, creature_loc)
    local player = context.player

    -- Iterate prey list first (priority order)
    for _, prey_id in ipairs(prey_list) do
        -- Check player target
        if prey_id == "player" and player and player.location == creature_loc then
            return player
        end
        -- Check registry creatures
        for _, other in ipairs(others) do
            if other ~= creature and other._state ~= "dead"
               and other.animate ~= false and other.id == prey_id then
                return other
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- evaluate_source_filter(creature, stimulus, filter) -> bool
-- Checks whether a stimulus source matches the creature's source_filter
-- criteria (e.g., "only react to prey-type creatures").
---------------------------------------------------------------------------
