end

return M

end

package.preload["engine.creatures.respawn"] = function()
-- engine/creatures/respawn.lua
-- Respawn manager: tracks dead creatures with respawn metadata,
-- counts down timers, and spawns new instances when conditions are met.
-- Metadata-driven (Principle 8) — creatures declare respawn behavior.
--
-- Ownership: Bart (Architecture Lead)

local M = {}

---------------------------------------------------------------------------
-- Internal state: pending respawns keyed by original creature guid
---------------------------------------------------------------------------
local pending = {}
-- { guid = { type_id, home_room, timer, ticks_remaining, max_population, template_data } }

---------------------------------------------------------------------------
-- register(creature)
-- Called when a creature with respawn metadata dies.
-- Captures the respawn spec and starts the countdown.
---------------------------------------------------------------------------
function M.register(creature)
    if not creature then return false end
    local rs = creature.respawn
    if not rs or not rs.home_room then return false end
    local key = creature.guid or creature.id
    if not key then return false end
    -- Don't double-register
    if pending[key] then return false end
    pending[key] = {
        type_id = creature._original_type_id or creature.type_id or creature.id,
        home_room = rs.home_room,
        timer = rs.timer or 100,
        ticks_remaining = rs.timer or 100,
        max_population = rs.max_population or 1,
        template_data = creature._respawn_template or nil,
    }
    return true
end

---------------------------------------------------------------------------
-- count_population(registry, type_id, room_id, list_fn)
-- Counts living creatures of a given type in a specific room.
---------------------------------------------------------------------------
local function count_population(registry, type_id, room_id, list_fn)
    local count = 0
    local objects = list_fn(registry)
    for _, obj in ipairs(objects) do
        if obj.animate and obj.alive ~= false then
            local obj_type = obj._original_type_id or obj.type_id or obj.id
            local loc = obj.location
            if type(registry.get_location) == "function" then
                loc = registry:get_location(obj.guid) or loc
            end
            if obj_type == type_id and loc == room_id then
                count = count + 1
            end
        end
    end
    return count
end

---------------------------------------------------------------------------
-- spawn_creature(context, entry, list_fn, get_room_fn)
-- Instantiates a new creature in its home room.
-- Returns true if spawn succeeded.
---------------------------------------------------------------------------
local function spawn_creature(context, entry, list_fn, get_room_fn)
    local reg = context.registry
    if not reg then return false end
    local room = get_room_fn(context, entry.home_room)
    if not room then return false end

    -- Population cap check
    local pop = count_population(reg, entry.type_id, entry.home_room, list_fn)
    if pop >= entry.max_population then return false end

    -- Build new instance from template_data or minimal scaffold
    local new_creature
    if entry.template_data then
        new_creature = {}
        for k, v in pairs(entry.template_data) do
            if type(v) == "table" then
                new_creature[k] = {}
                for kk, vv in pairs(v) do new_creature[k][kk] = vv end
            else
                new_creature[k] = v
            end
        end
    else
        new_creature = {
            id = entry.type_id,
            type_id = entry.type_id,
            animate = true,
            alive = true,
        }
    end

    -- Fresh GUID for the new instance
    new_creature.guid = "{respawn-" .. (entry.type_id or "creature")
        .. "-" .. tostring(os.clock()):gsub("%.", "") .. "}"
    new_creature.animate = true
    new_creature.alive = true
    new_creature.location = entry.home_room
    new_creature._original_type_id = entry.type_id

    -- Reset health to max
    if new_creature.max_health then
        new_creature.health = new_creature.max_health
    end

    -- Register in the object registry
    if type(reg.register) == "function" then
        reg:register(new_creature)
    elseif type(reg.add) == "function" then
        reg:add(new_creature)
    elseif reg._objects then
        reg._objects[new_creature.guid] = new_creature
    end

    -- Set location through registry if supported
    if type(reg.set_location) == "function" then
        reg:set_location(new_creature.guid, entry.home_room)
    end

    return true
end

---------------------------------------------------------------------------
-- tick(context, list_fn, get_room_fn, player_room_id)
-- Advances all respawn timers by one tick. Spawns when ready.
-- list_fn(registry) -> objects[]   (registry abstraction)
-- get_room_fn(context, id) -> room (room lookup)
-- player_room_id: string           (prevents spawn-in-face)
---------------------------------------------------------------------------
function M.tick(context, list_fn, get_room_fn, player_room_id)
    if not context or not context.registry then return end
    local spawned = {}
    for key, entry in pairs(pending) do
        entry.ticks_remaining = entry.ticks_remaining - 1
        if entry.ticks_remaining <= 0 then
            -- Don't spawn if player is watching
            if entry.home_room ~= player_room_id then
                spawn_creature(context, entry, list_fn, get_room_fn)
            else
                -- Reset timer — try again next cycle
                entry.ticks_remaining = entry.timer
            end
            spawned[#spawned + 1] = key
        end
    end
    -- Clear completed entries (spawned or not-in-face reset handled above)
    for _, key in ipairs(spawned) do
        if pending[key] and pending[key].ticks_remaining <= 0 then
            pending[key] = nil
        end
    end
end

---------------------------------------------------------------------------
-- Utility / test API
---------------------------------------------------------------------------
function M.get_pending() return pending end
function M.clear() pending = {} end
function M.count_pending()
    local n = 0
    for _ in pairs(pending) do n = n + 1 end
    return n
end
function M.count_population(registry, type_id, room_id, list_fn)
    return count_population(registry, type_id, room_id, list_fn)
end

return M

end

package.preload["engine.creatures.stimulus"] = function()
-- engine/creatures/stimulus.lua
-- Stimulus queue management: emission, processing, and clearing.
-- Extracted from creatures/init.lua for WAVE-0 module split (Phase 2).
--
-- Ownership: Bart (Architecture Lead)

local M = {}

-- Stimulus queue: array of { room_id, stimulus_type, data }
local stimulus_queue = {}

---------------------------------------------------------------------------
-- emit(room_id, stimulus_type, data)
-- Queues a stimulus for creatures to process on the next tick.
---------------------------------------------------------------------------
function M.emit(room_id, stimulus_type, data)
    stimulus_queue[#stimulus_queue + 1] = {
        room_id = room_id,
        stimulus_type = stimulus_type,
        data = data or {},
    }
end

---------------------------------------------------------------------------
-- emit_creature_attacked(room_id, attacker, defender)
-- Convenience: emits creature_attacked stimulus after an attack resolves.
---------------------------------------------------------------------------
function M.emit_creature_attacked(room_id, attacker, defender)
    M.emit(room_id, "creature_attacked", {
        attacker_id = attacker and (attacker.id or attacker.guid),
        defender_id = defender and (defender.id or defender.guid),
        attacker_name = attacker and attacker.name,
        defender_name = defender and defender.name,
    })
end

---------------------------------------------------------------------------
-- emit_creature_died(room_id, creature, killer)
-- Convenience: emits creature_died stimulus when a creature is killed.
---------------------------------------------------------------------------
function M.emit_creature_died(room_id, creature, killer)
    M.emit(room_id, "creature_died", {
        creature_id = creature and (creature.id or creature.guid),
        creature_name = creature and creature.name,
        killer_id = killer and (killer.id or killer.guid),
        killer_name = killer and killer.name,
    })
end

---------------------------------------------------------------------------
-- clear()
-- Drains the stimulus queue (called after tick processes all stimuli).
---------------------------------------------------------------------------
function M.clear()
    stimulus_queue = {}
end

---------------------------------------------------------------------------
-- process(context, creature, helpers) -> messages[]
-- Matches queued stimuli against creature's reactions table, applies drive
-- deltas.  `helpers` must provide:
--   helpers.get_location(registry, creature)  -> room_id
--   helpers.get_room_distance(context, from_id, to_id) -> number
---------------------------------------------------------------------------
function M.process(context, creature, helpers)
    local messages = {}
    if type(creature.reactions) ~= "table" then return messages end
    local creature_loc = helpers.get_location(context.registry, creature)

    for _, stimulus in ipairs(stimulus_queue) do
        local dist = 999
        if creature_loc == stimulus.room_id then
            dist = 0
        else
            dist = helpers.get_room_distance(context, creature_loc, stimulus.room_id)
        end

        -- Only same-room and adjacent creatures react
        if dist <= 1 then
            local reaction = creature.reactions[stimulus.stimulus_type]
            if reaction then
                if reaction.fear_delta and creature.drives and creature.drives.fear then
                    local scale = dist == 0 and 1.0 or 0.5
                    local delta = reaction.fear_delta * scale
                    local fear = creature.drives.fear
                    fear.value = (fear.value or 0) + delta
                    local max_val = fear.max or 100
                    local min_val = fear.min or 0
                    if fear.value > max_val then fear.value = max_val end
                    if fear.value < min_val then fear.value = min_val end
                end
                if dist == 0 and reaction.message then
                    messages[#messages + 1] = reaction.message
                end
            end
        end
    end
    return messages
end

return M

end

package.preload["engine.creatures.territorial"] = function()
-- engine/creatures/territorial.lua
-- Territory marking system: place markers, BFS radius detection, response dispatch.
-- Phase 4 WAVE-5. Q5 resolved: player detects markers via SMELL only.
-- territory-marker.lua object created by Flanders; this engine reads from it.
--
-- Ownership: Bart (Architecture Lead)

local M = {}

local navigation = require("engine.creatures.navigation")

---------------------------------------------------------------------------
-- Helpers: extract owner and radius from a marker (handles both formats)
-- Flanders' territory-marker.lua uses top-level owner/radius fields.
-- Test mocks may use territory.owner/territory.radius subtable.
---------------------------------------------------------------------------
local function marker_owner(marker)
    if marker.territory and marker.territory.owner then
        return marker.territory.owner
    end
    return marker.owner or marker.creator
end

local function marker_radius(marker)
    if marker.territory and marker.territory.radius then
        return marker.territory.radius
    end
    return marker.radius or 2
end

---------------------------------------------------------------------------
-- is_marker(obj) -> bool
-- Identifies territory markers by id or structural presence.
---------------------------------------------------------------------------
local function is_marker(obj)
    if obj.id == "territory-marker" then return true end
    if type(obj.id) == "string" and obj.id:find("^territory%-marker") then return true end
    if obj.territory then return true end
    return false
end
local function get_room(context, room_id)
    if context.rooms and context.rooms[room_id] then
        return context.rooms[room_id]
    end
    local reg = context.registry
    if type(reg.get_room) == "function" then return reg:get_room(room_id) end
    if type(reg.get) == "function" then
        local obj = reg:get(room_id)
        if obj then return obj end
    end
    return nil
end

local function list_objects(registry)
    if type(registry.list) == "function" then return registry:list() end
    if type(registry.all) == "function" then return registry:all() end
    if registry._objects then
        local result = {}
        for _, obj in pairs(registry._objects) do result[#result + 1] = obj end
        return result
    end
    return {}
end

---------------------------------------------------------------------------
-- mark_territory(creature, ctx) -> marker or nil
-- Places an invisible territory-marker object in the creature's room.
---------------------------------------------------------------------------
function M.mark_territory(creature, ctx)
    if not creature or not ctx or not ctx.registry then return nil end
    local loc = creature.location
    if not loc then return nil end

    -- Each marker gets a unique id so multiple markers coexist in the registry
    local uid = (creature.guid or creature.id) .. "-mark-" .. tostring(os.time()) .. "-" .. tostring(math.random(1000, 9999))
    local marker = {
        id = "territory-marker-" .. uid,
        guid = uid,
        template = "small-item",
        name = "a territorial scent mark",
        keywords = { "scent", "mark", "territory marker" },
        material = "organic",
        portable = false,
        visible = false,
        hidden = true,
        invisible = true,
        searchable = false,
        on_feel = "You feel nothing unusual.",
        on_smell = "A musky, animal scent lingers here.",
        on_look = nil,
        description = nil,
        location = loc,
        -- Top-level fields (Flanders format)
        owner = creature.guid,
        creator = creature.guid,
        radius = (creature.behavior and creature.behavior.mark_radius) or 2,
        timestamp = ctx.game_time or os.time(),
        -- Subtable format (test compatibility)
        territory = {
            owner = creature.guid,
            radius = (creature.behavior and creature.behavior.mark_radius) or 2,
            timestamp = ctx.game_time or os.time(),
        },
    }

    -- Register in registry under unique id
    local reg = ctx.registry
    if type(reg.register) == "function" then
        reg:register(marker.id, marker)
    elseif type(reg.add) == "function" then
        reg:add(marker)
    elseif reg._objects then
        reg._objects[marker.guid] = marker
    end

    -- Add to room contents using the registration id (matches reg:get key)
    local room = get_room(ctx, loc)
    if room then
        room.contents = room.contents or {}
        room.contents[#room.contents + 1] = marker.id
    end

    return marker
end

---------------------------------------------------------------------------
-- get_territory_rooms(marker, ctx) -> array of room_id
-- BFS from marker location, up to marker.territory.radius hops.
---------------------------------------------------------------------------
function M.get_territory_rooms(marker, ctx)
    if not marker or not ctx then return {} end

    local start_room = marker.location
    if not start_room then return {} end
    local radius = marker_radius(marker)

    local visited = { [start_room] = true }
    local frontier = { start_room }
    local result = { start_room }
    local depth = 0

    while #frontier > 0 and depth < radius do
        depth = depth + 1
        local next_frontier = {}
        for _, rid in ipairs(frontier) do
            local room = get_room(ctx, rid)
            if room and room.exits then
                for _, exit in pairs(room.exits) do
                    local target = navigation.get_exit_target(ctx, exit)
                    if target and not visited[target] then
                        visited[target] = true
                        next_frontier[#next_frontier + 1] = target
                        result[#result + 1] = target
                    end
                end
            end
        end
        frontier = next_frontier
    end

    return result
end

---------------------------------------------------------------------------
-- is_in_territory(creature, room_id, ctx) -> bool
-- Checks whether room_id falls within any territory marker owned by creature.
---------------------------------------------------------------------------
function M.is_in_territory(creature, room_id, ctx)
    if not creature or not room_id or not ctx or not ctx.registry then return false end

    for _, obj in ipairs(list_objects(ctx.registry)) do
        if is_marker(obj) and marker_owner(obj) == creature.guid then
            local rooms = M.get_territory_rooms(obj, ctx)
            for _, rid in ipairs(rooms) do
                if rid == room_id then return true end
            end
        end
    end
    return false
end

---------------------------------------------------------------------------
-- evaluate_marker(creature, marker, ctx) -> response string or table
-- Determines creature's response to an encountered territory marker.
-- Own marker → "patrol"; foreign + high aggression → "challenge"; foreign + low → "avoid"
---------------------------------------------------------------------------
function M.evaluate_marker(creature, marker, ctx)
    if not creature or not marker then return "ignore" end

    local owner = marker_owner(marker)
    if not owner then return "ignore" end

    -- Own marker: patrol / defend
    if owner == creature.guid then
        return "patrol"
    end

    -- Foreign marker: response based on aggression
    local behavior = creature.behavior or {}
    local aggression = behavior.aggression or 0
    -- Normalize: if > 1, treat as 0-100 scale
    local aggro_normalized = aggression > 1 and (aggression / 100) or aggression

    if aggro_normalized > 0.7 then
        return "challenge"
    else
        return "avoid"
    end
end

---------------------------------------------------------------------------
-- find_markers_in_room(registry, room_id) -> array of marker objects
-- Finds all territory-marker objects in a given room.
---------------------------------------------------------------------------
function M.find_markers_in_room(registry, room_id)
    if not registry or not room_id then return {} end
    local markers = {}
    for _, obj in ipairs(list_objects(registry)) do
        if is_marker(obj) and obj.location == room_id then
            markers[#markers + 1] = obj
        end
    end
    return markers
end

---------------------------------------------------------------------------
-- expire_markers(ctx, duration_hours)
-- Removes territory markers whose timestamp is older than duration_hours.
-- duration_hours: max age in game hours (e.g. 24 for "1 day").
-- ctx must have .registry and .game_time (current game hours).
---------------------------------------------------------------------------
function M.expire_markers(ctx, duration_hours)
    if not ctx or not ctx.registry or not duration_hours then return end
    local now = ctx.game_time or 0
    local to_remove = {}

    for _, obj in ipairs(list_objects(ctx.registry)) do
        if is_marker(obj) then
            local ts = (obj.territory and obj.territory.timestamp) or obj.timestamp
            if ts and (now - ts) >= duration_hours then
                to_remove[#to_remove + 1] = obj
            end
        end
    end

    for _, marker in ipairs(to_remove) do
        -- Remove from registry using both id and guid to handle all marker formats
        local reg = ctx.registry
        if type(reg.remove) == "function" then
            reg:remove(marker.id)
            if marker.guid and marker.guid ~= marker.id then
                if type(reg.get) == "function" and reg:get(marker.guid) then
                    reg:remove(marker.guid)
                end
            end
        elseif reg._objects then
            reg._objects[marker.id] = nil
            if marker.guid then reg._objects[marker.guid] = nil end
        end

        -- Remove from room contents (by id or guid, matching how it was added)
        if marker.location then
            local room = get_room(ctx, marker.location)
            if room and room.contents then
                for i = #room.contents, 1, -1 do
                    if room.contents[i] == marker.id or room.contents[i] == marker.guid then
                        table.remove(room.contents, i)
                    end
                end
            end
        end
    end
end

return M

end

package.preload["engine.display"] = function()
-- engine/display.lua
-- Word-wrap utility for clean terminal output.
-- Wraps long lines at word boundaries to prevent terminal-level character
-- splitting (which can duplicate characters at wrap points on some terminals).
--
-- When display.ui is set to an active UI module, print() routes through
-- ui.output() instead of the raw terminal.  This lets the split-screen UI
-- own all output without changing any verb handler code.

local display = {}

display.WIDTH = 78

-- Set this to the engine.ui module after ui.init() succeeds.
-- When non-nil and ui.is_enabled(), print() routes through ui.output().
display.ui = nil

-- word_wrap(text, width) -> string
-- Splits text at word boundaries. Preserves existing newlines and leading
-- whitespace (for indented bullet lists like "  a tallow candle").
function display.word_wrap(text, width)
    width = width or display.WIDTH
    if not text or text == "" then return "" end

    local output = {}
    -- Split on existing newlines, wrap each line independently
    for segment in (text .. "\n"):gmatch("(.-)\n") do
        if segment == "" then
            output[#output + 1] = ""
        else
            local indent = segment:match("^(%s*)") or ""
            local content = segment:sub(#indent + 1)
            if #indent + #content <= width then
                output[#output + 1] = segment
            else
                local lines = {}
                local line = indent
                for word in content:gmatch("%S+") do
                    if line == indent then
                        line = indent .. word
                    elseif #line + 1 + #word > width then
                        lines[#lines + 1] = line
                        line = indent .. word
                    else
                        line = line .. " " .. word
                    end
                end
                if line ~= indent then
                    lines[#lines + 1] = line
                end

                -- Orphan prevention: if last line is very short (< width/4),
                -- pull the last word from the previous line down so phrases
                -- stay together instead of leaving a single word stranded.
                if #lines >= 2 then
                    local last = lines[#lines]
                    local last_content = last:sub(#indent + 1)
                    if #last_content < width / 4 then
                        local prev = lines[#lines - 1]
                        local sp = prev:match(".*()%s%S+$")
                        if sp and sp > #indent + 1 then
                            local moved = prev:sub(sp + 1)
                            lines[#lines - 1] = prev:sub(1, sp - 1)
                            lines[#lines] = indent .. moved:match("^%s*(.+)") .. " " .. last_content
                        end
                    end
                end

                for _, l in ipairs(lines) do
                    output[#output + 1] = l
                end
            end
        end
    end

    -- The gmatch pattern adds a trailing empty string from the appended "\n";
    -- remove it so we don't inject a phantom blank line.
    if #output > 0 and output[#output] == "" and not text:match("\n$") then
        table.remove(output)
    end

    return table.concat(output, "\n")
end

-- install() — replaces the global print with a word-wrapping version.
-- When display.ui is active, output routes through the split-screen UI.
-- Call once at startup (before the game loop).
function display.install()
    local original_print = _G.print
    _G.print = function(...)
        local n = select("#", ...)
        local parts = {}
        for i = 1, n do
            parts[i] = tostring(select(i, ...))
        end
        local text = table.concat(parts, "\t")

        if display.ui and display.ui.is_enabled() then
            -- Route through split-screen UI (it does its own word-wrap)
            display.ui.output(text)
        else
            original_print(display.word_wrap(text))
        end
    end
end

return display

end

package.preload["engine.effects"] = function()
-- engine/effects.lua
-- Unified effect processor. Objects declare effects; this module routes them.
--
-- Ownership: Smithers (UI Engineer) — implementation
--            Bart (Architect) — design (D-EFFECTS-PIPELINE)
--
-- Objects declare WHAT happens (structured effect tables).
-- The engine decides WHEN it happens (hook integration points).
-- This module decides HOW it happens (dispatch to subsystems).
--
-- Supports three declaration formats:
--   1. Legacy string:  effect = "poison"
--   2. Single table:   effect = { type = "inflict_injury", ... }
--   3. Array of tables: effect = { { type = "inflict_injury" }, { type = "narrate" } }

local effects = {}
local handlers = {}

---------------------------------------------------------------------------
-- Handler registry
---------------------------------------------------------------------------

--- Register a handler for an effect type.
-- @param effect_type  string           The type value (e.g. "inflict_injury")
-- @param handler_fn   function(effect, ctx) -> any
function effects.register(effect_type, handler_fn)
    handlers[effect_type] = handler_fn
end

--- Unregister a handler (primarily for testing).
function effects.unregister(effect_type)
    handlers[effect_type] = nil
end

--- Check if a handler is registered for a given effect type.
function effects.has_handler(effect_type)
    return handlers[effect_type] ~= nil
end

---------------------------------------------------------------------------
-- Before/After interceptor infrastructure
---------------------------------------------------------------------------
local interceptors = { before = {}, after = {} }

--- Add an interceptor for a phase ("before" or "after").
-- Before interceptors can return "cancel" to abort the effect.
-- After interceptors cannot cancel (effect already happened).
function effects.add_interceptor(phase, fn)
    interceptors[phase] = interceptors[phase] or {}
    interceptors[phase][#interceptors[phase] + 1] = fn
end

--- Clear all interceptors (primarily for testing).
function effects.clear_interceptors()
    interceptors = { before = {}, after = {} }
end

--- Run interceptors for a phase. Returns true if cancelled (before phase only).
function effects._run_interceptors(phase, effect, ctx)
    for _, fn in ipairs(interceptors[phase] or {}) do
        local result = fn(effect, ctx)
        if phase == "before" and result == "cancel" then
            return true -- cancelled
        end
    end
    return false
end

---------------------------------------------------------------------------
-- Legacy normalization
---------------------------------------------------------------------------

-- Maps legacy string effect tags to structured effect tables.
local legacy_map = {
    poison = { type = "inflict_injury", injury_type = "poisoned-nightshade",
               source = "unknown", damage = 10 },
    cut    = { type = "inflict_injury", injury_type = "minor-cut",
               source = "unknown", damage = 3 },
    burn   = { type = "inflict_injury", injury_type = "burn",
               source = "unknown", damage = 5 },
    bruise = { type = "inflict_injury", injury_type = "bruised",
               source = "unknown", damage = 4 },
    nausea = { type = "add_status", status = "nauseated", duration = 12 },
}

--- Normalize any effect declaration into an array of structured tables.
-- Accepts: string ("poison"), single table ({type=...}), or array of tables.
-- Returns: array of {type=...} tables, or nil if unrecognized.
function effects.normalize(raw)
    if type(raw) == "string" then
        local mapped = legacy_map[raw]
        if mapped then
            -- Return a copy to avoid mutating the template
            local copy = {}
            for k, v in pairs(mapped) do copy[k] = v end
            return { copy }
        end
        return nil
    end
    if type(raw) == "table" then
        if raw.type then return { raw } end   -- single effect → wrap in array
        if raw[1] then return raw end          -- already an array of effects
    end
    return nil
end

---------------------------------------------------------------------------
-- Main processing entry point
---------------------------------------------------------------------------

--- Process an effect declaration.
-- Accepts: string ("poison"), single table ({type=...}), or array of tables.
-- @param raw    string|table   The effect declaration from object metadata
-- @param ctx    table          Game context (player, registry, source object, etc.)
-- @return boolean              true if at least one effect was processed
function effects.process(raw, ctx)
    local effect_list = effects.normalize(raw)
    if not effect_list then return false end

    ctx = ctx or {}
    local any = false

    for _, effect in ipairs(effect_list) do
        -- Phase 1: before_effect interceptors can cancel or modify
        local cancelled = effects._run_interceptors("before", effect, ctx)
        if not cancelled then
            -- Phase 2: dispatch to registered handler
            local handler = handlers[effect.type]
            if handler then
                handler(effect, ctx)
                any = true
            end
            -- Phase 3: after_effect interceptors (cleanup, narration, achievements)
            effects._run_interceptors("after", effect, ctx)

            -- Phase 4: emit loud_noise stimulus for creature reactions
            if effect.loud then
                local room_id = ctx.room_id
                    or (ctx.current_room and ctx.current_room.id)
                    or (ctx.player and ctx.player.location)
                if room_id then
                    local cok, creatures = pcall(require, "engine.creatures")
                    if cok and creatures and creatures.emit_stimulus then
                        creatures.emit_stimulus(room_id, "loud_noise", {
                            source = effect.source or ctx.source_id or "unknown",
                        })
                    end
                end
            end
        end
    end

    return any
end

---------------------------------------------------------------------------
-- Built-in handler: inflict_injury
-- Routes to the existing injuries.inflict() API with zero changes to that system.
---------------------------------------------------------------------------
effects.register("inflict_injury", function(effect, ctx)
    local inj_ok, injury_mod = pcall(require, "engine.injuries")
    if not inj_ok then return nil end

    local instance = injury_mod.inflict(
        ctx.player,
        effect.injury_type,
        effect.source or ctx.source_id or "unknown",
        effect.location,
        effect.damage
    )

    -- Print effect-level message (distinct from transition message)
    if effect.message then
        print(effect.message)
    end

    -- Trigger unconsciousness if the effect declares it
    if effect.causes_unconsciousness and ctx.player and instance then
        local severity = effect.severity or "moderate"
        local conc_def = injury_mod.load_definition("concussion")
        local duration = conc_def and conc_def.unconscious_duration
                         and conc_def.unconscious_duration[severity]
        if not duration then
            duration = effect.unconscious_duration
                       and effect.unconscious_duration.min or 5
        end
        ctx.player.consciousness = ctx.player.consciousness or {}
        ctx.player.consciousness.state = "unconscious"
        ctx.player.consciousness.wake_timer = duration
        ctx.player.consciousness.cause = effect.source or ctx.source_id or "unknown"
        ctx.player.consciousness.unconscious_since = ctx.time_offset or 0
    end

    -- Check for instant death after injury infliction
    if instance and ctx.player then
        local health = injury_mod.compute_health(ctx.player)
        if health <= 0 then
            ctx.game_over = true
        end
    end

    return instance
end)

---------------------------------------------------------------------------
-- Built-in handler: narrate
-- Prints a message to the player. Future: narrator formatting via style field.
---------------------------------------------------------------------------
effects.register("narrate", function(effect, ctx)
    if effect.message then
        print(effect.message)
    end
end)

---------------------------------------------------------------------------
-- Built-in handler: add_status
-- Adds a status condition to the player's state table.
---------------------------------------------------------------------------
effects.register("add_status", function(effect, ctx)
    if not effect.status or not ctx.player then return end
    ctx.player.state = ctx.player.state or {}
    ctx.player.state[effect.status] = {
        active = true,
        duration = effect.duration,
        severity = effect.severity,
    }
    if effect.message then
        print(effect.message)
    end
end)

---------------------------------------------------------------------------
-- Built-in handler: remove_status
-- Removes a status condition from the player's state table.
---------------------------------------------------------------------------
effects.register("remove_status", function(effect, ctx)
    if not effect.status or not ctx.player then return end
    ctx.player.state = ctx.player.state or {}
    ctx.player.state[effect.status] = nil
    if effect.message then
        print(effect.message)
    end
end)

---------------------------------------------------------------------------
-- Built-in handler: mutate
-- Changes a field on an object. target = "self" uses ctx.source object.
---------------------------------------------------------------------------
effects.register("mutate", function(effect, ctx)
    if not effect.field then return end
    local target_obj
    if effect.target == "self" and ctx.source then
        target_obj = ctx.source
    elseif effect.target and ctx.registry then
        target_obj = ctx.registry:get(effect.target)
    elseif ctx.source then
        target_obj = ctx.source
    end
    if target_obj then
        target_obj[effect.field] = effect.value
    end
end)

---------------------------------------------------------------------------
-- Built-in handler: heal
-- Restores player health by reducing injury damage or adding health.
---------------------------------------------------------------------------
effects.register("heal", function(effect, ctx)
    if not ctx.player then return end
    local amount = effect.amount or 0
    if amount > 0 then
        -- Reduce accumulated injury damage (healing)
        local inj_ok, injury_mod = pcall(require, "engine.injuries")
        if inj_ok and injury_mod and ctx.player.injuries then
            local healed = 0
            for _, inj in ipairs(ctx.player.injuries) do
                if healed >= amount then break end
                if inj.damage and inj.damage > 0 then
                    local reduce = math.min(inj.damage, amount - healed)
                    inj.damage = inj.damage - reduce
                    healed = healed + reduce
                end
            end
        end
        -- Also boost nutrition as a general health benefit
        if effect.nutrition then
            ctx.player.nutrition = (ctx.player.nutrition or 0) + effect.nutrition
        end
    end
    if effect.message then
        print(effect.message)
    end
end)

---------------------------------------------------------------------------
-- Built-in handler: play_sound
-- Canonical sound dispatch path (v1.1). Objects declare play_sound effects;
-- the effects pipeline routes them to the sound manager via trigger().
---------------------------------------------------------------------------
effects.register("play_sound", function(effect, ctx)
    if not ctx or not ctx.sound_manager then return end
    local obj = effect.source_obj or ctx.source
    local key = effect.key or effect.sound_key
    if key then
        ctx.sound_manager:trigger(obj, key)
    elseif effect.filename then
        ctx.sound_manager:play(effect.filename, {
            owner_id = obj and (obj.guid or obj.id),
        })
    end
end)

return effects

end

package.preload["engine.errors"] = function()
-- engine/errors.lua
-- Tier 2: Structured Error Context System (Prime Directive #106)
-- Owned by Smithers (UI Engineer). Pure functions, no side effects.
--
-- Provides category-based error messages that are helpful, in-world,
-- and never generic. Each error category has a template function that
-- renders context into a player-facing message.
--
-- API:
--   errors.CATEGORY — table of string constants
--   errors.context(category, fields) → error context table
--   errors.format(err_ctx) → player-facing message string
--   errors.TEMPLATES — externally extensible template registry

local M = {}

-- Error categories
M.CATEGORY = {
    NOT_FOUND    = "not_found",
    WRONG_TARGET = "wrong_target",
    MISSING_TOOL = "missing_tool",
    IMPOSSIBLE   = "impossible",
    DARK         = "dark",
    NO_VERB      = "no_verb",
    AMBIGUOUS    = "ambiguous",
}

--- Build an error context table from a category and field overrides.
function M.context(category, fields)
    fields = fields or {}
    return {
        category = category,
        verb = fields.verb or nil,
        noun = fields.noun or nil,
        object = fields.object or nil,
        reason = fields.reason or nil,
        suggestions = fields.suggestions or {},
        close_match = fields.close_match or nil,
    }
end

-- Message templates keyed by category.
-- Each template: function(err_ctx) → string
M.TEMPLATES = {
    [M.CATEGORY.NOT_FOUND] = function(e)
        if e.close_match then
            return string.format(
                "You don't see '%s' nearby. Did you mean '%s'? Type 'look' to see what's around.",
                e.noun or "that", e.close_match)
        end
        return string.format(
            "You don't see anything called '%s' here. Try 'look' to see what's in the room.",
            e.noun or "that")
    end,

    [M.CATEGORY.WRONG_TARGET] = function(e)
        local obj_name = e.object and (e.object.name or e.object.id) or e.noun or "that"
        if e.suggestions and #e.suggestions > 0 then
            return string.format(
                "You can't %s %s. Try: %s",
                e.verb or "do that to", obj_name,
                table.concat(e.suggestions, ", "))
        end
        return string.format(
            "You can't %s %s. Try 'examine %s' to learn more about it.",
            e.verb or "do that to", obj_name, e.noun or "it")
    end,

    [M.CATEGORY.MISSING_TOOL] = function(e)
        return string.format(
            "You need %s to %s %s.%s",
            e.reason or "the right tool",
            e.verb or "do that to",
            e.object and (e.object.name or e.object.id) or e.noun or "that",
            e.close_match and (" Maybe " .. e.close_match .. "?") or "")
    end,

    [M.CATEGORY.DARK] = function(e)
        return string.format(
            "It's too dark to %s. Try 'feel %s' to explore by touch, or find a light source.",
            e.verb or "do that", e.noun or "around")
    end,

    [M.CATEGORY.NO_VERB] = function(e)
        if e.close_match then
            return string.format(
                "I don't recognize '%s'. Did you mean '%s'? Type 'help' for commands.",
                e.verb or "that", e.close_match)
        end
        return string.format(
            "I'm not sure what '%s' means. Try phrasing as verb + object (e.g., 'open drawer'). Type 'help' for commands.",
            e.verb or "that")
    end,

    [M.CATEGORY.IMPOSSIBLE] = function(e)
        local obj_name = e.object and (e.object.name or e.object.id) or e.noun or "that"
        local suggestion_text = ""
        if e.suggestions and #e.suggestions > 0 then
            suggestion_text = " Try: " .. table.concat(e.suggestions, ", ")
        end
        return string.format("The %s %s%s", obj_name, e.reason or "won't budge.", suggestion_text)
    end,

    [M.CATEGORY.AMBIGUOUS] = function(e)
        if e.suggestions and #e.suggestions > 0 then
            if #e.suggestions == 2 then
                return string.format(
                    "Which do you mean: %s or %s?",
                    e.suggestions[1], e.suggestions[2])
            end
            return "Which do you mean: " .. table.concat(e.suggestions, ", ") .. "?"
        end
        return "Could you be more specific?"
    end,
}

--- Format an error context into a player-facing message.
function M.format(err_ctx)
    local template = M.TEMPLATES[err_ctx.category]
    if template then
        return template(err_ctx)
    end
    return "Something went wrong. Type 'help' for guidance."
end

return M

end

package.preload["engine.factory"] = function()
-- engine/factory/init.lua
-- Object instancing factory (Core Principle 5).
-- Creates multiple independent instances from a single base object definition.
-- Each instance gets a unique instance_guid, deep-copied state, and optional
-- per-instance overrides. Instances share the base template's shape but
-- maintain fully independent runtime state.

local factory = {}

---------------------------------------------------------------------------
-- Pure-Lua GUID generator (v4-style, no external dependencies)
---------------------------------------------------------------------------
local guid_seeded = false

local function ensure_seed()
    if not guid_seeded then
        math.randomseed(os.time() + math.floor(os.clock() * 1000))
        -- Burn a few values to improve randomness on some Lua implementations
        for _ = 1, 10 do math.random() end
        guid_seeded = true
    end
end

local function hex4()
    return string.format("%04x", math.random(0, 0xFFFF))
end

-- generate_guid() -> string  e.g. "a1b2c3d4-e5f6-4a7b-8c9d-e0f1a2b3c4d5"
function factory.generate_guid()
    ensure_seed()
    -- UUID v4 format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
    -- where y is one of 8, 9, a, b
    local y = string.format("%x", 8 + math.random(0, 3))
    return hex4() .. hex4() .. "-" .. hex4() .. "-4" .. hex4():sub(2)
        .. "-" .. y .. hex4():sub(2) .. "-" .. hex4() .. hex4() .. hex4():sub(1, 4)
end

---------------------------------------------------------------------------
-- Deep merge (local copy — keeps factory self-contained)
---------------------------------------------------------------------------
local function deep_copy(t)
    if type(t) ~= "table" then return t end
    local copy = {}
    for k, v in pairs(t) do
        copy[k] = deep_copy(v)
    end
    return copy
end

local function deep_merge(base, override)
    local result = deep_copy(base)
    for k, v in pairs(override) do
        if type(v) == "table" and type(result[k]) == "table" then
            result[k] = deep_merge(result[k], v)
        else
            result[k] = v
        end
    end
    return result
end

---------------------------------------------------------------------------
-- factory.create_instances(base, count, options) -> array of instance tables
--
-- Parameters:
--   base    — The base object table (e.g., loaded from match.lua).
--   count   — How many instances to create (>= 1).
--   options — Optional table:
--     id_prefix  : string — prefix for generated ids (default: base.id)
--     overrides  : table  — applied to ALL instances
--     per_instance_overrides : array of tables — per_instance_overrides[i]
--                              is merged onto instance i (1-indexed)
--     location   : string — default location for all instances
--
-- Returns:
--   Array of instance tables, each with:
--     instance_guid — unique runtime GUID
--     id            — "prefix-1", "prefix-2", etc.
--     type_id       — base.guid (traceability back to base definition)
--     All base properties deep-copied (independent state)
--     Overrides applied on top
---------------------------------------------------------------------------
function factory.create_instances(base, count, options)
    assert(type(base) == "table", "factory: base must be a table")
    assert(type(count) == "number" and count >= 1,
           "factory: count must be a number >= 1")

    options = options or {}
    local prefix = options.id_prefix or base.id or "instance"
    local global_overrides = options.overrides or {}
    local per_overrides = options.per_instance_overrides or {}
    local location = options.location

    local instances = {}

    for i = 1, count do
        -- Deep-copy all base properties for independent state
        local inst = deep_copy(base)

        -- Stamp instance identity
        inst.instance_guid = factory.generate_guid()
        inst.id = prefix .. "-" .. tostring(i)
        inst.type_id = base.guid  -- links back to the base definition

        -- The base guid belongs to the definition, not the instance
        inst.guid = nil

        -- Apply global overrides (shared across all instances)
        if next(global_overrides) then
            inst = deep_merge(inst, global_overrides)
        end

        -- Apply per-instance overrides
        if per_overrides[i] then
            inst = deep_merge(inst, per_overrides[i])
        end

        -- Apply location if provided and not overridden
        if location and not inst.location then
            inst.location = location
        end

        instances[#instances + 1] = inst
    end

    return instances
end

---------------------------------------------------------------------------
-- factory.create_one(base, overrides) -> single instance table
-- Convenience wrapper for creating exactly one instance.
---------------------------------------------------------------------------
function factory.create_one(base, overrides)
    local instances = factory.create_instances(base, 1, {
        overrides = overrides or {},
    })
    return instances[1]
end

return factory

end

package.preload["engine.fire_propagation"] = function()
-- engine/fire_propagation/init.lua
-- Fire propagation system (#121).
-- When objects burn, fire can spread to nearby flammable objects.
-- Runs once per game tick (post-command), checking all burning objects in the
-- current room for propagation candidates.
--
-- Proximity model:
--   SAME_SURFACE  (items on the same furniture surface)  → highest spread chance
--   SAME_PARENT   (items in the same container/furniture) → medium spread chance
--   SAME_ROOM     (items loose in the same room)          → low spread chance
--
-- Spread chance = proximity_factor × target_flammability × source_intensity
-- A roll below spread_chance means the target ignites.
--
-- Ownership: Bart (Architecture Lead)

local M = {}

-- Lazy-load dependencies to avoid circular requires
local _materials
local function get_materials()
    if _materials then return _materials end
    local ok, mod = pcall(require, "engine.materials")
    if ok then _materials = mod end
    return _materials
end

local _fsm
local function get_fsm()
    if _fsm then return _fsm end
    local ok, mod = pcall(require, "engine.fsm")
    if ok then _fsm = mod end
    return _fsm
end

---------------------------------------------------------------------------
-- Configuration
---------------------------------------------------------------------------

-- Minimum material flammability to catch fire (same threshold as burn verb)
M.BURN_THRESHOLD = 0.3

-- Proximity factors: how much proximity contributes to spread chance
M.PROXIMITY = {
    SAME_SURFACE = 0.8,   -- touching on the same shelf/table
    SAME_PARENT  = 0.5,   -- inside the same piece of furniture
    SAME_ROOM    = 0.2,   -- across the room (radiant heat)
}

-- Source intensity: burning objects radiate heat proportional to their
-- material flammability. Higher flammability = fiercer fire = wider spread.
-- Default intensity if the source has no material data.
M.DEFAULT_INTENSITY = 0.6

-- Maximum number of objects that can ignite in a single tick.
-- Prevents runaway chain reactions from consuming the whole room instantly.
M.MAX_IGNITIONS_PER_TICK = 2

---------------------------------------------------------------------------
-- Internal helpers
---------------------------------------------------------------------------

-- Determine whether an object is currently on fire.
-- An object is "burning" if:
--   1. Its FSM state has `casts_light = true` AND it has a burn/fire-related state name, OR
--   2. Its FSM state name contains "burning" or "lit" (convention), OR
--   3. It has `is_burning = true` flag (simple objects).
local function is_burning(obj)
    if not obj then return false end

    -- Explicit flag (set by propagation itself)
    if obj.is_burning then return true end

    -- FSM-based: check current state
    if obj._state and obj.states then
        local state_name = obj._state
        if state_name == "burning" then return true end
        local state_data = obj.states[state_name]
        if state_data and state_data.is_burning then return true end
    end

    return false
end

-- Get the fire intensity of a burning source object.
-- Hotter materials spread fire more aggressively.
local function source_intensity(obj)
    local mats = get_materials()
    if not mats or not obj.material then return M.DEFAULT_INTENSITY end
    local mat = mats.get(obj.material)
    if not mat then return M.DEFAULT_INTENSITY end
    return mat.flammability or M.DEFAULT_INTENSITY
end

-- Get the flammability of a target object from its material.
local function target_flammability(obj)
    local mats = get_materials()
    if not mats or not obj.material then return 0 end
    local mat = mats.get(obj.material)
    if not mat then return 0 end
    return mat.flammability or 0
end

-- Check if an object can catch fire (flammable + not already burning/burnt).
local function can_ignite(obj)
    if not obj then return false end
    if is_burning(obj) then return false end

    -- Already burnt out / terminal state
    if obj._state and obj.states then
        local st = obj.states[obj._state]
        if st and st.terminal then return false end
    end

    local flam = target_flammability(obj)
    return flam >= M.BURN_THRESHOLD
end

-- Compute the spread chance from a burning source to a target at given proximity.
-- Returns a number 0–1.
local function spread_chance(source, target_obj, proximity_factor)
    local intensity = source_intensity(source)
    local flam = target_flammability(target_obj)
    return proximity_factor * flam * intensity
end

-- Deterministic roll: uses ctx.fire_rng if available, else math.random.
-- This allows tests to inject a predictable RNG.
local function roll(ctx)
    if ctx.fire_rng then
        return ctx.fire_rng()
    end
    return math.random()
end

---------------------------------------------------------------------------
-- Ignition logic
---------------------------------------------------------------------------

-- Ignite a target object. Tries in order:
--   1. FSM "burn" transition from current state
--   2. Generic destruction (remove from world)
-- Returns a message string describing what happened, or nil.
local function ignite_object(ctx, obj)
    local fsm = get_fsm()

    -- FSM path: look for a "burn" transition from current state
    if fsm and obj._state and obj.states then
        local transitions = obj.transitions or {}
        for _, t in ipairs(transitions) do
            if t.from == obj._state and (t.verb == "burn" or t.verb == "ignite") then
                local trans = fsm.transition(ctx.registry, obj.id, t.to, {})
                if trans then
                    return trans.message
                        or ("The " .. (obj.id or "object") .. " catches fire!")
                end
            end
            -- Check aliases
            if t.from == obj._state and t.aliases then
                for _, alias in ipairs(t.aliases) do
                    if alias == "burn" or alias == "ignite" then
                        local trans = fsm.transition(ctx.registry, obj.id, t.to, {})
                        if trans then
                            return trans.message
                                or ("The " .. (obj.id or "object") .. " catches fire!")
                        end
                    end
                end
            end
        end
    end

    -- Generic destruction: set burning flag, then mark for removal
    -- For simple objects without FSM burn states, we destroy them
    -- but give them one tick of "burning" before removal so the player
    -- has a chance to react next turn.
    obj.is_burning = true
    obj._burn_ticks_remaining = 1
    return "The " .. (obj.name or obj.id or "object"):gsub("^a%s+", "")
        .. " catches fire from the nearby flames!"
end

-- Remove a burnt-out generic object (no FSM) from the world.
local function remove_burnt_object(ctx, obj)
    local reg = ctx.registry
    local room = ctx.current_room

    -- Remove from room contents
    if room and room.contents then
        for i, id in ipairs(room.contents) do
            if id == obj.id then
                table.remove(room.contents, i)
                break
            end
        end
    end

    -- Remove from surface contents
    if room and room.contents then
        for _, parent_id in ipairs(room.contents) do
            local parent = reg:get(parent_id)
            if parent and parent.surfaces then
                for _, zone in pairs(parent.surfaces) do
                    for i, id in ipairs(zone.contents or {}) do
                        if id == obj.id then
                            table.remove(zone.contents, i)
                            break
                        end
                    end
                end
            end
        end
    end

    -- Remove from player hands
    if ctx.player then
        for i = 1, 2 do
            local hand = ctx.player.hands[i]
            local hand_id = hand and (type(hand) == "table" and hand.id or hand)
            if hand_id == obj.id then
                ctx.player.hands[i] = nil
            end
        end
    end

    reg:remove(obj.id)
end

---------------------------------------------------------------------------
-- Collector: find all burning and flammable objects in the room
---------------------------------------------------------------------------

-- Collect all objects in the room with their proximity context.
-- Returns two lists:
--   burning:   { { obj=..., parent_id=..., surface_name=... }, ... }
--   flammable: { { obj=..., parent_id=..., surface_name=... }, ... }
local function collect_room_objects(ctx)
    local reg = ctx.registry
    local room = ctx.current_room
    if not room or not room.contents then return {}, {} end

    local burning = {}
    local flammable = {}

    local function classify(obj_id, parent_id, surface_name)
        local obj = reg:get(obj_id)
        if not obj then return end
        if is_burning(obj) then
            burning[#burning + 1] = {
                obj = obj, parent_id = parent_id, surface_name = surface_name
            }
        end
        if can_ignite(obj) then
            flammable[#flammable + 1] = {
                obj = obj, parent_id = parent_id, surface_name = surface_name
            }
        end
    end

    for _, obj_id in ipairs(room.contents) do
        classify(obj_id, nil, nil)
        local obj = reg:get(obj_id)
        if obj and obj.surfaces then
            for sname, zone in pairs(obj.surfaces) do
                for _, item_id in ipairs(zone.contents or {}) do
                    classify(item_id, obj_id, sname)
                end
            end
        end
        if obj and obj.contents then
            for _, item_id in ipairs(obj.contents) do
                classify(item_id, obj_id, "contents")
            end
        end
    end

    -- Also check player hands (burning item in hand can spread to other hand)
    if ctx.player then
        for i = 1, 2 do
            local hand = ctx.player.hands[i]
            local hand_id = hand and (type(hand) == "table" and hand.id or hand)
            if hand_id then
                local obj = reg:get(hand_id)
                if obj then
                    if is_burning(obj) then
                        burning[#burning + 1] = {
                            obj = obj, parent_id = "player_hand", surface_name = "hand"
                        }
                    end
                    if can_ignite(obj) then
                        flammable[#flammable + 1] = {
                            obj = obj, parent_id = "player_hand", surface_name = "hand"
                        }
                    end
                end
            end
        end
    end

    return burning, flammable
end

-- Determine the proximity factor between a burning source and a flammable target.
local function get_proximity(source_entry, target_entry)
    -- Same surface on same parent → highest
    if source_entry.parent_id
       and source_entry.parent_id == target_entry.parent_id
       and source_entry.surface_name
       and source_entry.surface_name == target_entry.surface_name then
        return M.PROXIMITY.SAME_SURFACE
    end

    -- Same parent object (different surfaces or contents)
    if source_entry.parent_id
       and source_entry.parent_id == target_entry.parent_id then
        return M.PROXIMITY.SAME_PARENT
    end

    -- Both loose in the room (no parent)
    if not source_entry.parent_id and not target_entry.parent_id then
        return M.PROXIMITY.SAME_ROOM
    end

    -- Default: across the room
    return M.PROXIMITY.SAME_ROOM
end

---------------------------------------------------------------------------
-- Public API
---------------------------------------------------------------------------

-- Check if an object is currently burning. Exported for use by other modules.
M.is_burning = is_burning

-- Main tick function. Call once per game tick after FSM processing.
-- Checks all burning objects in the room and attempts to spread fire to
-- nearby flammable objects.
-- Returns a list of message strings describing what happened.
function M.tick(ctx)
    if not ctx or not ctx.registry or not ctx.current_room then return {} end

    local messages = {}

    -- Phase 0: tick down generic burning objects (no FSM)
    local reg = ctx.registry
    local room = ctx.current_room
    local to_remove = {}
    for _, obj_id in ipairs(room and room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.is_burning and obj._burn_ticks_remaining then
            obj._burn_ticks_remaining = obj._burn_ticks_remaining - 1
            if obj._burn_ticks_remaining <= 0 then
                to_remove[#to_remove + 1] = obj
            end
        end
    end
    for _, obj in ipairs(to_remove) do
        remove_burnt_object(ctx, obj)
        messages[#messages + 1] = "The "
            .. (obj.name or obj.id or "object"):gsub("^a%s+", "")
            .. " crumbles to ash."
    end

    -- Phase 1: collect burning sources and flammable targets
    local burning, flammable = collect_room_objects(ctx)
    if #burning == 0 or #flammable == 0 then return messages end

    -- Phase 2: for each burning source, try to spread to nearby flammable targets
    local ignited_count = 0
    local ignited_ids = {}

    for _, src in ipairs(burning) do
        if ignited_count >= M.MAX_IGNITIONS_PER_TICK then break end

        for _, tgt in ipairs(flammable) do
            if ignited_count >= M.MAX_IGNITIONS_PER_TICK then break end
            if ignited_ids[tgt.obj.id] then goto continue end

            local prox = get_proximity(src, tgt)
            local chance = spread_chance(src.obj, tgt.obj, prox)

            if roll(ctx) < chance then
                local msg = ignite_object(ctx, tgt.obj)
                if msg then
                    messages[#messages + 1] = msg
                    ignited_ids[tgt.obj.id] = true
                    ignited_count = ignited_count + 1
                end
            end

            ::continue::
        end
    end

    return messages
end

return M

end

package.preload["engine.fsm"] = function()
-- engine/fsm/init.lua
-- Table-driven FSM engine for object state management.
-- Objects with inline `states` and `_state` fields are managed by this system.
-- FSM definitions live INSIDE the object file (one file = one object = one FSM).
-- Non-FSM objects are unaffected (backward compatible).

local fsm = {}

-- Material registry (lazy-loaded on first threshold check)
local _materials
local function get_materials()
    if _materials then return _materials end
    local ok, mod = pcall(require, "engine.materials")
    if ok then _materials = mod end
    return _materials
end

-- Active timed events: keyed by object ID
-- Each entry: { state, remaining, event, to_state }
fsm.active_timers = {}

-- Paused timers for objects in unloaded rooms
fsm.paused_timers = {}

-- Check if an object has inline FSM data.
-- Returns the object itself as the definition, or nil.
function fsm.load(obj)
    if type(obj) == "table" and obj.states then
        return obj
    end
    return nil
end

-- Apply transition-level mutations to an object instance.
-- Supports: direct values, functions (computed from current), and list ops (add/remove).
local function apply_mutations(obj, mutations)
    if not mutations then return end
    for k, v in pairs(mutations) do
        if type(v) == "function" then
            obj[k] = v(obj[k])
        elseif type(v) == "table" and (v.add ~= nil or v.remove ~= nil) then
            local list = obj[k]
            if type(list) ~= "table" then list = {}; obj[k] = list end
            -- #402: support table remove (e.g., remove = {"barred", "iron bar"})
            if v.remove then
                if type(v.remove) == "table" then
                    local rm_set = {}
                    for _, r in ipairs(v.remove) do rm_set[r] = true end
                    for i = #list, 1, -1 do
                        if rm_set[list[i]] then table.remove(list, i) end
                    end
                else
                    for i = #list, 1, -1 do
                        if list[i] == v.remove then table.remove(list, i) end
                    end
                end
            end
            -- #402: support table add (e.g., add = {"barred", "iron bar"})
            if v.add then
                local adds = type(v.add) == "table" and v.add or { v.add }
                for _, item_to_add in ipairs(adds) do
                    local found = false
                    for _, item in ipairs(list) do
                        if item == item_to_add then found = true; break end
                    end
                    if not found then list[#list + 1] = item_to_add end
                end
            end
        else
            obj[k] = v
        end
    end
end

-- Apply state properties to an object, preserving containment and identity.
-- Removes old state-specific keys, then applies new state properties.
-- Base properties (not defined in any state) persist untouched.
local function apply_state(obj, new_state_name, old_state_name)
    local new_state = obj.states[new_state_name]
    if not new_state then return false end

    -- Save containment data BEFORE cleanup (surfaces, contents, location)
    local saved_surface_contents = {}
    if obj.surfaces then
        for sname, zone in pairs(obj.surfaces) do
            saved_surface_contents[sname] = zone.contents or {}
        end
    end
    local saved_contents = obj.contents
    local saved_location = obj.location

    -- Remove old state-specific keys (skip engine-only keys)
    if old_state_name and obj.states[old_state_name] then
        for k in pairs(obj.states[old_state_name]) do
            if k ~= "on_tick" and k ~= "terminal" then
                obj[k] = nil
            end
        end
    end

    -- Apply new state properties
    for k, v in pairs(new_state) do
        if k == "on_tick" or k == "terminal" then
            -- Engine-only: not applied to the object
        elseif k == "surfaces" then
            -- Rebuild surfaces with new structure but preserved contents
            obj.surfaces = {}
            for sname, zone in pairs(v) do
                obj.surfaces[sname] = {}
                for zk, zv in pairs(zone) do
                    if zk ~= "contents" then
                        obj.surfaces[sname][zk] = zv
                    end
                end
                obj.surfaces[sname].contents = saved_surface_contents[sname] or {}
            end
        else
            obj[k] = v
        end
    end

    -- Restore containment
    obj.location = saved_location
    if saved_contents and not obj.surfaces then
        obj.contents = saved_contents
    end
    obj._state = new_state_name
    return true
end

-- Return available (non-auto) transitions from the object's current state.
function fsm.get_transitions(obj)
    if not obj or not obj.states or not obj._state then return {} end
    local result = {}
    for _, t in ipairs(obj.transitions or {}) do
        if t.from == obj._state and t.trigger ~= "auto" then
            result[#result + 1] = t
        end
    end
    return result
end

-- Transition an object to target_state. Returns transition table on success,
-- or nil + error code on failure. Optional context table for guard checks.
-- verb_hint narrows transition search when multiple transitions share a target.

-- After a portal FSM transition, sync the paired portal (same bidirectional_id)
-- to the same state. Generic: reads portal metadata, no object-specific logic.
local function sync_bidirectional(registry, obj)
    if not obj or not obj.portal then return end
    local bid = obj.portal.bidirectional_id
    if not bid then return end
    local new_state = obj._state
    if not new_state then return end

    for _, other in ipairs(registry:list()) do
        if other ~= obj and other.portal
           and other.portal.bidirectional_id == bid then
            if other.states and other.states[new_state] and other._state ~= new_state then
                local old = other._state
                apply_state(other, new_state, old)
            end
            return
        end
    end
end

function fsm.transition(registry, obj_id, target_state, context, verb_hint)
    local obj = registry:get(obj_id)
    if not obj or not obj.states or not obj._state then
        return nil, "not_fsm"
    end

    local cur = obj.states[obj._state]
    if cur and cur.terminal then return nil, "terminal" end

    -- Find a matching transition (prefer verb_hint when given)
    local trans
    for _, t in ipairs(obj.transitions or {}) do
        if t.from == obj._state and t.to == target_state and t.trigger ~= "auto" then
            if not verb_hint or t.verb == verb_hint then
                trans = t
                break
            end
            -- Also check aliases for verb_hint
            if verb_hint and t.aliases then
                for _, a in ipairs(t.aliases) do
                    if a == verb_hint then trans = t; break end
                end
                if trans then break end
            end
        end
    end
    -- Fallback: if verb_hint didn't match, pick the first available transition
    if not trans then
        for _, t in ipairs(obj.transitions or {}) do
            if t.from == obj._state and t.to == target_state and t.trigger ~= "auto" then
                trans = t
                break
            end
        end
    end
    if not trans then return nil, "no_transition" end

    -- Guard: requires_property on context.target
    if trans.requires_property then
        local target = context and context.target
        if not target or not target[trans.requires_property] then
            return nil, "requires_property", trans
        end
    end

    -- Guard: custom function
    if trans.guard and not trans.guard(obj, context) then
        return nil, "guard_failed", trans
    end

    -- Snapshot casts_light before transition for stimulus detection
    local old_casts_light = obj.casts_light
    local old_state = obj._state
    -- Stop timer for the old state (extinguish, etc.)
    fsm.stop_timer(obj_id)
    apply_state(obj, target_state, old_state)
    apply_mutations(obj, trans.mutate)
    if trans.on_transition then trans.on_transition(obj, context) end
    -- Start timer for the new state if it has timed_events
    fsm.start_timer(registry, obj_id)

    -- Bidirectional portal sync: propagate state to paired portal
    sync_bidirectional(registry, obj)

    -- Emit light_change stimulus when casts_light changes
    if obj.casts_light ~= old_casts_light then
        local room_id = obj.location
            or (context and context.current_room and context.current_room.id)
            or (context and context.player and context.player.location)
        if room_id then
            local cok, creatures = pcall(require, "engine.creatures")
            if cok and creatures and creatures.emit_stimulus then
                creatures.emit_stimulus(room_id, "light_change", { source = obj_id })
            end
        end
    end

    -- Sound: trigger on_state_{new_state} after successful FSM transition
    if context and context.sound_manager then
        context.sound_manager:trigger(obj, "on_state_" .. target_state)
    end

    return trans
end

-- Check property thresholds for auto-transitions.
-- Thresholds are declarative: { property = "temperature", above = 62, transition = "melting" }
-- The property is checked against env_context values.
-- Optional: above_material / below_material resolves the limit from the object's material.
-- Returns a message string if a threshold transition fires, nil otherwise.
local function check_thresholds(registry, obj, obj_id, env_context)
    if not obj.thresholds or not env_context then return nil end

    local mat = nil
    if obj.material then
        local mats = get_materials()
        if mats then mat = mats.get(obj.material) end
    end

    for _, threshold in ipairs(obj.thresholds) do
        local env_value = env_context[threshold.property]
        if env_value ~= nil then
            local crossed = false

            -- Direct numeric threshold: above / below
            if threshold.above and env_value > threshold.above then
                crossed = true
            elseif threshold.below and env_value < threshold.below then
                crossed = true
            end

            -- Material-referenced threshold: above_material / below_material
            if not crossed and mat then
                if threshold.above_material then
                    local limit = mat[threshold.above_material]
                    if limit and env_value > limit then crossed = true end
                elseif threshold.below_material then
                    local limit = mat[threshold.below_material]
                    if limit and env_value < limit then crossed = true end
                end
            end

            if crossed and threshold.transition then
                -- Find a matching transition from current state to the threshold target
                for _, t in ipairs(obj.transitions or {}) do
                    if t.from == obj._state and t.to == threshold.transition then
                        local old_state = obj._state
                        fsm.stop_timer(obj_id)
                        apply_state(obj, t.to, old_state)
                        apply_mutations(obj, t.mutate)
                        if t.on_transition then t.on_transition(obj, env_context) end
                        fsm.start_timer(registry, obj_id)
                        return t.message or threshold.message
                    end
                end
            end
        end
    end
    return nil
end

-- Process auto-transitions (burn countdown, duration expiry, threshold checks).
-- Returns a message string if a transition or warning fired, nil otherwise.
-- Optional env_context: room environmental state for threshold checking.
function fsm.tick(registry, obj_id, env_context)
    local obj = registry:get(obj_id)
    if not obj or not obj.states or not obj._state then return nil end

    -- Step 1: existing on_tick callback (legacy burn countdown, etc.)
    local state = obj.states[obj._state]
    if state and state.on_tick then
        local result = state.on_tick(obj)
        if result then
            if result.warning then return result.warning end
            if result.trigger then
                for _, t in ipairs(obj.transitions or {}) do
                    if t.from == obj._state and t.trigger == "auto"
                       and t.condition == result.trigger then
                        apply_state(obj, t.to, obj._state)
                        apply_mutations(obj, t.mutate)
                        return t.message
                    end
                end
            end
        end
    end

    -- Step 2: threshold checking (material property-based auto-transitions)
    local threshold_msg = check_thresholds(registry, obj, obj_id, env_context)
    if threshold_msg then return threshold_msg end

    return nil
end

-- Start a timed event for an object if its current state has timed_events.
-- Uses remaining_burn for candle-style partial timers, otherwise the delay from metadata.
function fsm.start_timer(registry, obj_id)
    local obj = registry:get(obj_id)
    if not obj or not obj.states or not obj._state then return end

    local state = obj.states[obj._state]
    if not state or not state.timed_events then return end

    local te = state.timed_events[1]  -- first timed event
    if not te then return end

    -- Use remaining_burn if the object tracks partial burn (candle pattern)
    local delay = te.delay
    if obj.remaining_burn and obj.remaining_burn > 0 then
        delay = obj.remaining_burn
    end

    fsm.active_timers[obj_id] = {
        state = obj._state,
        remaining = delay,
        event = te.event,
        to_state = te.to_state,
    }
end

-- Stop/remove the timer for an object (e.g., on extinguish or room unload).
function fsm.stop_timer(obj_id)
    fsm.active_timers[obj_id] = nil
end

-- Pause a timer, preserving remaining time for later resume.
function fsm.pause_timer(obj_id)
    local timer = fsm.active_timers[obj_id]
    if timer then
        fsm.paused_timers[obj_id] = timer
        fsm.active_timers[obj_id] = nil
    end
end

-- Resume a paused timer.
function fsm.resume_timer(obj_id)
    local timer = fsm.paused_timers[obj_id]
    if timer then
        fsm.active_timers[obj_id] = timer
        fsm.paused_timers[obj_id] = nil
    end
end

-- Scan all objects in a room and start timers for any with timed_events.
-- Called on room load.
function fsm.scan_room_timers(registry, room)
    if not room or not room.contents then return end
    for _, obj_id in ipairs(room.contents) do
        -- Resume paused timer if available, otherwise start fresh
        if fsm.paused_timers[obj_id] then
            fsm.resume_timer(obj_id)
        else
            fsm.start_timer(registry, obj_id)
        end
        -- Also check surface/container contents
        local obj = registry:get(obj_id)
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                for _, item_id in ipairs(zone.contents or {}) do
                    if fsm.paused_timers[item_id] then
                        fsm.resume_timer(item_id)
                    else
                        fsm.start_timer(registry, item_id)
                    end
                end
            end
        end
        if obj and obj.contents then
            for _, item_id in ipairs(obj.contents) do
                if fsm.paused_timers[item_id] then
                    fsm.resume_timer(item_id)
                else
                    fsm.start_timer(registry, item_id)
                end
            end
        end
    end
end

-- Pause all timers for objects in a room. Called on room unload.
function fsm.pause_room_timers(room)
    if not room or not room.contents then return end
    for _, obj_id in ipairs(room.contents) do
        fsm.pause_timer(obj_id)
    end
end

-- Tick all active timers by delta_seconds.
-- Fires auto-transitions when timers expire.
-- Returns a list of { obj_id, message } for any transitions that fired.
function fsm.tick_timers(registry, delta_seconds)
    local messages = {}
    local expired = {}
    -- Phase 1: decrement and collect expired timers
    for obj_id, timer in pairs(fsm.active_timers) do
        timer.remaining = timer.remaining - delta_seconds
        if timer.remaining <= 0 then
            expired[#expired + 1] = { id = obj_id, timer = timer }
        else
            -- Update remaining_burn on the object for save/resume fidelity
            local obj = registry:get(obj_id)
            if obj and obj.remaining_burn then
                obj.remaining_burn = timer.remaining
            end
        end
    end
    -- Phase 2: process expired timers (safe to mutate active_timers now)
    for _, entry in ipairs(expired) do
        local obj_id = entry.id
        local timer = entry.timer
        fsm.active_timers[obj_id] = nil
        local obj = registry:get(obj_id)
        if obj and obj._state == timer.state then
            -- Update remaining_burn if object tracks it
            if obj.remaining_burn then
                obj.remaining_burn = 0
            end
            -- Fire the auto-transition
            for _, t in ipairs(obj.transitions or {}) do
                if t.from == timer.state and t.trigger == "auto"
                   and t.condition == "timer_expired" then
                    apply_state(obj, t.to, timer.state)
                    apply_mutations(obj, t.mutate)
                    if t.message then
                        messages[#messages + 1] = { obj_id = obj_id, message = t.message }
                    end
                    break
                end
            end
            -- Start new timer if the new state also has timed_events (cyclic clocks)
            fsm.start_timer(registry, obj_id)
        end
    end
    return messages
end

return fsm

end

package.preload["engine.injuries.cure"] = function()
-- engine/injuries/cure.lua
-- Cure/healing logic: try_heal, resolve_target, apply_treatment, remove_treatment,
-- heal, get_restrictions. Split from injuries/init.lua in Phase 3 WAVE-0.
--
-- Ownership: Bart (Architect)

local cure = {}

-- Injected reference to parent injuries module (set via cure.init)
local injuries = nil

function cure.init(injuries_mod)
    injuries = injuries_mod
end

local function table_contains(t, val)
    for _, v in ipairs(t) do
        if v == val then return true end
    end
    return false
end

---------------------------------------------------------------------------
-- Try to heal an injury with a healing object
-- Returns: true if healed, false otherwise
---------------------------------------------------------------------------
function cure.try_heal(player, healing_object, verb)
    local effect = healing_object["on_" .. verb]
    if not effect or not effect.cures then return false end

    -- Find matching active injury by exact type
    local injury, index = injuries.find_by_type(player, effect.cures)
    if not injury then
        print("You don't have that kind of injury.")
        return false
    end

    -- Disease curable_in guard: reject healing if current state is outside
    -- the allowed cure window
    local def = injuries.load_definition(injury.type)
    if def and def.curable_in then
        local in_window = false
        for _, s in ipairs(def.curable_in) do
            if s == injury._state then in_window = true; break end
        end
        if not in_window then
            print("The treatment has no effect.")
            return false
        end
    end

    -- Validate via injury definition's healing_interactions
    if not def then def = injuries.load_definition(injury.type) end
    if def and def.healing_interactions then
        local interaction = def.healing_interactions[healing_object.id]
        if interaction and interaction.from_states then
            local valid = false
            for _, s in ipairs(interaction.from_states) do
                if s == injury._state then valid = true; break end
            end
            if not valid then
                print("It's too late for that to help.")
                return false
            end
        end
    end

    -- Apply healing
    if effect.transition_to then
        -- Partial healing: transition FSM, stop damage
        injury._state = effect.transition_to
        injury.damage_per_tick = 0
        injury.turns_active = 0  -- Reset for auto-heal timer in new state
    else
        -- Full cure: remove injury entirely
        table.remove(player.injuries, index)
    end

    -- Print healing message
    if effect.message then
        print(effect.message)
    end

    return true
end

---------------------------------------------------------------------------
-- Injury targeting: resolve player text to an injury instance
-- @param player table
-- @param target_str string|nil  — text after "to", e.g. "left arm stab wound"
-- @param cures_list table       — e.g. {"bleeding", "minor-cut"}
-- @return injury|nil, error_msg string
---------------------------------------------------------------------------
function cure.resolve_target(player, target_str, cures_list)
    if not player.injuries or #player.injuries == 0 then
        return nil, "You don't have any injuries."
    end

    -- Filter to treatable injuries
    local treatable = {}
    for _, injury in ipairs(player.injuries) do
        if table_contains(cures_list, injury.type) and not injury.treatment then
            treatable[#treatable + 1] = injury
        end
    end

    if #treatable == 0 then
        return nil, "You don't have any injuries that would help."
    end

    -- Auto-target: if only one treatable injury and no target specified
    if target_str == nil or target_str == "" then
        if #treatable == 1 then
            return treatable[1], ""
        else
            return nil, cure.format_injury_options(treatable)
        end
    end

    local normalized = target_str:lower()

    -- Priority 1: Exact instance ID
    for _, injury in ipairs(treatable) do
        if injury.id == target_str then
            return injury, ""
        end
    end

    -- Priority 2: Display name substring
    for _, injury in ipairs(treatable) do
        local def = injuries.load_definition(injury.type)
        local state_def = def and def.states and def.states[injury._state]
        if state_def and state_def.name and
           string.find(state_def.name:lower(), normalized, 1, true) then
            return injury, ""
        end
    end

    -- Priority 3: Body location substring
    for _, injury in ipairs(treatable) do
        if injury.location and
           string.find(injury.location:lower(), normalized, 1, true) then
            return injury, ""
        end
    end

    -- Priority 4: Injury type exact match
    for _, injury in ipairs(treatable) do
        if injury.type == normalized then
            return injury, ""
        end
    end

    -- Priority 5: Ordinal index
    local ordinal_map = {first = 1, second = 2, third = 3, fourth = 4, fifth = 5}
    local ordinal_index = ordinal_map[normalized] or tonumber(normalized)
    if ordinal_index and treatable[ordinal_index] then
        return treatable[ordinal_index], ""
    end

    return nil, "You don't see that injury. " .. cure.format_injury_options(treatable)
end

function cure.format_injury_options(treatable)
    local lines = {"Which injury? You have:"}
    for i, injury in ipairs(treatable) do
        local def = injuries.load_definition(injury.type)
        local state_def = def and def.states and def.states[injury._state]
        local state_name = (state_def and state_def.name) or injury.type
        local location = injury.location and (" (" .. injury.location .. ")") or ""
        lines[#lines + 1] = "  " .. i .. ". " .. state_name .. location
    end
    return table.concat(lines, "\n")
end

---------------------------------------------------------------------------
-- Treatment: apply a treatment object to an injury (dual binding)
-- @param player table
-- @param treatment_obj table  — bandage instance
-- @param injury table         — target injury instance
---------------------------------------------------------------------------
function cure.apply_treatment(player, treatment_obj, injury)
    -- 1. Bind treatment → injury
    treatment_obj.applied_to = injury.id

    -- 2. Bind injury → treatment
    injury.treatment = {
        type = treatment_obj.id,
        item_id = treatment_obj.id,
        healing_boost = treatment_obj.healing_boost or 1,
    }

    -- 3. Transition bandage FSM: clean/soiled → applied
    treatment_obj._state = "applied"

    -- 4. Transition injury FSM if applicable
    local def = injuries.load_definition(injury.type)
    if def and def.healing_interactions then
        local interaction = def.healing_interactions[treatment_obj.id]
        if interaction and interaction.from_states then
            if table_contains(interaction.from_states, injury._state) then
                injury._state = interaction.transitions_to
                injury.damage_per_tick = 0
            end
        end
    end
end

---------------------------------------------------------------------------
-- Treatment: remove a treatment object from its attached injury
-- @param player table
-- @param treatment_obj table
-- @return boolean, string|nil
---------------------------------------------------------------------------
function cure.remove_treatment(player, treatment_obj)
    if not treatment_obj.applied_to then
        return false, "That isn't applied to anything."
    end

    -- Find the injury this treatment is attached to
    local injury = injuries.find_by_id(player, treatment_obj.applied_to)
    if not injury then
        -- Injury healed while bandage was on — just clean up bandage side
        treatment_obj.applied_to = nil
        treatment_obj._state = "soiled"
        return true
    end

    -- Clear injury → treatment reference
    injury.treatment = nil

    -- If injury is still active, resume damage
    local def = injuries.load_definition(injury.type)
    if def then
        -- Revert to active state if currently treated
        if injury._state == "treated" then
            injury._state = "active"
        end
        local state_def = def.states and def.states[injury._state]
        if state_def and state_def.damage_per_tick then
            injury.damage_per_tick = state_def.damage_per_tick
        end
    end

    -- Clear treatment → injury reference
    treatment_obj.applied_to = nil

    -- Transition bandage FSM: applied → soiled
    treatment_obj._state = "soiled"

    return true
end

---------------------------------------------------------------------------
-- Metadata-driven cure: scan injuries for healing_interactions match
-- The injury definition declares what cures it (no disease-specific code).
-- @param player table
-- @param healing_object table — item being applied (needs .id)
-- @return boolean success, string|nil message
---------------------------------------------------------------------------
function cure.apply_healing_interaction(player, healing_object)
    if not player.injuries or #player.injuries == 0 then
        return false, "You don't have any injuries to treat."
    end

    local obj_id = healing_object and healing_object.id
    if not obj_id then return false, nil end

    for idx, injury in ipairs(player.injuries) do
        local def = injuries.load_definition(injury.type)
        if def and def.healing_interactions then
            local interaction = def.healing_interactions[obj_id]
            if interaction then
                -- Check if injury is in a curable state
                if interaction.from_states then
                    local valid = false
                    for _, s in ipairs(interaction.from_states) do
                        if s == injury._state then valid = true; break end
                    end
                    if not valid then
                        return false, interaction.reject_message
                            or "It's too late for that to help."
                    end
                end
                -- Transition to target state
                injury._state = interaction.transitions_to or "cured"
                injury.damage_per_tick = 0
                -- Remove fully cured injuries
                if injury._state == "cured" or injury._state == "healed" then
                    table.remove(player.injuries, idx)
                end
                return true, interaction.message
                    or "The treatment takes effect."
            end
        end
    end

    return false, "That doesn't seem to help with any of your injuries."
end

---------------------------------------------------------------------------
-- Direct disease healing: check curable_in before allowing cure
-- @param player table
-- @param injury_type string
-- @return true if healed, false otherwise
---------------------------------------------------------------------------
function cure.heal(player, injury_type)
    local injury, index = injuries.find_by_type(player, injury_type)
    if not injury then
        print("You don't have that affliction.")
        return false
    end

    local def = injuries.load_definition(injury.type)
    if def and def.curable_in then
        local in_window = false
        for _, s in ipairs(def.curable_in) do
            if s == injury._state then in_window = true; break end
        end
        if not in_window then
            print("The treatment has no effect.")
            return false
        end
    end

    -- Cure: transition to healed and remove
    injury._state = "healed"
    injury.damage_per_tick = 0
    table.remove(player.injuries, index)
    return true
end

---------------------------------------------------------------------------
-- Get merged restriction set from all active injuries
-- @param player table
-- @return table — keys are restriction names, values are true
---------------------------------------------------------------------------
function cure.get_restrictions(player)
    local restrictions = {}
    for _, injury in ipairs(player.injuries or {}) do
        local def = injuries.load_definition(injury.type)
        local state_def = def and def.states and def.states[injury._state]
        if state_def and state_def.restricts then
            for k, v in pairs(state_def.restricts) do
                if v then restrictions[k] = true end
            end
        end
    end
    return restrictions
end

return cure

end

package.preload["engine.injuries"] = function()
-- engine/injuries.lua
-- Injury engine: infliction, per-turn ticking, health computation, healing.
-- Health is derived: max_health - sum(injury.damage for active injuries).
--
-- Ownership: Bart (Architect)

local injuries = {}

local SECONDS_PER_TICK = 360

-- Forward declaration for stress system (WAVE-3)
local _stress_def = nil
local load_stress_def  -- forward declaration; defined in stress section

---------------------------------------------------------------------------
-- Injury definition loader
---------------------------------------------------------------------------
local _cache = {}

function injuries.load_definition(injury_type)
    if _cache[injury_type] then return _cache[injury_type] end
    local ok, def = pcall(require, "meta.injuries." .. injury_type)
    if ok and def then
        _cache[injury_type] = def
        return def
    end
    return nil
end

-- Allow tests to inject definitions without filesystem access
function injuries.register_definition(injury_type, def)
    _cache[injury_type] = def
end

function injuries.clear_cache()
    _cache = {}
    _stress_def = nil
end

---------------------------------------------------------------------------
-- Health computation (derived — never stored)
---------------------------------------------------------------------------
function injuries.compute_health(player)
    local total_damage = 0
    for _, injury in ipairs(player.injuries or {}) do
        total_damage = total_damage + (injury.damage or 0)
    end
    return math.max(0, (player.max_health or 100) - total_damage)
end

---------------------------------------------------------------------------
-- Instance ID generation
---------------------------------------------------------------------------
local _next_id = 0
local function next_instance_id(injury_type)
    _next_id = _next_id + 1
    return injury_type .. "-" .. _next_id
end

-- Allow tests to reset
function injuries.reset_id_counter()
    _next_id = 0
end

---------------------------------------------------------------------------
-- Text interpolation: replace {key} placeholders with context values.
-- Used by injury templates that declare {source}, {location}, etc.
-- Falls back to definition's interpolation_defaults, then raw key name.
---------------------------------------------------------------------------
local function readable_source(source_id)
    if not source_id or source_id == "" or source_id == "unknown" then
        return nil
    end
    return source_id:gsub("%-", " ")
end

function injuries.interpolate(text, vars)
    if not text then return nil end
    if not vars then return text end
    return (text:gsub("{(%w+)}", function(key)
        return vars[key] or key
    end))
end

local function build_interp_vars(instance, def)
    local defaults = def and def.interpolation_defaults or {}
    return {
        location = instance.location or defaults.location or "body",
        source = readable_source(instance.source) or defaults.source or "something",
    }
end

---------------------------------------------------------------------------
-- Compute initial state_turns_remaining from definition state metadata.
-- Supports both `duration` (direct turn count) and `timed_events` (seconds).
---------------------------------------------------------------------------
local function compute_state_turns(state_def)
    if not state_def then return nil end
    if state_def.duration then return state_def.duration end
    if state_def.timed_events and state_def.timed_events[1] then
        local delay = state_def.timed_events[1].delay
        if delay and delay > 0 then
            return math.ceil(delay / SECONDS_PER_TICK)
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Inflict an injury on the player
-- @param player table
-- @param injury_type string
-- @param source string           — e.g. "silver-dagger"
-- @param location string|nil     — body area, e.g. "left arm"
-- @param override_damage number|nil — weapon-supplied damage overrides def
---------------------------------------------------------------------------
function injuries.inflict(player, injury_type, source, location, override_damage)
    local def = injuries.load_definition(injury_type)
    if not def then
        print("Unknown injury type: " .. tostring(injury_type))
        return nil
    end

    local on_inflict = def.on_inflict or {}
    local initial_dmg = override_damage or on_inflict.initial_damage or 0
    local instance = {
        id = next_instance_id(injury_type),
        type = injury_type,
        _state = def.initial_state or "active",
        source = source or "unknown",
        location = location,
        turns_active = 0,
        damage = initial_dmg,
        damage_per_tick = on_inflict.damage_per_tick or 0,
    }

    -- Copy degenerative config if present
    if def.degenerative then
        instance.damage_per_tick = def.degenerative.base_damage or instance.damage_per_tick
    end

    -- Disease-specific initialization
    if def.category == "disease" then
        instance.category = "disease"
        if def.hidden_until_state then
            instance._hidden = true
            instance.hidden_until_state = def.hidden_until_state
        end
        local init_state_def = def.states and def.states[instance._state]
        instance.state_turns_remaining = compute_state_turns(init_state_def)
    end

    -- Self-infliction damage ceiling: never reduce health below 1
    if source and source:find("self%-inflicted") then
        local current_health = injuries.compute_health(player)
        if current_health - instance.damage < 1 then
            instance.damage = math.max(0, current_health - 1)
        end
    end

    player.injuries = player.injuries or {}
    player.injuries[#player.injuries + 1] = instance

    -- Print infliction message (interpolate placeholders from context)
    if on_inflict.message then
        local vars = build_interp_vars(instance, def)
        print(injuries.interpolate(on_inflict.message, vars))
    end

    return instance
end

---------------------------------------------------------------------------
-- Find injury by instance ID
---------------------------------------------------------------------------
function injuries.find_by_id(player, instance_id)
    for i, injury in ipairs(player.injuries or {}) do
        if injury.id == instance_id then
            return injury, i
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Find injury by type
---------------------------------------------------------------------------
function injuries.find_by_type(player, injury_type)
    for i, injury in ipairs(player.injuries or {}) do
        if injury.type == injury_type then
            return injury, i
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Per-turn injury tick
-- Returns: messages table, death flag
---------------------------------------------------------------------------
function injuries.tick(player)
    local messages = {}
    local died = false

    if not player.injuries or #player.injuries == 0 then
        return messages, false
    end

    -- Phase 1: Tick each active injury
    for _, injury in ipairs(player.injuries) do
        local def = injuries.load_definition(injury.type)
        if not def then goto continue_tick end

        local state_def = def.states and def.states[injury._state]
        if not state_def then goto continue_tick end

        -- Skip terminal states
        if state_def.terminal then goto continue_tick end

        -- Advance turn counter
        injury.turns_active = (injury.turns_active or 0) + 1

        -- Disease progression: decrement state_turns_remaining, transition
        if injury.category == "disease" and injury.state_turns_remaining then
            injury.state_turns_remaining = injury.state_turns_remaining - 1
            if injury.state_turns_remaining <= 0 then
                local transitioned = false
                for _, t in ipairs(def.transitions or {}) do
                    if t.from == injury._state and t.trigger == "auto"
                       and (t.condition == "duration_expired"
                            or t.condition == "timer_expired") then
                        injury._state = t.to
                        injury.turns_active = 0
                        -- Apply mutations from transition
                        if t.mutate then
                            for k, v in pairs(t.mutate) do
                                injury[k] = v
                            end
                        end
                        -- Check hidden_until_state visibility
                        local show_msg = true
                        if injury._hidden then
                            if injury._state == injury.hidden_until_state then
                                injury._hidden = false
                            else
                                show_msg = false
                            end
                        end
                        if show_msg and t.message then
                            local vars = build_interp_vars(injury, def)
                            messages[#messages + 1] = injuries.interpolate(t.message, vars)
                        end
                        -- Initialize state_turns_remaining for new state
                        local new_state_def = def.states and def.states[injury._state]
                        injury.state_turns_remaining = compute_state_turns(new_state_def)
                        -- Refresh state_def for subsequent checks this tick
                        state_def = new_state_def
                        transitioned = true
                        break
                    end
                end
                if not transitioned then
                    injury.state_turns_remaining = nil
                end
            end
        end

        -- Accumulate per-turn damage (over-time injuries)
        if injury.damage_per_tick and injury.damage_per_tick > 0 then
            injury.damage = injury.damage + injury.damage_per_tick
        end

        -- Degenerative scaling: increase damage_per_tick each turn
        if def.damage_type == "degenerative" and def.degenerative then
            local degen = def.degenerative
            injury.damage_per_tick = math.min(
                degen.max_damage or 999,
                (injury.damage_per_tick or 0) + (degen.increment or 0)
            )
        end

        -- Auto-healing: some injuries heal after N turns in their current state
        if state_def.auto_heal_turns and injury.turns_active >= state_def.auto_heal_turns then
            injury._state = "healed"
            local healed_state = def.states and def.states["healed"]
            if healed_state and healed_state.description then
                messages[#messages + 1] = healed_state.description
            end
            goto continue_tick
        end

        ::continue_tick::
    end

    -- Phase 2: Remove healed/terminal injuries
    local active = {}
    for _, injury in ipairs(player.injuries) do
        local def = injuries.load_definition(injury.type)
        local state_def = def and def.states and def.states[injury._state]
        if state_def and state_def.terminal then
            -- Check for death message on fatal states
            if injury._state == "fatal" and state_def.death_message then
                messages[#messages + 1] = state_def.death_message
            end
        else
            active[#active + 1] = injury
        end
    end
    player.injuries = active

    -- Phase 3: Check death
    local health = injuries.compute_health(player)
    if health <= 0 then
        -- Self-inflicted injuries alone cannot kill (design: ceiling on self-damage)
        local has_external = false
        for _, injury in ipairs(player.injuries) do
            if not injury.source or not injury.source:find("self%-inflicted") then
                has_external = true
                break
            end
        end
        if has_external then
            died = true
        end
    end

    return messages, died
end

---------------------------------------------------------------------------
-- Try to heal an injury with a healing object
-- Delegates to cure module
---------------------------------------------------------------------------
local cure = require("engine.injuries.cure")
cure.init(injuries)

injuries.try_heal = cure.try_heal

---------------------------------------------------------------------------
-- List injuries (for the `injuries` verb)
---------------------------------------------------------------------------
function injuries.list(player)
    local has_injuries = player.injuries and #player.injuries > 0
    local stress_val = player.stress or 0
    local stress_level = injuries.get_stress_level(player)
    local has_stress = stress_val > 0

    if not has_injuries and not has_stress then
        print("You feel fine. No injuries to speak of.")
        return
    end

    print("You examine yourself:")
    for _, injury in ipairs(player.injuries or {}) do
        -- Skip hidden diseases (not yet symptomatic)
        if injury._hidden then goto continue_list end

        local def = injuries.load_definition(injury.type)
        local state_def = def and def.states and def.states[injury._state]

        local name = (state_def and state_def.name) or (def and def.name) or injury.type
        local symptom = (state_def and state_def.symptom)
                     or (state_def and state_def.description)
                     or ""

        -- Interpolate placeholders in symptom/description text
        local vars = build_interp_vars(injury, def)
        symptom = injuries.interpolate(symptom, vars) or symptom

        local line = "  " .. name
        if injury.location then
            line = line .. " on your " .. injury.location
        end
        if symptom ~= "" then
            line = line .. " — " .. symptom
        end
        if injury.treatment then
            line = line .. " [treated]"
        end
        print(line)

        ::continue_list::
    end

    -- Stress: show level description or sub-threshold feedback
    if has_stress then
        if stress_level then
            local def = load_stress_def()
            if def and def.levels then
                for _, lvl in ipairs(def.levels) do
                    if lvl.name == stress_level then
                        print("  " .. lvl.description)
                        break
                    end
                end
            end
        else
            print("  You feel a growing unease.")
        end
    end
end

---------------------------------------------------------------------------
-- Compute total health drain per tick from all untreated injuries
---------------------------------------------------------------------------
function injuries.compute_total_drain(player)
    local total_drain = 0
    for _, injury in ipairs(player.injuries or {}) do
        total_drain = total_drain + (injury.damage_per_tick or 0)
    end
    return total_drain
end

-- Delegate cure/healing functions to cure module
injuries.resolve_target = cure.resolve_target
injuries.format_injury_options = cure.format_injury_options
injuries.apply_treatment = cure.apply_treatment
injuries.remove_treatment = cure.remove_treatment
injuries.heal = cure.heal
injuries.apply_healing_interaction = cure.apply_healing_interaction
injuries.get_restrictions = cure.get_restrictions

---------------------------------------------------------------------------
-- Stress system (WAVE-3): psychological injury via accumulated trauma
-- Stress metadata lives in meta/injuries/stress.lua (Principle 8).
-- Narration owned by Smithers (UI Engineer).
---------------------------------------------------------------------------

load_stress_def = function()
    if _stress_def then return _stress_def end
    -- Check definition cache (supports test injection via register_definition)
    if _cache["stress"] then
        _stress_def = _cache["stress"]
        return _stress_def
    end
    local ok, def = pcall(require, "meta.injuries.stress")
    if ok and def then
        _stress_def = def
        return def
    end
    return nil
end

-- Allow tests to inject the stress definition
function injuries.register_stress_definition(def)
    _stress_def = def
end

function injuries.clear_stress_definition()
    _stress_def = nil
end

---------------------------------------------------------------------------
-- Stress narration tables (Smithers — WAVE-3)
---------------------------------------------------------------------------

local STRESS_TRIGGER_NARRATION = {
    witness_creature_death = "The sight of death shakes you.",
    near_death_combat      = "A wave of terror washes over you as death looms close.",
    witness_gore           = "The gore turns your stomach.",
}

local STRESS_LEVEL_NARRATION = {
    shaken      = "Your hands begin to tremble.",
    distressed  = "Your breathing quickens. Heart pounding.",
    overwhelmed = "Panic overwhelms you.",
}

---------------------------------------------------------------------------
-- Stress: level computation helpers
---------------------------------------------------------------------------

-- Compute stress level name from numeric stress value and definition.
local function compute_stress_level(stress_value, def)
    if not def or not def.levels then return nil end
    local current_level = nil
    for _, lvl in ipairs(def.levels) do
        if stress_value >= lvl.threshold then
            current_level = lvl.name
        end
    end
    return current_level
end

-- Return a copy of the effects table for a given stress level name.
local function get_level_effects(level_name, def)
    if not level_name or not def or not def.effects then return {} end
    local fx = def.effects[level_name]
    if not fx then return {} end
    local copy = {}
    for k, v in pairs(fx) do copy[k] = v end
    return copy
end

---------------------------------------------------------------------------
-- Stress API
---------------------------------------------------------------------------

-- Add stress from a trauma trigger.
-- Looks up trigger value from stress.lua metadata, adds to player.stress.
-- Prints trigger-specific narration and level-change narration.
function injuries.add_stress(player, trigger_name)
    local def = load_stress_def()
    if not def or not def.triggers then return end
    local amount = def.triggers[trigger_name]
    if not amount then return end

    local old_level = player.stress_level

    player.stress = (player.stress or 0) + amount

    -- Trigger narration
    local trigger_msg = STRESS_TRIGGER_NARRATION[trigger_name]
    if trigger_msg then
        print(trigger_msg)
    end

    -- Recompute level and effects
    local new_level = compute_stress_level(player.stress, def)
    player.stress_level = new_level
    player.stress_effects = get_level_effects(new_level, def)

    -- Level-change narration (only when crossing a new threshold)
    if new_level and new_level ~= old_level then
        local level_msg = STRESS_LEVEL_NARRATION[new_level]
        if level_msg then
            print(level_msg)
        end
    end
end

-- Return current stress level name based on accumulated stress vs thresholds.
-- Returns nil if stress is below the lowest threshold.
function injuries.get_stress_level(player)
    local def = load_stress_def()
    if not def or not def.levels then return nil end
    local stress = player.stress or 0
    return compute_stress_level(stress, def)
end

-- Return the effects table for the player's current stress level.
-- Returns empty table if no stress or below threshold.
function injuries.get_stress_effects(player)
    local def = load_stress_def()
    if not def or not def.effects then return {} end
    local level = injuries.get_stress_level(player)
    if not level then return {} end
    return get_level_effects(level, def)
end

-- Parse cure duration from stress definition (e.g. "2 hours" -> 2.0)
local function parse_stress_cure_duration()
    local def = load_stress_def()
    if not def or not def.cure or not def.cure.duration then return nil end
    local s = def.cure.duration
    local num, unit = s:match("(%d+)%s*(%a+)")
    if not num then return nil end
    num = tonumber(num)
    unit = unit:lower()
    if unit:match("^hour") then return num
    elseif unit:match("^min") then return num / 60
    elseif unit:match("^day") then return num * 24
    end
    return num
end

-- Cure stress via rest. Accepts optional ctx for safe-room checking.
-- rest_hours: how many game hours of rest this call represents.
-- When rest_hours is provided, enforces the cure.duration from stress.lua.
-- Without rest_hours, cures instantly (backward compatibility).
function injuries.cure_stress(player, ctx, rest_hours)
    if not player or (player.stress or 0) <= 0 then return false end

    -- Check safe room via ctx.room creatures (test-compatible path)
    if ctx then
        local room = ctx.room
        if room and room.creatures then
            for _, creature in ipairs(room.creatures) do
                if creature.hostile and creature.alive ~= false then
                    return false
                end
            end
        end
    end

    -- Duration enforcement when rest_hours is provided
    if rest_hours then
        local required = parse_stress_cure_duration() or 2
        player.stress_rest_accumulated = (player.stress_rest_accumulated or 0) + rest_hours
        if player.stress_rest_accumulated < required then
            return false
        end
    end

    player.stress = 0
    player.stress_level = nil
    player.stress_effects = {}
    player.stress_rest_accumulated = 0

    print("With rest and safety, the panic slowly fades.")
    return true
end

-- Check if a room qualifies as "safe" for stress cure.
-- Q2 resolved: any room without hostile creatures is safe.
function injuries.is_safe_room(room, registry)
    if not room then return false end
    local creatures_ok, creatures_mod = pcall(require, "engine.creatures")
    if not creatures_ok or not creatures_mod then return true end
    local room_id = room.id or room
    if not registry then return true end
    local room_creatures = creatures_mod.get_creatures_in_room(registry, room_id)
    for _, c in ipairs(room_creatures) do
        if c.alive ~= false and c._state ~= "dead" and c._state ~= "fled" then
            local aggression = c.behavior and c.behavior.aggression or 0
            if aggression > 0 then return false end
        end
    end
    return true
end

return injuries

end

package.preload["engine.loader"] = function()
-- engine/loader/init.lua
-- Sandboxed loader: accepts a Lua source string, returns a live table.
-- The sandbox deliberately excludes os, io, and other dangerous globals.
-- Also handles template resolution -- merging base templates under instances.

local loader = {}

-- normalize_guid(guid) -> string
-- Strips braces from GUIDs to handle both "{abc-123}" and "abc-123" formats.
-- This allows object definitions and room references to use either style.
local function normalize_guid(guid)
  if type(guid) ~= "string" then return guid end
  return guid:gsub("^%{(.-)%}$", "%1")
end

-- Minimal safe environment available to all loaded object code.
local function make_sandbox()
  return {
    ipairs   = ipairs,
    pairs    = pairs,
    next     = next,
    select   = select,
    tonumber = tonumber,
    tostring = tostring,
    type     = type,
    unpack   = unpack or table.unpack,
    error    = error,
    pcall    = pcall,
    math     = math,
    string   = string,
    table    = table,
  }
end

-- deep_merge(base, override) -> merged table
-- Copies all fields from base into a new table, then overlays override on top.
-- Nested tables are recursively merged (arrays are replaced, not appended).
-- The override always wins for any key it defines.
local function deep_merge(base, override)
  local result = {}

  -- Copy base values
  for k, v in pairs(base) do
    if type(v) == "table" then
      result[k] = deep_merge(v, {})
    else
      result[k] = v
    end
  end

  -- Overlay override values
  for k, v in pairs(override) do
    if type(v) == "table" and type(result[k]) == "table" then
      result[k] = deep_merge(result[k], v)
    else
      result[k] = v
    end
  end

  return result
end

-- load_source(source) -> table, nil  |  nil, error_string
-- Executes `source` inside the sandbox and returns whatever the chunk returns.
-- The source is expected to return a Lua table (the object definition).
function loader.load_source(source)
  local env = make_sandbox()

  -- Lua 5.1 uses loadstring; 5.2+ uses load() with an env argument.
  local chunk, err
  if _VERSION == "Lua 5.1" then
    chunk, err = loadstring(source)
    if chunk then setfenv(chunk, env) end
  else
    chunk, err = load(source, "object", "t", env)
  end

  if not chunk then
    return nil, "compile error: " .. tostring(err)
  end

  local ok, result = pcall(chunk)
  if not ok then
    return nil, "runtime error: " .. tostring(result)
  end

  if type(result) ~= "table" then
    return nil, "object source must return a table, got " .. type(result)
  end

  return result, nil
end

-- resolve_template(object, templates) -> resolved_object, nil | nil, error_string
-- If the object has a `template` field, looks up the template by id in the
-- templates table and merges base properties under the instance's overrides.
-- The instance always wins. The `template` field is removed after resolution.
function loader.resolve_template(object, templates)
  if not object.template then
    return object, nil
  end

  local template_id = object.template
  local tmpl = templates[template_id]
  if not tmpl then
    return nil, "template '" .. tostring(template_id) .. "' not found"
  end

  local resolved = deep_merge(tmpl, object)
  resolved.template = nil  -- consumed; no longer needed at runtime
  return resolved, nil
end

-- load_template(source) -> table, nil | nil, error_string
-- Convenience: loads a template source string. Identical to load_source,
-- but named separately for clarity in calling code.
function loader.load_template(source)
  return loader.load_source(source)
end

-- resolve_instance(instance, base_classes, templates) -> resolved_object, nil | nil, error_string
-- Takes an instance definition (with type_id and optional overrides),
-- looks up the base class by GUID, deep-merges overrides on top,
-- and prepares the object for registration.
-- Contents arrays are cleared -- they are rebuilt from the instance tree.
function loader.resolve_instance(instance, base_classes, templates)
  if not instance.type_id then
    return nil, "instance '" .. tostring(instance.id) .. "' missing type_id"
  end

  local normalized_type_id = normalize_guid(instance.type_id)
  local base = base_classes[normalized_type_id]
  if not base then
    return nil, "base class not found for guid '" .. normalized_type_id
        .. "' (instance '" .. tostring(instance.id) .. "')"
  end

  -- Deep-copy base, then overlay instance overrides
  local resolved = deep_merge(base, instance.overrides or {})

  -- Resolve template if base was not pre-resolved
  if resolved.template then
    local tmpl_resolved, err = loader.resolve_template(resolved, templates or {})
    if not tmpl_resolved then
      return nil, err
    end
    resolved = tmpl_resolved
  end

  -- Instance identity overrides base identity
  resolved.id = instance.id
  resolved.type_id = instance.type_id
  resolved.guid = nil  -- guid belongs to the base class, not the instance

  -- Clear contents -- these are rebuilt from the instance tree.
  -- Preserve the field if the base class defined it (for on_look etc.)
  if resolved.contents ~= nil then
    resolved.contents = {}
  end
  if resolved.surfaces then
    for _, zone in pairs(resolved.surfaces) do
      zone.contents = {}
    end
  end

  return resolved, nil
end

-- Relationship key → surface name mapping for deep-nested instance trees.
-- Room files use on_top/underneath/nested keys; the engine uses surface names.
local RELATIONSHIP_SURFACES = {
    on_top      = "top",
    underneath  = "underneath",
}

-- flatten_instances(instances) -> flat list of instances with .location set
-- Walks the deep-nested instance tree and produces a flat array where every
-- instance has a .location field compatible with Phase 2 containment building.
--   "room"              → room-level object
--   "parent_id.surface" → placed on a parent's named surface
--   "parent_id"         → simple containment (inside parent, no surface)
function loader.flatten_instances(instances)
    local flat = {}

    local function walk(inst, location)
        inst.location = location
        flat[#flat + 1] = inst

        -- Surface-mapped relationships (on_top → .top, underneath → .underneath)
        for key, surface in pairs(RELATIONSHIP_SURFACES) do
            if inst[key] then
                for _, child in ipairs(inst[key]) do
                    walk(child, inst.id .. "." .. surface)
                end
                inst[key] = nil
            end
        end

        -- Nested parts (drawer in nightstand) — simple containment
        if inst.nested then
            for _, child in ipairs(inst.nested) do
                walk(child, inst.id)
            end
            inst.nested = nil
        end

        -- Simple containment (contents = array of child instance tables)
        if type(inst.contents) == "table" and inst.contents[1]
           and type(inst.contents[1]) == "table" and inst.contents[1].id then
            local children = inst.contents
            inst.contents = nil
            for _, child in ipairs(children) do
                walk(child, inst.id)
            end
        end
    end

    for _, inst in ipairs(instances) do
        walk(inst, "room")
    end

    return flat
end

-- Post-registration sound hook: scan a newly registered object for sound
-- declarations. Call after resolve_instance + register to queue file loading.
-- No-op when sound_manager is nil (headless mode).
function loader.scan_for_sounds(sound_manager, obj)
    if sound_manager and obj then
        sound_manager:scan_object(obj)
    end
end

return loader

end

package.preload["engine.loop"] = function()
-- engine/loop/init.lua
-- Terminal REPL game loop.
-- Routes player input through the parser pipeline and dispatches to verb handlers.
--
-- Ownership:
--   Smithers (UI Engineer): REPL I/O, parse pipeline (Tier 1→2→3), scroll, quit
--   Bart (Architect): Post-command FSM tick phase, timed events
--
-- Parser pipeline lives in engine/parser/preprocess.lua (Smithers owns).

local loop = {}

-- Parser preprocessing (Smithers owns — see engine/parser/preprocess.lua)
local preprocess = require("engine.parser.preprocess")

-- Tier 3: goal-oriented prerequisite planner (optional module)
local planner_ok, goal_planner = pcall(require, "engine.parser.goal_planner")
if not planner_ok then goal_planner = nil end

-- Tier 4: context window for recent interaction memory
local cw_ok, context_window = pcall(require, "engine.parser.context")
if not cw_ok then context_window = nil end

-- run(context)
-- context fields:
--   registry     -- live registry instance
--   current_room -- room table (must have .id, .name, .description)
--   verbs        -- table of { [verb_string] = handler_function }
--   ui           -- (optional) engine.ui module instance
--   on_quit      -- optional callback fired before exit
-- BUG-060: Pronouns that resolve to the last referenced noun
-- Tier 4: Added discovery reference patterns
local PRONOUNS = {
  it = true, them = true, that = true, this = true, those = true,
  ["the same"] = true, ["the same thing"] = true,
  ["thing i found"] = true, ["the thing i found"] = true,
  ["one i found"] = true, ["the one i found"] = true,
  ["what i found"] = true, ["item i found"] = true,
  ["thing i discovered"] = true, ["one i discovered"] = true,
  ["the one i discovered"] = true,
}

function loop.run(context)
  assert(context and context.registry, "loop: context.registry is required")
  context.verbs = context.verbs or {}

  -- Context tracking for Tier 3 planner
  context.last_tool = context.last_tool or nil
  context.known_objects = context.known_objects or {}

  -- BUG-060: last referenced noun for context retention between commands
  context.last_noun = context.last_noun or nil

  -- Session transcript for "report bug" (last 100 exchanges)
  context.transcript = context.transcript or {}

  if not context.headless then
    print("Type 'look' to look around. Type 'report bug' to report issues. Type 'quit' to exit.")
    if context.ui and context.ui.is_enabled() then
      print("Scroll: /up  /down  /bottom")
    end
    print("")
  end

  while true do
    -- Update status bar if UI is active
    if context.ui and context.ui.is_enabled() and context.update_status then
      context.update_status(context)
    end

    -- ═══ CONSCIOUSNESS GATE ═══
    -- If unconscious, skip input and run forced ticks until wake or death
    local player = context.player
    if player and player.consciousness
       and player.consciousness.state == "unconscious" then
      local inj_ok2, inj_mod2 = pcall(require, "engine.injuries")

      -- Tick injuries during unconsciousness
      if inj_ok2 and inj_mod2 then
        local msgs, died = inj_mod2.tick(player)
        for _, msg in ipairs(msgs or {}) do
          print(msg)
        end
        if died then
          -- Death during unconsciousness
          local cause = player.consciousness.cause or "your injuries"
          local death_messages = {
            ["blow-to-head"] = "You never wake up. The bleeding was too much.",
            ["poison-gas"]   = "The gas fills your lungs. You stop breathing.",
            ["knockout"]     = "Darkness takes you, and this time it doesn't let go.",
          }
          print("")
          print(death_messages[cause] or "You never wake up. Your injuries were too much.")
          print("")
          print("YOU HAVE DIED.")
          context.game_over = true
          if context.headless then io.write("---END---\n"); io.flush() end
          break
        end
      end

      -- Decrement wake timer
      player.consciousness.wake_timer = player.consciousness.wake_timer - 1

      -- Check wake-up
      if player.consciousness.wake_timer <= 0 then
        -- Transition: waking → conscious
        local cause = player.consciousness.cause or "unknown"
        local wake_narrations = {
          ["blow-to-head"] = "Your eyes flutter open. Your head throbs with a dull, persistent ache. Stars still dance at the edges of your vision.",
          ["poison-gas"]   = "You gasp and cough. Your throat is raw. The poison has run its course.",
          ["knockout"]     = "Pain drags you back to consciousness. Every muscle aches.",
        }
        print("")
        print(wake_narrations[cause] or "You slowly regain consciousness.")

        -- Health status on wake
        if inj_ok2 and inj_mod2 then
          local health = inj_mod2.compute_health(player)
          local max_hp = player.max_health or 100
          if health < max_hp * 0.5 then
            print("You feel weak. Something is very wrong.")
          elseif health < max_hp * 0.75 then
            print("You feel battered but alive.")
          end
        end
        print("")

        -- Reset consciousness state
        player.consciousness.state = "conscious"
        player.consciousness.wake_timer = 0
        player.consciousness.cause = nil
        player.consciousness.unconscious_since = nil
      else
        -- Still unconscious — emit a brief sensory fragment
        if context.headless then io.write("---END---\n"); io.flush() end
      end
      goto continue
    end

    -- ═══ UNCONSCIOUS INPUT REJECTION ═══
    -- (This is a safety check — normally the gate above handles it)

    -- If search is active and no input yet, process one search step
    local search_ok, search_mod = pcall(require, "engine.search")
    if search_ok and search_mod and search_mod.is_searching() then
      if _G.TRACE then io.stderr:write("[TRACE] search tick (active)\n") end
      -- Safety net: limit consecutive search ticks to prevent infinite spin
      local search_tick_limit = 0
      while search_mod.is_searching() and search_tick_limit < 200 do
        local continue_search = search_mod.tick(context)
        search_tick_limit = search_tick_limit + 1
        if _G.TRACE and search_tick_limit % 10 == 0 then
          io.stderr:write("[TRACE] search tick #" .. search_tick_limit .. " result: " .. tostring(continue_search) .. "\n")
        end
        if not continue_search then break end
      end
      if search_mod.is_searching() then
        -- Search exceeded tick limit — force abort
        if _G.TRACE then io.stderr:write("[TRACE] search force-aborted after " .. search_tick_limit .. " ticks\n") end
        search_mod.abort(context)
      end
      -- Search completed or aborted — fall through to normal input
    end

    -- Read input (UI-aware, headless, or fallback)
    local input
    if context.ui and context.ui.is_enabled() then
      input = context.ui.input()
    elseif context.headless then
      input = io.read()
    else
      io.write("> ")
      io.flush()
      input = io.read()
    end
    if not input then break end -- EOF / piped input exhausted

    local trimmed = input:match("^%s*(.-)%s*$")
    if trimmed == "" then goto continue end
    
    -- If search is active and user entered a command, abort search
    if search_ok and search_mod and search_mod.is_searching() then
      search_mod.abort(context)
    end

    -- Handle scroll commands before game processing
    if context.ui and context.ui.handle_scroll(trimmed) then
      goto continue
    end

    -- Echo command into the output window
    if context.ui and context.ui.is_enabled() then
      context.ui.output("> " .. trimmed)
    end

    -- Strip trailing question marks before parsing
    trimmed = trimmed:gsub("%?+$", ""):match("^%s*(.-)%s*$")
    if trimmed == "" then goto continue end

    -- BUG-105/106: Direct transform for common help/confusion phrases.
    -- Safety net: preprocess.natural_language() handles these patterns, but
    -- the live game reportedly hangs on them. This early bailout guarantees
    -- they never reach Tier 2 regardless of pipeline state or input encoding.
    do
      local lc = trimmed:lower()
      if lc == "what do i do" or lc == "what now"
          or lc == "now what" or lc == "what can i do"
          or lc == "what should i do" then
        trimmed = "help"
      end
    end

    -- Multi-command splitting: commas, semicolons, "then" (Issue #1)
    -- BUG-066: Added safety limits to prevent infinite loops or hangs
    local command_parts = preprocess.split_commands(trimmed)

    -- Global safety net: detect CPU-bound hangs in verb handlers.
    -- BUG-105/106/116/117/118: makes it architecturally impossible to hang.
    local _cmd_deadline = os.clock() + 2  -- 2-second timeout
    debug.sethook(function()
      if os.clock() > _cmd_deadline then
        debug.sethook()
        error("__COMMAND_TIMEOUT__")
      end
    end, "", 500000)

    -- Issue #168: Verb-aware "and" compound splitting.
    -- Uses preprocess.split_compound to only split "X and Y" when Y starts
    -- with a recognized verb. Prevents breaking "get candle and matchbox".
    local sub_commands = {}
    for _, part in ipairs(command_parts) do
      local compounds = preprocess.split_compound(part)
      for _, c in ipairs(compounds) do
        sub_commands[#sub_commands + 1] = c
      end
    end

    -- If compound command's last part has a GOAP plan, let GOAP handle everything.
    -- e.g. "get match from matchbox and light candle" → GOAP plans "light candle"
    -- end-to-end, making the first part redundant.
    if #sub_commands > 1 and goal_planner then
      local last = sub_commands[#sub_commands]
      local lv, ln = preprocess.natural_language(last)
      if not lv then lv, ln = preprocess.parse(last) end
      if lv == "light" or lv == "ignite" or lv == "burn" then
        local clean = ln:match("^(.-)%s+with%s+.+$")
        if clean and clean ~= "" then ln = clean end
      end
      -- BUG-084: Resolve pronouns in last sub-command from earlier fragments.
      -- "find a match and light it" → resolve "it" to "match" from first sub-cmd.
      if PRONOUNS[ln] then
        for i = #sub_commands - 1, 1, -1 do
          local pv, pn = preprocess.natural_language(sub_commands[i])
          if not pv then pv, pn = preprocess.parse(sub_commands[i]) end
          if pn and pn ~= "" then
            ln = pn
            break
          end
        end
      end
      local plan = goal_planner.plan(lv, ln, context)
      if plan and #plan > 0 then
        sub_commands = { last }
      end
    end

    -- Issue #16: Detect conditional clauses in compound commands.
    -- "if", "when", "unless" etc. signal clauses we can't handle yet.
    -- Trim everything from the conditional onward and give ONE helpful message.
    if #sub_commands > 1 then
      local conditional_idx = nil
      for ci = 1, #sub_commands do
        local lc = sub_commands[ci]:lower():match("^%s*(.-)%s*$")
        if lc:match("^if%s+") or lc:match("^when%s+") or lc:match("^unless%s+")
            or lc:match("^once%s+") or lc:match("^after%s+you%s+")
            or lc:match("^in%s+case%s+") then
          conditional_idx = ci
          break
        end
      end
      if conditional_idx then
        -- Keep everything before the conditional; drop the rest
        local kept = {}
        for ci = 1, conditional_idx - 1 do
          kept[#kept + 1] = sub_commands[ci]
        end
        if #kept == 0 then
          -- The very first part was conditional — nothing actionable
          print("I can only handle one action at a time. Try the first step on its own.")
          goto continue
        end
        sub_commands = kept
        -- Queue a single helpful message after the kept commands execute
        sub_commands[#sub_commands + 1] = "__conditional_trimmed__"
      end
    end

    local should_quit = false
    -- BUG-066: Safety limit to prevent hanging on pathological multi-command input
    if #sub_commands > 50 then
      print("Error: Too many commands at once (limit: 50). Try breaking them into smaller groups.")
      goto continue
    end
    
    for _, sub_input in ipairs(sub_commands) do
      -- Issue #16: sentinel from conditional trimming
      if sub_input == "__conditional_trimmed__" then
        print("I understood the first part, but I can only do one thing at a time. Try each step separately.")
        goto next_sub
      end

      -- BUG-084: Drain any active search before processing the next sub-command.
      -- "find a match and light it" — search must complete before "light" runs.
      if search_ok and search_mod and search_mod.is_searching() then
        local drain_limit = 0
        while search_mod.is_searching() and drain_limit < 150 do
          search_mod.tick(context)
          drain_limit = drain_limit + 1
        end
      end

      -- Try natural language preprocessing first (Smithers's parser pipeline)
      if _G.TRACE then io.stderr:write("[TRACE] parsing: " .. tostring(sub_input) .. "\n") end
      local verb, noun = preprocess.natural_language(sub_input)
      if _G.TRACE then io.stderr:write("[TRACE] natural_language => verb=" .. tostring(verb) .. " noun=" .. tostring(noun) .. "\n") end
      if not verb then
        verb, noun = preprocess.parse(sub_input)
        if _G.TRACE then io.stderr:write("[TRACE] parse fallback => verb=" .. tostring(verb) .. " noun=" .. tostring(noun) .. "\n") end
      end

      if verb == "" then goto next_sub end

      if verb == "quit" then
        should_quit = true
        break
      end

      -- BUG-060: Context noun resolution — resolve pronouns and empty nouns
      -- Verbs that operate on the room (no noun expected) are excluded.
      local no_noun_verbs = {
        look = true, feel = true, smell = true, listen = true, taste = true,
        inventory = true, i = true, help = true, time = true, quit = true,
        sleep = true, rest = true, nap = true, wait = true, score = true,
        report_bug = true, injuries = true, injury = true, wounds = true, health = true, appearance = true,
        -- Direction verbs should never inherit a context noun
        north = true, south = true, east = true, west = true,
        up = true, down = true, n = true, s = true, e = true, w = true,
        u = true, d = true, go = true, enter = true, walk = true, run = true,
        climb = true, ascend = true, descend = true,
        -- Tier 4: "back"/"return" handle their own noun semantics
        back = true, ["return"] = true,
        -- #288: goto/teleport should never inherit a context noun
        ["goto"] = true, teleport = true,
        -- Drop/put verbs inherit noun correctly from their own grammar
        drop = true,
        -- BUG-105b: Bare "examine" (no noun) should prompt the player, not
        -- silently fill in a stale context noun that may fail to resolve.
        examine = true, x = true, inspect = true,
      }
      if noun ~= "" and PRONOUNS[noun] and context.last_noun then
        -- Tier 4: discovery references resolve from context window
        if context_window and (noun == "thing i found" or noun == "the thing i found"
            or noun == "one i found" or noun == "the one i found"
            or noun == "what i found" or noun == "item i found"
            or noun == "thing i discovered" or noun == "one i discovered"
            or noun == "the one i discovered") then
          local disc = context_window.last_discovery()
          if disc then
            noun = disc.id
          else
            noun = context.last_noun
          end
        else
          noun = context.last_noun
        end
      elseif noun == "" and not no_noun_verbs[verb] then
        -- Tier 4: bare noun fallback — try last_noun, then context window
        if context.last_noun then
          noun = context.last_noun
        elseif context_window then
          local ctx_obj = context_window.peek()
          if ctx_obj then
            noun = ctx_obj.id
          end
        end
      end

      -- BUG-049, #169: extract "with Y" tool for verbs that use tools
      context.tool_noun = nil
      if verb == "open" or verb == "pry"
          or verb == "light" or verb == "ignite" or verb == "burn" then
        local obj_noun, tool = noun:match("^(.-)%s+with%s+(.+)$")
        if obj_noun and obj_noun ~= "" and tool and tool ~= "" then
          noun = obj_noun
          context.tool_noun = tool
        end
      end

      -- #108: extract "into Y" target for pour and stash on context
      context.pour_target = nil
      if verb == "pour" or verb == "spill" or verb == "dump" then
        local source, target = noun:match("^(.-)%s+into%s+(.+)$")
        if source and source ~= "" and target and target ~= "" then
          noun = source
          context.pour_target = target
        end
      end

      -- #112: extract "in Y" target for wash and stash on context
      context.wash_target = nil
      if verb == "wash" then
        local item, target = noun:match("^(.-)%s+in%s+(.+)$")
        if item and item ~= "" and target and target ~= "" then
          noun = item
          context.wash_target = target
        end
      end

      -- #109: extract "to Y" target for apply/treat and stash on context
      context.apply_target = nil
      if verb == "apply" or verb == "treat" then
        local source, target = noun:match("^(.-)%s+to%s+(.+)$")
        if source and source ~= "" and target and target ~= "" then
          noun = source
          context.apply_target = target
        end
      end

      -- Tier 3: goal-oriented prerequisite planning
      if goal_planner then
        if _G.TRACE then io.stderr:write("[TRACE] GOAP plan: verb=" .. verb .. " noun=" .. noun .. "\n") end
        local goap_ok, plan_or_err = pcall(goal_planner.plan, verb, noun, context)
        if not goap_ok then
          if type(plan_or_err) == "string" and plan_or_err:find("__COMMAND_TIMEOUT__") then
            print("That took longer than expected. Try a simpler command, or type 'help'.")
            _G.print = old_print or _G.print
            debug.sethook()
            goto next_sub
          end
        end
        local plan = goap_ok and plan_or_err or nil
        if _G.TRACE then io.stderr:write("[TRACE] GOAP result: " .. tostring(plan and #plan or "nil") .. " steps\n") end
        if plan then
          if not goal_planner.execute(plan, context) then
            goto next_sub
          end
        end
      end

      -- Capture print output for transcript recording (BUG-060 / report bug)
      local old_print = _G.print
      local response_lines = {}
      _G.print = function(...)
        local parts = {}
        for i = 1, select("#", ...) do
          parts[i] = tostring(select(i, ...))
        end
        local line = table.concat(parts, "\t")
        response_lines[#response_lines + 1] = line
        old_print(...)
      end

      local handler = context.verbs[verb]
      if handler then
        if _G.TRACE then io.stderr:write("[TRACE] dispatch handler: " .. verb .. "(" .. noun .. ")\n") end
        context.current_verb = verb
        local h_ok, h_err = pcall(handler, context, noun)
        if not h_ok then
          if type(h_err) == "string" and h_err:find("__COMMAND_TIMEOUT__") then
            print("That took longer than expected. Try a simpler command, or type 'help'.")
          elseif _G.TRACE then
            io.stderr:write("[TRACE] handler error: " .. tostring(h_err) .. "\n")
          end
          _G.print = old_print
          debug.sethook()
          goto next_sub
        end
        if _G.TRACE then io.stderr:write("[TRACE] handler complete: " .. verb .. "\n") end
        -- Sound: fire generic on_verb_{verb} event after successful dispatch
        -- Resolve noun → object so trigger() can check object-specific sounds
        -- before falling back to defaults (WAVE-2 Track 2B)
        if context.sound_manager then
            local sound_obj = nil
            if noun ~= "" and context.registry then
                local bare = noun:match("^%a+%s+(.+)$") or noun
                sound_obj = context.registry:find_by_keyword(bare)
            end
            context.sound_manager:trigger(sound_obj, "on_verb_" .. verb)
        end
        -- BUG-060: Update last_noun after successful handler with a real noun
        if noun ~= "" and not no_noun_verbs[verb] then
          -- Strip prepositions for context: "in wardrobe" → "wardrobe"
          local bare = noun:match("^%a+%s+(.+)$")
          context.last_noun = bare or noun
        end
      elseif context.parser then
        -- Tier 2 fallback: try embedding-based phrase matching
        if _G.TRACE then io.stderr:write("[TRACE] Tier 2 fallback entry: " .. sub_input .. "\n") end
        local parser_fallback = require("engine.parser")
        local t2_ok, t2_result = pcall(parser_fallback.fallback, context.parser, sub_input, context)
        if not t2_ok then
          if type(t2_result) == "string" and t2_result:find("__COMMAND_TIMEOUT__") then
            print("That took longer than expected. Try a simpler command, or type 'help'.")
          end
          _G.print = old_print
          debug.sethook()
          goto next_sub
        end
        local handled = t2_result
        if _G.TRACE then io.stderr:write("[TRACE] Tier 2 fallback result: " .. tostring(handled) .. "\n") end
        if not handled then
          -- Tier 2 failed — restore print and skip
          _G.print = old_print
          goto next_sub
        end
      else
        -- No Tier 2 available -- original behaviour
        local question_words = { what = true, where = true, how = true, who = true, why = true }
        if question_words[verb] then
          print("Try 'feel' to explore by touch, or 'look' if you have light. Type 'help' for a full list of commands.")
        else
          print("That's not something you can do here. Try 'look', 'examine', 'take', or type 'help' for a full list.")
        end
      end

      -- Restore print and record transcript entry
      _G.print = old_print
      if #response_lines > 0 then
        local entry = {
          input = sub_input,
          output = table.concat(response_lines, "\n"),
        }
        local transcript = context.transcript
        transcript[#transcript + 1] = entry
        -- Keep only last 100 exchanges
        while #transcript > 100 do
          table.remove(transcript, 1)
        end
      end

      ::next_sub::
    end

    -- Clear the command timeout hook
    debug.sethook()

    if should_quit then
      if context.on_quit then context.on_quit() end
      print("Goodbye.")
      if context.headless then io.write("---END---\n"); io.flush() end
      break
    end

    -- Post-command FSM tick phase: process auto-transitions (burn countdown, etc.)
    local fsm_ok, fsm_mod = pcall(require, "engine.fsm")
    if fsm_ok and fsm_mod and context.registry then
      local tick_targets = {}
      local reg = context.registry
      local room = context.current_room
      -- Room contents + their surface/container contents
      for _, obj_id in ipairs(room and room.contents or {}) do
        tick_targets[#tick_targets + 1] = obj_id
        local obj = reg:get(obj_id)
        if obj and obj.surfaces then
          for _, zone in pairs(obj.surfaces) do
            for _, item_id in ipairs(zone.contents or {}) do
              tick_targets[#tick_targets + 1] = item_id
            end
          end
        end
        if obj and obj.contents then
          for _, item_id in ipairs(obj.contents) do
            tick_targets[#tick_targets + 1] = item_id
          end
        end
      end
      -- Player hands (extract IDs from object instances)
      if context.player then
        for i = 1, 2 do
          local hand = context.player.hands[i]
          if hand then
            tick_targets[#tick_targets + 1] = type(hand) == "table" and hand.id or hand
          end
        end
      end
      -- Tick all FSM objects (legacy on_tick callbacks + threshold checks)
      -- Build environment context from room properties for threshold evaluation
      local env_context = {
          temperature = room and room.temperature or 20,
          wetness = room and room.wetness or 0,
          moisture = room and room.moisture or 0,
          light_level = room and room.light_level or 0,
      }
      for _, obj_id in ipairs(tick_targets) do
        local obj = reg:get(obj_id)
        if obj and obj._state then
          local msg = fsm_mod.tick(reg, obj_id, env_context)
          if msg then
            print(msg)
          end
        end
      end

      -- Timed events engine: each command tick = 360 game seconds
      -- (consistent with SLEEP: 10 ticks per game hour = 3600s / 10 = 360s)
      local SECONDS_PER_TICK = 360
      local timer_msgs = fsm_mod.tick_timers(reg, SECONDS_PER_TICK)
      for _, entry in ipairs(timer_msgs) do
        print(entry.message)
        -- Remove spent consumables from player's hands after auto-transition
        if context.player then
          local obj = reg:get(entry.obj_id)
          if obj and obj._state then
            local st = obj.states and obj.states[obj._state]
            if st and st.terminal and st.consumable then
              for i = 1, 2 do
                local hand = context.player.hands[i]
                local hand_id = hand and (type(hand) == "table" and hand.id or hand)
                if hand_id == entry.obj_id then
                  context.player.hands[i] = nil
                end
              end
              if context.current_room then
                context.current_room.contents[#context.current_room.contents + 1] = entry.obj_id
                obj.location = context.current_room.id
              end
            end
          end
        end
      end
    end

    -- Post-command tick (flame countdown, candle burn, etc.)
    if context.on_tick then
      context.on_tick(context)
    end

    -- Fire propagation tick (#121): spread fire from burning to nearby flammable objects
    local fp_ok, fire_propagation = pcall(require, "engine.fire_propagation")
    if fp_ok and fire_propagation then
      local fire_msgs = fire_propagation.tick(context)
      for _, msg in ipairs(fire_msgs) do
        print(msg)
      end
    end

    -- Creature tick: evaluate behavior for all animate objects
    -- C14: During combat_active, creature tick still runs but wander is suppressed
    -- (suppression handled inside creatures.score_actions via context.combat_active)
    local creature_ok, creature_mod = pcall(require, "engine.creatures")
    if creature_ok and creature_mod then
      local creature_msgs = creature_mod.tick(context)
      for _, msg in ipairs(creature_msgs or {}) do
        print(msg)
      end
    end

    -- Injury tick: advance injury FSMs, accumulate damage, check death
    -- Issue #29: Skip if game_over already set (e.g., sleep bleedout death)
    if not context.game_over
       and context.player and context.player.injuries and #context.player.injuries > 0 then
      local inj_ok, injury_mod = pcall(require, "engine.injuries")
      if inj_ok and injury_mod then
        local msgs, died = injury_mod.tick(context.player)
        for _, msg in ipairs(msgs) do
          print(msg)
        end
        if died then
          print("")
          print("Your injuries have overwhelmed you.")
          print("YOU HAVE DIED.")
          context.game_over = true
        end
      end
    end

    -- Game over check (death by poison, etc.)
    if context.game_over then
      print("Game over. Thanks for playing.")
      if context.headless then io.write("---END---\n"); io.flush() end
      break
    end

    -- Headless response delimiter: marks end of output for this command
    if context.headless then io.write("---END---\n"); io.flush() end

    ::continue::
  end
end

return loop

end

package.preload["engine.materials"] = function()
-- engine/materials/init.lua
-- Material registry: loads individual material definitions from src/meta/materials/.
-- Objects reference materials by name (e.g., material = "wax") or by GUID.
-- The engine resolves properties at runtime via materials.get(name) or
-- materials.get_by_guid(guid).
-- Adding new materials requires only a new .lua file in src/meta/materials/.

local materials = {}
materials.registry = {}
materials.guid_index = {}

-- Discover and load material files from src/meta/materials/
local SEP = package.config:sub(1, 1)
local is_windows = SEP == "\\"
local materials_dir = "." .. SEP .. "src" .. SEP .. "meta" .. SEP .. "materials"

local list_cmd
if is_windows then
    list_cmd = 'dir /b "' .. materials_dir .. SEP .. '*.lua" 2>nul'
else
    list_cmd = 'ls -1 "' .. materials_dir .. '"/*.lua 2>/dev/null'
end

local handle = io.popen(list_cmd)
if handle then
    for line in handle:lines() do
        local fname = line:match("([^/\\]+)$") or line
        if fname:match("%.lua$") then
            local path = materials_dir .. SEP .. fname
            local ok, mat = pcall(dofile, path)
            if ok and type(mat) == "table" and mat.name then
                local name = mat.name
                local guid = mat.guid
                mat.name = nil
                mat.guid = nil
                materials.registry[name] = mat
                if guid then
                    local bare = guid:gsub("[{}]", "")
                    materials.guid_index[bare] = name
                end
            end
        end
    end
    handle:close()
end

-- Look up a material's property table by name.
-- Returns the property table or nil if not found.
function materials.get(name)
    if not name then return nil end
    return materials.registry[name]
end

-- Look up a material's property table by GUID (braced or bare).
-- Returns the property table and name, or nil if not found.
function materials.get_by_guid(guid)
    if not guid then return nil, nil end
    local bare = guid:gsub("[{}]", "")
    local name = materials.guid_index[bare]
    if not name then return nil, nil end
    return materials.registry[name], name
end

-- Look up a specific property for a material.
-- Returns the property value or nil.
function materials.get_property(name, property)
    local mat = materials.registry[name]
    if not mat then return nil end
    return mat[property]
end

return materials
end

package.preload["engine.mutation"] = function()
-- engine/mutation/init.lua
-- The rewrite engine: replaces a live object definition with a new one.
-- This is the only place in the engine that performs a hot-swap.
-- Supports template-based objects and multi-surface containment preservation.

local mutation = {}

-- mutate(registry, loader, object_id, new_source, templates, ctx)
--   -> new_object, nil  |  nil, error_string
--
-- Loads new_source into a fresh table, carries over containment references
-- from the old object (location, container, surface contents), then replaces
-- the registry entry. If `templates` is provided and the new object has a
-- `template` field, resolves it before registration.
-- Optional `ctx` enables sound hooks (stop old, fire on_mutate, scan new).
function mutation.mutate(reg, ldr, object_id, new_source, templates, ctx)
  local old = reg:get(object_id)
  if not old then
    return nil, "mutation: object '" .. tostring(object_id) .. "' not found in registry"
  end

  local new_obj, err = ldr.load_source(new_source)
  if not new_obj then
    return nil, err
  end

  -- Resolve template if present
  if new_obj.template and templates then
    new_obj, err = ldr.resolve_template(new_obj, templates)
    if not new_obj then
      return nil, err
    end
  end

  -- Preserve containment references so the object stays in the world.
  new_obj.location  = old.location
  new_obj.container = old.container

  -- Preserve surface contents across mutations.
  -- If both old and new objects have surfaces, carry contents from matching zones.
  if old.surfaces and new_obj.surfaces then
    for surface_name, old_zone in pairs(old.surfaces) do
      if new_obj.surfaces[surface_name] and old_zone.contents then
        new_obj.surfaces[surface_name].contents = old_zone.contents
      end
    end
  end

  -- If old had root contents and new has root contents, preserve them.
  if old.contents and #old.contents > 0 and not new_obj.surfaces then
    new_obj.contents = old.contents
  end

  -- Sound: stop old object sounds, fire on_mutate, scan replacement
  if ctx and ctx.sound_manager then
      ctx.sound_manager:stop_by_owner(object_id)
      ctx.sound_manager:trigger(old, "on_mutate")
  end

  reg:register(object_id, new_obj)

  -- Sound: scan the mutated replacement for new sound declarations
  if ctx and ctx.sound_manager then
      ctx.sound_manager:scan_object(new_obj)
  end

  return new_obj, nil
end

return mutation

end

