package.preload["engine.parser.context"] = function()
-- engine/parser/context.lua
-- Context Window (Tier 4): Tracks recent interactions so the game remembers
-- what the player just did. Maintains a stack of recently referenced objects,
-- search discoveries, and previous room for "go back" support.
--
-- Ownership: Smithers (UI Engineer) — parser pipeline component.
-- Architecture: Module-level state (same pattern as engine/search/init.lua).
--
-- Integration points:
--   verbs/init.lua   — push() on find_visible, set_previous_room on movement
--   search/init.lua  — push_discovery() when search finds an item
--   loop/init.lua    — resolve() for pronoun and bare-noun fallback

local context_window = {}

---------------------------------------------------------------------------
-- Internal state (volatile, not persisted)
---------------------------------------------------------------------------
local _stack = {}               -- Recent interacted objects (most recent first)
local _max_stack = 5
local _previous_room_id = nil   -- Room ID before last room transition
local _discoveries = {}         -- Objects found via search (most recent first)
local _max_discoveries = 5
local _last_command = nil       -- { verb, noun, raw } for "again" support
local _last_direction = nil     -- Last movement direction for "continue" support

---------------------------------------------------------------------------
-- Context stack operations
---------------------------------------------------------------------------

--- Push an object to the context stack (most recent interaction).
--- Deduplicates: if the object is already in the stack, moves it to top.
function context_window.push(obj)
    if not obj or not obj.id then return end
    -- Already at top — skip
    if _stack[1] and _stack[1].id == obj.id then return end
    -- Remove duplicate if present (move to top)
    for i = #_stack, 1, -1 do
        if _stack[i].id == obj.id then
            table.remove(_stack, i)
            break
        end
    end
    table.insert(_stack, 1, obj)
    while #_stack > _max_stack do table.remove(_stack) end
end

--- Push a search discovery to both the discovery list and context stack.
--- Called by search/init.lua when an item is found during search.
function context_window.push_discovery(obj)
    if not obj or not obj.id then return end
    -- Deduplicate in discovery list
    for i = #_discoveries, 1, -1 do
        if _discoveries[i].id == obj.id then
            table.remove(_discoveries, i)
            break
        end
    end
    table.insert(_discoveries, 1, obj)
    while #_discoveries > _max_discoveries do table.remove(_discoveries) end
    -- Also push to main context stack
    context_window.push(obj)
end

--- Get the most recent context object (top of stack).
function context_window.peek()
    return _stack[1]
end

--- Get the most recent search discovery.
function context_window.last_discovery()
    return _discoveries[1]
end

--- Get the full context stack (for debugging/testing).
function context_window.get_stack()
    return _stack
end

--- Get the discovery list (for debugging/testing).
function context_window.get_discoveries()
    return _discoveries
end

---------------------------------------------------------------------------
-- Room history for "go back"
---------------------------------------------------------------------------

--- Record the current room before a room transition.
function context_window.set_previous_room(room_id)
    _previous_room_id = room_id
end

--- Get the previous room ID (for "go back").
function context_window.get_previous_room()
    return _previous_room_id
end

---------------------------------------------------------------------------
-- Resolution: resolve noun references from context
---------------------------------------------------------------------------

--- Resolve a noun reference using the context window.
--- Handles pronouns ("it", "that", "this"), discovery references
--- ("the thing I found"), and returns the resolved object or nil.
function context_window.resolve(noun)
    if not noun then return nil end
    local kw = noun:lower()
        :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")

    -- Direct pronouns → most recent context object
    if kw == "it" or kw == "that" or kw == "this" or kw == "one" then
        return _stack[1]
    end

    -- Tier 4: "the other one" → second most recent context object
    if kw == "other one" or kw == "other" then
        if #_stack >= 2 then return _stack[2] end
        return nil
    end

    -- BUG-114: "thing I found" / "one I found" / "what I found" etc. → last discovery
    if kw:match("thing%s+i%s+found")
        or kw:match("one%s+i%s+found")
        or kw:match("what%s+i%s+found")
        or kw:match("thing%s+i%s+discovered")
        or kw:match("one%s+i%s+discovered")
        or kw:match("item%s+i%s+found")
        or kw:match("thing%s+i%s+just%s+found")
        or kw:match("one%s+i%s+just%s+found") then
        return _discoveries[1]
    end

    return nil
end

---------------------------------------------------------------------------
-- Tier 4: Command repeat ("again" / "do it again")
---------------------------------------------------------------------------

--- Record the last executed command (called after successful dispatch).
function context_window.set_last_command(verb, noun, raw)
    _last_command = { verb = verb, noun = noun, raw = raw }
end

--- Resolve repeat phrases. Returns last command table or nil.
function context_window.resolve_repeat(text)
    if not text then return nil end
    local kw = text:lower():gsub("^%s+", ""):gsub("%s+$", "")
    if kw == "again" or kw == "do it again" or kw == "repeat"
        or kw == "do that again" or kw == "same thing"
        or kw == "one more time" then
        return _last_command
    end
    return nil
end

---------------------------------------------------------------------------
-- Tier 4: Direction history
---------------------------------------------------------------------------

--- Record the last movement direction.
function context_window.set_last_direction(dir)
    _last_direction = dir
end

--- Get the last movement direction.
function context_window.get_last_direction()
    return _last_direction
end

---------------------------------------------------------------------------
-- Tier 4: Recency scoring (for Tier 5 fuzzy integration)
---------------------------------------------------------------------------

--- Score an object by recency in the context stack.
--- Returns 0 for unknown objects, higher for more recent.
function context_window.recency_score(obj_id)
    if not obj_id then return 0 end
    for i, obj in ipairs(_stack) do
        if obj.id == obj_id then
            return _max_stack - i + 1
        end
    end
    return 0
end

---------------------------------------------------------------------------
-- Reset (for testing)
---------------------------------------------------------------------------

function context_window.reset()
    _stack = {}
    _discoveries = {}
    _previous_room_id = nil
    _last_command = nil
    _last_direction = nil
end

return context_window

end

package.preload["engine.parser.embedding_matcher"] = function()
-- engine/parser/embedding_matcher.lua
-- Tier 2 parser: loads the embedding index JSON as a phrase dictionary
-- and matches player input via BM25 scoring with Jaccard fallback.
--
-- The embedding vectors are not used at runtime — matching is purely
-- text-based using BM25 (IDF-weighted), synonym expansion, and
-- typo correction. Gracefully degrades if optional modules are missing.

local json = require("engine.parser.json")

-- BM25 data (IDF table, avg doc length) — generated by build scripts
local bm25_ok, bm25_data = pcall(require, "engine.parser.bm25_data")
if not bm25_ok then bm25_data = nil end

-- Synonym table for input expansion
local syn_ok, synonym_table = pcall(require, "engine.parser.synonym_table")
if not syn_ok then synonym_table = nil end

-- Word similarity matrix for MaxSim re-ranking (D3: MaxSim first)
local sim_ok, word_similarity = pcall(require, "engine.parser.word_similarity")
if not sim_ok then word_similarity = nil end

-- Context window for recency boost in phase3 mode
local ctx_ok, context = pcall(require, "engine.parser.context")
if not ctx_ok then context = nil end

local matcher = {}
matcher.__index = matcher

-- Stop words stripped from both input and phrase text before comparison.
-- Includes common English filler that carries no game meaning.
local STOP_WORDS = {
  -- Determiners & pronouns
  ["the"] = true, ["a"] = true, ["an"] = true, ["some"] = true,
  ["my"] = true, ["its"] = true, ["this"] = true, ["that"] = true,
  ["it"] = true, ["i"] = true, ["me"] = true, ["you"] = true,
  ["we"] = true, ["they"] = true, ["them"] = true,
  -- Prepositions & conjunctions
  ["to"] = true, ["at"] = true, ["on"] = true, ["in"] = true,
  ["of"] = true, ["and"] = true, ["or"] = true, ["with"] = true,
  ["for"] = true, ["up"] = true, ["down"] = true, ["around"] = true,
  ["if"] = true, ["so"] = true, ["but"] = true, ["from"] = true,
  -- Modals & auxiliaries
  ["is"] = true, ["be"] = true, ["do"] = true, ["can"] = true,
  ["would"] = true, ["could"] = true, ["should"] = true,
  ["shall"] = true, ["might"] = true, ["will"] = true,
  -- Common filler verbs (not game verbs)
  ["please"] = true, ["want"] = true, ["need"] = true,
  ["try"] = true, ["let"] = true, ["go"] = true, ["like"] = true,
  -- Adverbs & adjectives (filler)
  ["now"] = true, ["just"] = true, ["here"] = true, ["right"] = true,
  ["really"] = true, ["very"] = true, ["quite"] = true,
  ["quickly"] = true, ["carefully"] = true, ["closely"] = true,
  ["gently"] = true, ["ahead"] = true, ["slowly"] = true,
  ["sitting"] = true, ["lying"] = true, ["standing"] = true,
  -- Other filler
  ["hey"] = true, ["maybe"] = true, ["perhaps"] = true,
  ["possible"] = true, ["great"] = true, ["kind"] = true,
  ["thing"] = true, ["think"] = true, ["see"] = true,
  ["hoping"] = true, ["yes"] = true, ["no"] = true, ["not"] = true,
  ["something"] = true, ["anything"] = true, ["everything"] = true,
}

---------------------------------------------------------------------------
-- Levenshtein edit distance for typo correction
---------------------------------------------------------------------------
local function levenshtein(a, b)
  local la, lb = #a, #b
  if la == 0 then return lb end
  if lb == 0 then return la end
  local matrix = {}
  for i = 0, la do
    matrix[i] = { [0] = i }
  end
  for j = 0, lb do
    matrix[0][j] = j
  end
  for i = 1, la do
    for j = 1, lb do
      local cost = (a:sub(i, i) == b:sub(j, j)) and 0 or 1
      matrix[i][j] = math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      )
    end
  end
  return matrix[la][lb]
end

---------------------------------------------------------------------------
-- Typo correction: fix misspelled verbs using known verb set.
-- Skip tokens that exist in the BM25 IDF vocabulary — they are
-- known game-world words (nouns, adjectives) and must not be "corrected"
-- to verbs. E.g. "small" (IDF-known adjective) must not become "smell".
---------------------------------------------------------------------------
local function correct_typos(tokens, known_verbs)
  if not known_verbs or not next(known_verbs) then return tokens end
  local idf_table = bm25_data and bm25_data.idf or nil
  local corrected = {}
  for _, token in ipairs(tokens) do
    if known_verbs[token] then
      corrected[#corrected + 1] = token
    elseif idf_table and idf_table[token] then
      -- Token is a known game-world word — don't "correct" it to a verb
      corrected[#corrected + 1] = token
    else
      -- 4-char words: max dist 1 (conservative — kick≠lick but brek→break).
      -- 5-char words: max dist 1. 6+ chars: max dist 2.
      if #token <= 3 then
        corrected[#corrected + 1] = token
      else
        local max_dist = #token <= 5 and 1 or 2
        local best_verb, best_dist = nil, max_dist + 1
        for verb in pairs(known_verbs) do
          if math.abs(#token - #verb) <= 2 then
            local dist = levenshtein(token, verb)
            if dist < best_dist then
              best_dist = dist
              best_verb = verb
            end
          end
        end
        if best_verb then
          corrected[#corrected + 1] = best_verb
        else
          corrected[#corrected + 1] = token
        end
      end
    end
  end
  return corrected
end

---------------------------------------------------------------------------
-- Tokenizer: lowercase, strip punctuation, remove stop words
---------------------------------------------------------------------------
local function tokenize(text)
  local tokens = {}
  local seen = {}
  for word in text:lower():gsub("[^%a%d%-]", " "):gmatch("%S+") do
    if not STOP_WORDS[word] and not seen[word] then
      tokens[#tokens + 1] = word
      seen[word] = true
    end
  end
  return tokens
end

local function token_set(tokens)
  local s = {}
  for _, t in ipairs(tokens) do s[t] = true end
  return s
end

---------------------------------------------------------------------------
-- Similarity: Jaccard index (|A ∩ B| / |A ∪ B|) with substring bonus
---------------------------------------------------------------------------
local function jaccard_with_bonus(input_tokens, phrase_tokens)
  local set_a = token_set(input_tokens)
  local set_b = token_set(phrase_tokens)

  local intersection = 0
  local union_set = {}

  for t in pairs(set_a) do union_set[t] = true end
  for t in pairs(set_b) do union_set[t] = true end

  for t in pairs(set_a) do
    if set_b[t] then
      intersection = intersection + 1
    end
  end

  -- Substring/prefix bonus for near-matches
  local partial = 0
  for _, a in ipairs(input_tokens) do
    if not set_b[a] then
      for _, b in ipairs(phrase_tokens) do
        if not set_a[b] then
          if a:sub(1, 3) == b:sub(1, 3) and #a >= 3 and #b >= 3 then
            local overlap = 0
            for i = 1, math.min(#a, #b) do
              if a:sub(i, i) == b:sub(i, i) then overlap = overlap + 1
              else break end
            end
            partial = partial + (overlap / math.max(#a, #b)) * 0.5
          end
        end
      end
    end
  end

  local union_size = 0
  for _ in pairs(union_set) do union_size = union_size + 1 end

  if union_size == 0 then return 0 end
  return (intersection + partial) / union_size
end

---------------------------------------------------------------------------
-- BM25 scoring: IDF-weighted term frequency with length normalization
-- k1=1.2 (TF saturation), b=0.5 (moderate length norm for short docs)
---------------------------------------------------------------------------
local BM25_K1 = 1.2
local BM25_B  = 0.5

local function bm25_score(input_tokens, phrase_tokens)
  if not bm25_data or not bm25_data.idf then return 0 end

  local avgdl = bm25_data.avg_doc_length
  local doc_len = #phrase_tokens
  local idf_table = bm25_data.idf

  local phrase_set = {}
  for _, t in ipairs(phrase_tokens) do phrase_set[t] = true end

  local score = 0
  for _, qt in ipairs(input_tokens) do
    if phrase_set[qt] then
      local idf = idf_table[qt] or 0
      local tf = 1
      local tf_component = (tf * (BM25_K1 + 1)) /
        (tf + BM25_K1 * (1 - BM25_B + BM25_B * doc_len / avgdl))
      score = score + idf * tf_component
    end
  end

  return score
end

---------------------------------------------------------------------------
-- MaxSim scoring: for each input token, find best-matching candidate
-- token via the word similarity matrix, sum the max similarities.
-- D3: MaxSim first — simpler, debuggable, noise-robust at 2-4 token scale.
---------------------------------------------------------------------------
local function maxsim_score(input_tokens, phrase_tokens, sim_matrix)
  if not sim_matrix then return 0 end
  local score = 0
  for _, qt in ipairs(input_tokens) do
    local best = 0
    for _, pt in ipairs(phrase_tokens) do
      if qt == pt then
        best = 1.0
        break
      end
      local row = sim_matrix[qt]
      if row and row[pt] and row[pt] > best then
        best = row[pt]
      end
    end
    score = score + best
  end
  return score
end

---------------------------------------------------------------------------
-- Two-stage hybrid scoring constants (D1: 70/30 BM25-heavy)
---------------------------------------------------------------------------
local HYBRID_BM25_WEIGHT   = 0.70
local HYBRID_MAXSIM_WEIGHT = 0.30
local HYBRID_THRESHOLD     = 0.20   -- reserved minimum for hybrid match
local BM25_TOP_N           = 50     -- stage-1 retrieval pool size

---------------------------------------------------------------------------
-- Tiebreaker: prefer base-state (non-suffixed) noun variant.
-- "examine match" should match "examine a wooden match" not "examine a lit match".
---------------------------------------------------------------------------
local STATE_SUFFIXES = {"%-lit$", "%-open$", "%-broken$", "%-closed$"}

local function has_state_suffix(noun)
  if not noun or not noun:find("-", 1, true) then return false end
  for _, pat in ipairs(STATE_SUFFIXES) do
    if noun:match(pat) then return true end
  end
  return false
end

local function prefer_base_state(cur_phrase, new_phrase)
  if not cur_phrase or not new_phrase then return false end
  return has_state_suffix(cur_phrase.noun) and not has_state_suffix(new_phrase.noun)
end

---------------------------------------------------------------------------
-- P1 helpers: Noun validation gate — prevent verb-only false positives
---------------------------------------------------------------------------
local function token_matches(a, b)
  if a == b then return true end
  if b:find("-", 1, true) then
    for part in b:gmatch("[^%-]+") do
      if a == part then return true end
    end
  end
  if a:find("-", 1, true) then
    for part in a:gmatch("[^%-]+") do
      if part == b then return true end
    end
  end
  local len = #a
  if len <= 3 then return false end
  local threshold = len <= 5 and 1 or 2
  return levenshtein(a, b) <= threshold
end

local function noun_overlap(input_noun_tokens, phrase_tokens)
  for _, inp in ipairs(input_noun_tokens) do
    for _, pt in ipairs(phrase_tokens) do
      if token_matches(inp, pt) then
        return true
      end
    end
  end
  return false
end

---------------------------------------------------------------------------
-- P4 helper: Noun exactness tiebreaker — prefer exact noun match
---------------------------------------------------------------------------
local function noun_exactness(input_noun_tokens, phrase_noun)
  if not phrase_noun or phrase_noun == "" then return 0 end
  local pn = phrase_noun:lower()
  for _, t in ipairs(input_noun_tokens) do
    if t == pn then return 2 end
  end
  return 0
end

---------------------------------------------------------------------------
-- P5: Adjective-only guard — reject inputs with only generic adjectives.
-- Material/descriptive adjectives (heavy, dirty, wooden) are kept because
-- they can narrow down to a specific game object.
---------------------------------------------------------------------------
local KNOWN_ADJECTIVES = {
  small=true, big=true, large=true, little=true, tiny=true, huge=true,
  old=true, new=true, long=true, short=true, round=true, flat=true,
  red=true, blue=true, green=true, white=true, black=true, yellow=true,
  brown=true, gray=true, grey=true,
}

local function all_adjectives(tokens)
  for _, t in ipairs(tokens) do
    if not KNOWN_ADJECTIVES[t] then return false end
  end
  return true
end

---------------------------------------------------------------------------
-- Constructor
---------------------------------------------------------------------------
function matcher.new(index_path, debug)
  local self = setmetatable({}, matcher)
  self.phrases = {}
  self.loaded = false
  self.diagnostic = debug or false

  local f = io.open(index_path, "r")
  if not f then
    io.stderr:write("[Parser] Warning: embedding index not found: " .. index_path .. "\n")
    return self
  end

  local content = f:read("*a")
  f:close()

  local ok, index = pcall(json.decode, content)
  if not ok then
    io.stderr:write("[Parser] Warning: failed to parse embedding index: " .. tostring(index) .. "\n")
    return self
  end

  -- Build phrase dictionary (vectors are not used — slim index only)
  for i, entry in ipairs(index.phrases or {}) do
    local noun_toks = entry.noun and tokenize(entry.noun) or {}
    self.phrases[#self.phrases + 1] = {
      id = i,
      text = entry.text,
      verb = entry.verb,
      noun = entry.noun,
      tokens = tokenize(entry.text),
      noun_tokens = noun_toks,
    }
  end

  -- Build known-verbs set from the index for typo correction
  self.known_verbs = {}
  for _, entry in ipairs(self.phrases) do
    if entry.verb then
      self.known_verbs[entry.verb] = true
    end
  end

  -- Build verb_tokens set for the noun validation gate (P1)
  self.verb_tokens = {}
  for v in pairs(self.known_verbs) do self.verb_tokens[v] = true end
  for _, phrase in ipairs(self.phrases) do
    if phrase.text then
      local first_word = phrase.text:lower():match("^([%a%-]+)")
      if first_word and not STOP_WORDS[first_word] then
        self.verb_tokens[first_word] = true
      end
    end
  end
  if synonym_table and synonym_table.verbs then
    for syn in pairs(synonym_table.verbs) do
      self.verb_tokens[syn] = true
    end
  end

  -- Build known noun tokens set (for P2 truncation priority)
  self.known_noun_tokens = {}
  for _, phrase in ipairs(self.phrases) do
    for _, nt in ipairs(phrase.noun_tokens) do
      self.known_noun_tokens[nt] = true
      if nt:find("-", 1, true) then
        for part in nt:gmatch("[^%-]+") do
          self.known_noun_tokens[part] = true
        end
      end
    end
  end

  -- Build inverted index: token → list of phrase references
  -- Enables fast candidate retrieval for BM25 scoring
  self.inverted_index = {}
  for _, phrase in ipairs(self.phrases) do
    for _, token in ipairs(phrase.tokens) do
      if not self.inverted_index[token] then
        self.inverted_index[token] = {}
      end
      local list = self.inverted_index[token]
      list[#list + 1] = phrase
    end
  end

  self.loaded = true
  if self.diagnostic then
    io.stderr:write("[Parser] Tier 2 loaded: " .. #self.phrases .. " phrases from index\n")
    local idx_count = 0
    for _ in pairs(self.inverted_index) do idx_count = idx_count + 1 end
    io.stderr:write("[Parser] Inverted index: " .. idx_count .. " unique tokens\n")
  end
  return self
end

---------------------------------------------------------------------------
-- Inverted index candidate retrieval — only score phrases sharing tokens
---------------------------------------------------------------------------
local function get_candidates(inverted_index, input_tokens)
  local seen = {}
  local candidates = {}
  for _, qt in ipairs(input_tokens) do
    local postings = inverted_index[qt]
    if postings then
      for _, phrase in ipairs(postings) do
        if not seen[phrase.id] then
          seen[phrase.id] = true
          candidates[#candidates + 1] = phrase
        end
      end
    end
  end
  return candidates
end

---------------------------------------------------------------------------
-- match(input_text) -> verb, noun, score, matched_phrase
-- Uses BM25 scoring when IDF data is available, Jaccard as fallback.
-- Synonym expansion maps casual verbs to canonical forms before scoring.
---------------------------------------------------------------------------
function matcher:match(input_text)
  if not self.loaded or #self.phrases == 0 then
    return nil, nil, 0, nil
  end

  -- P3: Question transform — "what is X" → "examine X" before tokenization
  local lower = input_text:lower()
  if lower:match("^what%s+is%s+") or lower:match("^what'?s%s+") then
    local noun = lower:match("^what%s+is%s+the%s+(.+)$")
        or lower:match("^what'?s%s+the%s+(.+)$")
        or lower:match("^what%s+is%s+an?%s+(.+)$")
        or lower:match("^what%s+is%s+(.+)$")
        or lower:match("^what'?s%s+(.+)$")
    if noun then
      input_text = "examine " .. noun
    end
  end

  local input_tokens = tokenize(input_text)
  if #input_tokens == 0 then
    return nil, nil, 0, nil
  end

  -- Synonym expansion: map unknown verbs to canonical forms
  if synonym_table then
    input_tokens = synonym_table.expand_tokens(input_tokens)
  end

  -- Apply typo correction against known verbs on remaining tokens
  input_tokens = correct_typos(input_tokens, self.known_verbs)

  -- P2: Verbose input truncation — keep only the most relevant tokens.
  -- Known game nouns get priority; remaining slots sorted by IDF.
  local MAX_INPUT_TOKENS = 5
  if #input_tokens > MAX_INPUT_TOKENS then
    local scored = {}
    for _, t in ipairs(input_tokens) do
      local idf = (bm25_data and bm25_data.idf and bm25_data.idf[t]) or 0
      local noun_priority = self.known_noun_tokens[t] and 1 or 0
      scored[#scored + 1] = { token = t, idf = idf, noun_priority = noun_priority }
    end
    table.sort(scored, function(a, b)
      if a.noun_priority ~= b.noun_priority then
        return a.noun_priority > b.noun_priority
      end
      return a.idf > b.idf
    end)
    local kept = {}
    for i = 1, MAX_INPUT_TOKENS do
      if scored[i] then kept[#kept + 1] = scored[i].token end
    end
    input_tokens = kept
  end

  -- Classify input tokens into verb-like and noun-like
  local input_noun_tokens = {}
  for _, t in ipairs(input_tokens) do
    if not self.verb_tokens[t] then
      input_noun_tokens[#input_noun_tokens + 1] = t
    end
  end
  local has_input_nouns = #input_noun_tokens > 0

  -- P5: Adjective-only guard — if all noun tokens are generic adjectives, reject
  if has_input_nouns and all_adjectives(input_noun_tokens) then
    return nil, nil, 0, nil
  end

  -- P6: Unknown lead-word guard — if the first content token is completely
  -- foreign to the game world (not in any phrase, not a recognized verb or
  -- noun), it's likely an unsupported verb like "fly" or "swim". Reject to
  -- prevent noun-only false positives (e.g. "fly north" → "look north").
  if #input_tokens >= 2 then
    local first = input_tokens[1]
    if not self.verb_tokens[first]
       and not self.known_noun_tokens[first]
       and not (self.inverted_index and self.inverted_index[first]) then
      return nil, nil, 0, nil
    end
  end

  local use_bm25 = (bm25_data ~= nil)
  local use_maxsim = (word_similarity ~= nil)

  -- Candidate retrieval: inverted index when BM25 is available
  local phrase_pool
  if use_bm25 and self.inverted_index then
    phrase_pool = get_candidates(self.inverted_index, input_tokens)
  else
    phrase_pool = self.phrases
  end

  ---------------------------------------------------------------------------
  -- Stage 1: BM25 scoring with noun validation gates
  ---------------------------------------------------------------------------
  local use_context = (self.scoring_mode == "phase3") and context and context.recency_score
  local CONTEXT_BOOST_WEIGHT = 0.1

  local scored_candidates = {}

  for _, phrase in ipairs(phrase_pool) do
    -- P1: Noun validation gate — skip candidates where no input noun
    -- token matches any phrase token (prevents verb-only false positives)
    if has_input_nouns and phrase.noun and phrase.noun ~= "" then
      if not noun_overlap(input_noun_tokens, phrase.tokens) then
        goto continue
      end
    end

    local score
    if use_bm25 then
      score = bm25_score(input_tokens, phrase.tokens)
    else
      score = jaccard_with_bonus(input_tokens, phrase.tokens)
    end

    -- Noun match bonus: boost when input directly names the phrase noun
    if has_input_nouns and phrase.noun and phrase.noun ~= "" then
      local pn = phrase.noun:lower()
      for _, t in ipairs(input_noun_tokens) do
        if t == pn then
          score = score + 0.5
          break
        end
      end
    end

    -- Phase 3: apply context recency boost to BM25 scores
    if use_context and phrase.noun then
      local recency = context.recency_score(phrase.noun)
      if recency > 0 then
        score = score + recency * CONTEXT_BOOST_WEIGHT
      end
    end

    scored_candidates[#scored_candidates + 1] = { phrase = phrase, bm25 = score }
    ::continue::
  end

  if #scored_candidates == 0 then
    return nil, nil, 0, nil
  end

  ---------------------------------------------------------------------------
  -- Stage 2: MaxSim re-ranking on top-N candidates (D1 two-stage pipeline)
  ---------------------------------------------------------------------------
  if use_bm25 and use_maxsim and #scored_candidates > 1 then
    -- Sort by BM25 descending, keep top-N for re-ranking (stable sort)
    table.sort(scored_candidates, function(a, b)
      if a.bm25 ~= b.bm25 then return a.bm25 > b.bm25 end
      return a.phrase.id < b.phrase.id
    end)
    local rerank_pool = math.min(#scored_candidates, BM25_TOP_N)

    -- Find BM25 max for normalization (already sorted, index 1 is max)
    local bm25_max = scored_candidates[1].bm25
    if bm25_max <= 0 then bm25_max = 1 end

    -- Compute MaxSim scores and find max for normalization
    local maxsim_max = 0
    for i = 1, rerank_pool do
      local ms = maxsim_score(input_tokens, scored_candidates[i].phrase.tokens, word_similarity)
      scored_candidates[i].maxsim = ms
      if ms > maxsim_max then maxsim_max = ms end
    end
    if maxsim_max <= 0 then maxsim_max = 1 end

    -- Compute hybrid score: 70% BM25 + 30% MaxSim (both normalized to 0-1)
    for i = 1, rerank_pool do
      local c = scored_candidates[i]
      local bm25_norm = c.bm25 / bm25_max
      local maxsim_norm = c.maxsim / maxsim_max
      c.hybrid = HYBRID_BM25_WEIGHT * bm25_norm + HYBRID_MAXSIM_WEIGHT * maxsim_norm
    end

    -- Re-sort top-N by hybrid score (stable: use phrase id as tiebreaker)
    local top_pool = {}
    for i = 1, rerank_pool do top_pool[i] = scored_candidates[i] end
    table.sort(top_pool, function(a, b)
      if a.hybrid ~= b.hybrid then return a.hybrid > b.hybrid end
      return a.phrase.id < b.phrase.id
    end)

    -- Replace scored_candidates with re-ranked pool
    scored_candidates = top_pool
  end

  ---------------------------------------------------------------------------
  -- Final selection with P4 exactness tiebreaker
  -- Ranking uses hybrid score; returned score is raw BM25 for compatibility
  ---------------------------------------------------------------------------
  local best_rank = -1
  local best_score = -1
  local best_phrase = nil
  local best_exactness = 0

  for _, c in ipairs(scored_candidates) do
    local rank = c.hybrid or c.bm25
    local phrase = c.phrase

    if rank > best_rank then
      best_rank = rank
      best_score = c.bm25
      best_phrase = phrase
      best_exactness = noun_exactness(input_noun_tokens, phrase.noun)
    elseif rank == best_rank then
      -- P4: Prefer exact noun match over substring match
      local ex = noun_exactness(input_noun_tokens, phrase.noun)
      if ex > best_exactness then
        best_score = c.bm25
        best_phrase = phrase
        best_exactness = ex
      elseif ex == best_exactness and prefer_base_state(best_phrase, phrase) then
        best_score = c.bm25
        best_phrase = phrase
      end
    end
  end

  if best_phrase then
    return best_phrase.verb, best_phrase.noun, best_score, best_phrase.text
  end

  return nil, nil, 0, nil
end

return matcher

end

package.preload["engine.parser.fuzzy"] = function()
-- engine/parser/fuzzy.lua
-- Tier 5: Fuzzy Noun Resolution
-- Owned by Smithers (UI Engineer). Pure functions, no side effects.
--
-- Provides fallback noun matching when exact keyword matching fails:
--   1. Material matching: "the wooden thing" → objects with material="wood"
--   2. Property matching: "the heavy one" → match by weight/size
--   3. Partial name match: "that bottle" → "small glass bottle" (unambiguous)
--   4. Typo tolerance: "nighstand" → "nightstand" via Levenshtein distance
--   5. Disambiguation prompt: multiple matches → ask the player
--
-- Only fires when exact matching fails (don't slow down the happy path).

local fuzzy = {}

---------------------------------------------------------------------------
-- Levenshtein edit distance
-- Reuses the algorithm from embedding_matcher.lua for consistency.
---------------------------------------------------------------------------
function fuzzy.levenshtein(a, b)
    local la, lb = #a, #b
    if la == 0 then return lb end
    if lb == 0 then return la end
    local prev = {}
    local curr = {}
    for j = 0, lb do prev[j] = j end
    for i = 1, la do
        curr[0] = i
        for j = 1, lb do
            local cost = (a:sub(i, i) == b:sub(j, j)) and 0 or 1
            curr[j] = math.min(
                prev[j] + 1,
                curr[j - 1] + 1,
                prev[j - 1] + cost
            )
        end
        prev, curr = curr, prev
    end
    return prev[lb]
end

---------------------------------------------------------------------------
-- Typo tolerance thresholds (per D-BUG018: no fuzzy on short words)
-- ≤3 chars: exact only. 4 chars: distance ≤1. 5-7: distance ≤2. 8+: distance ≤2.
-- Tier 5 enhancement: allow single typo for 4-char words (e.g., "dor" → "door")
---------------------------------------------------------------------------
function fuzzy.max_typo_distance(word_len)
    if word_len <= 3 then return 0 end
    if word_len == 4 then return 1 end
    if word_len <= 7 then return 2 end
    return 2
end

---------------------------------------------------------------------------
-- Material adjective → material value mapping
---------------------------------------------------------------------------
local MATERIAL_ADJECTIVES = {
    wooden = "wood", wood = "wood",
    metal = "metal", metallic = "metal",
    brass = "brass", bronze = "bronze",
    iron = "iron", steel = "steel",
    glass = "glass", crystal = "crystal",
    stone = "stone", rocky = "stone",
    cloth = "cloth", fabric = "cloth",
    leather = "leather",
    paper = "paper", parchment = "parchment",
    wax = "wax", waxen = "wax",
    ceramic = "ceramic", clay = "ceramic",
    silver = "silver", gold = "gold",
    copper = "copper", tin = "tin",
    bone = "bone",
    rubber = "rubber",
    silk = "silk",
    wool = "wool", woolen = "wool",
    cotton = "cotton",
    linen = "linen",
    velvet = "velvet",
    rope = "rope",
    porcelain = "porcelain",
}

fuzzy.MATERIAL_ADJECTIVES = MATERIAL_ADJECTIVES

---------------------------------------------------------------------------
-- Property adjective → property/comparator mapping
---------------------------------------------------------------------------
local PROPERTY_ADJECTIVES = {
    heavy  = { field = "weight", compare = "high" },
    light  = { field = "weight", compare = "low" },
    big    = { field = "size",   compare = "high" },
    large  = { field = "size",   compare = "high" },
    small  = { field = "size",   compare = "low" },
    tiny   = { field = "size",   compare = "low" },
    little = { field = "size",   compare = "low" },
}

fuzzy.PROPERTY_ADJECTIVES = PROPERTY_ADJECTIVES

---------------------------------------------------------------------------
-- Parse a fuzzy noun phrase into components:
--   "the wooden thing" → { material_adj = "wooden", base_noun = "thing" }
--   "the heavy one"    → { property_adj = "heavy", base_noun = "one" }
--   "that bottle"      → { base_noun = "bottle" }
---------------------------------------------------------------------------
function fuzzy.parse_noun_phrase(noun)
    if not noun or noun == "" then return nil end
    local kw = noun:lower()
        :gsub("^the%s+", "")
        :gsub("^a%s+", "")
        :gsub("^an%s+", "")
        :gsub("^that%s+", "")
        :gsub("^this%s+", "")

    if kw == "" then return nil end

    local result = { raw = kw }

    -- Check for material adjective as first word
    local first, rest = kw:match("^(%S+)%s+(.+)$")
    if first then
        if MATERIAL_ADJECTIVES[first] then
            result.material_adj = first
            result.material_value = MATERIAL_ADJECTIVES[first]
            result.base_noun = rest
            return result
        end
        if PROPERTY_ADJECTIVES[first] then
            result.property_adj = first
            result.property_spec = PROPERTY_ADJECTIVES[first]
            result.base_noun = rest
            return result
        end
    end

    result.base_noun = kw
    return result
end

---------------------------------------------------------------------------
-- Gather all visible objects from context (room + surfaces + hands + bags + worn)
-- Returns flat list of { obj = <table>, loc = <string>, parent = <obj|nil>, surface = <string|nil> }
---------------------------------------------------------------------------
function fuzzy.gather_visible(ctx)
    local results = {}
    local room = ctx.current_room
    local reg = ctx.registry
    local seen = {}

    local function add(obj, loc, parent, surface)
        if obj and not seen[obj.id or tostring(obj)] then
            seen[obj.id or tostring(obj)] = true
            results[#results + 1] = { obj = obj, loc = loc, parent = parent, surface = surface }
        end
    end

    -- Room contents (non-hidden)
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and not obj.hidden then
            add(obj, "room", nil, nil)
            -- Surface contents
            if obj.surfaces then
                for sname, zone in pairs(obj.surfaces) do
                    if zone.accessible ~= false then
                        for _, item_id in ipairs(zone.contents or {}) do
                            local item = reg:get(item_id)
                            if item then
                                add(item, "surface", obj, sname)
                                -- Nested container contents
                                if item.contents then
                                    for _, inner_id in ipairs(item.contents) do
                                        local inner = reg:get(inner_id)
                                        if inner then add(inner, "container", item, nil) end
                                    end
                                end
                            end
                        end
                    end
                end
            end
            -- Parts
            if obj.parts then
                for part_key, part in pairs(obj.parts) do
                    add(part, "part", obj, part_key)
                end
            end
        end
    end

    -- Player hands
    local player = ctx.player
    for i = 1, 2 do
        local hand = player.hands[i]
        if hand then
            local obj = type(hand) == "table" and hand or reg:get(hand)
            if obj then
                add(obj, "hand", nil, nil)
                -- Bag contents
                if obj.container and obj.contents then
                    for _, item_id in ipairs(obj.contents) do
                        local item = reg:get(item_id)
                        if item then add(item, "bag", obj, nil) end
                    end
                end
                -- Parts of held objects
                if obj.parts then
                    for pk, part in pairs(obj.parts) do
                        add(part, "part", obj, pk)
                    end
                end
            end
        end
    end

    -- Worn items
    for _, worn_id in ipairs(player.worn or {}) do
        local obj = reg:get(worn_id)
        if obj then
            add(obj, "worn", nil, nil)
            if obj.container and obj.contents then
                for _, item_id in ipairs(obj.contents) do
                    local item = reg:get(item_id)
                    if item then add(item, "bag", obj, nil) end
                end
            end
        end
    end

    return results
end

---------------------------------------------------------------------------
-- Build a flat list of matchable strings for an object (name + keywords + id)
---------------------------------------------------------------------------
local function matchable_strings(obj)
    local strings = {}
    if obj.name then strings[#strings + 1] = obj.name:lower() end
    if obj.id then strings[#strings + 1] = obj.id:lower() end
    if type(obj.keywords) == "table" then
        for _, k in ipairs(obj.keywords) do
            strings[#strings + 1] = k:lower()
        end
    end
    return strings
end

---------------------------------------------------------------------------
-- Score a single object against a fuzzy noun phrase.
-- Returns: score (0 = no match, higher = better), match_reason (string)
---------------------------------------------------------------------------
function fuzzy.score_object(obj, parsed)
    if not obj or not parsed then return 0, nil end
    local base = parsed.base_noun or parsed.raw

    -- Generic nouns that match by adjective alone
    local generic_nouns = { thing = true, one = true, object = true, item = true, stuff = true }

    ---------------------------------------------------------------------------
    -- 1. Material matching: "the wooden thing"
    ---------------------------------------------------------------------------
    if parsed.material_value then
        local obj_material = obj.material and obj.material:lower() or nil
        local obj_cats = obj.categories or {}

        local material_match = false
        if obj_material == parsed.material_value then
            material_match = true
        end
        -- Also check categories for material
        if not material_match then
            for _, cat in ipairs(obj_cats) do
                if cat:lower() == parsed.material_value
                    or cat:lower() == parsed.material_adj then
                    material_match = true
                    break
                end
            end
        end

        if material_match then
            if generic_nouns[base] then
                return 3, "material"
            end
            -- Material + partial name
            for _, s in ipairs(matchable_strings(obj)) do
                if s:find(base, 1, true) then
                    return 5, "material+name"
                end
            end
            return 2, "material_only"
        end
        return 0, nil
    end

    ---------------------------------------------------------------------------
    -- 2. Property matching: "the heavy one"
    ---------------------------------------------------------------------------
    if parsed.property_spec then
        local spec = parsed.property_spec
        local val = obj[spec.field]
        if val and type(val) == "number" then
            if generic_nouns[base] then
                return 3, "property"
            end
            -- Property + partial name
            for _, s in ipairs(matchable_strings(obj)) do
                if s:find(base, 1, true) then
                    return 5, "property+name"
                end
            end
            return 0, nil
        end
        return 0, nil
    end

    ---------------------------------------------------------------------------
    -- 3. Partial name match: "bottle" → "small glass bottle"
    -- Requires base noun ≥3 chars to avoid spurious substring matches.
    -- #71: Check exact keyword/id match first (priority over partial).
    ---------------------------------------------------------------------------
    if #base >= 3 then
        -- Pass 1: exact match on any keyword/id/name (highest priority)
        for _, s in ipairs(matchable_strings(obj)) do
            if s == base then return 10, "exact" end
        end
        -- Pass 2: substring match (lower priority)
        for _, s in ipairs(matchable_strings(obj)) do
            if s:find(base, 1, true) then
                return 4, "partial"
            end
        end
    end

    ---------------------------------------------------------------------------
    -- 4. Typo tolerance via Levenshtein distance
    -- #71/#335: Tighten length ratio check — the shorter word must be at least
    -- 80% of the longer word's length. Prevents false positives like
    -- "meat"→"mat" (3/4=75% < 80%) while allowing "candel"→"candle" (100%).
    -- Raised from 75% to 80% to eliminate cross-length absurd matches (#335).
    ---------------------------------------------------------------------------
    local max_dist = fuzzy.max_typo_distance(#base)
    if max_dist > 0 then
        local best_dist = max_dist + 1
        for _, s in ipairs(matchable_strings(obj)) do
            -- Compare against each word in multi-word strings too
            for word in s:gmatch("%S+") do
                local shorter = math.min(#word, #base)
                local longer = math.max(#word, #base)
                if math.abs(#word - #base) <= max_dist
                    and shorter / longer >= 0.80 then
                    local d = fuzzy.levenshtein(base, word)
                    if d < best_dist then best_dist = d end
                end
            end
            -- Also compare against full string for single-word keywords
            if not s:find(" ") then
                local shorter = math.min(#s, #base)
                local longer = math.max(#s, #base)
                if math.abs(#s - #base) <= max_dist
                    and shorter / longer >= 0.80 then
                    local d = fuzzy.levenshtein(base, s)
                    if d < best_dist then best_dist = d end
                end
            end
        end
        if best_dist <= max_dist then
            -- Tier 5: Score relative to max_dist so all accepted typos meet MIN_CONFIDENCE
            return max_dist - best_dist + 3, "typo"
        end
    end

    return 0, nil
end

---------------------------------------------------------------------------
-- Rank visible objects by fuzzy match quality for property comparisons.
-- For "heavy one": pick the highest-weight object among matches.
-- For "light one": pick the lowest-weight object.
---------------------------------------------------------------------------
local function rank_by_property(matches, spec)
    if #matches <= 1 then return matches end
    table.sort(matches, function(a, b)
        local va = a.obj[spec.field] or 0
        local vb = b.obj[spec.field] or 0
        if spec.compare == "high" then return va > vb end
        return va < vb
    end)
    -- If top two have different values, the top one is clearly "the heavy one"
    local top_val = matches[1].obj[spec.field] or 0
    local second_val = matches[2].obj[spec.field] or 0
    if top_val ~= second_val then
        return { matches[1] }
    end
    return matches
end

---------------------------------------------------------------------------
-- resolve(ctx, keyword) -> obj, loc, parent, surface, prompt_text
-- Main entry point. Called as fallback when exact matching fails.
-- Returns:
--   Single match: obj, loc, parent, surface, nil
--   Multiple matches: nil, nil, nil, nil, disambiguation_prompt
--   No match: nil, nil, nil, nil, nil
---------------------------------------------------------------------------
function fuzzy.resolve(ctx, keyword)
    if not keyword or keyword == "" then return nil end

    local parsed = fuzzy.parse_noun_phrase(keyword)
    if not parsed then return nil end

    local visible = fuzzy.gather_visible(ctx)
    if #visible == 0 then return nil end

    -- Score all visible objects
    local scored = {}
    for _, entry in ipairs(visible) do
        local score, reason = fuzzy.score_object(entry.obj, parsed)
        if score > 0 then
            scored[#scored + 1] = {
                obj = entry.obj, loc = entry.loc,
                parent = entry.parent, surface = entry.surface,
                score = score, reason = reason,
            }
        end
    end

    if #scored == 0 then return nil end

    -- Sort by score descending
    table.sort(scored, function(a, b) return a.score > b.score end)

    -- Filter to top-scoring tier
    local top_score = scored[1].score
    local top_matches = {}
    for _, m in ipairs(scored) do
        if m.score == top_score then
            top_matches[#top_matches + 1] = m
        end
    end

    -- Property-based: use ranking to pick best
    if parsed.property_spec and #top_matches > 1 then
        top_matches = rank_by_property(top_matches, parsed.property_spec)
    end

    -- Single unambiguous match
    if #top_matches == 1 then
        local m = top_matches[1]
        return m.obj, m.loc, m.parent, m.surface, nil
    end

    -- Multiple matches → disambiguation prompt (Prime Directive friendly)
    local names = {}
    for _, m in ipairs(top_matches) do
        local name = m.obj.name or m.obj.id or "something"
        names[#names + 1] = name
    end

    local prompt
    if #names == 2 then
        prompt = "Which do you mean: " .. names[1] .. " or " .. names[2] .. "?"
    else
        local parts = {}
        for i, n in ipairs(names) do
            if i == #names then
                parts[#parts + 1] = "or " .. n
            else
                parts[#parts + 1] = n
            end
        end
        prompt = "Which do you mean: " .. table.concat(parts, ", ") .. "?"
    end

    return nil, nil, nil, nil, prompt
end

---------------------------------------------------------------------------
-- correct_typo(keyword, visible_objects) -> corrected_keyword or nil
-- Standalone typo correction: given a keyword and list of visible objects,
-- returns the corrected keyword if a close Levenshtein match is found.
-- Used for providing "Did you mean...?" suggestions.
---------------------------------------------------------------------------
function fuzzy.correct_typo(keyword, visible)
    if not keyword or keyword == "" then return nil end
    local kw = keyword:lower()
    local max_dist = fuzzy.max_typo_distance(#kw)
    if max_dist == 0 then return nil end

    local best_word = nil
    local best_dist = max_dist + 1

    for _, entry in ipairs(visible) do
        for _, s in ipairs(matchable_strings(entry.obj)) do
            for word in s:gmatch("%S+") do
                if math.abs(#word - #kw) <= max_dist then
                    local d = fuzzy.levenshtein(kw, word)
                    if d > 0 and d < best_dist then
                        best_dist = d
                        best_word = word
                    end
                end
            end
        end
    end

    if best_word then return best_word end
    return nil
end

---------------------------------------------------------------------------
-- Tier 5 Enhancement: Confidence scoring
---------------------------------------------------------------------------
local MAX_SCORE = 10

--- Normalize a raw match score to 0.0–1.0 confidence.
function fuzzy.confidence(raw_score)
    if not raw_score or raw_score <= 0 then return 0.0 end
    return math.min(raw_score / MAX_SCORE, 1.0)
end

-- Minimum confidence to accept a fuzzy match (below = reject)
fuzzy.MIN_CONFIDENCE = 0.3

-- Minimum confidence to auto-accept without disambiguation
fuzzy.AUTO_ACCEPT = 0.7

---------------------------------------------------------------------------
-- Tier 5 Enhancement: Context-integrated scoring
-- Adds recency bonus from context_window as a tiebreaker.
---------------------------------------------------------------------------
function fuzzy.score_with_context(obj, parsed, context_window)
    local base_score, reason = fuzzy.score_object(obj, parsed)
    if base_score == 0 then return 0, nil end

    local recency = 0
    if context_window and context_window.recency_score and obj and obj.id then
        recency = context_window.recency_score(obj.id)
    end

    -- Recency adds up to 0.5 bonus (tiebreaker, never overrides a better match)
    return base_score + (recency * 0.1), reason
end

return fuzzy

end

package.preload["engine.parser.goal_planner"] = function()
-- engine/parser/goal_planner.lua
-- Tier 3→6: backward-chaining prerequisite resolver.
-- Fires when a verb+object has unmet tool/capability requirements.
-- Builds a plan of preparatory steps, executes them through Tier 1 dispatch.
--
-- Tier 6: Generalized GOAP — property-based goal matching.
-- Goals are defined by requirement properties (needs_light, needs_key,
-- needs_tool) rather than hardcoded verb chains. The planner walks
-- backwards from the goal, finding objects that provide required properties.
-- Safety limit: MAX_PLAN_DEPTH (7 steps) prevents runaway chains.

local goal_planner = {}
local MAX_DEPTH = 7
-- BUG-090: Maximum plan steps to prevent infinite prerequisite chains
local MAX_PLAN_STEPS = 20
local preprocess = require("engine.parser.preprocess")

-- Tier 6: Presentation module for light-level checks
local pres_ok, presentation = pcall(require, "engine.ui.presentation")
if not pres_ok then presentation = nil end

-- Verb synonyms: verbs that should trigger the same GOAP prerequisite chain
local VERB_SYNONYMS = { burn = "light" }

-- Tier 6: Verbs that require light (room must not be dark)
local LIGHT_VERBS = {
    read = true, write = true,
}

---------------------------------------------------------------------------
-- Helpers: keyword matching (mirrors verbs module)
-- BUG-056: tries singular forms of plural nouns as fallback
---------------------------------------------------------------------------
local function kw_match(obj, kw)
    if not obj then return false end
    kw = kw:lower()
    local candidates = { kw }
    for _, s in ipairs(preprocess.singularize(kw)) do
        candidates[#candidates + 1] = s
    end
    for _, try_kw in ipairs(candidates) do
        if obj.id and obj.id:lower() == try_kw then return true end
        for _, k in ipairs(obj.keywords or {}) do
            if k:lower() == try_kw then return true end
        end
        if obj.name then
            local p = " " .. obj.name:lower() .. " "
            if p:find(" " .. try_kw .. " ", 1, true) then return true end
        end
    end
    return false
end

local function strip_articles(noun)
    return noun:lower():gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
end

--- Comprehensive check: is an object in a terminal/spent/consumed state?
-- Covers _state == "spent", state.terminal, consumable flag, and "useless" category.
local function is_spent_or_terminal(obj)
    if not obj then return true end
    if obj._state == "spent" then return true end
    if obj.consumable == true then return true end
    if obj.states and obj._state then
        local state_data = obj.states[obj._state]
        if state_data and state_data.terminal then return true end
    end
    if obj.categories then
        for _, cat in ipairs(obj.categories) do
            if cat == "useless" then return true end
        end
    end
    return false
end

-- Instance-aware hand accessors for goal planner
local function _gp_hid(hand)
    if type(hand) == "table" then return hand.id end
    return hand
end
local function _gp_hobj(hand, reg)
    if type(hand) == "table" then return hand end
    if type(hand) == "string" then return reg:get(hand) end
    return nil
end

---------------------------------------------------------------------------
-- State queries
---------------------------------------------------------------------------
local function has_tool(ctx, cap)
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj then
                local pt = obj.provides_tool
                if pt == cap then return true end
                if type(pt) == "table" then
                    for _, c in ipairs(pt) do if c == cap then return true end end
                end
            end
            if obj and obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item and item.provides_tool == cap then return true end
                end
            end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = ctx.registry:get(id)
        if obj and obj.provides_tool == cap then return true end
    end
    if cap == "fire_source" and ctx.player.state.has_flame
        and ctx.player.state.has_flame > 0 then
        return true
    end
    return false
end

local function is_held(ctx, obj_id)
    return _gp_hid(ctx.player.hands[1]) == obj_id or _gp_hid(ctx.player.hands[2]) == obj_id
end

---------------------------------------------------------------------------
-- Find all reachable objects matching a keyword
---------------------------------------------------------------------------
local function find_all(ctx, keyword)
    local out = {}
    local reg = ctx.registry
    local kw = strip_articles(keyword)
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and kw_match(obj, kw) then
                out[#out + 1] = { obj = obj, where = "hand" }
            end
            if obj and obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item and kw_match(item, kw) then
                        out[#out + 1] = { obj = item, where = "container",
                            parent = obj, accessible = (obj.accessible ~= false) }
                    end
                end
            end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and not obj.hidden and kw_match(obj, kw) then
            out[#out + 1] = { obj = obj, where = "room" }
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and kw_match(item, kw) then
                    out[#out + 1] = { obj = item, where = "container",
                        parent = obj, accessible = (obj.accessible ~= false) }
                end
            end
        end
        -- Search ALL surfaces (including inaccessible ones for planning)
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                local zone_ok = (zone.accessible ~= false)
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and kw_match(item, kw) then
                        out[#out + 1] = { obj = item, where = "surface", parent = obj,
                            surface_accessible = zone_ok }
                    end
                    -- Nested: items inside containers on surfaces
                    if item and item.container and item.contents then
                        for _, inner_id in ipairs(item.contents) do
                            local inner = reg:get(inner_id)
                            if inner and kw_match(inner, kw) then
                                out[#out + 1] = { obj = inner, where = "nested",
                                    parent = item, grandparent = obj,
                                    accessible = (item.accessible ~= false),
                                    surface_accessible = zone_ok }
                            end
                        end
                    end
                end
            end
        end
    end
    return out
end

local function find_property(ctx, prop)
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and obj[prop] then return obj end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and obj[prop] then return obj end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and item[prop] then return item end
                end
            end
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and item[prop] then return item end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Tier 6: Find objects that can cast light via FSM state transition
-- Returns list of { obj, transition, entry } candidates
---------------------------------------------------------------------------
local function find_lightable(ctx)
    local reg = ctx.registry
    local candidates = {}

    local function check_obj(obj, entry_info)
        if not obj or not obj.states or not obj._state then return end
        if is_spent_or_terminal(obj) then return end
        for state_name, state_data in pairs(obj.states) do
            if type(state_data) == "table" and state_data.casts_light then
                if obj._state ~= state_name then
                    for _, t in ipairs(obj.transitions or {}) do
                        if t.from == obj._state and t.to == state_name
                            and t.trigger ~= "auto" then
                            candidates[#candidates + 1] = {
                                obj = obj, transition = t, entry = entry_info,
                            }
                        end
                    end
                end
            end
        end
    end

    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj then check_obj(obj, { where = "hand" }) end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj then
            check_obj(obj, { where = "room" })
            if obj.surfaces then
                for _, zone in pairs(obj.surfaces) do
                    local zone_ok = (zone.accessible ~= false)
                    for _, cid in ipairs(zone.contents or {}) do
                        local item = reg:get(cid)
                        if item then
                            check_obj(item, { where = "surface", parent = obj,
                                surface_accessible = zone_ok })
                        end
                        if item and item.container and item.contents then
                            for _, inner_id in ipairs(item.contents) do
                                local inner = reg:get(inner_id)
                                if inner then
                                    check_obj(inner, { where = "nested",
                                        parent = item, grandparent = obj,
                                        accessible = (item.accessible ~= false),
                                        surface_accessible = zone_ok })
                                end
                            end
                        end
                    end
                end
            end
            if obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item then
                        check_obj(item, { where = "container", parent = obj,
                            accessible = (obj.accessible ~= false) })
                    end
                end
            end
        end
    end
    return candidates
end

---------------------------------------------------------------------------
-- Tier 6: Find objects by exact ID across all reachable locations
-- Returns list of { obj, where, parent, ... } entries (same format as find_all)
---------------------------------------------------------------------------
local function find_by_id(ctx, target_id)
    local out = {}
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and obj.id == target_id then
                out[#out + 1] = { obj = obj, where = "hand" }
            end
            if obj and obj.container and obj.contents then
                for _, cid in ipairs(obj.contents) do
                    local item = reg:get(cid)
                    if item and item.id == target_id then
                        out[#out + 1] = { obj = item, where = "container",
                            parent = obj, accessible = (obj.accessible ~= false) }
                    end
                end
            end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and obj.id == target_id then
            out[#out + 1] = { obj = obj, where = "room" }
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and item.id == target_id then
                    out[#out + 1] = { obj = item, where = "container",
                        parent = obj, accessible = (obj.accessible ~= false) }
                end
            end
        end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                local zone_ok = (zone.accessible ~= false)
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and item.id == target_id then
                        out[#out + 1] = { obj = item, where = "surface",
                            parent = obj, surface_accessible = zone_ok }
                    end
                    if item and item.container and item.contents then
                        for _, inner_id in ipairs(item.contents) do
                            local inner = reg:get(inner_id)
                            if inner and inner.id == target_id then
                                out[#out + 1] = { obj = inner, where = "nested",
                                    parent = item, grandparent = obj,
                                    accessible = (item.accessible ~= false),
                                    surface_accessible = zone_ok }
                            end
                        end
                    end
                end
            end
        end
    end
    return out
end

---------------------------------------------------------------------------
-- Tier 6: Keyword for an object (first keyword or id)
---------------------------------------------------------------------------
local function obj_keyword(obj)
    return obj.keywords and obj.keywords[1] or obj.id
end

---------------------------------------------------------------------------
-- Try to plan fire_source from a single match candidate
---------------------------------------------------------------------------
local function try_plan_match(entry, ctx, visited)
    local m = entry.obj
    if is_spent_or_terminal(m) then return nil end
    local key = m.id .. ":fire"
    if visited[key] then return nil end
    visited[key] = true
    local steps = {}

    -- Already lit — just ensure it's held
    if m._state == "lit" then
        if not is_held(ctx, m.id) then
            steps[#steps + 1] = { verb = "take", noun = "match" }
        end
        return steps
    end

    -- Count spent matches preceding the fresh one in a container.
    -- The take verb grabs the first keyword-matching item, so spent
    -- matches must be removed before the fresh one can be taken.
    local function spent_before_fresh(parent)
        if not parent or not parent.contents then return 0 end
        local count = 0
        for _, cid in ipairs(parent.contents) do
            if cid == m.id then break end
            local item = ctx.registry:get(cid)
            if item and kw_match(item, "match") and is_spent_or_terminal(item) then
                count = count + 1
            end
        end
        return count
    end

    -- Nested match: inside a container that is inside a surface (e.g., matchbox in nightstand)
    if entry.where == "nested" then
        -- Open the grandparent surface if inaccessible (open nightstand drawer)
        if not entry.surface_accessible and entry.grandparent then
            local gn = entry.grandparent.keywords and entry.grandparent.keywords[1]
                or entry.grandparent.id
            steps[#steps + 1] = { verb = "open", noun = gn }
        end
        -- Open the container in place if inaccessible (open matchbox)
        if not entry.accessible and entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            steps[#steps + 1] = { verb = "open", noun = pn }
        end
        -- Clear spent matches then take the fresh one
        if entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            for _ = 1, spent_before_fresh(entry.parent) do
                steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
                steps[#steps + 1] = { verb = "drop", noun = "match" }
            end
            steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
        end
    elseif entry.where == "container" then
        -- Match in a direct container
        if not entry.accessible and entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            steps[#steps + 1] = { verb = "open", noun = pn }
        end
        if entry.parent then
            local pn = entry.parent.keywords and entry.parent.keywords[1]
                or entry.parent.id
            -- Clear spent matches then take the fresh one
            for _ = 1, spent_before_fresh(entry.parent) do
                steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
                steps[#steps + 1] = { verb = "drop", noun = "match" }
            end
            steps[#steps + 1] = { verb = "take", noun = "match from " .. pn }
        else
            steps[#steps + 1] = { verb = "take", noun = "match" }
        end
    elseif entry.where ~= "hand" then
        steps[#steps + 1] = { verb = "take", noun = "match" }
    end

    local striker = find_property(ctx, "has_striker")
    if not striker then return nil end
    local sn = striker.keywords and striker.keywords[1] or striker.id
    steps[#steps + 1] = { verb = "strike", noun = "match on " .. sn }
    return steps
end

---------------------------------------------------------------------------
-- Backward chaining: build steps to obtain fire_source specifically
-- (Preserved from Tier 3 — handles match/striker complexity)
---------------------------------------------------------------------------
local function plan_fire_source(ctx, visited, depth)
    -- Drop any spent/terminal matches from hands
    local spent_drops = {}
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, ctx.registry)
            if obj and kw_match(obj, "match") and is_spent_or_terminal(obj) then
                spent_drops[#spent_drops + 1] = { verb = "drop", noun = "match" }
            end
        end
    end

    local candidates = find_all(ctx, "match")

    -- Check if any viable candidate needs spent-match container cleanup
    local needs_free_hand = false
    if #spent_drops == 0 and ctx.player.hands[1] and ctx.player.hands[2] then
        for _, entry in ipairs(candidates) do
            if not is_spent_or_terminal(entry.obj)
                and (entry.where == "container" or entry.where == "nested")
                and entry.parent and entry.parent.contents then
                for _, cid in ipairs(entry.parent.contents) do
                    if cid == entry.obj.id then break end
                    local item = ctx.registry:get(cid)
                    if item and kw_match(item, "match") and is_spent_or_terminal(item) then
                        needs_free_hand = true
                        break
                    end
                end
                if needs_free_hand then break end
            end
        end
    end

    -- Free a hand by dropping a non-container held item
    if needs_free_hand then
        for i = 1, 2 do
            local hand = ctx.player.hands[i]
            if hand then
                local obj = _gp_hobj(hand, ctx.registry)
                if obj and not (obj.container and obj.contents) then
                    local n = obj.keywords and obj.keywords[1] or obj.id
                    spent_drops[#spent_drops + 1] = { verb = "drop", noun = n }
                    break
                end
            end
        end
    end

    for _, entry in ipairs(candidates) do
        local result = try_plan_match(entry, ctx, visited)
        if result then
            -- Prepend spent-match drops so the hand slot is free
            for j = #spent_drops, 1, -1 do
                table.insert(result, 1, spent_drops[j])
            end
            return result
        end
    end

    return nil
end

---------------------------------------------------------------------------
-- Tier 6: Plan retrieval steps for an object found at a given location
-- Shared by plan_for_key and plan_generic_tool
---------------------------------------------------------------------------
local function plan_retrieval(entry)
    local steps = {}
    local kn = obj_keyword(entry.obj)

    if entry.where == "nested" then
        if not entry.surface_accessible and entry.grandparent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.grandparent) }
        end
        if not entry.accessible and entry.parent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.parent) }
        end
        local pn = entry.parent and obj_keyword(entry.parent)
        if pn then
            steps[#steps + 1] = { verb = "take", noun = kn .. " from " .. pn }
        else
            steps[#steps + 1] = { verb = "take", noun = kn }
        end
    elseif entry.where == "container" then
        if not entry.accessible and entry.parent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.parent) }
        end
        local pn = entry.parent and obj_keyword(entry.parent)
        if pn then
            steps[#steps + 1] = { verb = "take", noun = kn .. " from " .. pn }
        else
            steps[#steps + 1] = { verb = "take", noun = kn }
        end
    elseif entry.where == "surface" then
        if not entry.surface_accessible and entry.parent then
            steps[#steps + 1] = { verb = "open", noun = obj_keyword(entry.parent) }
        end
        steps[#steps + 1] = { verb = "take", noun = kn }
    elseif entry.where == "room" then
        steps[#steps + 1] = { verb = "take", noun = kn }
    end
    -- "hand" → already held, no retrieval needed
    return steps
end

---------------------------------------------------------------------------
-- Tier 6: Plan to provide light to the room
-- Backward chain: find lightable object → plan its tool requirement
---------------------------------------------------------------------------
local function plan_for_light(ctx, visited, depth)
    if depth > MAX_DEPTH then return nil end
    if presentation and presentation.has_some_light
        and presentation.has_some_light(ctx) then
        return {}
    end

    local cands = find_lightable(ctx)
    for _, cand in ipairs(cands) do
        local vkey = cand.obj.id .. ":light_goal"
        if not visited[vkey] then
            visited[vkey] = true
            local steps = {}

            -- If the lightable object requires a tool, plan for it first
            if cand.transition.requires_tool then
                -- Forward-declare: plan_for_tool is defined below
                local tool_steps = plan_fire_source(ctx, visited, depth + 1)
                if not tool_steps then goto next_light end
                for _, s in ipairs(tool_steps) do steps[#steps + 1] = s end
            end

            -- Add the light step itself
            local kn = obj_keyword(cand.obj)
            steps[#steps + 1] = { verb = "light", noun = kn }
            return steps
        end
        ::next_light::
    end

    return nil
end

---------------------------------------------------------------------------
-- Tier 6: Generic tool resolution — find any object providing the
-- requested capability, plan retrieval if needed
---------------------------------------------------------------------------
local function plan_generic_tool(capability, ctx, visited, depth)
    if depth > MAX_DEPTH then return nil end
    local reg = ctx.registry

    local function check_provides(obj)
        if not obj then return false end
        local pt = obj.provides_tool
        if pt == capability then return true end
        if type(pt) == "table" then
            for _, c in ipairs(pt) do if c == capability then return true end end
        end
        return false
    end

    -- Search hands first
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and check_provides(obj) then return {} end
        end
    end

    -- Search room, surfaces, containers
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and check_provides(obj) then
            return { { verb = "take", noun = obj_keyword(obj) } }
        end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                local zone_ok = (zone.accessible ~= false)
                for _, cid in ipairs(zone.contents or {}) do
                    local item = reg:get(cid)
                    if item and check_provides(item) then
                        local steps = {}
                        if not zone_ok then
                            steps[#steps + 1] = { verb = "open", noun = obj_keyword(obj) }
                        end
                        steps[#steps + 1] = { verb = "take", noun = obj_keyword(item) }
                        return steps
                    end
                end
            end
        end
        if obj and obj.container and obj.contents then
            for _, cid in ipairs(obj.contents) do
                local item = reg:get(cid)
                if item and check_provides(item) then
                    local steps = {}
                    if obj.accessible == false then
                        steps[#steps + 1] = { verb = "open", noun = obj_keyword(obj) }
                    end
                    steps[#steps + 1] = { verb = "take",
                        noun = obj_keyword(item) .. " from " .. obj_keyword(obj) }
                    return steps
                end
            end
        end
    end

    return nil
end

---------------------------------------------------------------------------
-- Backward chaining: build steps to obtain a tool capability
-- Tier 6: dispatches to specialized resolvers by capability type
---------------------------------------------------------------------------
local function plan_for_tool(capability, ctx, visited, depth)
    if depth > MAX_DEPTH then return nil end
    if has_tool(ctx, capability) then return {} end
    visited = visited or {}

    -- BUG-090: Safety limit on visited set size to prevent runaway planning
    local visited_count = 0
    for _ in pairs(visited) do visited_count = visited_count + 1 end
    if visited_count > 50 then return nil end

    -- Specialized resolver: fire_source (match/striker chain)
    if capability == "fire_source" then
        return plan_fire_source(ctx, visited, depth)
    end

    -- Generic: find any reachable object providing this capability
    return plan_generic_tool(capability, ctx, visited, depth + 1)
end

---------------------------------------------------------------------------
-- Resolve target object from noun string
---------------------------------------------------------------------------
local function resolve_target(ctx, noun)
    local kw = strip_articles(noun)
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _gp_hobj(hand, reg)
            if obj and kw_match(obj, kw) then return obj end
        end
    end
    for _, id in ipairs(ctx.current_room.contents or {}) do
        local obj = reg:get(id)
        if obj and not obj.hidden and kw_match(obj, kw) then return obj end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                if zone.accessible ~= false then
                    for _, cid in ipairs(zone.contents or {}) do
                        local item = reg:get(cid)
                        -- Search inside surface item contents first
                        if item and item.contents then
                            for _, inner_id in ipairs(item.contents) do
                                local inner = reg:get(inner_id)
                                if inner and kw_match(inner, kw) then return inner end
                            end
                        end
                        if item and kw_match(item, kw) then return item end
                    end
                end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Public: plan prerequisite steps for verb + noun
-- Tier 6: checks verb-level requirements (light, key) before object-level
-- Returns: list of {verb, noun} steps, or nil if no planning needed/possible
---------------------------------------------------------------------------
function goal_planner.plan(verb, noun, ctx)
    if not noun or noun == "" or not ctx then return nil end

    local canonical = VERB_SYNONYMS[verb] or verb

    -- Tier 6: Verb-level requirement — light
    if LIGHT_VERBS[canonical] then
        if presentation and presentation.has_some_light
            and not presentation.has_some_light(ctx) then
            local steps = plan_for_light(ctx, {}, 0)
            if steps and #steps > 0 then return steps end
        end
    end

    -- Object-level: existing prerequisite / FSM tool requirements
    local target_noun = noun:match("^(.-)%s+with%s+") or noun
    local target = resolve_target(ctx, target_noun)
    if not target then return nil end

    -- Check explicit prerequisites table on the object
    local prereqs = target.prerequisites and
        (target.prerequisites[verb] or target.prerequisites[canonical])

    -- Infer from FSM transitions if no explicit prerequisites
    if not prereqs and target.transitions and target._state then
        for _, t in ipairs(target.transitions) do
            if t.from == target._state and t.trigger ~= "auto" then
                local vm = (t.verb == verb) or (t.verb == canonical)
                if not vm and t.aliases then
                    for _, a in ipairs(t.aliases) do
                        if a == verb or a == canonical then vm = true; break end
                    end
                end
                if vm and t.requires_tool then
                    prereqs = { needs_tool = t.requires_tool }
                    break
                end
            end
        end
    end
    if not prereqs then return nil end

    local needed = prereqs.needs_tool or (prereqs.requires and prereqs.requires[1])
    if not needed then return nil end
    return plan_for_tool(needed, ctx, {}, 0)
end

--- Issue #17: Narration templates for GOAP auto-chain steps.
--- Maps verb → function(noun) returning a brief narration prefix.
--- When a verb isn't in the table, the handler's own output suffices.
local STEP_NARRATION = {
    take  = function(noun) return "You look for " .. noun .. "..." end,
    open  = function(noun) return "You need to open " .. noun .. " first." end,
    find  = function(noun) return "You search for " .. noun .. "..." end,
    drop  = function(_)    return nil end,   -- silent helper step
}

--- Execute planned steps through Tier 1 dispatch. Returns true on success.
--- Issue #17: Each step now narrates what's happening so the player sees
--- every intermediate action, not just the final result.
function goal_planner.execute(steps, ctx)
    if not steps or #steps == 0 then return true end
    -- Safety limit: max 7 plan depth → max ~20 individual steps
    if #steps > MAX_PLAN_STEPS then
        print("(That would take too many steps — " .. #steps
            .. " needed, limit is " .. MAX_PLAN_STEPS
            .. ". Try breaking it into simpler steps.)")
        return false
    end
    print("\nYou'll need to prepare first...\n")
    for i, step in ipairs(steps) do
        local handler = ctx.verbs[step.verb]
        if not handler then
            print("(You're not sure how to " .. step.verb .. ".)")
            return false
        end
        -- Issue #17: narrate the step before executing
        local narrator = STEP_NARRATION[step.verb]
        if narrator then
            local msg = narrator(step.noun)
            if msg then print(msg) end
        end
        ctx.current_verb = step.verb
        handler(ctx, step.noun)
    end
    print("")
    return true
end

--- Tier 6: Expose internals for testing
goal_planner._plan_for_light = function(ctx, visited, depth)
    return plan_for_light(ctx, visited or {}, depth or 0)
end
goal_planner._plan_for_tool = function(cap, ctx, visited, depth)
    return plan_for_tool(cap, ctx, visited or {}, depth or 0)
end
goal_planner._find_lightable = function(ctx)
    return find_lightable(ctx)
end
goal_planner._find_by_id = function(ctx, id)
    return find_by_id(ctx, id)
end
goal_planner._MAX_DEPTH = MAX_DEPTH

return goal_planner

end

