    { pattern = "^what%s+is%s+this$",             verb = "look",      noun_capture = 0, priority = 70 },
    { pattern = "^what'?s%s+this$",               verb = "look",      noun_capture = 0, priority = 70 },

    -- P3: "what is X" → examine X
    { pattern = "^what%s+is%s+the%s+(.+)$",       verb = "examine",   noun_capture = 1, priority = 72 },
    { pattern = "^what'?s%s+the%s+(.+)$",         verb = "examine",   noun_capture = 1, priority = 72 },
    { pattern = "^what%s+is%s+an?%s+(.+)$",       verb = "examine",   noun_capture = 1, priority = 72 },
    { pattern = "^what%s+is%s+(.+)$",             verb = "examine",   noun_capture = 1, priority = 74 },
    { pattern = "^what'?s%s+(.+)$",               verb = "examine",   noun_capture = 1, priority = 74 },

    -- Inventory queries
    { pattern = "^what%s+am%s+i%s+carry",         verb = "inventory", noun_capture = 0, priority = 80 },
    { pattern = "^what%s+am%s+i%s+hold",          verb = "inventory", noun_capture = 0, priority = 80 },
    { pattern = "^what%s+do%s+i%s+have",          verb = "inventory", noun_capture = 0, priority = 80 },

    -- Help/confusion
    { pattern = "^what%s+can%s+i%s+do",           verb = "help",      noun_capture = 0, priority = 90 },
    { pattern = "^what%s+do%s+i%s+do",            verb = "help",      noun_capture = 0, priority = 90 },
    { pattern = "^how%s+do%s+i",                  verb = "help",      noun_capture = 0, priority = 90 },

    -- Time queries
    { pattern = "^what%s+time",                   verb = "time",      noun_capture = 0, priority = 95 },
}

--- match(text) -> "verb noun" string | nil
--- Tries each question pattern in table order.
--- Returns transformed command string on match, or nil.
function M.match(text)
    if not text or text == "" then return nil end
    for _, entry in ipairs(M.QUESTION_MAP) do
        if entry.verb == "$1" then
            -- Dynamic verb extraction (e.g., "can I verb target")
            local v, n = text:match(entry.pattern)
            if v then
                local result = v
                if n and n ~= "" then result = result .. " " .. n end
                return result
            end
        elseif entry.noun_capture == 0 then
            if text:match(entry.pattern) then
                return entry.verb
            end
        else
            local noun = text:match(entry.pattern)
            if noun then
                return entry.verb .. " " .. noun
            end
        end
    end
    return nil
end

return M

end

package.preload["engine.parser.synonym_table"] = function()
-- engine/parser/synonym_table.lua
-- Manual POS-filtered synonyms for Tier 2 matching.
-- Format: canonical_verb = { synonym1, synonym2, ... }
-- Per D2 decision: conservative 2-3 synonyms per term.
--
-- These synonyms map NON-INDEX verbs to canonical forms that exist in the
-- phrase index. If the phrase index already has "grab candle" indexed under
-- verb=grab, we don't need grab→take here. We only need synonyms for words
-- the player might type that do NOT appear as verbs in the index.

local M = {}

-- Verb synonyms: player_word → canonical verb in phrase index
-- Only words NOT already in the embedding index as verbs
M.verbs = {
  -- Acquisition synonyms (take/get/grab are in index, these are NOT)
  snatch    = "take",
  acquire   = "take",
  collect   = "take",
  snag      = "take",    -- #242: casual pickup
  obtain    = "get",
  retrieve  = "get",
  pick      = "take",   -- "pick up" after preprocess strips "up"
  nab       = "grab",
  swipe     = "grab",
  gimme     = "get",    -- #174: casual pickup
  hold      = "get",    -- #174: "hold X" → acquire
  lift      = "get",    -- #174: "lift X" → acquire

  -- Looking synonyms (look/examine are in index)
  gaze      = "look",
  peer      = "examine",  -- #242: "peer at X" → examine (close inspection)
  check     = "examine",  -- #242: "check X" → examine
  observe   = "examine",
  inspect   = "examine",  -- #174: confirmed
  view      = "examine",
  study     = "examine",
  regard    = "examine",
  survey    = "look",
  glance    = "look",
  show      = "look",    -- #242: "show me X" → look
  peek      = "examine",

  -- Open/close synonyms (open/close/shut are in index)
  unlock    = "open",
  unseal    = "open",
  unfasten  = "open",
  seal      = "close",
  fasten    = "close",
  lock      = "close",

  -- Sensory synonyms (feel/smell/taste/listen are in index)
  touch     = "feel",
  handle    = "feel",
  fondle    = "feel",
  caress    = "feel",
  inhale    = "smell",
  whiff     = "smell",
  sample    = "taste",
  sip       = "taste",
  nibble    = "taste",

  -- Destruction synonyms (break/smash/shatter/rip/tear/cut are in index)
  destroy   = "break",
  wreck     = "break",
  crush     = "smash",
  demolish  = "smash",
  slice     = "cut",
  chop      = "cut",
  sever     = "cut",
  shred     = "rip",

  -- Movement/placement (drop/put are in index)
  discard   = "drop",
  toss      = "drop",
  throw     = "drop",
  dump      = "drop",
  set       = "put",
  deposit   = "put",
  stash     = "put",

  -- Fire synonyms (ignite/burn/strike/extinguish/snuff are in index)
  kindle    = "ignite",
  inflame   = "burn",
  use       = "ignite",   -- #174: "use candle" → ignite

  -- Reading/writing (read/write are in index)
  peruse    = "read",
  skim      = "read",
  scribble  = "write",
  jot       = "write",

  -- Repair (mend/sew are in index)
  fix       = "mend",
  repair    = "mend",
  patch     = "mend",
  stitch    = "sew",

  -- Clothing (don/remove are in index)
  wear      = "don",
  equip     = "don",
  doff      = "remove",
  unequip   = "remove",

  -- Search (search/find are in index)
  rummage   = "search",
  ransack   = "search",
  locate    = "find",
  discover  = "find",
  hunt      = "search",
}

-- Reverse lookup: given a synonym, return the canonical verb
function M.canonical_verb(word)
  return M.verbs[word]
end

-- Expand input tokens: replace synonyms with canonical forms for matching
function M.expand_tokens(tokens)
  local expanded = {}
  local mappings = {}
  local seen = {}

  for _, t in ipairs(tokens) do
    local canonical = M.verbs[t]
    if canonical then
      -- Replace synonym with canonical form (don't keep the unknown original)
      if not seen[canonical] then
        expanded[#expanded + 1] = canonical
        seen[canonical] = true
      end
      mappings[t] = canonical
    else
      if not seen[t] then
        expanded[#expanded + 1] = t
        seen[t] = true
      end
    end
  end

  return expanded, mappings
end

return M

end

