package.preload["engine.player.appearance"] = function()
-- engine/player/appearance.lua
-- Player appearance subsystem: reads player state and composes a natural
-- language description for mirrors, "look at self", and future multiplayer.
-- Pure read → compose → return pipeline. Never modifies player state.
--
-- Ownership: Smithers (UI Engineer)

local appearance = {}

---------------------------------------------------------------------------
-- Helpers
---------------------------------------------------------------------------

--- Combine phrases into natural English with Oxford comma.
--- Deduplicates identical phrases (Issue #31: duplicate bruise text).
--- #156: Strips trailing periods from each phrase before joining to prevent
--- comma splices like "your head., a deep bruise".
local function compose_natural(phrases)
    -- Deduplicate identical phrases (Issue #31: duplicate bruise text)
    local seen = {}
    local unique = {}
    for _, p in ipairs(phrases) do
        if not seen[p] then
            seen[p] = true
            unique[#unique + 1] = p
        end
    end
    phrases = unique

    -- #156: Strip trailing periods from each phrase before joining
    for i, p in ipairs(phrases) do
        phrases[i] = p:gsub("[%.]+$", "")
    end

    if #phrases == 0 then return nil end
    if #phrases == 1 then return phrases[1] end
    if #phrases == 2 then return phrases[1] .. " and " .. phrases[2] end
    local last = table.remove(phrases)
    return table.concat(phrases, ", ") .. ", and " .. last
end

--- Get injuries at specific body locations.
local function get_injuries_at(player, locations)
    local matches = {}
    for _, injury in ipairs(player.injuries or {}) do
        if injury.location then
            local loc_lower = injury.location:lower()
            for _, pattern in ipairs(locations) do
                if loc_lower:find(pattern:lower(), 1, true) then
                    matches[#matches + 1] = injury
                    break
                end
            end
        end
    end
    return matches
end

--- Severity → adjective mapping.
local severity_adjectives = {
    minor    = { "small", "slight" },
    moderate = { "deep", "nasty" },
    severe   = { "grievous", "terrible" },
}

local function pick_severity_adjective(severity, index)
    local options = severity_adjectives[severity]
    if not options then return nil end
    -- Issue #92: Use deterministic cycling so multiple injuries get distinct adjectives
    local idx = ((index or math.random(#options)) - 1) % #options + 1
    return options[idx]
end

--- Compose a natural injury phrase from structured data.
-- @param injury table — injury data
-- @param index number|nil — ordinal index for deterministic adjective cycling
local function render_injury_phrase(injury, index)
    local sev = injury.severity or "moderate"
    local adj = pick_severity_adjective(sev, index)

    -- Determine injury noun based on type
    local noun_map = {
        bleeding = "gash",
        bruised  = "bruise",
        concussion = "bruise",
        burn     = "burn",
    }
    local noun = noun_map[injury.type] or "wound"

    local phrase = adj and (adj .. " " .. noun) or noun

    if injury.location then
        phrase = phrase .. " on your " .. injury.location
    end

    -- Treatment check
    if injury._state == "treated" or injury.treatment then
        phrase = phrase .. ", wrapped in a bandage"
    end

    return "a " .. phrase
end

--- Resolve the wear slot from either obj.wear_slot or obj.wear.slot.
local function get_wear_slot(obj)
    if obj.wear_slot then return obj.wear_slot end
    if obj.wear and obj.wear.slot then return obj.wear.slot end
    return nil
end
local function resolve_obj(item, registry)
    if type(item) == "table" then return item end
    if type(item) == "string" and registry then
        local get = registry.get
        if get then return registry:get(item) end
    end
    return nil
end

---------------------------------------------------------------------------
-- Layer renderers
---------------------------------------------------------------------------

local function render_head(player, registry)
    local parts = {}

    -- Worn headgear
    if player.worn then
        for _, worn_id in ipairs(player.worn) do
            local obj = resolve_obj(worn_id, registry)
            if obj and (get_wear_slot(obj) == "head" or obj.is_helmet) then
                if obj.appearance and obj.appearance.worn_description then
                    parts[#parts + 1] = obj.appearance.worn_description
                else
                    parts[#parts + 1] = (obj.name or "a helmet") .. " sits on your head"
                end
            end
        end
    end

    -- Head injuries
    local head_injuries = get_injuries_at(player, {"head", "face", "forehead", "scalp"})
    for i, injury in ipairs(head_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury, i)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_torso(player, registry)
    local parts = {}

    -- Worn torso armor/clothing
    if player.worn then
        for _, worn_id in ipairs(player.worn) do
            local obj = resolve_obj(worn_id, registry)
            if obj and get_wear_slot(obj) == "torso" then
                if obj.appearance and obj.appearance.worn_description then
                    parts[#parts + 1] = obj.appearance.worn_description
                else
                    parts[#parts + 1] = "you are wearing " .. (obj.name or "something") .. " on your torso"
                end
            end
        end
    end

    -- Torso injuries
    local torso_injuries = get_injuries_at(player, {"torso", "chest", "ribs", "stomach", "side"})
    for i, injury in ipairs(torso_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury, i)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_arms(player, registry)
    local parts = {}

    -- Arm injuries
    local arm_injuries = get_injuries_at(player, {"left arm", "right arm", "arm"})
    for i, injury in ipairs(arm_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury, i)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_hands(player, registry)
    local parts = {}
    local hand_names = { "left", "right" }

    -- Held items
    for i, hand_slot in ipairs(player.hands or {}) do
        if hand_slot then
            local obj = resolve_obj(hand_slot, registry)
            if obj then
                parts[#parts + 1] = "your " .. hand_names[i] .. " hand grips " .. (obj.name or "something")
            else
                parts[#parts + 1] = "your " .. hand_names[i] .. " hand grips something"
            end
        end
    end

    -- Hand injuries
    local hand_injuries = get_injuries_at(player, {"hand", "fingers", "wrist"})
    for i, injury in ipairs(hand_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury, i)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_legs(player, registry)
    local parts = {}

    -- Leg injuries
    local leg_injuries = get_injuries_at(player, {"left leg", "right leg", "leg"})
    for i, injury in ipairs(leg_injuries) do
        parts[#parts + 1] = render_injury_phrase(injury, i)
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_feet(player, registry)
    local parts = {}

    -- Worn footwear
    if player.worn then
        for _, worn_id in ipairs(player.worn) do
            local obj = resolve_obj(worn_id, registry)
            if obj and get_wear_slot(obj) == "feet" then
                if obj.appearance and obj.appearance.worn_description then
                    parts[#parts + 1] = obj.appearance.worn_description
                else
                    parts[#parts + 1] = (obj.name or "boots") .. " cover your feet"
                end
            end
        end
    end

    if #parts == 0 then return nil end
    return compose_natural(parts)
end

local function render_overall(player)
    local parts = {}

    -- Health-based pallor
    local inj_ok, injury_mod = pcall(require, "engine.injuries")
    local health = player.max_health or 100
    if inj_ok and injury_mod then
        health = injury_mod.compute_health(player)
    end
    local pct = health / (player.max_health or 100)

    if pct <= 0.25 then
        parts[#parts + 1] = "your skin is deathly pale, eyes sunken"
    elseif pct <= 0.50 then
        parts[#parts + 1] = "you look pale and unsteady"
    elseif pct <= 0.75 then
        parts[#parts + 1] = "you look a bit worn but standing"
    else
        parts[#parts + 1] = "you appear healthy and alert"
    end

    -- Global blood state
    if player.state and player.state.bloody then
        parts[#parts + 1] = "dried blood stains your skin"
    end

    if #parts == 0 then return nil end
    -- Issue #95: Use semicolons when phrases already contain "and"
    if #parts == 1 then return parts[1] end
    return table.concat(parts, "; ")
end
---------------------------------------------------------------------------

--- Compose a natural language description of a player's appearance.
--- @param player table — player state table (hands, worn, injuries, max_health)
--- @param registry table|nil — object registry for resolving IDs
--- @return string — composed description (multi-sentence, natural English)
function appearance.describe(player, registry)
    -- Guard: unconscious player can't see their reflection
    if player.consciousness
       and (player.consciousness.state == "unconscious"
         or player.consciousness.state == "waking") then
        return "You can't examine yourself — you're unconscious."
    end

    local layers = {
        render_head,
        render_torso,
        render_arms,
        render_hands,
        render_legs,
        render_feet,
    }

    local phrases = {}
    for _, renderer in ipairs(layers) do
        local phrase = renderer(player, registry)
        if phrase then
            phrases[#phrases + 1] = phrase
        end
    end

    -- Overall health (separate — it's a summary, not a body part)
    local overall = render_overall(player)
    if overall then
        phrases[#phrases + 1] = overall
    end

    if #phrases == 0 then
        return "Your reflection shows an unremarkable figure in plain clothes, unharmed and unburdened."
    end

    -- Capitalize first letter of composed description
    -- Issue #91: strip trailing periods from each phrase before joining
    for i, p in ipairs(phrases) do
        phrases[i] = p:gsub("[%.]+$", "")
    end
    local desc = table.concat(phrases, ". ")
    -- Issue #30: Capitalize first letter after every ". " separator
    desc = desc:gsub("%.%s+(%l)", function(c) return ". " .. c:upper() end)
    desc = desc:sub(1, 1):upper() .. desc:sub(2)
    if not desc:match("[%.!?]$") then desc = desc .. "." end

    return "In the mirror, you see: " .. desc
end

---------------------------------------------------------------------------
-- Test exports
---------------------------------------------------------------------------
appearance._render_head = render_head
appearance._render_torso = render_torso
appearance._render_arms = render_arms
appearance._render_hands = render_hands
appearance._render_legs = render_legs
appearance._render_feet = render_feet
appearance._render_overall = render_overall
appearance._get_injuries_at = get_injuries_at
appearance._render_injury_phrase = render_injury_phrase
appearance._compose_natural = compose_natural

return appearance

end

package.preload["engine.registry"] = function()
-- engine/registry/init.lua
-- The universe's object store: id -> live object table.
-- Every live object in a universe is registered here.
-- Supports weight tracking and category-based queries.

local registry = {}
registry.__index = registry

-- normalize_guid(guid) -> string
-- Strips braces from GUIDs to handle both "{abc-123}" and "abc-123" formats.
local function normalize_guid(guid)
  if type(guid) ~= "string" then return guid end
  return guid:gsub("^%{(.-)%}$", "%1")
end

-- new() -> registry instance
function registry.new()
  return setmetatable({ _objects = {}, _guid_index = {} }, registry)
end

-- register(id, object) -- adds or replaces an object; stamps the id onto the object.
-- Also indexes by guid if the object has one.
function registry:register(id, object)
  assert(type(id) == "string" and id ~= "", "registry: id must be a non-empty string")
  assert(type(object) == "table", "registry: object must be a table")
  object.id = id
  self._objects[id] = object
  if type(object.guid) == "string" and object.guid ~= "" then
    self._guid_index[normalize_guid(object.guid)] = id
  end
end

-- get(id) -> object | nil
function registry:get(id)
  return self._objects[id]
end

-- find_by_guid(guid) -> object | nil
-- Looks up an object by its definition guid using the guid index.
function registry:find_by_guid(guid)
  local id = self._guid_index[normalize_guid(guid)]
  if id then return self._objects[id] end
  return nil
end

-- remove(id) -> removed object | nil
function registry:remove(id)
  local obj = self._objects[id]
  if obj and type(obj.guid) == "string" then
    self._guid_index[normalize_guid(obj.guid)] = nil
  end
  self._objects[id] = nil
  return obj
end

-- list() -> array of all live objects (order undefined)
function registry:list()
  local result = {}
  for _, obj in pairs(self._objects) do
    result[#result + 1] = obj
  end
  return result
end

-- find_by_keyword(keyword) -> first matching object | nil
-- Matches against object.keywords (array of strings) and object.name.
-- BUG-056: also tries singular forms of plural nouns.
function registry:find_by_keyword(keyword)
  local preprocess = require("engine.parser.preprocess")
  local kw = keyword:lower()
  local candidates = { kw }
  for _, s in ipairs(preprocess.singularize(kw)) do
    candidates[#candidates + 1] = s
  end
  for _, try_kw in ipairs(candidates) do
    for _, obj in pairs(self._objects) do
      if obj.name and obj.name:lower() == try_kw then
        return obj
      end
      if type(obj.keywords) == "table" then
        for _, k in ipairs(obj.keywords) do
          if k:lower() == try_kw then return obj end
        end
      end
    end
  end
  return nil
end

-- find_by_category(category) -> array of matching objects
-- Returns all objects that have the given category in their categories list.
function registry:find_by_category(category)
  local result = {}
  local cat = category:lower()
  for _, obj in pairs(self._objects) do
    if type(obj.categories) == "table" then
      for _, c in ipairs(obj.categories) do
        if c:lower() == cat then
          result[#result + 1] = obj
          break
        end
      end
    end
  end
  return result
end

-- total_weight(location_id) -> number
-- Sums the weight of all objects at a given location.
-- Useful for room weight limits or structural checks.
function registry:total_weight(location_id)
  local total = 0
  for _, obj in pairs(self._objects) do
    if obj.location == location_id then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

-- contents_weight(container_id, surface_name) -> number
-- Sums the weight of all objects inside a container (or a specific surface).
function registry:contents_weight(container_id, surface_name)
  local container_obj = self._objects[container_id]
  if not container_obj then return 0 end

  local contents = {}
  if surface_name and container_obj.surfaces and container_obj.surfaces[surface_name] then
    contents = container_obj.surfaces[surface_name].contents or {}
  else
    contents = container_obj.contents or {}
  end

  local total = 0
  for _, item_id in ipairs(contents) do
    local obj = self._objects[item_id]
    if obj then
      total = total + (obj.weight or 0)
    end
  end
  return total
end

return registry

end

package.preload["engine.search.containers"] = function()
-- engine/search/containers.lua
-- Container interaction during search: detection, opening, locking.
-- Reuses existing container logic, thin wrapper.
--
-- Ownership: Bart (Architect)

local containers = {}

---------------------------------------------------------------------------
-- Container detection and state checks
---------------------------------------------------------------------------

--- Check if object is a container
-- @param object object instance
-- @return boolean
function containers.is_container(object)
    if not object then return false end
    if object.is_container == true or object.container == true then
        return true
    end
    -- BUG-125 (#33): Also check the categories array for "container"
    if object.categories then
        for _, cat in ipairs(object.categories) do
            if cat == "container" then return true end
        end
    end
    return false
end

--- Check if container is locked
-- @param object object instance
-- @return boolean
function containers.is_locked(object)
    if not object then return false end
    return object.is_locked == true or object.locked == true
end

--- Check if container is open
-- @param object object instance
-- @return boolean
function containers.is_open(object)
    if not object then return false end
    -- Default to open if not explicitly closed
    if object.is_open ~= nil then
        return object.is_open
    end
    if object.open ~= nil then
        return object.open
    end
    -- For containers, default to closed unless specified
    if containers.is_container(object) then
        return false
    end
    return true
end

--- Check if container can be auto-opened during search
-- @param object object instance
-- @return boolean
function containers.can_auto_open(object)
    if not containers.is_container(object) then
        return false
    end
    if containers.is_locked(object) then
        return false
    end
    if containers.is_open(object) then
        return false  -- Already open
    end
    return true
end

---------------------------------------------------------------------------
-- Container manipulation
---------------------------------------------------------------------------

--- Open a container (if unlocked)
-- @param ctx game context
-- @param object object instance
-- @return {success: boolean, narrative: string}
function containers.open(ctx, object)
    if containers.is_locked(object) then
        return {
            success = false,
            narrative = "It's locked."
        }
    end
    
    if containers.is_open(object) then
        return {
            success = false,
            narrative = "It's already open."
        }
    end
    
    -- Open it
    object.is_open = true
    object.open = true
    object.accessible = true
    
    -- Apply FSM transition if available
    local fsm_ok, fsm_mod = pcall(require, "engine.fsm")
    if fsm_ok and fsm_mod and object._state and ctx.registry then
        local trans, err = fsm_mod.transition(ctx.registry, object.id, "open", nil, "open")
        if not trans and object.states and object.states.open then
            -- Manual state transition (no matching FSM transition found)
            fsm_mod.stop_timer(object.id)
            object._state = "open"
            fsm_mod.start_timer(ctx.registry, object.id)
        end
    end
    
    return {
        success = true,
        narrative = ""  -- Narrator will generate the message
    }
end

--- Get container contents
-- @param object object instance
-- @param registry registry instance
-- @return list of object IDs
function containers.get_contents(object, registry)
    if not object then return {} end
    
    local contents = {}
    
    -- Check various content fields
    if object.contents then
        if type(object.contents) == "table" then
            for _, item_id in ipairs(object.contents) do
                contents[#contents + 1] = item_id
            end
        end
    end
    
    if object.contains then
        if type(object.contains) == "table" then
            for _, item_id in ipairs(object.contains) do
                contents[#contents + 1] = item_id
            end
        end
    end
    
    return contents
end

return containers

end

package.preload["engine.search.goals"] = function()
-- engine/search/goals.lua
-- Goal-oriented matching: "find something that can light"
-- Property-based implementation (simpler, faster).
-- GOAP-based approach can be added later if needed.
--
-- Ownership: Bart (Architect)

local goals = {}

---------------------------------------------------------------------------
-- Goal query parsing
---------------------------------------------------------------------------

--- Parse goal-oriented query
-- @param query string (e.g., "something that can light the candle")
-- @return {type: "action", value: "light", context: "candle"} or nil
function goals.parse_goal(query)
    if not query then return nil end
    
    local lower = query:lower()
    
    -- Pattern: "something that can [action]"
    local action = lower:match("something that can (%w+)")
    if action then
        -- Check for context: "something that can [action] [context]"
        local full_action, context = lower:match("something that can (%w+)%s+(.+)")
        if full_action and context then
            return {
                type = "action",
                value = full_action,
                context = context,
                original_query = query,
            }
        end
        return {
            type = "action",
            value = action,
            context = nil,
            original_query = query,
        }
    end
    
    -- Pattern: "something [property]"
    local property = lower:match("something (%w+)")
    if property then
        return {
            type = "property",
            value = property,
            context = nil,
            original_query = query,
        }
    end
    
    -- Pattern: "something to [verb]"
    local verb = lower:match("something to (%w+)")
    if verb then
        return {
            type = "action",
            value = verb,
            context = nil,
            original_query = query,
        }
    end
    
    return nil
end

---------------------------------------------------------------------------
-- Goal matching (property-based)
---------------------------------------------------------------------------

--- Check if object matches goal
-- @param object object to check
-- @param goal_type "action" | "property"
-- @param goal_value e.g., "light" | "sharp"
-- @param registry registry instance
-- @return boolean
function goals.matches_goal(object, goal_type, goal_value, registry)
    if not object or not goal_type or not goal_value then
        return false
    end
    
    if goal_type == "property" then
        -- Property matching: check is_[property] flag
        local prop_key = "is_" .. goal_value
        if object[prop_key] == true then
            return true
        end
        
        -- Also check direct property
        if object[goal_value] == true then
            return true
        end
        
        return false
    end
    
    if goal_type == "action" then
        -- Action matching: check if object can perform action
        
        -- 1. Check fire_source for lighting actions
        if goal_value == "light" or goal_value == "ignite" or goal_value == "burn" then
            if object.fire_source == true then
                return true
            end
            -- Check if object has "light" action
            if object.actions then
                for _, action in ipairs(object.actions) do
                    if action == "light" or action == "ignite" then
                        return true
                    end
                end
            end
        end
        
        -- 2. Check if object has the action in its actions list
        if object.actions then
            for _, action in ipairs(object.actions) do
                if action == goal_value then
                    return true
                end
            end
        end
        
        -- 3. Check verbs table
        if object.verbs then
            for verb_name, _ in pairs(object.verbs) do
                if verb_name == goal_value then
                    return true
                end
            end
        end
        
        return false
    end
    
    return false
end

---------------------------------------------------------------------------
-- Future: GOAP-based matching
---------------------------------------------------------------------------

-- GOAP-based matching would use the existing GOAP planner to check
-- if an object can achieve a goal through a sequence of actions.
-- This is more flexible but computationally heavier.
--
-- Example implementation (commented out for now):
--[[
function goals.matches_goal_goap(object, goal_type, goal_value, registry, ctx)
    if goal_type ~= "action" then
        return false
    end
    
    -- Try to plan: can we use this object to achieve the goal?
    local goap_ok, goap = pcall(require, "engine.goap")
    if not goap_ok then
        return false
    end
    
    local goal_state = { [goal_value] = true }
    local plan = goap.plan(ctx, goal_state, object)
    
    return plan ~= nil and #plan > 0
end
]]--

return goals

end

