-- Narrative templates
---------------------------------------------------------------------------

-- BUG-088: Templates use {object} directly — format_object_name adds articles
local STEP_TEMPLATES = {
    vision = {
        "Your eyes scan {object} — nothing notable.",
        "You look at {object}. Nothing interesting.",
        "You glance at {object}. Nothing there.",
    },
    touch = {
        "You feel {object} — nothing there.",
        "Your fingers explore {object}. Nothing.",
        "You reach out to {object}. Nothing.",
    },
}

local CONTAINER_OPEN_TEMPLATES = {
    touch = {
        "It has a drawer... you pull it open.",
        "You find a compartment. You open it.",
        "It has a container. You open it.",
    },
}

local CONTAINER_LOCKED_TEMPLATES = {
    touch = {
        "You find it's locked. You can't open it without a key.",
        "It's locked tight.",
        "You try to open it, but it's locked.",
    },
    vision = {
        "You spot a lock. It's secured.",
        "It's locked.",
        "You notice it's locked.",
    },
}

local FOUND_TEMPLATES = {
    touch = {
        "You feel: {item}.",
        "Your fingers find: {item}.",
    },
    vision = {
        "You spot: {item}.",
        "You see: {item}.",
        "You notice: {item}.",
    },
}

--- Format object name for narrative
-- @param object object instance
-- @return string
local function format_object_name(object)
    if not object then return "something" end
    
    local name = object.name or object.id or "object"
    
    -- BUG-088: Don't add article if name already has one
    if not name:match("^[Tt]he ") and not name:match("^[Aa]n? ") then
        -- Only add article if name doesn't start with an article-like word
        local lower_name = name:lower()
        if not lower_name:match("^the ") and not lower_name:match("^a ") and not lower_name:match("^an ") then
            local first_char = name:sub(1, 1):lower()
            if first_char == "a" or first_char == "e" or first_char == "i" or first_char == "o" or first_char == "u" then
                name = "an " .. name
            else
                name = "a " .. name
            end
        end
    end
    
    return name
end

---------------------------------------------------------------------------
-- Helpers for #63/#64/#65
---------------------------------------------------------------------------

--- Strip leading article from a name
local function strip_article(name)
    return name:gsub("^[Aa]n? ", ""):gsub("^[Tt]he ", "")
end

--- Simple English pluralisation (covers common game-object nouns)
local function pluralize(name)
    if name:match("ch$") or name:match("sh$") or name:match("x$") or name:match("ss$") then
        return name .. "es"
    elseif name:match("y$") and not name:match("[aeiou]y$") then
        return name:sub(1, -2) .. "ies"
    else
        return name .. "s"
    end
end

--- Look up the part that maps to a given surface name on the parent (#64)
local function get_part_for_surface(parent, surface_name)
    if not parent or not parent.parts then return nil end
    for _, part in pairs(parent.parts) do
        if part.surface == surface_name then
            return part
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Public API
---------------------------------------------------------------------------

--- Generate narrative for a search step (nothing found)
-- @param ctx game context
-- @param object current object being searched
-- @param found_target was the target found? (boolean)
-- @return string (prose output)
function narrator.step_narrative(ctx, object, found_target)
    if found_target then
        return ""  -- Handled by found_target()
    end
    
    local sense = get_primary_sense(ctx, ctx.current_room)
    local templates = STEP_TEMPLATES[sense] or STEP_TEMPLATES.touch
    
    -- Pick a template (simple rotation for now)
    local template = templates[1]
    
    -- Format object name
    local obj_name = format_object_name(object)
    
    -- Substitute
    local narrative = template:gsub("{object}", obj_name)
    
    return narrative
end

--- #385: Enumerate object during undirected room sweep.
-- Brief one-liner listing the object, without "nothing there" suffix.
-- @param ctx game context
-- @param object discovered object
-- @return string
function narrator.enumerate_room_object(ctx, object)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local name = format_object_name(object)
    if sense == "touch" then
        return "  " .. name
    else
        return "  " .. name
    end
end

--- Generate narrative for container open
-- @param ctx game context
-- @param container container being opened
-- @return string
function narrator.container_open(ctx, container)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local templates = CONTAINER_OPEN_TEMPLATES[sense] or CONTAINER_OPEN_TEMPLATES.touch
    
    local template = templates[1]
    return template
end

--- Generate narrative for locked container
-- @param ctx game context
-- @param container locked container
-- @return string
function narrator.container_locked(ctx, container)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local templates = CONTAINER_LOCKED_TEMPLATES[sense] or CONTAINER_LOCKED_TEMPLATES.touch
    
    local template = templates[1]
    return template
end

--- Generate narrative for target found
-- @param ctx game context
-- @param item found item
-- @param container container it was found in (or nil)
-- @return string
function narrator.found_target(ctx, item, container)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local templates = FOUND_TEMPLATES[sense] or FOUND_TEMPLATES.touch
    
    local template = templates[1]
    
    -- Format item name
    local item_name = format_object_name(item)
    
    -- Substitute
    local narrative = template:gsub("{item}", item_name)
    
    return narrative
end

--- Generate narrative for peeking inside a container without opening (#24)
-- Bug #47: sensory-aware — uses touch language in darkness
-- @param ctx game context
-- @param container container being peeked into
-- @return string
function narrator.container_peek(ctx, container)
    local name = container.name or container.id or "it"
    -- Strip leading article for "the" prefix
    local display = name:gsub("^[Aa]n? ", ""):gsub("^[Tt]he ", "")
    local sense = get_primary_sense(ctx, ctx.current_room)
    if sense == "touch" then
        return "You feel around inside the " .. display .. "."
    end
    return "You check inside the " .. display .. "."
end

--- Generate narrative for container contents when target not found (#27)
-- Bug #47: sensory-aware — uses feel/touch language in darkness
-- @param ctx game context
-- @param container container that was checked
-- @param items list of item name strings found inside
-- @param target string the player was searching for
-- @return string
function narrator.container_contents_no_target(ctx, container, items, target)
    local name = container.name or container.id or "it"
    local display = name:gsub("^[Aa]n? ", ""):gsub("^[Tt]he ", "")
    local sense = get_primary_sense(ctx, ctx.current_room)
    local see_word = sense == "touch" and "you feel" or "you see"
    if #items == 0 then
        if target then
            return "You check inside the " .. display .. ". It's empty. No " .. target .. " here."
        else
            return "You check inside the " .. display .. ". It's empty."
        end
    else
        -- #65: aggregate duplicate items for natural narration
        local agg = narrator.aggregate_items(items)
        local list = table.concat(agg, ", ")
        if target then
            return "You check inside the " .. display .. ". Inside " .. see_word .. " " .. list .. ", but no " .. target .. "."
        else
            return "You check inside the " .. display .. ". Inside " .. see_word .. " " .. list .. "."
        end
    end
end

--- Generate narrative for search completion (exhausted)
-- @param ctx game context
-- @param found_items list of discovered objects
-- @param target what was being searched for
-- @return string
function narrator.completion(ctx, found_items, target)
    if target then
        return "You finish searching but didn't find anything matching that. Try 'search' to see everything in the area."
    else
        if #found_items > 0 then
            return "You finish searching the area."
        else
            return "You finish searching the area thoroughly, but didn't find anything new. Try 'look' to get your bearings."
        end
    end
end

--- Generate narrative for search interruption
-- @param ctx game context
-- @param steps_taken number
-- @return string
function narrator.interruption(ctx, steps_taken)
    return "[Search interrupted]"
end

--- Generate narrative when a direct part search hits a closed/inaccessible surface (#41)
-- @param ctx game context
-- @param surface_name string (e.g., "inside")
-- @param parent object that owns the part
-- @return string
function narrator.part_closed(ctx, surface_name, parent)
    local name = parent and parent.name or "it"
    local display = name:gsub("^[Aa]n? ", ""):gsub("^[Tt]he ", "")
    return "The drawer is closed. You need to open it first."
end

--- Resolve a human-friendly part name.
-- If the parent object has parts, find the part that maps to this surface.
-- e.g. nightstand surface "inside" → part with surface="inside" → "drawer"
local function resolve_part_display(surface_name, parent)
    if parent and parent.parts and surface_name then
        -- First try: find a part with matching surface mapping
        for key, part in pairs(parent.parts) do
            if part.surface == surface_name then
                return key
            end
        end
        -- Second try: find a part with matching key
        if parent.parts[surface_name] then
            local part = parent.parts[surface_name]
            return part.name or surface_name
        end
        -- Third try: use the first available part name (more descriptive than
        -- a generic spatial term like "inside")
        for key, part in pairs(parent.parts) do
            return part.name or key
        end
    end
    return surface_name or "compartment"
end

--- Generate narrative for direct part search contents (#41, #47)
-- @param ctx game context
-- @param surface_name string
-- @param parent object
-- @param items list of item name strings
-- @return string
function narrator.part_contents(ctx, surface_name, parent, items)
    if #items == 0 then
        return narrator.part_empty(ctx, surface_name, parent)
    end
    local list = table.concat(items, ", ")
    local room = ctx and ctx.current_room
    local sense = get_primary_sense(ctx, room)
    local part = resolve_part_display(surface_name, parent)
    local verb = (sense == "touch") and "feel" or "find"
    return "You rummage through the " .. part .. " and " .. verb .. ": " .. list .. "."
end

--- Generate narrative for empty direct part search (#41, #47)
-- @param ctx game context
-- @param surface_name string
-- @param parent object
-- @return string
function narrator.part_empty(ctx, surface_name, parent)
    local part = resolve_part_display(surface_name, parent)
    return "You rummage through the " .. part .. ". It is empty."
end

---------------------------------------------------------------------------
-- #63: Surface-aware content narration
---------------------------------------------------------------------------

--- Aggregate duplicate item names into counted descriptions (#65)
-- "a wooden match" x7 → "several wooden matches"
-- @param items list of item name strings
-- @return list of aggregated name strings
function narrator.aggregate_items(items)
    local counts = {}
    local order = {}
    for _, name in ipairs(items) do
        if not counts[name] then
            counts[name] = 0
            order[#order + 1] = name
        end
        counts[name] = counts[name] + 1
    end
    local result = {}
    for _, name in ipairs(order) do
        local count = counts[name]
        if count == 1 then
            result[#result + 1] = name
        else
            local base = strip_article(name)
            local plural = pluralize(base)
            if count == 2 then
                result[#result + 1] = "a couple of " .. plural
            else
                result[#result + 1] = "several " .. plural
            end
        end
    end
    return result
end

--- Generate narration for surface contents, distinguishing "top" from "inside" (#63, #96)
-- @param ctx game context
-- @param surface_name string ("top", "inside", etc.)
-- @param parent object that owns the surface
-- @param items list of item name strings
-- @param target string or nil — when set, appends "but no <target>" suffix
-- @return string
function narrator.surface_contents(ctx, surface_name, parent, items, target)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local agg = narrator.aggregate_items(items)
    local list = table.concat(agg, ", ")
    local parent_display = strip_article(parent.name or parent.id or "it")
    local suffix = target and (", but no " .. target) or ""

    -- #96: Resolve part name for "inside" surfaces (e.g., "drawer" instead of "nightstand")
    local container_display = parent_display
    if surface_name ~= "top" then
        local part_name = resolve_part_display(surface_name, parent)
        if part_name and part_name ~= surface_name then
            container_display = part_name
        end
    end

    if surface_name == "top" then
        if sense == "touch" then
            return "On top of the " .. parent_display .. ", you feel: " .. list .. suffix .. "."
        else
            return "On top of the " .. parent_display .. ", you find: " .. list .. suffix .. "."
        end
    else
        -- #96: Always include container name in "inside" narration
        if sense == "touch" then
            return "Inside the " .. container_display .. ", you feel: " .. list .. suffix .. "."
        else
            return "Inside the " .. container_display .. ", you find: " .. list .. suffix .. "."
        end
    end
end

---------------------------------------------------------------------------
-- #64: Container discovery / opening narration
---------------------------------------------------------------------------

--- Generate narration for discovering and opening a container part during search (#64)
-- @param ctx game context
-- @param part_name string — display name of the part (e.g., "a small drawer")
-- @return string
function narrator.container_opening(ctx, part_name)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local name = part_name or "a container"
    if sense == "touch" then
        return "You feel " .. name .. ". You pull it open."
    else
        return "You see " .. name .. ". You open it."
    end
end

--- Generate narration for the contents found inside a container part (#64)
-- @param ctx game context
-- @param part object or part table with .name
-- @param items list of item name strings
-- @return string
function narrator.container_part_contents(ctx, part, items)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local agg = narrator.aggregate_items(items)
    local list = table.concat(agg, ", ")
    local display = strip_article(part.name or part.id or "it")
    if sense == "touch" then
        return "Inside the " .. display .. ", you feel: " .. list .. "."
    else
        return "Inside the " .. display .. ", you find: " .. list .. "."
    end
end

--- Generate narration for opening a nested container found during search (#64)
-- @param ctx game context
-- @param container object
-- @return string
function narrator.nested_container_opening(ctx, container)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local name = strip_article(container.name or container.id or "it")
    if sense == "touch" then
        return "You open the " .. name .. "."
    else
        return "You open the " .. name .. "."
    end
end

--- Generate narration for nested container contents (#64, #65, #96)
-- @param ctx game context
-- @param container object
-- @param items list of item name strings
-- @return string
function narrator.nested_container_contents(ctx, container, items)
    local sense = get_primary_sense(ctx, ctx.current_room)
    local agg = narrator.aggregate_items(items)
    local list = table.concat(agg, ", ")
    -- #96: Include container name
    local display = strip_article(container.name or container.id or "it")
    if sense == "touch" then
        return "Inside the " .. display .. ", you feel: " .. list .. "."
    else
        return "Inside the " .. display .. ", you find: " .. list .. "."
    end
end

return narrator

end

package.preload["engine.search.traverse"] = function()
-- engine/search/traverse.lua
-- Walk algorithm: proximity ordering, step-by-step traversal.
--
-- Ownership: Bart (Architect)

local traverse = {}

local containers = require("engine.search.containers")
local narrator = require("engine.search.narrator")
local goals = require("engine.search.goals")

---------------------------------------------------------------------------
-- #384: Search peeks into containers without changing open/closed state.
-- Opens the container to mark surfaces accessible, then immediately
-- restores is_open/open/_state so the container appears unchanged.
---------------------------------------------------------------------------
local function peek_open(ctx, obj)
    local saved_is_open = obj.is_open
    local saved_open = obj.open
    local saved_state = obj._state
    containers.open(ctx, obj)
    obj.is_open = saved_is_open
    obj.open = saved_open
    if saved_state ~= nil then obj._state = saved_state end
end

---------------------------------------------------------------------------
-- Build search queue from room proximity list
---------------------------------------------------------------------------

--- Get proximity-ordered list for a room
-- @param room room object
-- @return ordered list of object IDs
function traverse.get_proximity_list(room)
    if room.proximity_list then
        return room.proximity_list
    end
    
    -- Fallback: use room contents in definition order
    if room.contents then
        return room.contents
    end
    
    return {}
end

--- Expand an object into searchable surfaces and containers
-- @param object_id string
-- @param registry registry instance
-- @param depth number (current nesting depth)
-- @param include_nested_containers boolean (true when scope search)
-- @return list of queue entries
local function expand_object(object_id, registry, depth, include_nested_containers, visited)
    depth = depth or 0
    include_nested_containers = include_nested_containers or false
    visited = visited or {}

    -- Cycle detection: skip objects already expanded in this traversal.
    -- Containment is a tree by design, but a visited set protects against
    -- data bugs (e.g., circular contents references) without magic constants.
    if visited[object_id] then
        return {}
    end
    visited[object_id] = true

    -- Secondary safety belt: max depth 3 matches the data model
    -- (room → furniture → container → item = 3 levels)
    if depth > 3 then
        return {}
    end
    
    local obj = registry:get(object_id)
    if not obj then
        return {}
    end

    -- Spatial visibility: hidden objects are invisible to search (#26)
    if obj.hidden then
        return {}
    end
    
    local entries = {}
    
    -- Add the object itself as a searchable entry
    entries[#entries + 1] = {
        object_id = object_id,
        type = "object",
        depth = depth,
        parent_id = nil,
        is_container = containers.is_container(obj),
        is_locked = containers.is_locked(obj),
        is_open = containers.is_open(obj),
        surface_name = nil,
    }
    
    -- Expand surfaces first (if object has surfaces)
    -- Sort surface names for deterministic ordering: "top" before "inside"
    -- (physically correct — you'd examine the top before opening drawers)
    if obj.surfaces then
        local surface_names = {}
        for name, _ in pairs(obj.surfaces) do
            surface_names[#surface_names + 1] = name
        end
        table.sort(surface_names, function(a, b)
            if a == "top" then return true end
            if b == "top" then return false end
            return a < b
        end)
        for _, surface_name in ipairs(surface_names) do
            local surface_data = obj.surfaces[surface_name]
            -- Skip if surface_data is just a list (treat as contents)
            if type(surface_data) == "table" and surface_data.contents then
                entries[#entries + 1] = {
                    object_id = object_id .. "_" .. surface_name,
                    type = "surface",
                    depth = depth,
                    parent_id = object_id,
                    is_container = false,
                    is_locked = false,
                    is_open = true,
                    surface_name = surface_name,
                }
            end
        end
    end
    
    -- #85: Expand root container contents into the search queue.
    -- Objects with surfaces (e.g., nightstand) may also have root `contents`
    -- holding nested containers (e.g., the drawer). The surface branch in
    -- traverse.step only checks surface contents, not root contents, so these
    -- children must be queued explicitly.  Without this, "find match" never
    -- visits the nightstand drawer (which holds the matchbox with matches).
    -- Skip items already in a surface to avoid double-processing.
    if obj.surfaces then
        local surface_ids = {}
        for _, zone in pairs(obj.surfaces) do
            for _, sid in ipairs(zone.contents or {}) do
                surface_ids[sid] = true
            end
        end
        local root_contents = containers.get_contents(obj, registry)
        for _, child_id in ipairs(root_contents) do
            if not surface_ids[child_id] then
                local child = registry:get(child_id)
                if child then
                    local child_entries = expand_object(child_id, registry, depth + 1, include_nested_containers, visited)
                    for _, child_entry in ipairs(child_entries) do
                        entries[#entries + 1] = child_entry
                    end
                end
            end
        end
    end

    -- BUG-075: Then expand nested containers (recursive) when doing a scoped search
    if include_nested_containers and containers.is_container(obj) then
        -- Get the sub-containers (e.g., drawers inside nightstand)
        local contents = containers.get_contents(obj, registry)
        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child and containers.is_container(child) then
                -- Recursively expand nested containers
                local child_entries = expand_object(child_id, registry, depth + 1, include_nested_containers, visited)
                for _, child_entry in ipairs(child_entries) do
                    entries[#entries + 1] = child_entry
                end
            end
        end
    end
    
    return entries
end

--- Build a search queue from room proximity list
-- @param room room object
-- @param scope object ID or nil
-- @param target search target or nil
-- @param registry registry instance
-- @param part_surface string or nil (#41: restrict to this surface when searching a part)
-- @return ordered list of queue entries
function traverse.build_queue(room, scope, target, registry, part_surface)
    local queue = {}
    
    -- Get proximity-ordered object list
    local proximity_list = traverse.get_proximity_list(room)
    
    -- If scope provided, filter to just that object
    local search_list = proximity_list
    local include_nested_containers = false
    if scope then
        search_list = {}
        for _, obj_id in ipairs(proximity_list) do
            if obj_id == scope then
                search_list[#search_list + 1] = obj_id
                -- BUG-075: When searching a specific object, include nested containers
                include_nested_containers = true
                break
            end
        end
        -- BUG-082: If scope not found in proximity list, check parts of room objects
        -- This handles sub-components (e.g., "drawer" is a part of nightstand)
        if #search_list == 0 and registry then
            for _, obj_id in ipairs(proximity_list) do
                local obj = registry:get(obj_id)
                if obj and obj.parts then
                    for part_key, part in pairs(obj.parts) do
                        if part.id == scope or part_key == scope then
                            -- Use the parent object but with nested containers enabled
                            search_list[#search_list + 1] = obj_id
                            include_nested_containers = true
                            -- #41: Use the part's surface mapping if not already set
                            if not part_surface and part.surface then
                                part_surface = part.surface
                            end
                            break
                        end
                    end
                    if #search_list > 0 then break end
                end
            end
        end
        -- #377: If still not found, check surface contents of room objects.
        -- This handles child objects (e.g., pillow on top of bed) that aren't
        -- in the proximity list directly but are registered and findable.
        if #search_list == 0 and registry then
            for _, obj_id in ipairs(proximity_list) do
                local obj = registry:get(obj_id)
                if obj and obj.surfaces then
                    for _, surf_data in pairs(obj.surfaces) do
                        if type(surf_data) == "table" and surf_data.contents then
                            for _, child_id in ipairs(surf_data.contents) do
                                if child_id == scope then
                                    search_list[#search_list + 1] = child_id
                                    include_nested_containers = true
                                    break
                                end
                            end
                        end
                        if #search_list > 0 then break end
                    end
                end
                if #search_list > 0 then break end
            end
        end
    end
    
    -- Expand each object into searchable entries
    for _, obj_id in ipairs(search_list) do
        local entries = expand_object(obj_id, registry, 0, include_nested_containers)
        for _, entry in ipairs(entries) do
            -- #41: When part_surface is set, only include that specific surface
            -- and skip the parent object entry and other surfaces
            if part_surface then
                if entry.type == "surface" and entry.surface_name == part_surface then
                    entry.direct_part_search = true
                    queue[#queue + 1] = entry
                end
                -- Skip object entries and non-matching surfaces
            else
                queue[#queue + 1] = entry
            end
        end
    end
    
    return queue
end

---------------------------------------------------------------------------
-- Category synonym table (#68): map common search terms to category names
---------------------------------------------------------------------------
local CATEGORY_SYNONYMS = {
    clothing  = "wearable",
    clothes   = "wearable",
    garments  = "wearable",
    apparel   = "wearable",
    weapon    = "weapon",
    weapons   = "weapon",
    tools     = "tool",
    lights    = "light source",
    armor     = "armor",
    armour    = "armor",
    drinks    = "consumable",
    food      = "consumable",
}

--- Expose for tests
traverse.CATEGORY_SYNONYMS = CATEGORY_SYNONYMS

---------------------------------------------------------------------------
-- Exact-match helper (#74): does target match id/name/keyword exactly?
---------------------------------------------------------------------------
local function matches_exact(object, target)
    if not object or not target then return false end
    target = target:lower()
    target = target:gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
    if object.id  and object.id:lower()  == target then return true end
    if object.name and object.name:lower() == target then return true end
    if object.keywords then
        for _, kw in ipairs(object.keywords) do
            if kw:lower() == target then return true end
        end
    end
    return false
end

---------------------------------------------------------------------------
-- Direct-match helper (#84): matches the object itself (no child recursion)
-- Used for surface-parent objects where child matches are handled by
-- surface queue entries, not the parent object entry.
---------------------------------------------------------------------------
local function matches_direct(object, target)
    if not object or not target then return false end
    if object.hidden then return false end
    target = target:lower()
    target = target:gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
    if object.id and object.id:lower() == target then return true end
    if object.name and object.name:lower() == target then return true end
    if object.name and object.name:lower():find(target, 1, true) then return true end
    if object.keywords then
        for _, kw in ipairs(object.keywords) do
            if kw:lower() == target or kw:lower():find(target, 1, true) then return true end
        end
    end
    local cat_target = CATEGORY_SYNONYMS[target]
    if cat_target and object.categories then
        for _, cat in ipairs(object.categories) do
            if cat:lower() == cat_target then return true end
        end
    end
    return false
end

---------------------------------------------------------------------------
-- Process one step of traversal
---------------------------------------------------------------------------

--- Check if object matches target (fuzzy matching)
-- @param object object instance
-- @param target string
-- @param registry registry instance
-- @param depth number (recursion depth tracking)
-- @return boolean
local function matches_target(object, target, registry, depth, visited)
    depth = depth or 0
    visited = visited or {}
    
    if not object or not target then
        return false
    end

    -- Spatial visibility: hidden objects never match (#26)
    if object.hidden then
        return false
    end

    -- Cycle detection: skip objects already checked in this match walk.
    -- Prevents infinite recursion from circular containment references.
    local oid = object.id
    if oid and visited[oid] then
        return false
    end
    if oid then
        visited[oid] = true
    end

    -- Secondary safety belt: depth limit matches containment model depth
    if depth > 3 then
        return false
    end
    
    target = target:lower()
    -- BUG-081: Strip articles from target before matching
    target = target:gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
    
    -- Exact ID match
    if object.id and object.id:lower() == target then
        return true
    end
    
    -- Exact name match
    if object.name and object.name:lower() == target then
        return true
    end
    
    -- Substring match in name
    if object.name and object.name:lower():find(target, 1, true) then
        return true
    end
    
    -- Keyword match
    if object.keywords then
        for _, kw in ipairs(object.keywords) do
            if kw:lower() == target or kw:lower():find(target, 1, true) then
                return true
            end
        end
    end
    
    -- #68: Category synonym match — 'clothing' → objects with 'wearable' category
    local cat_target = CATEGORY_SYNONYMS[target]
    if cat_target and object.categories then
        for _, cat in ipairs(object.categories) do
            if cat:lower() == cat_target then
                return true
            end
        end
    end
    
    -- If object is container, check contents recursively (fuzzy)
    -- #84: Recurse into closed containers too — search peeks inside them
    if containers.is_container(object) then
        local contents = containers.get_contents(object, registry)
        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child and matches_target(child, target, registry, depth + 1, visited) then
                return true
            end
        end
    end
    
    return false
end

--- Peek inside a matched object for a more specific child match (#22, #74).
-- When search finds an object whose name/keyword matches the target via
-- substring (e.g., "candle holder" substring-matches "candle"), check whether
-- any child (container contents or composite parts) is an EXACT match.
-- If so, prefer the child.  Read-only: never mutates state (D-PEEK).
-- @param obj object that matched the target
-- @param target string search target
-- @param registry registry instance
-- @return child object if a deeper/exact match is found, nil otherwise
local function find_deeper_match(obj, target, registry)
    local contents = containers.get_contents(obj, registry)
    local has_children = #contents > 0 or obj.parts ~= nil

    if not has_children then return nil end

    -- Pass 1: exact match in container contents (highest confidence)
    for _, child_id in ipairs(contents) do
        local child = registry:get(child_id)
        if child and matches_exact(child, target) then
            return child
        end
    end

    -- Pass 2: exact match in composite parts via registry (#74)
    if obj.parts then
        for _, part_def in pairs(obj.parts) do
            if part_def.id then
                local part_obj = registry:get(part_def.id)
                if part_obj and matches_exact(part_obj, target) then
                    return part_obj
                end
            end
        end
    end

    -- Pass 3: any match in contents — recurse for deeper/exact match (#84)
    for _, child_id in ipairs(contents) do
        local child = registry:get(child_id)
        if child and matches_target(child, target, registry, 0) then
            local deeper = find_deeper_match(child, target, registry)
            if deeper then return deeper end
            return child
        end
    end

    return nil
end

--- Process one step of traversal
-- @param ctx game context
-- @param entry queue entry
-- @param target what we're looking for
-- @param is_goal_search boolean
-- @param goal_type string
-- @param goal_value string
-- @return result table {found: boolean, item: object or nil, continue: boolean, narrative: string}
function traverse.step(ctx, entry, target, is_goal_search, goal_type, goal_value)
    local registry = ctx.registry
    local room = ctx.current_room
    
    local result = {
        found = false,
        item = nil,
        continue = true,
        narrative = "",
    }
    
    -- BUG-075: Handle surface entries (e.g., nightstand's "inside" surface = drawer)
    if entry.type == "surface" and entry.parent_id and entry.surface_name then
        local parent = registry:get(entry.parent_id)
        if not parent then
            result.narrative = ""
            return result
        end
        
        -- Get current state's surfaces template (for accessibility check)
        -- But use parent's actual surfaces for contents (where items are)
        local surface_template = parent.surfaces and parent.surfaces[entry.surface_name]
        if parent._state and parent.states and parent.states[parent._state] then
            local state_obj = parent.states[parent._state]
            if state_obj.surfaces and state_obj.surfaces[entry.surface_name] then
                surface_template = state_obj.surfaces[entry.surface_name]
            end
        end
        
        -- Check if surface exists
        if not surface_template then
            result.narrative = ""
            return result
        end
        
        -- If surface is not accessible, check gating conditions
        if surface_template.accessible == false then
            -- #41: Direct part search (e.g., "search drawer") on closed surface
            -- should tell the player to open it first instead of peeking
            if entry.direct_part_search then
                result.narrative = narrator.part_closed(ctx, entry.surface_name, parent)
                return result
            end

            -- Check if parent is locked (via FSM state or container flag)
            local is_locked = containers.is_locked(parent)
            if is_locked then
                result.narrative = narrator.container_locked(ctx, parent)
                return result
            end

            -- Only open container surfaces (drawers, wardrobes, etc.)
            -- Non-container inaccessible surfaces (e.g., rug's "underneath")
            -- are truly hidden and can't be searched until made accessible (#26)
            if not containers.is_container(parent) then
                -- #377: Covering objects (rug) hide what's beneath — stay blocked
                if parent.covering then
                    result.narrative = ""
                    return result
                end
                -- #377: Non-covering non-containers (pillow) can be searched by
                -- feel/look. Peek into the surface without changing accessibility.
                local actual_surface = parent.surfaces and parent.surfaces[entry.surface_name]
                local peek_contents = actual_surface and actual_surface.contents or {}
                if #peek_contents > 0 then
                    if target and not is_goal_search then
                        for _, child_id in ipairs(peek_contents) do
                            local child = registry:get(child_id)
                            if child and matches_target(child, target, registry, 0) then
                                result.found = true
                                result.item = child
                                result.narrative = narrator.found_target(ctx, child, parent)
                                return result
                            end
                        end
                    elseif is_goal_search and goal_type and goal_value then
                        for _, child_id in ipairs(peek_contents) do
                            local child = registry:get(child_id)
                            if child and goals.matches_goal(child, goal_type, goal_value, registry) then
                                result.found = true
                                result.item = child
                                result.narrative = narrator.found_target(ctx, child, parent)
                                return result
                            end
                        end
                    else
                        -- Undirected: enumerate contents found by feel
                        local items = {}
                        for _, child_id in ipairs(peek_contents) do
                            local child = registry:get(child_id)
                            if child then
                                items[#items + 1] = child.name or child.id
                            end
                        end
                        if #items > 0 then
                            result.narrative = narrator.surface_contents(ctx, entry.surface_name, parent, items)
                        end
                    end
                end
                return result
            end

            -- #97/#98/#99: Actually open the container so items become
            -- accessible to subsequent take/get commands.
            surface_template.accessible = true
            local actual_surface_mut = parent.surfaces and parent.surfaces[entry.surface_name]
            if actual_surface_mut then
                actual_surface_mut.accessible = true
            end
            peek_open(ctx, parent)

            -- #97: Build opening narration line
            local open_part = nil
            if parent.parts then
                for _, p in pairs(parent.parts) do
                    if p.surface == entry.surface_name then
                        open_part = p; break
                    end
                end
            end
            local opening_line = open_part
                and narrator.container_opening(ctx, open_part.name or "a container")
                or narrator.container_opening(ctx, parent.name or "a container")

            -- Fall through to accessible-surface search below, prepending
            -- the opening narration to whatever the normal path produces.
            -- We mark this so the accessible path can prepend the opening line.
            entry._opening_narration = opening_line
        end
        
        -- Now surface is accessible - check its contents
        -- ALWAYS use parent.surfaces for contents (not state template)
        local actual_surface = parent.surfaces and parent.surfaces[entry.surface_name]
        local contents = actual_surface and actual_surface.contents or {}
        -- #97: Capture opening narration prefix if container was just opened
        local open_prefix = entry._opening_narration

        -- BUG-079: Undirected scoped search should enumerate surface contents
        if not target and not is_goal_search and #contents > 0 then
            local items = {}
            local nested_narration = {}
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    items[#items + 1] = child.name or child.id
                    -- #64: If child is a container, narrate opening and enumerate contents
                    if containers.is_container(child) then
                        -- #97: Also open nested containers during search
                        if containers.can_auto_open(child) then
                            peek_open(ctx, child)
                        end
                        local child_contents = containers.get_contents(child, registry)
                        if #child_contents > 0 then
                            local child_items = {}
                            for _, gc_id in ipairs(child_contents) do
                                local gc = registry:get(gc_id)
                                if gc then
                                    child_items[#child_items + 1] = gc.name or gc.id
                                end
                            end
                            if #child_items > 0 then
                                nested_narration[#nested_narration + 1] = narrator.nested_container_opening(ctx, child)
                                nested_narration[#nested_narration + 1] = narrator.nested_container_contents(ctx, child, child_items)
                            end
                        end
                    end
                end
            end
            if #items > 0 then
                -- #41: Use part-specific narration for direct drawer searches
                if entry.direct_part_search then
                    result.narrative = narrator.part_contents(ctx, entry.surface_name, parent, items)
                else
                    -- #63: Surface-aware narration (top vs inside)
                    result.narrative = narrator.surface_contents(ctx, entry.surface_name, parent, items)
                end
                -- #64: Append nested container narration
                for _, line in ipairs(nested_narration) do
                    result.narrative = result.narrative .. "\n" .. line
                end
            else
                if entry.direct_part_search then
                    result.narrative = narrator.part_empty(ctx, entry.surface_name, parent)
                end
            end
            -- #97: Prepend opening narration if container was just opened
            if open_prefix then
                result.narrative = open_prefix .. "\n" .. result.narrative
            end
            return result
        end
        
        -- #41: Direct part search with no contents
        if not target and not is_goal_search and #contents == 0 and entry.direct_part_search then
            result.narrative = narrator.part_empty(ctx, entry.surface_name, parent)
            if open_prefix then
                result.narrative = open_prefix .. "\n" .. result.narrative
            end
            return result
        end

        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child then
                -- Check if child matches target
                if target and not is_goal_search then
                    if matches_target(child, target, registry, 0) then
                        -- #22: deeper match check
                        local deeper = find_deeper_match(child, target, registry)
                        if deeper then
                            -- #97: Also open nested containers during search
                            if containers.is_container(child) and containers.can_auto_open(child) then
                                peek_open(ctx, child)
                            end
                            result.found = true
                            result.item = deeper
                            local narr = narrator.found_target(ctx, deeper, child)
                            if open_prefix then
                                narr = open_prefix .. "\n" .. narrator.nested_container_opening(ctx, child) .. "\n" .. narr
                            else
                                narr = narrator.nested_container_opening(ctx, child) .. "\n" .. narr
                            end
                            result.narrative = narr
                        else
                            result.found = true
                            result.item = child
                            local narr = narrator.found_target(ctx, child, parent)
                            if open_prefix then
                                narr = open_prefix .. "\n" .. narr
                            end
                            result.narrative = narr
                        end
                        return result
                    end
                elseif is_goal_search and goal_type and goal_value then
                    if goals.matches_goal(child, goal_type, goal_value, registry) then
                        result.found = true
                        result.item = child
                        local narr = narrator.found_target(ctx, child, parent)
                        if open_prefix then
                            narr = open_prefix .. "\n" .. narr
                        end
                        result.narrative = narr
                        return result
                    end
                end
            end
        end
        
        -- BUG-126 (#34): Target not found in accessible surface — report what IS there (#27)
        -- #63: Use surface-aware narration for targeted search too (top vs inside)
        if target and #contents > 0 then
            local items = {}
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    items[#items + 1] = child.name or child.id
                end
            end
            if #items > 0 then
                if entry.direct_part_search then
                    result.narrative = narrator.part_contents(ctx, entry.surface_name, parent, items)
                elseif entry.surface_name then
                    result.narrative = narrator.surface_contents(ctx, entry.surface_name, parent, items, target)
                else
                    result.narrative = narrator.container_contents_no_target(ctx, parent, items, target)
                end
            end
        end

        -- #97: Prepend opening narration if container was just opened
        if open_prefix and result.narrative ~= "" then
            result.narrative = open_prefix .. "\n" .. result.narrative
        elseif open_prefix then
            result.narrative = open_prefix
        end

        -- Surface checked, no match found
        return result
    end
    
    -- Get the object (for non-surface entries)
    local obj = registry:get(entry.object_id)
    if not obj then
        result.narrative = ""
        return result
    end
    
    -- #40: Objects with surfaces have their contents searched via surface entries
    -- in the queue. Skip the object entry to avoid contradictory narration
    -- (e.g., "nothing there" followed by surface entry reporting contents).
    -- For targeted searches, still check if the object itself matches the target.
    -- #84: Use matches_direct (no child recursion) — children are handled by
    -- the surface entries that follow in the queue.
    if obj.surfaces then
        if target and not is_goal_search then
            if matches_direct(obj, target) then
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
                return result
            end
        elseif is_goal_search and goal_type and goal_value then
            if goals.matches_goal(obj, goal_type, goal_value, registry) then
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
                return result
            end
        end
        -- Undirected sweep: surface entries in the queue handle content
        -- narration, so the parent object entry returns empty to avoid
        -- contradictory text (e.g., listing the object AND its contents).
        if not target and not is_goal_search then
            result.narrative = ""
            return result
        end
        -- Targeted/goal with no match — suppress; surfaces follow in queue
        result.narrative = ""
        return result
    end

    -- #97/#98/#99: Container is closed — open it, narrate opening, then search
    if entry.is_container and not entry.is_open then
        if entry.is_locked then
            -- Locked - skip with note
            result.narrative = narrator.container_locked(ctx, obj)
            return result
        else
            -- #97/#384: Peek inside container (accessible=true but is_open restored)
            peek_open(ctx, obj)
            local opening_line = narrator.nested_container_opening(ctx, obj)

            local contents = containers.get_contents(obj, registry)

            -- BUG-079: Undirected scoped search should enumerate container contents
            if not target and not is_goal_search then
                if #contents > 0 then
                    local items = {}
                    for _, child_id in ipairs(contents) do
                        local child = registry:get(child_id)
                        if child then
                            items[#items + 1] = child.name or child.id
                        end
                    end
                    result.narrative = opening_line .. "\n" .. narrator.container_contents_no_target(ctx, obj, items, nil)
                else
                    result.narrative = opening_line .. "\n" .. narrator.container_contents_no_target(ctx, obj, {}, nil)
                end
                return result
            end

            -- Targeted search: check contents, report what's there if not found (#27)
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    if target and not is_goal_search then
                        if matches_target(child, target, registry, 0) then
                            -- #22: If matched child is a container, peek inside for a more specific match
                            local deeper = find_deeper_match(child, target, registry)
                            if deeper then
                                -- #97: Also open nested containers
                                if containers.is_container(child) and containers.can_auto_open(child) then
                                    peek_open(ctx, child)
                                end
                                result.found = true
                                result.item = deeper
                                result.narrative = opening_line .. "\n" .. narrator.nested_container_opening(ctx, child) .. "\n" .. narrator.found_target(ctx, deeper, child)
                            else
                                result.found = true
                                result.item = child
                                result.narrative = opening_line .. "\n" .. narrator.found_target(ctx, child, obj)
                            end
                            return result
                        end
                    elseif is_goal_search and goal_type and goal_value then
                        if goals.matches_goal(child, goal_type, goal_value, registry) then
                            result.found = true
                            result.item = child
                            result.narrative = opening_line .. "\n" .. narrator.found_target(ctx, child, obj)
                            return result
                        end
                    end
                end
            end

            -- Target not found inside — check if the container itself matches (#22)
            if target and not is_goal_search then
                if matches_target(obj, target, registry, 0) then
                    result.found = true
                    result.item = obj
                    result.narrative = opening_line .. "\n" .. narrator.found_target(ctx, obj, nil)
                    return result
                end
            end

            -- Target not found inside or on container — report what IS there (#27)
            if target then
                local items = {}
                for _, child_id in ipairs(contents) do
                    local child = registry:get(child_id)
                    if child then
                        items[#items + 1] = child.name or child.id
                    end
                end
                result.narrative = opening_line .. "\n" .. narrator.container_contents_no_target(ctx, obj, items, target)
            end
            return result
        end
    end
    
    -- #34: Handle open container objects — check contents, report what's inside
    if entry.is_container and entry.is_open then
        local contents = containers.get_contents(obj, registry)
        
        -- Undirected search: enumerate contents
        if not target and not is_goal_search then
            if #contents > 0 then
                local items = {}
                for _, child_id in ipairs(contents) do
                    local child = registry:get(child_id)
                    if child then
                        items[#items + 1] = child.name or child.id
                    end
                end
                result.narrative = narrator.container_contents_no_target(ctx, obj, items, nil)
            else
                result.narrative = narrator.step_narrative(ctx, obj, false)
            end
            return result
        end
        
        -- Targeted search: check contents for match
        for _, child_id in ipairs(contents) do
            local child = registry:get(child_id)
            if child then
                if target and not is_goal_search then
                    if matches_target(child, target, registry, 0) then
                        local deeper = find_deeper_match(child, target, registry)
                        if deeper then
                            result.found = true
                            result.item = deeper
                            result.narrative = narrator.container_peek(ctx, child) .. "\n" .. narrator.found_target(ctx, deeper, child)
                        else
                            result.found = true
                            result.item = child
                            result.narrative = narrator.found_target(ctx, child, obj)
                        end
                        return result
                    end
                elseif is_goal_search and goal_type and goal_value then
                    if goals.matches_goal(child, goal_type, goal_value, registry) then
                        result.found = true
                        result.item = child
                        result.narrative = narrator.found_target(ctx, child, obj)
                        return result
                    end
                end
            end
        end
        
        -- Target not found in contents — check if the container itself matches (#22)
        if target and not is_goal_search then
            if matches_target(obj, target, registry, 0) then
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
                return result
            end
        end

        -- Target not found inside or on container — report what IS there (#34)
        if target and #contents > 0 then
            local items = {}
            for _, child_id in ipairs(contents) do
                local child = registry:get(child_id)
                if child then
                    items[#items + 1] = child.name or child.id
                end
            end
            result.narrative = narrator.container_contents_no_target(ctx, obj, items, target)
        else
            result.narrative = narrator.step_narrative(ctx, obj, false)
        end
        return result
    end
    
    -- Check if this object matches the target
    if target and not is_goal_search then
        if matches_target(obj, target, registry, 0) then
            -- #22: If matched object is a container, peek inside for a more specific match
            local deeper = find_deeper_match(obj, target, registry)
            if deeper then
                result.found = true
                result.item = deeper
                result.narrative = narrator.container_peek(ctx, obj) .. "\n" .. narrator.found_target(ctx, deeper, obj)
            else
                result.found = true
                result.item = obj
                result.narrative = narrator.found_target(ctx, obj, nil)
            end
            return result
        end
    elseif is_goal_search and goal_type and goal_value then
        if goals.matches_goal(obj, goal_type, goal_value, registry) then
            result.found = true
            result.item = obj
            result.narrative = narrator.found_target(ctx, obj, nil)
            return result
        end
    end
    
    -- Not found - generate step narrative
    result.narrative = narrator.step_narrative(ctx, obj, false)
    return result
end

--- Expose internals for testing (#68, #74, #84)
traverse._matches_target = matches_target
traverse._matches_exact  = matches_exact
traverse._matches_direct = matches_direct
traverse._find_deeper_match = find_deeper_match

return traverse

end

package.preload["engine.sound.defaults"] = function()
-- engine/sound/defaults.lua
-- Default verb-to-sound fallback table. When an object has no specific
-- sound for an event, the sound manager falls back to these generics.
-- Object-specific sounds in obj.sounds[key] ALWAYS override defaults.
-- See: sound-implementation-plan.md v1.1, Track 0A

return {
    -- Verb interaction sounds (on_verb_*)
    on_verb_break      = "generic-break.opus",
    on_verb_open       = "generic-creak.opus",
    on_verb_close      = "generic-close.opus",
    on_verb_lock       = "generic-lock.opus",
    on_verb_unlock     = "generic-unlock.opus",
    on_verb_light      = "generic-ignite.opus",
    on_verb_extinguish = "generic-extinguish.opus",
    on_verb_eat        = "generic-eat.opus",
    on_verb_drink      = "generic-drink.opus",
    on_verb_drop       = "generic-drop.opus",
    on_verb_take       = "generic-take.opus",
    on_verb_pour       = "generic-pour.opus",

    -- Combat impact sounds (on_verb_*)
    on_verb_hit        = "generic-blunt-hit.opus",
    on_verb_slash      = "generic-slash-hit.opus",
    on_verb_cut        = "generic-slash-hit.opus",
}

end

package.preload["engine.sound"] = function()
-- engine/sound/init.lua
-- Platform-agnostic sound manager. Provides play/stop/volume/mute with
-- injected platform drivers (Web Audio, terminal, null). No-op when no
-- driver is present — sound is opt-in (Principle 8).
--
-- Public API frozen at GATE-0 (v1.1):
--   new(), init(), shutdown(), scan_object(), flush_queue(),
--   play(), stop(), stop_by_owner(), enter_room(), exit_room(),
--   unload_room(), trigger(), set_volume(), set_enabled(),
--   mute(), unmute(), set_driver()

local defaults = require("engine.sound.defaults")

local M = {}
M.__index = M

-- Concurrency caps
local MAX_ONESHOTS = 4
local MAX_AMBIENTS = 3

----------------------------------------------------------------------------
-- Construction
----------------------------------------------------------------------------

--- Create a new sound manager instance.
-- @return SoundManager
function M.new()
    local self = setmetatable({}, M)
    self._driver = nil
    self._volume = 1.0       -- master volume 0.0–1.0
    self._enabled = true      -- global enable flag
    self._muted = false       -- mute toggle (preserves volume)
    self._queue = {}          -- filenames pending load
    self._loaded = {}         -- filename → driver handle
    self._playing = {}        -- play_id → { filename, handle, loop, owner_id }
    self._oneshots = {}       -- ordered list of active one-shot play_ids
    self._ambients = {}       -- ordered list of active ambient play_ids
    self._object_sounds = {}  -- obj_id → { event_key → filename }
    self._next_id = 1         -- monotonic play-id counter
    self._debug = false       -- debug logging flag
    return self
end

--- Initialize with a platform driver and options.
-- @param driver  Driver table (nil = no-op mode)
-- @param options Optional config table (reserved for future use)
function M:init(driver, options)
    self._driver = driver
    if options then
        if options.volume ~= nil then
            self:set_volume(options.volume)
        end
        if options.enabled ~= nil then
            self._enabled = options.enabled
        end
        if options.debug then
            self._debug = true
        end
    end
    if self._debug then
        local dname = "nil (headless)"
        if driver then
            dname = driver.name or "unknown"
        end
        print("[sound] driver: " .. dname)
        print("[sound] init: manager ready")
    end
end

--- Shut down: stop all sounds, release resources.
function M:shutdown()
    if self._driver and self._driver.stop_all then
        pcall(self._driver.stop_all, self._driver)
    end
    self._driver = nil
    self._playing = {}
    self._oneshots = {}
    self._ambients = {}
    self._loaded = {}
    self._queue = {}
    self._object_sounds = {}
end

----------------------------------------------------------------------------
-- Driver injection
----------------------------------------------------------------------------

--- Hot-swap the platform driver.
-- @param driver  New driver table (nil reverts to no-op)
function M:set_driver(driver)
    self._driver = driver
end

--- Return the current driver (or nil).
function M:get_driver()
    return self._driver
end

----------------------------------------------------------------------------
-- Object scanning (called by loader after registry registration)
----------------------------------------------------------------------------

--- Extract an object's `sounds` table and queue its files for loading.
-- Safe to call on any object — no-op if `sounds` is absent.
function M:scan_object(obj)
    if not obj or type(obj.sounds) ~= "table" then
        return
    end
    local id = obj.guid or obj.id
    if not id then return end
    local map = {}
    local count = 0
    for key, filename in pairs(obj.sounds) do
        map[key] = filename
        count = count + 1
        if not self._loaded[filename] then
            self._queue[#self._queue + 1] = filename
        end
    end
    self._object_sounds[id] = map
    if self._debug then
        local label = obj.id or id
        print("[sound] scan: " .. label .. " → " .. count .. " sound keys")
    end
end

--- Trigger async load for all queued files.
function M:flush_queue()
    if not self._driver or not self._driver.load then
        self._queue = {}
        return
    end
    for _, filename in ipairs(self._queue) do
        if not self._loaded[filename] then
            pcall(self._driver.load, self._driver, filename, function(handle, err)
                if handle and not err then
                    self._loaded[filename] = handle
                end
            end)
        end
    end
    self._queue = {}
end

----------------------------------------------------------------------------
-- Playback
----------------------------------------------------------------------------

local function _alloc_id(self)
    local id = self._next_id
    self._next_id = id + 1
    return id
end

--- Evict the oldest one-shot when at capacity.
local function _evict_oneshot(self)
    if #self._oneshots < MAX_ONESHOTS then return end
    local oldest_id = table.remove(self._oneshots, 1)
    local entry = self._playing[oldest_id]
    if entry and self._driver and self._driver.stop then
        pcall(self._driver.stop, self._driver, entry.handle)
    end
    self._playing[oldest_id] = nil
end

--- Evict the lowest-priority ambient when at capacity.
local function _evict_ambient(self)
    if #self._ambients < MAX_AMBIENTS then return end
    local oldest_id = table.remove(self._ambients, 1)
    local entry = self._playing[oldest_id]
    if entry and self._driver and self._driver.stop then
        pcall(self._driver.stop, self._driver, entry.handle)
    end
    self._playing[oldest_id] = nil
end

--- Play a sound file.
-- @param filename  Sound filename (e.g. "door-creak.opus")
-- @param opts      Optional table: { loop=bool, owner_id=string,
--                    fade_in_ms=number, fade_out_ms=number }
-- @return play_id or nil
function M:play(filename, opts)
    if not self._driver or not self._enabled or self._muted then
        return nil
    end
    if not self._driver.play then return nil end

    if self._debug then
        print("[sound] play: " .. tostring(filename))
    end

    opts = opts or {}
    local is_loop = opts.loop or false

    -- Enforce concurrency limits
    if is_loop then
        _evict_ambient(self)
    else
        _evict_oneshot(self)
    end

    local driver_opts = {
        volume = self._volume,
        loop = is_loop,
        fade_in_ms = opts.fade_in_ms,
        fade_out_ms = opts.fade_out_ms,
    }

    local ok, handle = pcall(self._driver.play, self._driver, filename, driver_opts)
    if not ok or not handle then return nil end

    local play_id = _alloc_id(self)
    self._playing[play_id] = {
        filename = filename,
        handle = handle,
        loop = is_loop,
        owner_id = opts.owner_id,
    }

    if is_loop then
        self._ambients[#self._ambients + 1] = play_id
    else
        self._oneshots[#self._oneshots + 1] = play_id
    end

    return play_id
end

--- Stop a specific playing sound by play_id.
function M:stop(play_id)
    local entry = self._playing[play_id]
    if not entry then return end
    if self._driver and self._driver.stop then
        pcall(self._driver.stop, self._driver, entry.handle)
    end
    self._playing[play_id] = nil
    -- Remove from tracking lists
    for i, id in ipairs(self._oneshots) do
        if id == play_id then table.remove(self._oneshots, i); break end
    end
    for i, id in ipairs(self._ambients) do
        if id == play_id then table.remove(self._ambients, i); break end
    end
end

--- Stop all sounds owned by a specific object.
function M:stop_by_owner(owner_id)
    if not owner_id then return end
    local to_stop = {}
    for play_id, entry in pairs(self._playing) do
        if entry.owner_id == owner_id then
            to_stop[#to_stop + 1] = play_id
        end
    end
    for _, play_id in ipairs(to_stop) do
        self:stop(play_id)
    end
end

----------------------------------------------------------------------------
-- Room transitions
----------------------------------------------------------------------------

--- Start room ambients and object ambients when entering a room.
function M:enter_room(room)
    if not room or not self._driver then return end
    if self._debug then
        local rid = room.id or room.guid or "?"
        local amb = (room.sounds and room.sounds.ambient) or "(no ambient)"
        print("[sound] enter_room: " .. rid .. " → " .. amb)
    end
    if room.sounds and room.sounds.ambient then
        self:play(room.sounds.ambient, { loop = true, owner_id = room.guid or room.id })
    end
end

--- Stop non-portable sounds when exiting a room.
function M:exit_room(room)
    if not room then return end
    if self._debug then
        local rid = room.id or room.guid or "?"
        print("[sound] exit_room: " .. rid)
    end
    local room_id = room.guid or room.id
    if room_id then
        self:stop_by_owner(room_id)
    end
end

--- Free audio handles for a room's objects.
function M:unload_room(room_id)
    if not room_id then return end
    -- Stop any sounds owned by objects in this room
    self:stop_by_owner(room_id)
    -- Unload cached handles for objects that belonged to the room
    if self._driver and self._driver.unload then
        local obj_map = self._object_sounds[room_id]
        if obj_map then
            for _, filename in pairs(obj_map) do
                local handle = self._loaded[filename]
                if handle then
                    pcall(self._driver.unload, self._driver, handle)
                    self._loaded[filename] = nil
                end
            end
        end
    end
end

----------------------------------------------------------------------------
-- Event dispatch
----------------------------------------------------------------------------

--- Resolve a sound key for an object and play it.
-- Resolution chain (v1.1 C6):
--   1. obj.sounds[event_key] → object-specific (always wins)
--   2. defaults[event_key]   → generic fallback
--   3. nil                   → silent (no sound)
-- State-qualified ambient: checks ambient_{state} before ambient.
function M:trigger(obj, event_key)
    if not self._driver or not self._enabled or self._muted then
        return nil
    end
    if not event_key then return nil end

    local filename = nil
    local owner_id = nil
    local obj_label = (obj and (obj.id or obj.guid)) or "nil"
    local source = nil -- tracks resolution path for debug

    -- Step 1: object-specific sound
    if obj and obj.sounds and obj.sounds[event_key] then
        filename = obj.sounds[event_key]
        owner_id = obj.guid or obj.id
        source = "object"
    end

    -- Step 1b: state-qualified ambient lookup
    if not filename and obj and obj._state and obj.sounds then
        local state_key = "ambient_" .. obj._state
        if obj.sounds[state_key] then
            filename = obj.sounds[state_key]
            owner_id = obj.guid or obj.id
            source = "object-state"
        end
    end

    -- Step 2: defaults fallback
    if not filename then
        filename = defaults[event_key]
        if filename then source = "default" end
    end

    -- Step 3: silent
    if not filename then
        if self._debug then
            print("[sound] trigger: " .. obj_label .. " " .. event_key .. " → (silent)")
        end
        return nil
    end

    if self._debug then
        if source == "default" then
            print("[sound] trigger: " .. obj_label .. " " .. event_key .. " → default: " .. filename)
        else
            print("[sound] trigger: " .. obj_label .. " " .. event_key .. " → " .. filename)
        end
    end

    local is_loop = event_key:find("^ambient") ~= nil
    return self:play(filename, { loop = is_loop, owner_id = owner_id })
end

----------------------------------------------------------------------------
-- Settings
----------------------------------------------------------------------------

--- Set master volume (0.0–1.0, clamped).
function M:set_volume(level)
    if type(level) ~= "number" then return end
    self._volume = math.max(0.0, math.min(1.0, level))
    if self._driver and self._driver.set_master_volume then
        pcall(self._driver.set_master_volume, self._driver, self._volume)
    end
end

--- Get current master volume.
function M:get_volume()
    return self._volume
end

--- Enable or disable all sound globally.
function M:set_enabled(enabled)
    self._enabled = enabled and true or false
    if not self._enabled then
        self:_stop_all()
    end
end

--- Mute (preserves volume setting).
function M:mute()
    self._muted = true
end

--- Unmute.
function M:unmute()
    self._muted = false
end

--- Return true if currently muted.
function M:is_muted()
    return self._muted
end

--- Return true if enabled.
function M:is_enabled()
    return self._enabled
end

----------------------------------------------------------------------------
-- Internal helpers
----------------------------------------------------------------------------

--- Stop all currently playing sounds.
function M:_stop_all()
    if self._driver and self._driver.stop_all then
        pcall(self._driver.stop_all, self._driver)
    end
    self._playing = {}
    self._oneshots = {}
    self._ambients = {}
end

return M

end

