package.preload["engine.traverse_effects.effects"] = function()
-- engine/traverse_effects/effects.lua

local traverse_effects = require("engine.traverse_effects.registry")

---------------------------------------------------------------------------
-- Built-in handler: wind_effect
--
-- Checks player inventory for items in the `extinguishes` list.
-- If a matching item is found AND is in a "lit" state AND is NOT
-- wind_resistant, transitions it to "extinguished" (or "unlit") state.
---------------------------------------------------------------------------
local function wind_effect_handler(effect, ctx)
    local fsm_mod = require("engine.fsm")
    local presentation = require("engine.ui.presentation")

    local carried_ids = presentation.get_all_carried_ids(ctx)
    local extinguish_set = {}
    for _, name in ipairs(effect.extinguishes or {}) do
        extinguish_set[name:lower()] = true
    end

    local something_extinguished = false
    local something_spared = false

    for _, obj_id in ipairs(carried_ids) do
        local obj = ctx.registry:get(obj_id)
        if obj then
            -- Check if this object is in the extinguishes list (by id or keywords)
            local targeted = false
            if obj.id and extinguish_set[obj.id:lower()] then
                targeted = true
            end
            if not targeted and type(obj.keywords) == "table" then
                for _, kw in ipairs(obj.keywords) do
                    if extinguish_set[kw:lower()] then
                        targeted = true
                        break
                    end
                end
            end

            if targeted and obj._state == "lit" then
                if obj.wind_resistant then
                    something_spared = true
                else
                    -- Try extinguished first, then unlit
                    local trans, err = fsm_mod.transition(
                        ctx.registry, obj_id, "extinguished", nil, "extinguish"
                    )
                    if not trans then
                        trans, err = fsm_mod.transition(
                            ctx.registry, obj_id, "unlit", nil, "extinguish"
                        )
                    end
                    if trans then
                        something_extinguished = true
                    end
                end
            elseif not targeted and obj._state == "lit" and obj.wind_resistant then
                -- Not in extinguish list but lit and wind-resistant — spared
                something_spared = true
            end
        end
    end

    -- Print messages: effect description first, then outcome
    if something_extinguished or something_spared then
        if effect.description then
            print(effect.description)
        end
    end
    if something_extinguished then
        print(effect.message_extinguish or "The draft snuffs out your flame!")
    end
    if something_spared and not something_extinguished then
        if effect.message_spared then
            print(effect.message_spared)
        end
    end
end

traverse_effects.register("wind_effect", wind_effect_handler)

end

package.preload["engine.traverse_effects.registry"] = function()
-- engine/traverse_effects/registry.lua
-- Extensible on_traverse exit-effect engine.
--
-- When a player moves through an exit, the engine checks for an optional
-- on_traverse table on that exit. If present, it dispatches to a registered
-- handler based on the effect's `type` field.
--
-- Ownership: Bart (Architect)
-- Decision: D-TRAVERSE001 — on_traverse exit-effect pattern
--
-- Usage in room metadata:
--   exits = {
--     up = {
--       target = "storage-cellar",
--       on_traverse = {
--         type = "wind_effect",
--         description = "A cold draft rushes up the stairway...",
--         extinguishes = { "candle" }
--       }
--     }
--   }

local traverse_effects = {}

-- Registry of effect handlers keyed by type string.
-- Each handler: function(effect, ctx) -> nil
-- Handlers print their own messages and mutate state via ctx.
local handlers = {}

--- Register a new on_traverse effect handler.
-- @param effect_type  string   The `type` value that triggers this handler.
-- @param handler_fn   function(effect, ctx)  Called when the effect fires.
function traverse_effects.register(effect_type, handler_fn)
    handlers[effect_type] = handler_fn
end

--- Normalize an on_traverse table into { type = ..., ...fields }.
-- Accepts two formats:
--   1. Flat:   { type = "wind_effect", extinguishes = {...}, ... }
--   2. Nested: { wind_effect = { extinguishes = {...}, ... } }
-- Returns the normalized effect table, or nil if unrecognized.
local function normalize_effect(raw)
    if raw.type then return raw end

    -- Nested format: single key whose value is the effect payload
    local effect_type, payload
    for k, v in pairs(raw) do
        if type(v) == "table" then
            if effect_type then return nil end  -- ambiguous: multiple keys
            effect_type = k
            payload = v
        end
    end
    if not effect_type then return nil end

    -- Merge into flat format expected by handlers
    local flat = { type = effect_type }
    for k, v in pairs(payload) do flat[k] = v end
    return flat
end

--- Process an exit's on_traverse effects, if any.
-- Called by the movement handler BEFORE the player is moved.
-- @param exit  table|string  The exit definition from room metadata.
-- @param ctx   table         The game context (registry, player, etc.)
function traverse_effects.process(exit, ctx)
    if type(exit) ~= "table" then return end
    local raw = exit.on_traverse
    if not raw then return end

    local effect = normalize_effect(raw)
    if not effect then return end

    local handler = handlers[effect.type]
    if not handler then return end

    handler(effect, ctx)
end

return traverse_effects

end

package.preload["engine.ui"] = function()
-- engine/ui/init.lua
-- Split-screen terminal UI using ANSI escape codes.
--
-- Layout (H = terminal height):
--   Line 1        : Status bar (reverse video)
--   Lines 2..H-2  : Output window (scrollable history)
--   Line H-1      : Delimiter (dashes)
--   Line H        : Input line ("> " prompt)
--
-- Pure Lua + ANSI. No external C libs.  Windows 10+ compatible.
-- Falls back to plain print/read when ANSI is unavailable.

local ui = {}

---------------------------------------------------------------------------
-- ANSI helpers
---------------------------------------------------------------------------
local ESC = "\27"

local function csi(...)  return ESC .. "[" .. table.concat({...}) end
local function move_to(r, c) io.write(csi(r, ";", c or 1, "H")) end
local function clear_eol()   io.write(csi("K")) end
local function hide_cursor() io.write(csi("?25l")) end
local function show_cursor() io.write(csi("?25h")) end
local function reverse()     io.write(csi("7m")) end
local function reset_attr()  io.write(csi("0m")) end
local function clear_screen()io.write(csi("2J")) end
local function set_scroll_region(top, bot)
    io.write(csi(top, ";", bot, "r"))
end
local function reset_scroll_region() io.write(csi("r")) end

---------------------------------------------------------------------------
-- State (module-level, single instance)
---------------------------------------------------------------------------
local enabled      = false
local width        = 80
local height       = 24
local buffer       = {}     -- scrollback: array of wrapped lines
local max_buffer   = 500
local scroll_off   = 0     -- 0 = viewing bottom; positive = scrolled up
local stat_left    = ""
local stat_right   = ""

-- Computed geometry (set by compute_regions)
local out_top, out_bot, out_lines
local delim_row, input_row

local function compute_regions()
    out_top    = 2
    out_bot    = height - 2
    out_lines  = out_bot - out_top + 1
    delim_row  = height - 1
    input_row  = height
end

---------------------------------------------------------------------------
-- Terminal size detection
---------------------------------------------------------------------------
local function detect_size()
    local w, h = 80, 24
    if package.config:sub(1, 1) == "\\" then
        -- Windows: parse "mode con" output
        local ok, p = pcall(io.popen, "mode con 2>nul")
        if ok and p then
            local out = p:read("*a")
            p:close()
            local cols  = out:match("Columns:%s*(%d+)")
            local lines = out:match("Lines:%s*(%d+)")
            if cols  then w = tonumber(cols)  end
            if lines then h = tonumber(lines) end
        end
    else
        local ok, p = pcall(io.popen, "stty size 2>/dev/null")
        if ok and p then
            local out = p:read("*l")
            p:close()
            if out then
                local r, c = out:match("(%d+)%s+(%d+)")
                if r then h = tonumber(r) end
                if c then w = tonumber(c) end
            end
        end
    end
    return w, h
end

---------------------------------------------------------------------------
-- Word-wrap (replicates display.word_wrap logic for buffer lines)
---------------------------------------------------------------------------
local function wrap_text(text, w)
    w = w or width
    if not text then return { "" } end
    if text == "" then return { "" } end

    local lines = {}
    for segment in (text .. "\n"):gmatch("(.-)\n") do
        if segment == "" then
            lines[#lines + 1] = ""
        elseif #segment <= w then
            lines[#lines + 1] = segment
        else
            local indent = segment:match("^(%s*)") or ""
            local content = segment:sub(#indent + 1)
            local line = indent
            for word in content:gmatch("%S+") do
                if line == indent then
                    line = indent .. word
                elseif #line + 1 + #word > w then
                    lines[#lines + 1] = line
                    line = indent .. word
                else
                    line = line .. " " .. word
                end
            end
            if line ~= indent or line ~= "" then
                lines[#lines + 1] = line
            end
        end
    end
    -- gmatch artifact: trailing empty string from appended "\n"
    if #lines > 1 and lines[#lines] == "" and not text:match("\n$") then
        table.remove(lines)
    end
    if #lines == 0 then lines = { "" } end
    return lines
end

---------------------------------------------------------------------------
-- Drawing primitives
---------------------------------------------------------------------------

local function draw_status()
    move_to(1, 1)
    reverse()
    local left  = stat_left  or ""
    local right = stat_right or ""
    local pad   = width - #left - #right
    if pad < 1 then pad = 1 end
    local bar = left .. string.rep(" ", pad) .. right
    if #bar > width then bar = bar:sub(1, width) end
    io.write(bar)
    reset_attr()
end

local function draw_delimiter()
    move_to(delim_row, 1)
    clear_eol()
    io.write(string.rep("-", width))
end

local function redraw_output()
    local total   = #buffer
    local visible = out_lines
    local start_idx = total - visible - scroll_off + 1
    if start_idx < 1 then start_idx = 1 end

    for i = 0, visible - 1 do
        local buf_idx = start_idx + i
        local row     = out_top + i
        move_to(row, 1)
        clear_eol()
        if buf_idx >= 1 and buf_idx <= total then
            local line = buffer[buf_idx] or ""
            if #line > width then line = line:sub(1, width) end
            io.write(line)
        end
    end
end

local function draw_input_prompt(text)
    move_to(input_row, 1)
    clear_eol()
    io.write("> " .. (text or ""))
end

local function full_refresh()
    hide_cursor()
    draw_status()
    redraw_output()
    draw_delimiter()
    draw_input_prompt("")
    show_cursor()
    io.flush()
end

---------------------------------------------------------------------------
-- Buffer management
---------------------------------------------------------------------------
local function append_to_buffer(text)
    local lines = wrap_text(text, width)
    for _, line in ipairs(lines) do
        buffer[#buffer + 1] = line
        if #buffer > max_buffer then
            table.remove(buffer, 1)
            if scroll_off > 0 then scroll_off = scroll_off - 1 end
        end
    end
end

---------------------------------------------------------------------------
-- Public API
---------------------------------------------------------------------------

--- Initialise the split-screen UI.  Returns true on success.
function ui.init()
    width, height = detect_size()
    if height < 8 or width < 20 then
        -- Terminal too small for split-screen
        return false
    end

    compute_regions()
    buffer     = {}
    scroll_off = 0
    stat_left  = ""
    stat_right = ""
    enabled    = true

    -- Enable VT processing on Windows (harmless no-op if already active)
    if package.config:sub(1, 1) == "\\" then
        os.execute("")
    end

    clear_screen()
    -- Set scroll region to output area so Enter on input line won't scroll
    set_scroll_region(out_top, out_bot)
    full_refresh()
    return true
end

function ui.is_enabled()
    return enabled
end

function ui.get_width()
    return width
end

--- Print text into the output window (replaces raw print when UI is active).
function ui.output(text)
    if not enabled then
        io.write((text or "") .. "\n")
        io.flush()
        return
    end

    append_to_buffer(text or "")
    scroll_off = 0  -- snap to bottom on new output

    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Update the status bar.
function ui.status(left, right)
    stat_left  = left  or stat_left
    stat_right = right or stat_right
    if not enabled then return end
    hide_cursor()
    draw_status()
    show_cursor()
    io.flush()
end

--- Read one line from the input area.
--- Returns nil on EOF.
function ui.input()
    if not enabled then
        io.write("> ")
        io.flush()
        return io.read()
    end

    -- Position cursor at input line
    move_to(input_row, 1)
    clear_eol()
    io.write("> ")
    show_cursor()
    io.flush()

    local text = io.read()
    if not text then return nil end

    -- Immediately clear the input line to prevent stale echo
    move_to(input_row, 1)
    clear_eol()
    io.flush()

    return text
end

--- Sub-prompt (e.g., "What do you want to write? > ").
--- Shows msg in the output window, then reads from input line.
function ui.prompt(msg)
    if not enabled then
        io.write(msg)
        io.flush()
        return io.read()
    end

    ui.output(msg)
    return ui.input()
end

--- Scroll the output window up by n lines (default ≈ one page).
function ui.scroll_up(n)
    if not enabled then return end
    n = n or math.max(1, out_lines - 2)
    local max_scroll = math.max(0, #buffer - out_lines)
    scroll_off = math.min(scroll_off + n, max_scroll)
    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Scroll the output window down by n lines (default ≈ one page).
function ui.scroll_down(n)
    if not enabled then return end
    n = n or math.max(1, out_lines - 2)
    scroll_off = math.max(0, scroll_off - n)
    hide_cursor()
    redraw_output()
    show_cursor()
    io.flush()
end

--- Returns true (and handles it) if input is a scroll command.
function ui.handle_scroll(input)
    if not enabled then return false end
    local cmd = (input or ""):match("^%s*(.-)%s*$")
    if cmd == "/up" or cmd == "/pgup" then
        ui.scroll_up()
        return true
    elseif cmd == "/down" or cmd == "/pgdn" then
        ui.scroll_down()
        return true
    elseif cmd == "/bottom" then
        scroll_off = 0
        hide_cursor()
        redraw_output()
        show_cursor()
        io.flush()
        return true
    end
    return false
end

--- Full-screen refresh (status + output + delimiter + input prompt).
function ui.refresh()
    if not enabled then return end
    full_refresh()
end

--- Restore terminal to normal state.
function ui.cleanup()
    if not enabled then return end
    enabled = false
    reset_scroll_region()
    reset_attr()
    show_cursor()
    clear_screen()
    move_to(1, 1)
    io.flush()
end

return ui

end

package.preload["engine.ui.presentation"] = function()
-- engine/ui/presentation.lua
-- Presentation helpers: time formatting, light level, vision checks.
-- Owned by Smithers (UI Engineer). These read game state to produce
-- display-ready values. No mutations — pure queries.
--
-- Shared constants (single source of truth for time calculations):
--   GAME_SECONDS_PER_REAL_SECOND, GAME_START_HOUR, DAYTIME_START, DAYTIME_END

local presentation = {}

---------------------------------------------------------------------------
-- Constants (authoritative — remove duplicates from verbs/init.lua, main.lua)
---------------------------------------------------------------------------
presentation.GAME_SECONDS_PER_REAL_SECOND = 24
presentation.GAME_START_HOUR = 2
presentation.DAYTIME_START = 6
presentation.DAYTIME_END = 18

---------------------------------------------------------------------------
-- Carried items utility (needed by get_light_level)
---------------------------------------------------------------------------

--- Returns flat list of all object IDs the player is carrying
--- (hands + held bag contents + worn items + worn bag contents)
function presentation.get_all_carried_ids(ctx)
    local ids = {}
    local reg = ctx.registry
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local hand_id = type(hand) == "table" and hand.id or hand
            ids[#ids + 1] = hand_id
            local obj = type(hand) == "table" and hand or reg:get(hand)
            if obj and obj.container and obj.contents then
                for _, item_id in ipairs(obj.contents) do
                    ids[#ids + 1] = item_id
                end
            end
        end
    end
    for _, worn_id in ipairs(ctx.player.worn or {}) do
        ids[#ids + 1] = worn_id
        local obj = reg:get(worn_id)
        if obj and obj.container and obj.contents then
            for _, item_id in ipairs(obj.contents) do
                ids[#ids + 1] = item_id
            end
        end
    end
    return ids
end

---------------------------------------------------------------------------
-- Time
---------------------------------------------------------------------------

--- Returns game hour and minute from real-time clock.
function presentation.get_game_time(ctx)
    local real_elapsed = os.time() - ctx.game_start_time
    local total_game_hours = (real_elapsed * presentation.GAME_SECONDS_PER_REAL_SECOND) / 3600
    local absolute_hour = presentation.GAME_START_HOUR + total_game_hours + (ctx.time_offset or 0)
    local hour = math.floor(absolute_hour % 24)
    local minute = math.floor((absolute_hour * 60) % 60)
    return hour, minute
end

--- Returns true if the game clock is between DAYTIME_START and DAYTIME_END.
function presentation.is_daytime(ctx)
    local hour = presentation.get_game_time(ctx)
    return hour >= presentation.DAYTIME_START and hour < presentation.DAYTIME_END
end

--- Formats hour+minute into "H:MM AM/PM".
function presentation.format_time(hour, minute)
    local period = hour >= 12 and "PM" or "AM"
    local display_hour = hour % 12
    if display_hour == 0 then display_hour = 12 end
    return string.format("%d:%02d %s", display_hour, minute, period)
end

--- Returns a prose description of the time of day.
--- Only returns a description when sky_visible is explicitly true.
--- Underground, interior, and rooms without sky access return nil.
function presentation.time_of_day_desc(hour, sky_visible)
    if not sky_visible then return nil end
    if hour >= 5 and hour < 7 then return "Dawn breaks on the horizon."
    elseif hour >= 7 and hour < 10 then return "Morning light fills the sky."
    elseif hour >= 10 and hour < 14 then return "The sun stands high overhead."
    elseif hour >= 14 and hour < 17 then return "The afternoon sun angles westward."
    elseif hour >= 17 and hour < 19 then return "Dusk gathers at the edges of the world."
    elseif hour >= 19 and hour < 21 then return "Night has fallen."
    else return "Deep night. The world sleeps."
    end
end

---------------------------------------------------------------------------
-- Light system — tri-state: "lit", "dim", "dark"
--   "lit"  = full light (open curtains + daytime, or artificial light)
--   "dim"  = filtered daylight through closed curtains during daytime
--   "dark" = no light at all (nighttime, no candle)
-- Dim light is enough to see and interact; descriptions note the dimness.
---------------------------------------------------------------------------

function presentation.get_light_level(ctx)
    local room = ctx.current_room
    local reg = ctx.registry

    -- Artificial light always gives full "lit" (candle, torch, etc.)
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.casts_light then return "lit" end
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                for _, item_id in ipairs(zone.contents or {}) do
                    local item = reg:get(item_id)
                    -- Check contents of surface items (e.g., candle inside holder)
                    if item and item.contents then
                        for _, inner_id in ipairs(item.contents) do
                            local inner = reg:get(inner_id)
                            if inner and inner.casts_light then return "lit" end
                        end
                    end
                    if item and item.casts_light then return "lit" end
                end
            end
        end
    end
    for _, obj_id in ipairs(presentation.get_all_carried_ids(ctx)) do
        local obj = reg:get(obj_id)
        if obj and obj.casts_light then return "lit" end
        -- #219: Check contents of carried items (e.g., candle inside holder)
        -- even for non-container composites that have a contents list.
        if obj and obj.contents then
            for _, inner_id in ipairs(obj.contents) do
                local inner = reg:get(inner_id)
                if inner and inner.casts_light then return "lit" end
            end
        end
    end

    -- Daylight: open curtains = "lit", closed curtains = "dim"
    if presentation.is_daytime(ctx) then
        local has_filter = false
        for _, obj_id in ipairs(room.contents or {}) do
            local obj = reg:get(obj_id)
            if obj and obj.allows_daylight then return "lit" end
            if obj and obj.filters_daylight then has_filter = true end
        end
        if has_filter then return "dim" end
    end

    -- #401: Ambient room light (moonlight, bioluminescence, etc.)
    -- light_level >= 2 is full visibility; 1 is dim (enough to see shapes)
    if room.light_level and room.light_level >= 1 then
        if room.light_level >= 2 then return "lit" end
        return "dim"
    end

    return "dark"
end

--- Convenience: can the player see enough to interact?
function presentation.has_some_light(ctx)
    return presentation.get_light_level(ctx) ~= "dark"
end

---------------------------------------------------------------------------
-- Vision check
---------------------------------------------------------------------------

--- Returns true, blocker_obj if player's vision is blocked by a worn item.
function presentation.vision_blocked_by_worn(ctx)
    local reg = ctx.registry
    for _, worn_id in ipairs(ctx.player.worn or {}) do
        local obj = reg:get(worn_id)
        if obj and obj.wear and obj.wear.blocks_vision then
            return true, obj
        end
    end
    return false, nil
end

return presentation

end

package.preload["engine.ui.status"] = function()
-- engine/ui/status.lua
-- Status bar updater for the split-screen terminal UI.
-- Owned by Smithers (UI Engineer). Pure formatting — no game mutations.

local presentation = require("engine.ui.presentation")

local status = {}

---------------------------------------------------------------------------
-- Level lookup: maps room IDs → { number, name }
-- Rooms don't yet carry a `level` field (see decision inbox note).
-- This table is the interim single source of truth until rooms declare
-- their own level. Moe should add `level = { number = 1, name = "..." }`
-- to each room .lua file; once that lands, this fallback can be removed.
---------------------------------------------------------------------------
status.LEVEL_MAP = {
    ["start-room"]     = { number = 1, name = "The Awakening" },
    ["cellar"]         = { number = 1, name = "The Awakening" },
    ["hallway"]        = { number = 1, name = "The Awakening" },
    ["storage-cellar"] = { number = 1, name = "The Awakening" },
    ["courtyard"]      = { number = 2, name = "The Courtyard" },
}

--- Returns the level info for a room: { number, name } or nil.
--- Prefers room.level (if Moe has added it), falls back to LEVEL_MAP.
function status.get_level(room)
    if room and room.level then
        return room.level
    end
    if room and room.id then
        return status.LEVEL_MAP[room.id]
    end
    return nil
end

--- Creates the update_status callback for the game context.
--- Returns a function(ctx) that updates the UI status bar each turn.
function status.create_updater()
    return function(ctx)
        if not ctx.ui then return end

        -- Compute game time
        local hour, minute = presentation.get_game_time(ctx)
        local time_str = presentation.format_time(hour, minute)

        -- Level + Room name
        local room_name = "UNKNOWN"
        if ctx.current_room and ctx.current_room.name then
            room_name = ctx.current_room.name:upper()
        end

        local level_info = status.get_level(ctx.current_room)
        local location_str
        if level_info then
            location_str = "Lv " .. level_info.number .. ": "
                         .. level_info.name .. " — " .. room_name
        else
            location_str = room_name
        end

        -- Right side: health status (if injured) + stress indicator
        local right_str = ""
        local p = ctx.player
        if p then
            local inj_ok, injury_mod = pcall(require, "engine.injuries")
            if inj_ok and injury_mod then
                local health = injury_mod.compute_health(p)
                local max_hp = p.max_health or 100
                if health < max_hp then
                    right_str = "Health: " .. health .. "/" .. max_hp .. " "
                end

                -- Stress indicator (WAVE-3)
                local stress_level = injury_mod.get_stress_level(p)
                if stress_level then
                    local stress_label = stress_level:sub(1,1):upper() .. stress_level:sub(2)
                    if right_str ~= "" then
                        right_str = right_str .. "| " .. stress_label .. " "
                    else
                        right_str = stress_label .. " "
                    end
                end
            end
        end

        local left  = " " .. location_str .. "  " .. time_str
        ctx.ui.status(left, right_str)
    end
end

return status

end

package.preload["engine.verbs.acquisition"] = function()
-- engine/verbs/acquisition.lua
local H = require("engine.verbs.helpers")

local fsm_mod = H.fsm_mod
local presentation = H.presentation
local preprocess = H.preprocess
local traverse_effects = H.traverse_effects
local effects = H.effects
local materials = H.materials
local context_window = H.context_window
local fuzzy = H.fuzzy

local GAME_SECONDS_PER_REAL_SECOND = H.GAME_SECONDS_PER_REAL_SECOND
local GAME_START_HOUR = H.GAME_START_HOUR
local DAYTIME_START = H.DAYTIME_START
local DAYTIME_END = H.DAYTIME_END

local next_instance_id = H.next_instance_id
local _hid = H._hid
local _hobj = H._hobj
local err_not_found = H.err_not_found
local err_cant_do_that = H.err_cant_do_that
local err_nothing_happens = H.err_nothing_happens
local matches_keyword = H.matches_keyword
local interaction_verbs = H.interaction_verbs
local hands_full = H.hands_full
local first_empty_hand = H.first_empty_hand
local which_hand = H.which_hand
local get_all_carried_ids = H.get_all_carried_ids
local count_hands_used = H.count_hands_used
local find_part = H.find_part
local detach_part = H.detach_part
local reattach_part = H.reattach_part
local _fv_room = H._fv_room
local _fv_surfaces = H._fv_surfaces
local _fv_parts = H._fv_parts
local _fv_hands = H._fv_hands
local _fv_bags = H._fv_bags
local _fv_worn = H._fv_worn
local find_visible = H.find_visible
local find_in_inventory = H.find_in_inventory
local find_tool_in_inventory = H.find_tool_in_inventory
local provides_capability = H.provides_capability
local find_visible_tool = H.find_visible_tool
local consume_tool_charge = H.consume_tool_charge
local remove_from_location = H.remove_from_location
local container_contents_accessible = H.container_contents_accessible
local find_mutation = H.find_mutation
local spawn_objects = H.spawn_objects
local perform_mutation = H.perform_mutation
local inventory_weight = H.inventory_weight
local move_spatial_object = H.move_spatial_object
local try_fsm_verb = H.try_fsm_verb

local get_game_time = H.get_game_time
local is_daytime = H.is_daytime
local format_time = H.format_time
local time_of_day_desc = H.time_of_day_desc
local get_light_level = H.get_light_level
local has_some_light = H.has_some_light
local vision_blocked_by_worn = H.vision_blocked_by_worn

local M = {}

function M.register(handlers)
    ---------------------------------------------------------------------------
    -- TAKE / GET / PICK UP / GET X FROM Y
    ---------------------------------------------------------------------------
    handlers["take"] = function(ctx, noun)
        if noun == "" then print("Take what?") return end

        -- "take off X" → remove (unequip worn item)
        local off_target = noun:match("^off%s+(.+)")
        if off_target then
            handlers["remove"](ctx, off_target)
            return
        end

        -- "pick up X"
        local target = noun:match("^up%s+(.+)") or noun

        -- "get X from Y" -- extract from a bag/container (carried or visible)
        local from_item, from_container = target:match("^(.+)%s+from%s+(.+)$")
        if from_item then
            local bag = find_in_inventory(ctx, from_container)
            if not bag then
                -- Also check visible containers (detached drawer on floor, etc.)
                local visible_bag = find_visible(ctx, from_container)
                if visible_bag and (visible_bag.container and visible_bag.contents) then
                    bag = visible_bag
                elseif visible_bag and visible_bag.surfaces then
                    -- Surface-based container (wardrobe, etc.)
                    bag = visible_bag
                elseif visible_bag then
                    print((visible_bag.name or "That") .. " is not a container.")
                    return
                else
                    print("You don't see " .. from_container .. " here.")
                    return
                end
            end

            -- Determine where to search: regular contents or surfaces
            local search_lists = {}
            if bag.container and bag.contents then
                -- BUG-116: check accessible flag on root-content containers
                if bag.accessible == false then
                    local bag_name = bag.name or "that"
                    print(bag_name:sub(1,1):upper() .. bag_name:sub(2) .. " is closed.")
                    return
                end
                search_lists[#search_lists + 1] = { source = bag.contents, type = "contents" }
            end
            if bag.surfaces then
                for sname, zone in pairs(bag.surfaces) do
                    if zone.accessible ~= false and zone.contents then
                        search_lists[#search_lists + 1] = { source = zone.contents, type = "surface", name = sname }
                    end
                end
            end

            if #search_lists == 0 then
                print((bag.name or "That") .. " is not a container.")
                return
            end

            local kw = from_item:lower()
                :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
            local found_idx, found_id, found_list
            for _, sl in ipairs(search_lists) do
                for i, item_id in ipairs(sl.source) do
                    local item = ctx.registry:get(item_id)
                    if item and matches_keyword(item, kw) then
                        found_idx = i
                        found_id = item_id
                        found_list = sl.source
                        break
                    end
                end
                if found_id then break end
            end
            if not found_id then
                print("There is no " .. from_item .. " in " .. (bag.name or "that") .. ".")
                return
            end
            local slot = first_empty_hand(ctx)
            if not slot then
                print("Your hands are full. Drop something first.")
                return
            end
            table.remove(found_list, found_idx)
            local item = ctx.registry:get(found_id)
            item.location = "player"
            if not item.instance_id then item.instance_id = next_instance_id() end
            ctx.player.hands[slot] = item
            print("You take " .. (item and item.name or found_id) .. " from " .. (bag.name or "the container") .. ".")
            -- on_pickup hook: fire callback if object declares one
            if item.on_pickup and type(item.on_pickup) == "function" then
                item.on_pickup(item, ctx)
            end
            -- event_output: one-shot flavor text for on_take
            if item.event_output and item.event_output["on_take"] then
                print(item.event_output["on_take"])
                item.event_output["on_take"] = nil
            end
            return
        end

        local obj, where, parent, sname = find_visible(ctx, target)
        if not obj then
            err_not_found(ctx)
            return
        end

        -- Bug #53 + #180 + #294: Guard against taking the exact same object.
        -- Use table identity (not id string) so different instances of the same
        -- type are not blocked (e.g., two silk-bundles for silk-rope crafting).
        if obj.location == "player" then
            for i = 1, 2 do
                if ctx.player.hands[i] then
                    local hand_obj = _hobj(ctx.player.hands[i], ctx.registry)
                    if hand_obj == obj then
                        print("You already have that.")
                        return
                    end
                end
            end
            for _, worn_id in ipairs(ctx.player.worn or {}) do
                if ctx.registry:get(worn_id) == obj then
                    print("You're wearing that. You'll need to remove it first.")
                    return
                end
            end
        end

        -- BUG-091: Prefer non-spent items from containers over terminal items on floor.
        -- Checks hand-held containers first, then visible containers in the room.
        if where == "room" and obj._state and obj.states then
            local cur_state = obj.states[obj._state]
            if cur_state and cur_state.terminal then
                local reg = ctx.registry
                local kw = target:lower()
                    :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
                local alt_obj, alt_parent
                -- 1) Search carried containers (bags in hands)
                for i = 1, 2 do
                    local hand = ctx.player.hands[i]
                    if hand then
                        local bag = _hobj(hand, reg)
                        if bag and bag.container and bag.contents then
                            for _, item_id in ipairs(bag.contents) do
                                local item = reg:get(item_id)
                                if item and matches_keyword(item, kw) then
                                    local istate = item.states and item._state
                                        and item.states[item._state]
                                    if not istate or not istate.terminal then
                                        alt_obj = item
                                        alt_parent = bag
                                        break
                                    end
                                end
                            end
                        end
                    end
                    if alt_obj then break end
                end
                -- 2) Search visible containers in the room (surfaces, open containers)
                if not alt_obj then
                    local room = ctx.current_room
                    for _, room_obj_id in ipairs(room.contents or {}) do
                        local room_obj = reg:get(room_obj_id)
                        if room_obj then
                            -- Check accessible surface containers (e.g. matchbox on nightstand)
                            if room_obj.surfaces then
                                for _, zone in pairs(room_obj.surfaces) do
                                    if zone.accessible ~= false then
                                        for _, item_id in ipairs(zone.contents or {}) do
                                            local item = reg:get(item_id)
                                            if item and item.container and item.contents
                                                    and item.accessible ~= false then
                                                for _, inner_id in ipairs(item.contents) do
                                                    local inner = reg:get(inner_id)
                                                    if inner and matches_keyword(inner, kw) then
                                                        local ist = inner.states and inner._state
                                                            and inner.states[inner._state]
                                                        if not ist or not ist.terminal then
                                                            alt_obj = inner
                                                            alt_parent = item
                                                            break
                                                        end
                                                    end
                                                end
                                            end
                                            if alt_obj then break end
                                        end
                                    end
                                    if alt_obj then break end
                                end
                            end
                            -- Check non-surface containers in room
                            if not alt_obj and room_obj.container and room_obj.contents
                                    and room_obj.accessible ~= false then
                                for _, item_id in ipairs(room_obj.contents) do
                                    local item = reg:get(item_id)
                                    if item and matches_keyword(item, kw) then
                                        local ist = item.states and item._state
                                            and item.states[item._state]
                                        if not ist or not ist.terminal then
                                            alt_obj = item
                                            alt_parent = room_obj
                                            break
                                        end
                                    end
                                end
                            end
                        end
                        if alt_obj then break end
                    end
                end
                if alt_obj then
                    obj = alt_obj
                    where = "bag"
                    parent = alt_parent
                    sname = nil
                end
            end
        end

        if where == "hand" or where == "worn" then
            print("You already have that.")
            return
        end

        -- "bag" or "container" means item is inside a container (held or in the room).
        -- Allow extracting it to a free hand (e.g., pulling a match from a matchbox,
        -- or taking a candle from a holder on a surface). (#215)
        if (where == "bag" or where == "container") and parent then
            if not obj.portable then
                print(obj.not_portable_reason or ("You can't carry " .. (obj.name or "that") .. "."))
                return
            end
            local slot = first_empty_hand(ctx)
            if not slot then
                print("Your hands are full. Drop something first.")
                return
            end
            if parent.contents then
                for i, cid in ipairs(parent.contents) do
                    if cid == obj.id then
                        table.remove(parent.contents, i)
                        break
                    end
                end
            end
            if not obj.instance_id then obj.instance_id = next_instance_id() end
            ctx.player.hands[slot] = obj
            obj.location = "player"
            print("You take " .. (obj.name or obj.id) .. " from " .. (parent.name or "the container") .. ".")
            -- on_pickup hook: fire callback if object declares one
            if obj.on_pickup and type(obj.on_pickup) == "function" then
                obj.on_pickup(obj, ctx)
            end
            -- event_output: one-shot flavor text for on_take
            if obj.event_output and obj.event_output["on_take"] then
                print(obj.event_output["on_take"])
                obj.event_output["on_take"] = nil
            end
            return
        end

        if not obj.portable then
            print(obj.not_portable_reason or ("You can't carry " .. (obj.name or "that") .. "."))
            return
        end

        -- Two-handed carry check
        local hr = obj.hands_required or 1
        if hr >= 2 then
            local used, free = count_hands_used(ctx)
            if free < 2 then
                print("You need both hands free to carry " .. (obj.name or "that") .. ".")
                return
            end
            remove_from_location(ctx, obj)
            if not obj.instance_id then obj.instance_id = next_instance_id() end
            ctx.player.hands[1] = obj
            ctx.player.hands[2] = obj
            obj.location = "player"
            print("You take " .. (obj.name or obj.id) .. " with both hands.")
            -- on_pickup hook: fire callback if object declares one
            if obj.on_pickup and type(obj.on_pickup) == "function" then
                obj.on_pickup(obj, ctx)
            end
            -- event_output: one-shot flavor text for on_take
            if obj.event_output and obj.event_output["on_take"] then
                print(obj.event_output["on_take"])
                obj.event_output["on_take"] = nil
            end
            return
        end

        local slot = first_empty_hand(ctx)
        if not slot then
            print("Your hands are full. Drop something first.")
            return
        end

        remove_from_location(ctx, obj)
        if not obj.instance_id then obj.instance_id = next_instance_id() end
        ctx.player.hands[slot] = obj
        obj.location = "player"

        print("You take " .. (obj.name or obj.id) .. ".")
        -- on_pickup hook: fire callback if object declares one
        if obj.on_pickup and type(obj.on_pickup) == "function" then
            obj.on_pickup(obj, ctx)
        end
        -- event_output: one-shot flavor text for on_take
        if obj.event_output and obj.event_output["on_take"] then
            print(obj.event_output["on_take"])
            obj.event_output["on_take"] = nil
        end
    end

    handlers["get"] = function(ctx, noun)
        -- "get X from Y" and regular get both go through take
        handlers["take"](ctx, noun)
    end
    handlers["pick"] = function(ctx, noun)
        -- "pick lock" → lockpicking (stub)
        if noun:match("^lock") then
            print("You don't know how to pick locks.")
            return
        end
        -- Otherwise fall through to take ("pick up X", "pick X")
        handlers["take"](ctx, noun)
    end
    handlers["grab"] = handlers["take"]

    ---------------------------------------------------------------------------
    -- PULL / YANK / TUG / EXTRACT — detach composite parts
    ---------------------------------------------------------------------------
    handlers["pull"] = function(ctx, noun)
        if noun == "" then print("Pull what?") return end

        -- Strip "out" preposition: "pull out drawer" → "drawer"
        local target = noun:match("^out%s+(.+)") or noun
        -- "pull X out of Y" → just use X
        target = target:match("^(.+)%s+out%s+of%s+") or target
        -- "pull X from Y" → just use X
        target = target:match("^(.+)%s+from%s+") or target

        -- First: check if the noun matches a detachable part
        local part, parent_obj, part_key = find_part(ctx, target)
        if part and part.detachable then
            -- Check if this verb is valid for this part
            local valid_verb = false
            if part.detach_verbs then
                for _, v in ipairs(part.detach_verbs) do
                    if v == "pull" then valid_verb = true; break end
                end
            else
                valid_verb = true  -- default: PULL always works
            end

            if valid_verb then
                local new_obj, msg = detach_part(ctx, parent_obj, part_key)
                if new_obj then
                    print(msg)
                else
                    print(msg or "You can't pull that out.")
                end
                return
            end
        end

        -- Non-detachable part: descriptive response
        if part and not part.detachable then
            print("You pull at " .. (part.name or "it") .. ", but it won't budge. It's firmly attached.")
            return
        end

        -- Fall through: try FSM "pull" transition on a visible object
        local obj = find_visible(ctx, target)
        if obj then
            -- Spatial movement for movable objects
            if obj.movable then
                move_spatial_object(ctx, obj, "pull")
                return
            end

            if obj.states then
                local transitions = fsm_mod.get_transitions(obj)
                local target_trans
                for _, t in ipairs(transitions) do
                    if t.verb == "pull" then target_trans = t; break end
                    if t.verb == "open" then target_trans = t; break end
                    if t.aliases then
                        for _, alias in ipairs(t.aliases) do
                            if alias == "pull" then target_trans = t; break end
                        end
                        if target_trans then break end
                    end
                end
                if target_trans then
                    local trans = fsm_mod.transition(ctx.registry, obj.id, target_trans.to, {})
                    if trans then
                        print(trans.message or ("You pull " .. (obj.name or obj.id) .. "."))
                    else
                        print("You can't pull " .. (obj.name or "that") .. ".")
                    end
                    return
                end
            end
            err_nothing_happens(obj)
            return
        end

        err_not_found(ctx)
    end

    handlers["yank"] = handlers["pull"]
    handlers["tug"] = handlers["pull"]
    handlers["extract"] = handlers["pull"]

    ---------------------------------------------------------------------------
    -- PUSH / SHOVE — move heavy objects aside
    ---------------------------------------------------------------------------
    handlers["push"] = function(ctx, noun)
        if noun == "" then print("Push what?") return end

        -- Strip trailing "aside" / "away" / "over"
        local target = noun:gsub("%s+aside$", ""):gsub("%s+away$", ""):gsub("%s+over$", "")

        local obj = find_visible(ctx, target)

        -- Registry fallback for objects not in standard search paths (traps, etc.)
        if not obj and ctx.registry and ctx.registry.find_by_keyword then
            obj = ctx.registry:find_by_keyword(target)
        end

        if not obj then
            err_not_found(ctx)
            return
        end

        -- Check for FSM transitions first (traps, mechanisms, etc.)
        if try_fsm_verb(ctx, obj, "push") then
            return
        end

        move_spatial_object(ctx, obj, "push")
    end

    handlers["shove"] = handlers["push"]
    handlers["nudge"] = handlers["push"]

    ---------------------------------------------------------------------------
    -- MOVE / SHIFT / DRAG — general spatial movement
    ---------------------------------------------------------------------------
    handlers["move"] = function(ctx, noun)
        if noun == "" then print("Move what?") return end

        -- Strip trailing "aside" / "away" / "over"
        local target = noun:gsub("%s+aside$", ""):gsub("%s+away$", ""):gsub("%s+over$", "")

        local obj = find_visible(ctx, target)
        if not obj then
            err_not_found(ctx)
            return
        end

        move_spatial_object(ctx, obj, "move")
    end

    handlers["shift"] = handlers["move"]
    handlers["drag"]  = handlers["move"]

    ---------------------------------------------------------------------------
    -- SLIDE — slide objects sideways (#111)
    ---------------------------------------------------------------------------
    handlers["slide"] = function(ctx, noun)
        if noun == "" then print("Slide what?") return end

        -- Strip trailing "aside" / "away" / "over"
        local target = noun:gsub("%s+aside$", ""):gsub("%s+away$", ""):gsub("%s+over$", "")

        local obj = find_visible(ctx, target)
        if not obj then
            err_not_found(ctx)
            return
        end

        move_spatial_object(ctx, obj, "slide")
    end

    ---------------------------------------------------------------------------
    -- LIFT / HEAVE — pick up or reveal what's under something
    ---------------------------------------------------------------------------
    handlers["lift"] = function(ctx, noun)
        if noun == "" then print("Lift what?") return end

        -- Strip trailing "up"
        local target = noun:gsub("%s+up$", "")

        local obj = find_visible(ctx, target)
        if not obj then
            err_not_found(ctx)
            return
        end

        -- If it's movable, treat like pull
        if obj.movable then
            move_spatial_object(ctx, obj, "lift")
            return
        end

        -- If portable, try to pick it up
        if obj.portable then
            handlers["take"](ctx, noun)
            return
        end

        if obj.weight and obj.weight >= 50 then
            print("You strain to lift " .. (obj.name or "it") .. ", but it won't budge. It's far too heavy.")
        else
            print("You can't lift " .. (obj.name or "that") .. ".")
        end
    end

    handlers["heave"] = handlers["lift"]

    ---------------------------------------------------------------------------
    -- UNCORK / UNSTOP / UNSEAL — shorthand for detaching cork-type parts
    ---------------------------------------------------------------------------
    handlers["uncork"] = function(ctx, noun)
        if noun == "" then print("Uncork what?") return end

        local obj = find_visible(ctx, noun)
        if not obj then
            err_not_found(ctx)
            return
        end

        -- Check if the object has a cork part we can detach
        if obj.parts then
            for part_key, part in pairs(obj.parts) do
                if part.detachable and part.detach_verbs then
                    for _, v in ipairs(part.detach_verbs) do
                        if v == "uncork" then
                            local new_obj, msg = detach_part(ctx, obj, part_key)
                            if new_obj then
                                print(msg)
                            else
                                print(msg or "You can't uncork that.")
                            end
                            return
                        end
                    end
                end
            end
        end

        -- Fall through: try FSM "open" transition with uncork alias
        if obj.states then
            local transitions = fsm_mod.get_transitions(obj)
            local target_trans
            for _, t in ipairs(transitions) do
                if t.verb == "uncork" then target_trans = t; break end
                if t.aliases then
                    for _, alias in ipairs(t.aliases) do
                        if alias == "uncork" then target_trans = t; break end
                    end
                    if target_trans then break end
                end
            end
            if target_trans then
                local trans = fsm_mod.transition(ctx.registry, obj.id, target_trans.to, {})
                if trans then
                    print(trans.message or ("You uncork " .. (obj.name or obj.id) .. "."))
                else
                    print("You can't uncork " .. (obj.name or "that") .. ".")
                end
                return
            end
        end

        print("You can't uncork " .. (obj.name or "that") .. ".")
    end

    handlers["unstop"] = handlers["uncork"]
    handlers["unseal"] = handlers["uncork"]

    ---------------------------------------------------------------------------
    -- DROP
    ---------------------------------------------------------------------------
    handlers["drop"] = function(ctx, noun)
        if noun == "" then print("Drop what?") return end

        -- #139: "drop all" / "drop everything" — bulk drop all held items
        local kw_raw = noun:lower()
            :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
        if kw_raw == "all" or kw_raw == "everything" then
            local dropped_any = false
            for i = 1, 2 do
                local hand = ctx.player.hands[i]
                if hand then
                    local held_obj = _hobj(hand, ctx.registry)
                    if held_obj then
                        ctx.player.hands[i] = nil
                        ctx.current_room.contents[#ctx.current_room.contents + 1] = held_obj.id
                        held_obj.location = ctx.current_room.id
                        print("You drop " .. (held_obj.name or held_obj.id) .. ".")
                        -- on_drop hook: fire callback if object declares one
                        if held_obj.on_drop and type(held_obj.on_drop) == "function" then
                            held_obj.on_drop(held_obj, ctx)
                        end
                        dropped_any = true
                    end
                end
            end
            if not dropped_any then
                print("You aren't holding anything.")
            end
            return
        end

        -- Only drop items directly in hands (not bag contents or worn)
        local obj = nil
        local hand_slot = nil
        local kw = kw_raw
        for i = 1, 2 do
            local hand = ctx.player.hands[i]
            if hand then
                local candidate = _hobj(hand, ctx.registry)
                if candidate and matches_keyword(candidate, kw) then
                    obj = candidate
                    hand_slot = i
                    break
                end
            end
        end

        -- Bug #181: Fuzzy fallback when exact keyword match fails on hands
        if not obj and fuzzy then
            local parsed = fuzzy.parse_noun_phrase(kw)
            for i = 1, 2 do
                local hand = ctx.player.hands[i]
                if hand then
                    local candidate = _hobj(hand, ctx.registry)
                    if candidate then
                        local score = fuzzy.score_object(candidate, parsed)
                        if score > 0 then
                            obj = candidate
                            hand_slot = i
                            break
                        end
                    end
                end
            end
        end

        if not obj then
            -- #137: Check if it's a worn item — give appropriate message
            local kw_check = noun:lower()
                :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
            local is_worn = false
            for _, worn_id in ipairs(ctx.player.worn or {}) do
                local worn_obj = ctx.registry and ctx.registry:get(worn_id)
                if worn_obj and matches_keyword(worn_obj, kw_check) then
                    is_worn = true
                    break
                end
            end
            -- Bug #181: Fuzzy fallback for worn item check
            if not is_worn and fuzzy then
                local parsed = fuzzy.parse_noun_phrase(kw_check)
                for _, worn_id in ipairs(ctx.player.worn or {}) do
                    local worn_obj = ctx.registry and ctx.registry:get(worn_id)
                    if worn_obj then
                        local score = fuzzy.score_object(worn_obj, parsed)
                        if score > 0 then
                            is_worn = true
                            break
                        end
                    end
                end
            end
            if is_worn then
                print("You're wearing that. You'll need to remove it first.")
            else
                -- Check if it's in a bag -- give a helpful message
                local bag_item = find_in_inventory(ctx, noun)
                if bag_item then
                    print("You'll need to get that out of the bag first, or drop the bag itself.")
                else
                    print("You aren't holding that.")
                end
            end
            return
        end

        -- Clear both hands if two-handed item
        ctx.player.hands[hand_slot] = nil
        if obj.hands_required and obj.hands_required >= 2 then
            for i = 1, 2 do
                if _hid(ctx.player.hands[i]) == obj.id then
                    ctx.player.hands[i] = nil
                end
            end
        end
        ctx.current_room.contents[#ctx.current_room.contents + 1] = obj.id
        obj.location = ctx.current_room.id

        -- on_drop: material fragility check
        local mat = obj.material and materials.get(obj.material)
        local floor_mat_name = ctx.current_room.floor_material or "stone"
        local floor_mat = materials.get(floor_mat_name)
        local surface_hardness = floor_mat and floor_mat.hardness or 7
        if mat and mat.fragility >= 0.5 and surface_hardness >= 5 then
            -- Object shatters on impact
            local shatter_mut = obj.mutations and obj.mutations.shatter
            if shatter_mut and shatter_mut.narration then
                print(shatter_mut.narration)
            else
                print("The " .. (obj.name or obj.id):gsub("^a%s+", ""):gsub("^an%s+", "")
                    .. " shatters on the " .. floor_mat_name .. " floor"
                    .. ", sending fragments skittering across the room.")
            end

            -- Fire FSM shatter/break transition if available
            if obj.states then
                local shatter_target = nil
                for _, t in ipairs(obj.transitions or {}) do
                    if (t.verb == "shatter" or t.verb == "break")
                       and (not t.from or t.from == obj._state) then
                        shatter_target = t.to
                        break
                    end
                end
                if shatter_target then
                    fsm_mod.transition(ctx.registry, obj.id, shatter_target, ctx, "break")
                end
            end

            -- Spawn debris from mutations.shatter.spawns
            if shatter_mut and shatter_mut.spawns then
                for _, shard_id in ipairs(shatter_mut.spawns) do
                    local shard_def = ctx.registry:get(shard_id)
                    if shard_def then
                        -- Shard already registered; place a copy in room
                        local shard_copy = {}
                        for k, v in pairs(shard_def) do shard_copy[k] = v end
                        shard_copy._instance_id = next_instance_id()
                        shard_copy.location = ctx.current_room.id
                        ctx.registry:register(shard_id .. "-" .. shard_copy._instance_id, shard_copy)
                        ctx.current_room.contents[#ctx.current_room.contents + 1] =
                            shard_id .. "-" .. shard_copy._instance_id
                    else
                        -- Attempt to load definition from disk
                        local SEP = package.config:sub(1, 1)
                        local shard_path = "." .. SEP .. "src" .. SEP .. "meta" .. SEP
                            .. "objects" .. SEP .. shard_id .. ".lua"
                        local load_ok, shard_data = pcall(dofile, shard_path)
                        if load_ok and shard_data then
                            shard_data._instance_id = next_instance_id()
                            shard_data.location = ctx.current_room.id
                            local inst_id = shard_id .. "-" .. shard_data._instance_id
                            shard_data.id = inst_id
                            ctx.registry:register(inst_id, shard_data)
                            ctx.current_room.contents[#ctx.current_room.contents + 1] = inst_id
                        end
                    end
                end
            end

            -- Remove original object from room
            for i = #ctx.current_room.contents, 1, -1 do
                if ctx.current_room.contents[i] == obj.id then
                    table.remove(ctx.current_room.contents, i)
                    break
                end
            end
            obj.location = nil
        else
            -- Object survives the drop
            if mat and mat.hardness and mat.hardness >= 5 then
                print("The " .. (obj.name or obj.id):gsub("^a%s+", ""):gsub("^an%s+", "")
                    .. " hits the floor with a resonant clang.")
            else
                print("You drop " .. (obj.name or obj.id) .. ".")
            end
        end

        -- on_drop hook: fire callback if object declares one
        if obj.on_drop and type(obj.on_drop) == "function" then
            obj.on_drop(obj, ctx)
        end
        -- event_output: one-shot flavor text for on_drop
        if obj.event_output and obj.event_output["on_drop"] then
            print(obj.event_output["on_drop"])
            obj.event_output["on_drop"] = nil
        end
    end
end

return M

end

package.preload["engine.verbs.butchery"] = function()
-- engine/verbs/butchery.lua
-- Butcher verb handler: converts large corpses into portable meat/bone/hide.
-- Split from crafting.lua for Phase 4 WAVE-1.
--
-- Ownership: Smithers (UI Engineer)

local H = require("engine.verbs.helpers")

local err_not_found = H.err_not_found
local find_visible = H.find_visible
local find_tool_in_inventory = H.find_tool_in_inventory
local find_visible_tool = H.find_visible_tool
local show_hint = H.show_hint
local _hid = H._hid

local fsm_mod = H.fsm_mod

local M = {}

function M.register(handlers)
    ---------------------------------------------------------------------------
    -- BUTCHER {corpse} — processes large corpses into portable resources.
    -- Requires a tool with "butchering" capability (e.g., knife).
    -- Products declared on corpse's death_state.butchery_products (Principle 8).
    -- Advances game time by 5 minutes (Option B, per D-BUTCHERY-TIME).
    ---------------------------------------------------------------------------
    handlers["butcher"] = function(ctx, noun)
        if noun == "" then
            print("Butcher what?")
            return
        end

        -- Resolve target (corpses are room-floor objects after death reshape)
        local target = find_visible(ctx, noun)
        if not target then
            err_not_found(ctx)
            return
        end

        -- #343: Must be dead — reject any living creature regardless of death_state
        if target.alive ~= false then
            print("You can't butcher a living creature.")
            return
        end

        -- Must have butchery_products declared in death_state
        local butch = target.death_state and target.death_state.butchery_products
        if not butch then
            print("There's nothing useful to carve from this corpse.")
            return
        end

        -- Tool check: player needs a tool with the required capability
        local tool = find_tool_in_inventory(ctx, butch.requires_tool)
        if not tool then
            tool = find_visible_tool(ctx, butch.requires_tool)
        end
        if not tool then
            -- #357: Distinguish "no tool" from "wrong tool" — check if player
            -- holds something knife-like that lacks the required capability
            local held_blade = nil
            for i = 1, 2 do
                local h_obj = ctx.player.hands[i]
                if h_obj then
                    local kws = h_obj.keywords or {}
                    for _, kw in ipairs(kws) do
                        if kw:find("knife") or kw:find("blade") or kw:find("dagger") then
                            held_blade = h_obj
                            break
                        end
                    end
                    if not held_blade and h_obj.id and
                       (h_obj.id:find("knife") or h_obj.id:find("blade") or h_obj.id:find("dagger")) then
                        held_blade = h_obj
                    end
                end
                if held_blade then break end
            end
            if held_blade then
                print("Your " .. (held_blade.id or "blade") .. " isn't suited for butchering. You need a proper butchering tool.")
            else
                print("You need a sharp tool capable of butchering.")
            end
            return
        end

        -- Start narration
        print(butch.narration.start)

        -- Advance game time: 5 minutes = 5/60 hours
        -- Follows rest.lua pattern: ctx.time_offset is in game hours
        local BUTCHER_HOURS = 5 / 60
        ctx.time_offset = (ctx.time_offset or 0) + BUTCHER_HOURS

        -- Tick FSMs for elapsed time (1 tick ≈ 6 minutes, close enough for 5 min)
        local reg = ctx.registry
        local room = ctx.current_room
        local tick_targets = {}
        for _, obj_id in ipairs(room and room.contents or {}) do
            tick_targets[#tick_targets + 1] = obj_id
            local obj = reg:get(obj_id)
            if obj and obj.surfaces then
                for _, zone in pairs(obj.surfaces) do
                    for _, item_id in ipairs(zone.contents or {}) do
                        tick_targets[#tick_targets + 1] = item_id
                    end
                end
            end
        end
        -- Include held items (candles burning in hand)
        if ctx.player then
            for i = 1, 2 do
                if ctx.player.hands[i] then
                    tick_targets[#tick_targets + 1] = _hid(ctx.player.hands[i])
                end
            end
        end

        for _, obj_id in ipairs(tick_targets) do
            local obj = reg:get(obj_id)
            if obj and obj._state then
                fsm_mod.tick(reg, obj_id)
            end
        end
        if ctx.on_tick then
            ctx.on_tick(ctx)
        end

        -- Instantiate products into room
        local spawns = {}
        for _, prod in ipairs(butch.products) do
            for i = 1, prod.quantity do
                spawns[#spawns + 1] = prod.id
            end
        end

        -- Use object_sources + loader when available (production engine),
        -- fall back to spawn_objects helper or skip gracefully.
        if ctx.object_sources and ctx.loader then
            local room = ctx.current_room
            for _, spawn_id in ipairs(spawns) do
                local source = ctx.object_sources[spawn_id]
                if source then
                    local spawn_obj, err = ctx.loader.load_source(source)
                    if spawn_obj and ctx.templates then
                        spawn_obj = ctx.loader.resolve_template(spawn_obj, ctx.templates)
                    end
                    if spawn_obj then
                        local actual_id = spawn_id
                        if reg:get(spawn_id) then
                            local n = 2
                            while reg:get(spawn_id .. "-" .. n) do n = n + 1 end
                            actual_id = spawn_id .. "-" .. n
                        end
                        spawn_obj.id = actual_id
                        spawn_obj.location = room.id
                        reg:register(actual_id, spawn_obj)
                        room.contents[#room.contents + 1] = actual_id
                    end
                end
            end
        end

        -- Remove corpse if specified
        if butch.removes_corpse then
            -- Remove from room contents (match by id or guid for robustness)
            local room_contents = room.contents or {}
            for i = #room_contents, 1, -1 do
                local entry = room_contents[i]
                if entry == target.id or entry == target.guid then
                    table.remove(room_contents, i)
                    break
                end
            end
            reg:remove(target.id)
        end

        -- Completion narration
        print(butch.narration.complete)

        -- WAVE-3: Trauma hook — butchery is gory, player witnesses gore
        local inj_ok, inj_mod = pcall(require, "engine.injuries")
        if inj_ok and inj_mod and inj_mod.add_stress then
            inj_mod.add_stress(ctx.player, "witness_gore")
        end

        show_hint(ctx, "butcher", "Butchering large creatures yields meat, bones, and hides you can use.")
    end

    -- Verb aliases
    if not handlers["carve"] then
        handlers["carve"] = handlers["butcher"]
    end
    handlers["skin"]    = handlers["butcher"]
    handlers["fillet"]  = handlers["butcher"]
    handlers["dissect"] = handlers["butcher"]
    handlers["gut"]     = handlers["butcher"]
end

return M

end

package.preload["engine.verbs.combat"] = function()
-- engine/verbs/combat.lua
local H = require("engine.verbs.helpers")

local fsm_mod = H.fsm_mod
local presentation = H.presentation
local preprocess = H.preprocess
local traverse_effects = H.traverse_effects
local effects = H.effects
local materials = H.materials
local context_window = H.context_window
local fuzzy = H.fuzzy

local GAME_SECONDS_PER_REAL_SECOND = H.GAME_SECONDS_PER_REAL_SECOND
local GAME_START_HOUR = H.GAME_START_HOUR
local DAYTIME_START = H.DAYTIME_START
local DAYTIME_END = H.DAYTIME_END

local next_instance_id = H.next_instance_id
local _hid = H._hid
local _hobj = H._hobj
local err_not_found = H.err_not_found
local err_cant_do_that = H.err_cant_do_that
local err_nothing_happens = H.err_nothing_happens
local matches_keyword = H.matches_keyword
local interaction_verbs = H.interaction_verbs
local hands_full = H.hands_full
local first_empty_hand = H.first_empty_hand
local which_hand = H.which_hand
local get_all_carried_ids = H.get_all_carried_ids
local count_hands_used = H.count_hands_used
local find_part = H.find_part
local detach_part = H.detach_part
local reattach_part = H.reattach_part
local _fv_room = H._fv_room
local _fv_surfaces = H._fv_surfaces
local _fv_parts = H._fv_parts
local _fv_hands = H._fv_hands
local _fv_bags = H._fv_bags
local _fv_worn = H._fv_worn
local find_visible = H.find_visible
local find_in_inventory = H.find_in_inventory
local find_tool_in_inventory = H.find_tool_in_inventory
local provides_capability = H.provides_capability
local find_visible_tool = H.find_visible_tool
local consume_tool_charge = H.consume_tool_charge
local remove_from_location = H.remove_from_location
local container_contents_accessible = H.container_contents_accessible
local find_mutation = H.find_mutation
local spawn_objects = H.spawn_objects
local perform_mutation = H.perform_mutation
local inventory_weight = H.inventory_weight
local move_spatial_object = H.move_spatial_object
local random_body_area = H.random_body_area
local parse_self_infliction = H.parse_self_infliction
local handle_self_infliction = H.handle_self_infliction

local get_game_time = H.get_game_time
local is_daytime = H.is_daytime
local format_time = H.format_time
local time_of_day_desc = H.time_of_day_desc
