local has_some_light = H.has_some_light
local vision_blocked_by_worn = H.vision_blocked_by_worn

-- Creature stimulus emission (guarded — module may not be loaded)
local function emit_player_attacks(ctx, target_id)
    local room_id = ctx.current_room and ctx.current_room.id
        or ctx.player and ctx.player.location
    if not room_id then return end
    local ok, creatures = pcall(require, "engine.creatures")
    if ok and creatures and creatures.emit_stimulus then
        creatures.emit_stimulus(room_id, "player_attacks", {
            source = "player",
            target = target_id,
        })
    end
end

local M = {}

function M.register(handlers)
    ---------------------------------------------------------------------------
    -- Self-infliction: shared logic for stab/cut/slash self
    ---------------------------------------------------------------------------
    ---------------------------------------------------------------------------
    -- STAB {target} WITH {tool}  /  STAB SELF
    ---------------------------------------------------------------------------
    handlers["stab"] = function(ctx, noun)
        if handle_self_infliction(ctx, noun, "stab", "on_stab") then
            emit_player_attacks(ctx, "self")
            return
        end
        -- Stab is only for self-infliction — there are no world objects to stab
        print("You can only stab yourself. (Try: stab self with <weapon>)")
    end
    handlers["jab"] = handlers["stab"]
    handlers["pierce"] = handlers["stab"]
    handlers["stick"] = handlers["stab"]

    ---------------------------------------------------------------------------
    -- HIT {body area}  /  PUNCH / STRIKE / BASH / BONK / SMASH / THUMP
    -- Self-infliction for blunt trauma: head → unconsciousness, limbs → bruise
    ---------------------------------------------------------------------------
    handlers["hit"] = function(ctx, noun)
        if noun == "" then
            print("Hit what?")
            return
        end

        local is_self, body_area, tool_word = parse_self_infliction(noun)
        if not is_self then
            -- Noun provided but doesn't target self/body — not-found (#278)
            err_not_found(ctx)
            return
        end

        -- Resolve body area (default to random if "self")
        if not body_area then
            body_area = random_body_area()
        end

        -- Load injury module
        local inj_ok, injury_mod = pcall(require, "engine.injuries")
        if not inj_ok then
            print("Something goes wrong.")
            return
        end

        -- Head hit → concussion (unconsciousness)
        if body_area == "head" then
            local base_duration = 5  -- bare fist: 5 turns

            -- Check for helmet (worn head armor) — reduces duration
            local helmet = nil
            if ctx.player.worn then
                for _, worn_id in ipairs(ctx.player.worn) do
                    local obj = ctx.registry and ctx.registry.get and ctx.registry:get(worn_id)
                    if not obj then
                        obj = _hobj(worn_id, ctx.registry)
                    end
                    if obj and (obj.wear_slot == "head" or obj.is_helmet) then
                        helmet = obj
                        break
                    end
                end
            end

            local reduction = 0
            if helmet then
                reduction = helmet.reduces_unconsciousness or 0.5
            end

            local final_duration = math.max(1, math.floor(base_duration * (1 - reduction)))

            -- Suppress inflict message (we print our own narration)
            local old_print = _G.print
            _G.print = function() end
            local instance = injury_mod.inflict(ctx.player, "concussion", "self-inflicted (bare fist, hit)", "head", 5)
            _G.print = old_print

            if not instance then
                print("You hit your head, but it doesn't seem to have much effect.")
                return
            end

            -- Trigger unconsciousness
            ctx.player.consciousness = ctx.player.consciousness or {}
            ctx.player.consciousness.state = "unconscious"
            ctx.player.consciousness.wake_timer = final_duration
            ctx.player.consciousness.cause = "blow-to-head"
            ctx.player.consciousness.unconscious_since = ctx.time_offset or 0

            emit_player_attacks(ctx, "self")

            if helmet then
                if final_duration <= 1 then
                    print("You punch your helmeted head. It clangs metallically. Your ears ring, but the helmet took most of the impact.")
                else
                    print("You slam your fist against your helmeted head. The impact rattles you even through the protection. Stars flash across your vision...")
                end
                -- Degrade worn head armor from the impact (#155)
                local armor_ok2, armor_mod = pcall(require, "engine.armor")
                if armor_ok2 and armor_mod.degrade_covering_armor then
                    armor_mod.degrade_covering_armor(ctx.player, "head", 5, "blunt")
                end
            else
                print("You slam your fist hard against the side of your head. Stars explode across your vision. The world tilts and fades...")
            end
            return
        end

        -- Non-head hit → bruise
        local old_print = _G.print
        _G.print = function() end
        local instance = injury_mod.inflict(ctx.player, "bruised", "self-inflicted (bare fist, hit)", body_area, 4)
        _G.print = old_print

        if not instance then
            print("You punch yourself, but it doesn't seem to have much effect.")
            return
        end

        emit_player_attacks(ctx, "self")

        -- Narration by body area
        local narrations = {
            ["left arm"]   = "You punch yourself in the left arm. Sharp pain blooms across the muscle.",
            ["right arm"]  = "You punch yourself in the right arm. Sharp pain blooms across the muscle.",
            ["left hand"]  = "You drive your fist into your left hand. The knuckles ache.",
            ["right hand"] = "You drive your fist into your right hand. The knuckles ache.",
            ["left leg"]   = "You drive your fist down against your left leg. Intense pain shoots through the limb.",
            ["right leg"]  = "You drive your fist down against your right leg. Intense pain shoots through the limb.",
            ["torso"]      = "You drive your fist into your ribs. Air explodes from your lungs.",
            ["stomach"]    = "You punch yourself in the stomach. You double over, gasping.",
        }
        print(narrations[body_area] or ("You punch your " .. body_area .. ". That hurt."))
    end
    handlers["punch"]  = handlers["hit"]
    handlers["bash"]   = handlers["hit"]
    handlers["bonk"]   = handlers["hit"]
    handlers["thump"]  = handlers["hit"]
    handlers["smack"]  = handlers["hit"]
    handlers["bang"]   = handlers["hit"]
    handlers["slap"]   = handlers["hit"]
    handlers["whack"]  = handlers["hit"]
    handlers["headbutt"] = handlers["hit"]
    handlers["toss"]   = handlers["drop"]
    handlers["throw"]  = handlers["drop"]

    ---------------------------------------------------------------------------
    -- CUT {target} WITH {tool}  /  CUT SELF WITH {tool}
    ---------------------------------------------------------------------------
    handlers["cut"] = function(ctx, noun)
        if noun == "" then
            print("Cut what? (Try: cut <thing> with <tool>)")
            return
        end

        -- Try self-infliction first
        if handle_self_infliction(ctx, noun, "cut", "on_cut") then
            emit_player_attacks(ctx, "self")
            return
        end

        -- CUT {object} — world object cutting (existing logic)
        local target_word, tool_word = noun:match("^(.+)%s+with%s+(.+)$")
        if not target_word then target_word = noun end

        if not has_some_light(ctx) then
            print("It is too dark to see what you're doing.")
            return
        end

        local obj = find_visible(ctx, target_word)
        if not obj then
            err_not_found(ctx)
            return
        end

        local mut_data = find_mutation(obj, "cut")
        if mut_data then
            if mut_data.requires_tool then
                local tool = nil
                if tool_word then
                    tool = find_in_inventory(ctx, tool_word)
                    if not tool then
                        print("You don't have " .. tool_word .. ".")
                        return
                    end
                    if not provides_capability(tool, mut_data.requires_tool) then
                        print(mut_data.fail_message or "That tool won't work for cutting this.")
                        return
                    end
                else
                    tool = find_tool_in_inventory(ctx, mut_data.requires_tool)
                    if not tool then
                        print(mut_data.fail_message or "You have nothing to cut with.")
                        return
                    end
                end
            end
            if perform_mutation(ctx, obj, mut_data) then
                print(mut_data.message or "You cut " .. (obj.name or "that") .. ".")
            end
            return
        end

        print("You can't cut " .. (obj.name or "that") .. ".")
    end
    handlers["slice"] = handlers["cut"]
    handlers["nick"] = handlers["cut"]

    ---------------------------------------------------------------------------
    -- SLASH {target} WITH {tool}  /  SLASH SELF WITH {tool}
    ---------------------------------------------------------------------------
    handlers["slash"] = function(ctx, noun)
        if noun == "" then
            print("Slash what?")
            return
        end

        -- Try self-infliction first
        if handle_self_infliction(ctx, noun, "slash", "on_slash") then
            emit_player_attacks(ctx, "self")
            return
        end

        -- Fall through to cut logic for world objects
        handlers["cut"](ctx, noun)
    end
    -- "carve" is a butchery alias (see butchery.lua), not a combat action

    ---------------------------------------------------------------------------
    -- PRICK SELF WITH {tool}
    ---------------------------------------------------------------------------
    handlers["prick"] = function(ctx, noun)
        if noun == "" then
            print("Prick what? (Try: prick self with <pin>)")
            return
        end

        local target_word, tool_word = noun:match("^(.+)%s+with%s+(.+)$")
        if not target_word then target_word = noun end

        -- PRICK SELF -- minor self-injury with any sharp point
        if target_word == "self" or target_word == "myself"
           or target_word == "me" or target_word == "finger"
           or target_word == "thumb" then

            local tool = nil
            if tool_word then
                tool = find_in_inventory(ctx, tool_word)
                if not tool then
                    print("You don't have " .. tool_word .. ".")
                    return
                end
                if not provides_capability(tool, "injury_source") then
                    print("You can't prick yourself with " .. (tool.name or "that") .. ".")
                    return
                end
            else
                tool = find_tool_in_inventory(ctx, "injury_source")
                if not tool then
                    print("You have nothing sharp enough to prick yourself with.")
                    return
                end
            end

            ctx.player.state = ctx.player.state or {}
            ctx.player.state.bloody = true
            ctx.player.state.bleed_ticks = 8
            emit_player_attacks(ctx, "self")
            print("You prick your finger with " .. (tool.name or "the sharp point") .. ". A bead of blood forms.")
            print("Your hands are now bloody.")
            return
        end

        print("You can only prick yourself. (Try: prick self with <pin>)")
    end
end

return M

end

package.preload["engine.verbs.consumption"] = function()
-- engine/verbs/consumption.lua
-- Eat/drink handlers, split from survival.lua in Phase 3 WAVE-0.
-- WAVE-3: raw meat consequences, cookable gating, food effects pipeline.
--
-- Ownership: Smithers (UI Engineer) — eat extensions; Bart (Architect) — drink handler

local H = require("engine.verbs.helpers")

local fsm_mod = H.fsm_mod
local effects = H.effects

local err_not_found = H.err_not_found
local find_visible = H.find_visible
local find_in_inventory = H.find_in_inventory
local find_tool_in_inventory = H.find_tool_in_inventory
local provides_capability = H.provides_capability
local find_visible_tool = H.find_visible_tool
local remove_from_location = H.remove_from_location
local show_hint = H.show_hint

local M = {}

function M.register(handlers)
    local inj_ok, injury_mod = pcall(require, "engine.injuries")

    ---------------------------------------------------------------------------
    -- EAT -- consume food items
    -- WAVE-3: raw meat consequences, cookable gating, food effects pipeline
    ---------------------------------------------------------------------------
    handlers["eat"] = function(ctx, noun)
        if noun == "" then
            print("Eat what? Try 'eat [item]' if you find something edible.")
            return
        end

        local obj = find_in_inventory(ctx, noun)
        if not obj then
            obj = find_visible(ctx, noun)
        end
        if not obj then
            err_not_found(ctx)
            return
        end

        -- WAVE-5 food objects require holding; legacy edible objects are grandfathered
        if obj.food and not find_in_inventory(ctx, noun) then
            print("You'll need to pick that up first.")
            return
        end

        -- Check injury restrictions (e.g. jaw injuries could block eating)
        if inj_ok and injury_mod then
            local restricts = injury_mod.get_restrictions(ctx.player)
            if restricts.eat then
                print("Your injuries prevent you from eating.")
                return
            end
        end

        local food = obj.food

        -- WAVE-3: Raw meat with consequences — edible=false but raw=true and cookable
        if food and food.raw == true and food.cookable == true then
            if food.edible ~= true then
                -- Category-based gating: only meat can be force-eaten raw
                if food.category == "meat" then
                    -- Raw meat: allow eating but with food-poisoning consequence
                    print(obj.on_taste or "The raw flesh tastes foul.")
                    print("You choke it down. Your stomach rebels almost immediately.")
                    -- Inflict food-poisoning injury
                    if inj_ok and injury_mod then
                        injury_mod.inflict(ctx.player, "food-poisoning", obj.id or "raw meat", nil, nil)
                    end
                    -- Apply nutrition (reduced benefit from raw food)
                    if food.nutrition then
                        ctx.player.nutrition = (ctx.player.nutrition or 0) + food.nutrition
                    end
                    show_hint(ctx, "cook", "Cooking raw meat makes it safe to eat and more nourishing.")
                    remove_from_location(ctx, obj)
                    ctx.registry:remove(obj.id)
                    return
                else
                    -- Non-meat raw cookable (grain, vegetables, etc.) — reject
                    print(obj.on_eat_reject or "You can't eat that raw. Try cooking it first.")
                    return
                end
            end
        end

        -- WAVE-3: Non-raw cookable rejection (e.g., items needing cooking but not flagged raw)
        if food and food.cookable == true and food.raw ~= true and food.edible ~= true then
            print(obj.on_eat_reject or "You can't eat that raw. Try cooking it first.")
            return
        end

        -- Check edibility: food.edible (WAVE-5 food table) or legacy obj.edible
        local is_edible = (food and food.edible) or obj.edible
        if not is_edible then
            print("You can't eat " .. (obj.name or "that") .. ".")
            return
        end

        -- Spoiled food warning
        if obj._state == "spoiled" then
            print("This food looks spoiled... but you eat it anyway.")
        else
            print("You eat " .. (obj.name or "it") .. ".")
        end

        -- Emit on_taste sensory text
        if obj.on_taste then
            print(obj.on_taste)
        end

        -- Apply nutrition to player
        if food and food.nutrition then
            ctx.player.nutrition = (ctx.player.nutrition or 0) + food.nutrition
        end

        if obj.on_eat_message then
            print(obj.on_eat_message)
        end
        -- on_eat hook: fire callback if object declares one
        if obj.on_eat and type(obj.on_eat) == "function" then
            obj.on_eat(obj, ctx)
        end
        -- event_output: one-shot flavor text for on_eat
        if obj.event_output and obj.event_output["on_eat"] then
            print(obj.event_output["on_eat"])
            obj.event_output["on_eat"] = nil
        end

        -- WAVE-3: Food effects pipeline — process obj.food.effects array
        if food and food.effects then
            effects.process(food.effects, {
                player = ctx.player,
                registry = ctx.registry,
                source = obj,
                source_id = obj.id or obj.guid,
                game_over = false,
            })
        end

        show_hint(ctx, "eat", "Careful what you eat — not everything is safe to consume.")
        remove_from_location(ctx, obj)
        ctx.registry:remove(obj.id)
    end

    handlers["consume"] = handlers["eat"]
    handlers["devour"] = handlers["eat"]

    ---------------------------------------------------------------------------
    -- DRINK -- consume a liquid (FSM or generic, WAVE-5: restriction check)
    ---------------------------------------------------------------------------
    handlers["drink"] = function(ctx, noun)
        if noun == "" then print("Drink what?") return end

        -- Check injury restrictions before object resolution (rabies hydrophobia)
        if inj_ok and injury_mod then
            local restricts = injury_mod.get_restrictions(ctx.player)
            if restricts.drink then
                print("You can't bring yourself to drink — the mere thought of water fills you with terror.")
                return
            end
        end

        -- Strip "from" preposition: "drink from bottle" → "bottle"
        local target = noun:match("^from%s+(.+)") or noun

        local obj = find_in_inventory(ctx, target)
        if not obj then
            local visible = find_visible(ctx, target)
            if visible then
                print("You'll need to pick that up first.")
            else
                err_not_found(ctx)
            end
            return
        end

        -- FSM path: check for "drink" transition
        if obj.states then
            local transitions = fsm_mod.get_transitions(obj)
            local target_trans
            for _, t in ipairs(transitions) do
                if t.verb == "drink" then target_trans = t; break end
                if t.aliases then
                    for _, alias in ipairs(t.aliases) do
                        if alias == "drink" then target_trans = t; break end
                    end
                    if target_trans then break end
                end
            end
            if target_trans then
                local trans = fsm_mod.transition(ctx.registry, obj.id, target_trans.to, {}, "drink")
                if trans then
                    print(trans.message or ("You drink from " .. (obj.name or obj.id) .. "."))
                    if trans.effect then
                        effects.process(trans.effect, {
                            player = ctx.player,
                            registry = ctx.registry,
                            source = obj,
                            source_id = obj.id,
                            game_over = false,
                        })
                        -- Propagate game_over back to the main context
                        local eff_ctx = { player = ctx.player }
                        if inj_ok and injury_mod then
                            local health = injury_mod.compute_health(ctx.player)
                            if health <= 0 then
                                ctx.game_over = true
                            end
                        end
                    end
                    -- on_drink hook: fire callback if object declares one
                    if obj.on_drink and type(obj.on_drink) == "function" then
                        obj.on_drink(obj, ctx)
                    end
                    -- event_output: one-shot flavor text for on_drink
                    if obj.event_output and obj.event_output["on_drink"] then
                        print(obj.event_output["on_drink"])
                        obj.event_output["on_drink"] = nil
                    end
                else
                end
                return
            end
        end

        -- Food-as-drink path (WAVE-5): objects with food.drinkable
        if obj.food and obj.food.drinkable then
            if obj.on_taste then
                print(obj.on_taste)
            end
            if obj.food.nutrition then
                ctx.player.nutrition = (ctx.player.nutrition or 0) + obj.food.nutrition
            end
            print("You drink " .. (obj.name or "it") .. ".")
            remove_from_location(ctx, obj)
            ctx.registry:remove(obj.id)
            return
        end

        if obj.on_drink_reject then
            print(obj.on_drink_reject)
        else
            print("You can't drink " .. (obj.name or "that") .. ".")
        end
    end

    handlers["quaff"] = handlers["drink"]
    handlers["sip"] = handlers["drink"]
end

return M

end

