package.preload["engine.verbs.helpers.inventory"] = function()
-- engine/verbs/helpers/inventory.lua
-- Inventory and placement helpers.

local core = require("engine.verbs.helpers.core")
local search = require("engine.verbs.helpers.search")

local M = {}

---------------------------------------------------------------------------
-- Instance-aware hand accessors: hands store object instances (tables).
-- Backward compatible with string IDs for transitional code.
---------------------------------------------------------------------------
local _next_instance_id = 0
local function next_instance_id()
    _next_instance_id = _next_instance_id + 1
    return _next_instance_id
end

local function _hid(hand)
    if type(hand) == "table" then return hand.id end
    return hand
end

local function _hobj(hand, reg)
    if type(hand) == "table" then return hand end
    if type(hand) == "string" then return reg:get(hand) end
    return nil
end

---------------------------------------------------------------------------
-- Hand inventory helpers
---------------------------------------------------------------------------
local function hands_full(ctx)
    return ctx.player.hands[1] ~= nil and ctx.player.hands[2] ~= nil
end

local function first_empty_hand(ctx)
    if ctx.player.hands[1] == nil then return 1 end
    if ctx.player.hands[2] == nil then return 2 end
    return nil
end

local function which_hand(ctx, obj_id)
    if _hid(ctx.player.hands[1]) == obj_id then return 1 end
    if _hid(ctx.player.hands[2]) == obj_id then return 2 end
    return nil
end

---------------------------------------------------------------------------
-- Helper: count hands used by carried objects (for two-handed carry)
-- Returns: hands_used, free_hands
---------------------------------------------------------------------------
local function count_hands_used(ctx)
    local used = 0
    local reg = ctx.registry
    for i = 1, 2 do
        if ctx.player.hands[i] then
            local obj = _hobj(ctx.player.hands[i], reg)
            local hr = (obj and obj.hands_required) or 1
            if hr >= 2 then
                return 2, 0  -- two-hand item uses both slots
            end
            used = used + 1
        end
    end
    return used, 2 - used
end

---------------------------------------------------------------------------
-- Helper: total carried weight (hands + worn)
---------------------------------------------------------------------------
local function inventory_weight(ctx)
    local total = 0
    local reg = ctx.registry
    for _, id in ipairs(core.get_all_carried_ids(ctx)) do
        local obj = reg:get(id)
        if obj then total = total + (obj.weight or 0) end
    end
    return total
end

---------------------------------------------------------------------------
-- Helper: remove an object from wherever it currently lives
---------------------------------------------------------------------------
local function remove_from_location(ctx, obj)
    local room = ctx.current_room
    local reg = ctx.registry

    -- Player hands
    for i = 1, 2 do
        if _hid(ctx.player.hands[i]) == obj.id then
            ctx.player.hands[i] = nil
            return true
        end
    end

    -- Bags in player's hands
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local bag = _hobj(hand, reg)
            if bag and bag.container and bag.contents then
                for j, item_id in ipairs(bag.contents) do
                    if item_id == obj.id then
                        table.remove(bag.contents, j)
                        return true
                    end
                end
            end
        end
    end

    -- Worn items
    for i, worn_id in ipairs(ctx.player.worn or {}) do
        if worn_id == obj.id then
            table.remove(ctx.player.worn, i)
            return true
        end
    end

    -- Worn bag contents
    for _, worn_id in ipairs(ctx.player.worn or {}) do
        local bag = reg:get(worn_id)
        if bag and bag.container and bag.contents then
            for j, item_id in ipairs(bag.contents) do
                if item_id == obj.id then
                    table.remove(bag.contents, j)
                    return true
                end
            end
        end
    end

    -- Room contents
    for i, id in ipairs(room.contents or {}) do
        if id == obj.id then
            table.remove(room.contents, i)
            return true
        end
    end

    -- Surface contents of room objects
    for _, parent_id in ipairs(room.contents or {}) do
        local parent = reg:get(parent_id)
        if parent and parent.surfaces then
            for _, zone in pairs(parent.surfaces) do
                for i, id in ipairs(zone.contents or {}) do
                    if id == obj.id then
                        table.remove(zone.contents, i)
                        return true
                    end
                end
            end
        end
        -- Non-surface container contents
        if parent and not parent.surfaces and parent.container and parent.contents then
            for i, id in ipairs(parent.contents) do
                if id == obj.id then
                    table.remove(parent.contents, i)
                    return true
                end
            end
        end
    end

    return false
end

---------------------------------------------------------------------------
-- Helper: find a detachable part on any reachable object matching keyword
-- Returns: part_def, parent_obj, part_key  (or nil)
---------------------------------------------------------------------------
local function find_part(ctx, keyword)
    if not keyword or keyword == "" then return nil end
    local room = ctx.current_room
    local reg = ctx.registry
    local kw = keyword:lower()
        :gsub("^the%s+", "")
        :gsub("^a%s+", "")
        :gsub("^an%s+", "")

    -- Search room objects for parts
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.parts then
            for part_key, part in pairs(obj.parts) do
                if search.matches_keyword(part, kw) then
                    return part, obj, part_key
                end
            end
        end
        -- Also search surface contents of room objects for composite parts
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                if zone.accessible ~= false then
                    for _, item_id in ipairs(zone.contents or {}) do
                        local item = reg:get(item_id)
                        if item and item.parts then
                            for part_key, part in pairs(item.parts) do
                                if search.matches_keyword(part, kw) then
                                    return part, item, part_key
                                end
                            end
                        end
                    end
                end
            end
        end
    end
    -- Search held objects for parts
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = _hobj(hand, reg)
            if obj and obj.parts then
                for part_key, part in pairs(obj.parts) do
                    if search.matches_keyword(part, kw) then
                        return part, obj, part_key
                    end
                end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Helper: detach a part from its parent — factory + FSM + room placement
-- Returns: new_obj (or nil, error_msg)
---------------------------------------------------------------------------
local function detach_part(ctx, parent, part_key)
    local part = parent.parts and parent.parts[part_key]
    if not part then return nil, "No such part." end
    if not part.detachable then return nil, "That can't be removed." end
    if not part.factory then return nil, "That can't be separated." end

    -- Check state precondition
    if part.requires_state_match then
        if parent._state ~= part.requires_state_match then
            return nil, part.blocked_message or ("You can't remove that right now.")
        end
    end

    -- Find the detach_part transition on the parent
    local detach_trans = nil
    for _, t in ipairs(parent.transitions or {}) do
        if t.verb == "detach_part" and t.part_id == part_key then
            if t.from == parent._state then
                detach_trans = t
                break
            end
        end
    end

    -- Create the new independent object via factory
    local new_obj = part.factory(parent)
    if not new_obj then return nil, "Something went wrong." end

    -- Set location to same room as parent
    local room = ctx.current_room
    new_obj.location = room.id

    -- Register the new object
    local new_id = new_obj.id
    if ctx.registry:get(new_id) then
        local n = 2
        while ctx.registry:get(new_id .. "-" .. n) do n = n + 1 end
        new_id = new_id .. "-" .. n
        new_obj.id = new_id
    end
    ctx.registry:register(new_id, new_obj)
    room.contents[#room.contents + 1] = new_id

    -- If the part carries contents, clear the parent's surface
    if part.carries_contents and parent.surfaces and parent.surfaces.inside then
        parent.surfaces.inside.contents = {}
    end

    -- Transition the parent's FSM state directly (bypass fsm.transition to use our specific transition)
    local message = part.detach_message or ("You remove " .. (part.name or part_key) .. ".")
    if detach_trans then
        -- Apply state change directly using the detach_part transition we found
        local fsm_m = require("engine.fsm")
        -- Use the FSM's apply_state through a transition call, but only if our exact
        -- detach_part transition matches. Since fsm.transition picks the first from→to,
        -- we must set the state directly when we already know the target.
        local old_state = parent._state
        if parent.states and parent.states[detach_trans.to] then
            -- Apply new state properties
            for k, v in pairs(parent.states[detach_trans.to]) do
                if k ~= "on_tick" and k ~= "terminal" then
                    if k == "surfaces" then
                        -- Preserve surface contents
                        local saved = {}
                        if parent.surfaces then
                            for sname, zone in pairs(parent.surfaces) do
                                saved[sname] = zone.contents or {}
                            end
                        end
                        parent.surfaces = {}
                        for sname, zone in pairs(v) do
                            parent.surfaces[sname] = {}
                            for zk, zv in pairs(zone) do
                                if zk ~= "contents" then
                                    parent.surfaces[sname][zk] = zv
                                end
                            end
                            parent.surfaces[sname].contents = saved[sname] or {}
                        end
                    else
                        parent[k] = v
                    end
                end
            end
            parent._state = detach_trans.to
        end
        message = detach_trans.message or message
    end

    return new_obj, message
end

---------------------------------------------------------------------------
-- Helper: reattach a part to its parent
-- Returns: true, message (or nil, error_msg)
---------------------------------------------------------------------------
local function reattach_part(ctx, drawer_obj, parent)
    if not parent or not parent.parts then return nil, "That doesn't go there." end

    -- Find which part this object can reattach as
    local part_key = nil
    for pk, part in pairs(parent.parts) do
        if part.reversible and part.id == drawer_obj.id then
            part_key = pk
            break
        end
        -- Also check by reattach_to on the detached object
        if part.reversible and drawer_obj.reattach_to == parent.id then
            part_key = pk
            break
        end
    end
    if not part_key then return nil, "That doesn't fit there." end

    -- Find the reattach transition
    local reattach_trans = nil
    for _, t in ipairs(parent.transitions or {}) do
        if t.verb == "reattach_part" and t.part_id == part_key then
            if t.from == parent._state then
                reattach_trans = t
                break
            end
        end
    end
    if not reattach_trans then return nil, "You can't put that back right now." end

    -- Transfer contents back to parent if applicable
    local part = parent.parts[part_key]
    if part.carries_contents and drawer_obj.contents then
        if parent.surfaces then
            parent.surfaces.inside = parent.surfaces.inside or { capacity = 2, max_item_size = 1, contents = {} }
            parent.surfaces.inside.contents = {}
            for _, id in ipairs(drawer_obj.contents) do
                parent.surfaces.inside.contents[#parent.surfaces.inside.contents + 1] = id
            end
        end
    end

    -- Remove drawer from world (inline to avoid forward-reference)
    local room = ctx.current_room
    for i, id in ipairs(room.contents or {}) do
        if id == drawer_obj.id then
            table.remove(room.contents, i)
            break
        end
    end
    -- Also check player hands
    for i = 1, 2 do
        if _hid(ctx.player.hands[i]) == drawer_obj.id then
            ctx.player.hands[i] = nil
        end
    end
    ctx.registry:remove(drawer_obj.id)

    -- Transition parent directly using the reattach transition
    if parent.states and parent.states[reattach_trans.to] then
        -- Save surface contents BEFORE cleanup (prevents BUG-017 data loss)
        local saved_surface_contents = {}
        if parent.surfaces then
            for sname, zone in pairs(parent.surfaces) do
                saved_surface_contents[sname] = zone.contents or {}
            end
        end

        -- Remove old state keys
        if parent._state and parent.states[parent._state] then
            for k in pairs(parent.states[parent._state]) do
                if k ~= "on_tick" and k ~= "terminal" then
                    parent[k] = nil
                end
            end
        end
        -- Apply new state properties
        for k, v in pairs(parent.states[reattach_trans.to]) do
            if k ~= "on_tick" and k ~= "terminal" then
                if k == "surfaces" then
                    parent.surfaces = {}
                    for sname, zone in pairs(v) do
                        parent.surfaces[sname] = {}
                        for zk, zv in pairs(zone) do
                            if zk ~= "contents" then
                                parent.surfaces[sname][zk] = zv
                            end
                        end
                        parent.surfaces[sname].contents = saved_surface_contents[sname] or {}
                    end
                else
                    parent[k] = v
                end
            end
        end
        parent._state = reattach_trans.to
    end
    local message = reattach_trans.message or "You put it back."
    return true, message
end

M.next_instance_id = next_instance_id
M._hid = _hid
M._hobj = _hobj
M.hands_full = hands_full
M.first_empty_hand = first_empty_hand
M.which_hand = which_hand
M.count_hands_used = count_hands_used
M.inventory_weight = inventory_weight
M.remove_from_location = remove_from_location
M.find_part = find_part
M.detach_part = detach_part
M.reattach_part = reattach_part
return M

end

package.preload["engine.verbs.helpers.mutation"] = function()
-- engine/verbs/helpers/mutation.lua
-- Mutation and spatial movement helpers.

local core = require("engine.verbs.helpers.core")
local inventory = require("engine.verbs.helpers.inventory")

local M = {}

---------------------------------------------------------------------------
-- Container sensory gating: check if a container's contents are accessible
-- to a given sense.  Uses _state (FSM) — "open" in state name means open.
-- sense: "visual" or "tactile"
-- Returns true if contents should be revealed to that sense.
---------------------------------------------------------------------------
local function container_contents_accessible(obj, sense)
    if not obj._state then return true end
    if obj._state:find("open") then return true end
    -- Closed: transparent containers still allow visual access
    if sense == "visual" and obj.transparent then return true end
    return false
end

---------------------------------------------------------------------------
-- Helper: find a mutation entry on an object for a given verb
-- Checks exact match first, then verb_* patterns (e.g. "break" → "break_mirror")
---------------------------------------------------------------------------
local function find_mutation(obj, verb)
    if not obj or not obj.mutations then return nil end
    if obj.mutations[verb] then return obj.mutations[verb] end
    for key, mut in pairs(obj.mutations) do
        if key:sub(1, #verb + 1) == verb .. "_" then
            return mut
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Helper: spawn objects from a mutation's spawns list
---------------------------------------------------------------------------
local function spawn_objects(ctx, spawns)
    local room = ctx.current_room
    for _, spawn_id in ipairs(spawns) do
        local source = ctx.object_sources[spawn_id]
        if source then
            local spawn_obj, err = ctx.loader.load_source(source)
            if spawn_obj then
                spawn_obj, err = ctx.loader.resolve_template(spawn_obj, ctx.templates)
                if spawn_obj then
                    local actual_id = spawn_id
                    if ctx.registry:get(spawn_id) then
                        local n = 2
                        while ctx.registry:get(spawn_id .. "-" .. n) do n = n + 1 end
                        actual_id = spawn_id .. "-" .. n
                    end
                    spawn_obj.id = actual_id
                    spawn_obj.location = room.id
                    ctx.registry:register(actual_id, spawn_obj)
                    room.contents[#room.contents + 1] = actual_id
                end
            end
        end
    end
end

---------------------------------------------------------------------------
-- Helper: perform an object mutation (swap or destroy + spawn)
---------------------------------------------------------------------------
local function perform_mutation(ctx, obj, mut_data)
    if mut_data.becomes then
        local source = ctx.object_sources[mut_data.becomes]
        if not source then
            print("Something strange happens, but nothing changes.")
            return false
        end
        local new_obj, err = ctx.mutation.mutate(
            ctx.registry, ctx.loader, obj.id, source, ctx.templates, ctx)
        if not new_obj then
            print("Error: " .. tostring(err))
            return false
        end
        -- Sync hand slot references: mutation replaces the registry entry
        -- but hand slots may still hold the old object table reference.
        if ctx.player then
            for i = 1, 2 do
                local hand = ctx.player.hands[i]
                if hand then
                    local hid = type(hand) == "table" and hand.id or hand
                    if hid == obj.id then
                        ctx.player.hands[i] = new_obj
                    end
                end
            end
        end
    elseif mut_data.spawns then
        -- Destruction: object ceases to exist, spawns replace it
        inventory.remove_from_location(ctx, obj)
        ctx.registry:remove(obj.id)
    end

    if mut_data.spawns then
        spawn_objects(ctx, mut_data.spawns)
    end

    return true
end

---------------------------------------------------------------------------
-- Spatial movement: push/pull/move objects with spatial relationships
---------------------------------------------------------------------------
local function move_spatial_object(ctx, obj, verb)
    local room = ctx.current_room
    local reg = ctx.registry

    -- Not movable
    if not obj.movable then
        if obj.weight and obj.weight >= 50 then
            print("You strain against " .. (obj.name or "it") .. ", but it won't budge. It's far too heavy to move.")
        else
            print("You can't move " .. (obj.name or "that") .. ".")
        end
        return
    end

    -- Already moved
    if obj.moved then
        print("You've already moved " .. (obj.name or "that") .. ".")
        return
    end

    -- Check if anything is resting on this object (prevents movement)
    for _, obj_id in ipairs(room.contents or {}) do
        local other = reg:get(obj_id)
        if other and other.resting_on == obj.id and not other.moved then
            print((other.name or "Something") .. " is sitting on " .. (obj.name or "it") .. ". You need to move it first.")
            return
        end
    end

    -- Perform the move
    obj.moved = true

    -- Print movement message (verb-specific → generic → fallback)
    local verb_msg_key = verb .. "_message"
    if obj[verb_msg_key] then
        print(obj[verb_msg_key])
    elseif obj.move_message then
        print(obj.move_message)
    else
        print("You " .. verb .. " " .. (obj.name or "it") .. " aside.")
    end

    -- Fire on_move callback if the object declares one (#111)
    if obj.on_move and type(obj.on_move) == "function" then
        obj:on_move(ctx, verb)
    end

    -- Clear resting_on relationship
    if obj.resting_on then
        obj.resting_on = nil
    end

    -- Update description/presence for moved state
    if obj.moved_room_presence then
        obj.room_presence = obj.moved_room_presence
    end
    if obj.moved_description then
        obj.description = obj.moved_description
    end
    if obj.moved_on_feel then
        obj.on_feel = obj.moved_on_feel
    end

    -- If this is a covering object, dump underneath surface items to floor
    if obj.covering and obj.surfaces and obj.surfaces.underneath then
        local underneath = obj.surfaces.underneath
        underneath.accessible = true   -- reveal surface after move (#26)
        for i = #(underneath.contents or {}), 1, -1 do
            local item_id = underneath.contents[i]
            room.contents[#room.contents + 1] = item_id
            local item = reg:get(item_id)
            if item then
                item.location = room.id
                print("Something clatters to the floor -- " .. (item.name or item_id) .. "!")
            end
            table.remove(underneath.contents, i)
        end
    end

    -- Reveal covered objects
    if obj.covering then
        for _, covered_id in ipairs(obj.covering) do
            local covered = reg:get(covered_id)
            local is_hidden = covered and (covered.hidden or (covered.states and covered._state == "hidden"))
            if is_hidden then
                -- FSM reveal transition
                if covered.states and covered._state == "hidden" then
                    local transitioned = false
                    for _, t in ipairs(covered.transitions or {}) do
                        if t.from == "hidden" then
                            core.fsm_mod.transition(reg, covered_id, t.to, {})
                            transitioned = true
                            break
                        end
                    end
                    if not transitioned then
                        covered.hidden = false
                    end
                else
                    covered.hidden = false
                end
                -- Discovery message
                if covered.discovery_message then
                    print("")
                    print(covered.discovery_message)
                end
            end
        end
    end
end

M.container_contents_accessible = container_contents_accessible
M.find_mutation = find_mutation
M.spawn_objects = spawn_objects
M.perform_mutation = perform_mutation
M.move_spatial_object = move_spatial_object

return M

end

package.preload["engine.verbs.helpers.portal"] = function()
-- engine/verbs/helpers/portal.lua
-- Portal-specific helper functions.

local search = require("engine.verbs.helpers.search")

local M = {}

---------------------------------------------------------------------------
-- Helper: find a portal object in the current room by keyword or direction.
-- Searches room.contents for objects with categories containing "portal"
-- and matches against keywords, name, id, or portal.direction_hint.
-- Returns the portal object if found, nil otherwise.
---------------------------------------------------------------------------
local function find_portal_by_keyword(ctx, keyword)
    if not keyword or keyword == "" then return nil end
    local room = ctx.current_room
    if not room or not room.contents then return nil end
    local kw = keyword:lower()
    for _, obj_id in ipairs(room.contents) do
        local obj = ctx.registry:get(obj_id)
        if obj and not obj.hidden and type(obj.categories) == "table" then
            local is_portal = false
            for _, cat in ipairs(obj.categories) do
                if cat == "portal" then is_portal = true; break end
            end
            if is_portal then
                -- Match by keyword (reuses existing matches_keyword)
                if search.matches_keyword(obj, kw) then return obj end
                -- Match by direction_hint (for "go north" → portal with hint "north")
                if obj.portal and obj.portal.direction_hint
                   and obj.portal.direction_hint:lower() == kw then
                    return obj
                end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Helper: sync bidirectional portal pair after an FSM state change.
-- When a portal transitions state, find its paired portal (same
-- bidirectional_id in another room) and apply the same state.
---------------------------------------------------------------------------
local function sync_bidirectional_portal(ctx, portal)
    if not portal or not portal.portal then return end
    local bid = portal.portal.bidirectional_id
    if not bid then return end
    local new_state = portal._state
    if not new_state then return end

    -- Search all rooms for the paired portal
    for _, room in pairs(ctx.rooms or {}) do
        for _, obj_id in ipairs(room.contents or {}) do
            local obj = ctx.registry:get(obj_id)
            if obj and obj ~= portal and obj.portal
               and obj.portal.bidirectional_id == bid then
                -- Apply the same state to the paired portal
                if obj.states and obj.states[new_state] and obj._state ~= new_state then
                    local old_state = obj._state
                    obj._state = new_state
                    -- Apply state properties from the new state
                    if obj.states[old_state] then
                        for k in pairs(obj.states[old_state]) do
                            if k ~= "on_tick" and k ~= "terminal" then
                                obj[k] = nil
                            end
                        end
                    end
                    for k, v in pairs(obj.states[new_state]) do
                        if k ~= "on_tick" and k ~= "terminal" then
                            obj[k] = v
                        end
                    end
                end
                return
            end
        end
    end
end

M.find_portal_by_keyword = find_portal_by_keyword
M.sync_bidirectional_portal = sync_bidirectional_portal

return M

end

package.preload["engine.verbs.helpers.search"] = function()
-- engine/verbs/helpers/search.lua
-- Keyword matching and visibility search helpers.

local core = require("engine.verbs.helpers.core")

local M = {}

---------------------------------------------------------------------------
-- Helper: keyword matching
---------------------------------------------------------------------------
local function matches_keyword(obj, kw)
    if not obj then return false end
    kw = kw:lower()
    -- Build list: original keyword + BUG-056 singular fallbacks
    local candidates = { kw }
    for _, s in ipairs(core.preprocess.singularize(kw)) do
        candidates[#candidates + 1] = s
    end
    for _, try_kw in ipairs(candidates) do
        if obj.id and obj.id:lower() == try_kw then return true end
        -- Exact keyword match (highest priority)
        if type(obj.keywords) == "table" then
            for _, k in ipairs(obj.keywords) do
                if k:lower() == try_kw then return true end
            end
        end
        -- Word-boundary match on name (avoids "match" matching "matchbox")
        if obj.name then
            local padded = " " .. obj.name:lower() .. " "
            if padded:find(" " .. try_kw .. " ", 1, true) then return true end
        end
    end
    return false
end

---------------------------------------------------------------------------
-- Adjective-aware scoring: count how many input tokens appear in an
-- object's keywords, name, or id. Used to break ties when multiple
-- objects share a keyword (e.g. "burlap sack" vs "grain sack"). (#182)
---------------------------------------------------------------------------
local function _score_adjective_match(obj, input_text)
    local score = 0
    for token in input_text:lower():gmatch("%S+") do
        local matched = false
        if type(obj.keywords) == "table" then
            for _, k in ipairs(obj.keywords) do
                if k:lower() == token then
                    score = score + 2
                    matched = true
                    break
                end
            end
        end
        if not matched and obj.name then
            local padded = " " .. obj.name:lower() .. " "
            if padded:find(" " .. token .. " ", 1, true) then
                score = score + 1
                matched = true
            end
        end
        if not matched and obj.id and obj.id:lower() == token then
            score = score + 2
        end
    end
    return score
end

---------------------------------------------------------------------------
-- Verb-dependent search order (see docs/architecture/player/inventory.md)
--
-- Interaction verbs act on something the player controls → search
-- hands/bags first, then fall back to room/surfaces.
-- Everything else (acquisition) reaches for things in the world → search
-- room/surfaces first, then fall back to hands/bags.
---------------------------------------------------------------------------
local interaction_verbs = {
    use = true, light = true, drink = true, open = true, close = true,
    pour = true, eat = true, extinguish = true, wear = true, remove = true,
    apply = true, stab = true, cut = true, slash = true,
    dump = true, empty = true,
    -- aliases that map to interaction verbs
    pry = true, shut = true, jab = true, pierce = true, stick = true,
    slice = true, nick = true, carve = true,
}

---------------------------------------------------------------------------
-- Sub-search: room contents (non-hidden objects sitting in the room)
---------------------------------------------------------------------------
local function _fv_room(kw, reg, room)
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and not obj.hidden and matches_keyword(obj, kw) then
            return obj, "room", nil, nil
        end
    end
end

-- Scored room search: collect ALL keyword matches, score by adjective
-- overlap, return best or set ctx.disambiguation_prompt if tied. (#182)
local function _try_room_scored(kw, reg, room, ctx)
    local matches = {}
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and not obj.hidden and matches_keyword(obj, kw) then
            matches[#matches + 1] = { obj = obj, loc = "room" }
        end
    end
    if #matches == 0 then return nil end
    if #matches == 1 then return matches[1].obj, "room", nil, nil end

    for _, m in ipairs(matches) do
        m.score = _score_adjective_match(m.obj, kw)
    end
    table.sort(matches, function(a, b) return a.score > b.score end)

    if matches[1].score > matches[2].score then
        return matches[1].obj, "room", nil, nil
    end

    -- Identical items bypass: when all top-scoring matches share the same
    -- base id (e.g. multiple silk-bundles from killed spiders), just pick
    -- the first one — no disambiguation needed for fungible items.
    -- Strip loot/craft/numeric suffixes to compare base IDs (#362).
    local function _base_id(id)
        return id:gsub("%-loot%-%d+$", ""):gsub("%-craft%-%d+$", ""):gsub("-%d+$", "")
    end
    local top_score = matches[1].score
    local all_same_id = true
    local first_id = _base_id(matches[1].obj.id)
    for _, m in ipairs(matches) do
        if m.score == top_score and _base_id(m.obj.id) ~= first_id then
            all_same_id = false
            break
        end
    end
    if all_same_id then
        return matches[1].obj, "room", nil, nil
    end

    -- Tied scores — build disambiguation prompt
    -- #309: When objects have identical display names (e.g., two iron-bound doors),
    -- include direction from room.exits to differentiate them.
    local function _door_direction(obj_item, room_ref)
        if not room_ref or not room_ref.exits then return nil end
        for dir, exit in pairs(room_ref.exits) do
            if type(exit) == "table" and exit.id and exit.id == obj_item.id then
                return dir
            end
        end
        return nil
    end

    local names = {}
    local raw_names = {}
    for _, m in ipairs(matches) do
        if m.score == top_score then
            local name = m.obj.name or m.obj.id or "something"
            raw_names[#raw_names + 1] = name
        end
    end
    -- Check for duplicate display names
    local has_dupes = false
    local seen_names = {}
    for _, n in ipairs(raw_names) do
        if seen_names[n] then has_dupes = true; break end
        seen_names[n] = true
    end
    -- #299: Ordinal words for differentiating identical-name items
    local ordinals = { "first", "second", "third", "fourth", "fifth",
                       "sixth", "seventh", "eighth", "ninth", "tenth" }
    local ordinal_idx = 0
    local name_idx = 0
    for _, m in ipairs(matches) do
        if m.score == top_score then
            name_idx = name_idx + 1
            local name = raw_names[name_idx]
            if has_dupes then
                local dir = _door_direction(m.obj, room)
                if dir then
                    local bare = name:gsub("^a%s+", ""):gsub("^an%s+", ""):gsub("^the%s+", "")
                    name = "the " .. dir .. " " .. bare
                else
                    -- #299: Ordinal fallback for non-door identical names
                    ordinal_idx = ordinal_idx + 1
                    local ord = ordinals[ordinal_idx] or tostring(ordinal_idx)
                    local bare = name:gsub("^a%s+", ""):gsub("^an%s+", ""):gsub("^the%s+", "")
                    name = "the " .. ord .. " " .. bare
                end
            end
            names[#names + 1] = name
        end
    end
    local prompt
    if #names == 2 then
        prompt = "Which do you mean: " .. names[1] .. " or " .. names[2] .. "?"
    else
        local parts = {}
        for i, n in ipairs(names) do
            if i == #names then
                parts[#parts + 1] = "or " .. n
            else
                parts[#parts + 1] = n
            end
        end
        prompt = "Which do you mean: " .. table.concat(parts, ", ") .. "?"
    end
    ctx.disambiguation_prompt = prompt
    return nil
end

-- Sub-search: accessible surface contents + non-surface containers in room
local function _fv_surfaces(kw, reg, room)
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.surfaces then
            for sname, zone in pairs(obj.surfaces) do
                if zone.accessible ~= false then
                    for _, item_id in ipairs(zone.contents or {}) do
                        local item = reg:get(item_id)
                        -- Search inside a surface item's contents first
                        -- (e.g., candle inside candle-holder on nightstand)
                        if item and item.contents then
                            for _, inner_id in ipairs(item.contents) do
                                local inner = reg:get(inner_id)
                                if inner and matches_keyword(inner, kw) then
                                    return inner, "container", item, nil
                                end
                            end
                        end
                        if item and matches_keyword(item, kw) then
                            return item, "surface", obj, sname
                        end
                    end
                end
            end
            -- #149: Also search root-level contents of surface-objects.
            -- Handles nightstand.contents → drawer → matchbox → match chain.
            -- The drawer lives in nightstand.contents (not in any surface),
            -- so it was invisible to find_visible before this fix.
            if obj.contents then
                local function _search_accessible_chain(ids, depth)
                    if depth > 3 then return nil end
                    for _, cid in ipairs(ids) do
                        local c = reg:get(cid)
                        if c and c.accessible ~= false then
                            if matches_keyword(c, kw) then
                                return c, "container", obj, nil
                            end
                            if c.contents then
                                for _, inner_id in ipairs(c.contents) do
                                    local inner = reg:get(inner_id)
                                    if inner and matches_keyword(inner, kw) then
                                        return inner, "container", c, nil
                                    end
                                end
                                local f, l, p, s = _search_accessible_chain(c.contents, depth + 1)
                                if f then return f, l, p, s end
                            end
                        end
                    end
                end
                local f, l, p, s = _search_accessible_chain(obj.contents, 0)
                if f then return f, l, p, s end
            end
        end
        -- Also search non-surface container contents (if accessible)
        if obj and not obj.surfaces and obj.container and obj.contents
            and obj.accessible ~= false then
            for _, item_id in ipairs(obj.contents) do
                local item = reg:get(item_id)
                if item and matches_keyword(item, kw) then
                    return item, "container", obj, nil
                end
            end
        end
    end
end

-- Sub-search: parts of room objects and parts of surface-hosted objects
local function _fv_parts(kw, reg, room)
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.parts then
            for part_key, part in pairs(obj.parts) do
                if matches_keyword(part, kw) then
                    -- Return the live registry object matching this part's keywords
                    local live = part.id and reg:get(part.id)
                    if not live and obj.contents then
                        for _, cid in ipairs(obj.contents) do
                            local candidate = reg:get(cid)
                            if candidate and matches_keyword(candidate, kw) then
                                live = candidate; break
                            end
                        end
                    end
                    return live or part, "part", obj, part_key
                end
            end
        end
        -- Also check parts of objects on surfaces
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                if zone.accessible ~= false then
                    for _, item_id in ipairs(zone.contents or {}) do
                        local item = reg:get(item_id)
                        if item and item.parts then
                            for part_key, part in pairs(item.parts) do
                                if matches_keyword(part, kw) then
                                    local live = part.id and reg:get(part.id)
                                    return live or part, "part", item, part_key
                                end
                            end
                        end
                    end
                end
            end
        end
    end
end

-- Sub-search: player hands (direct items only)
local function _fv_hands(kw, reg, player, hobj)
    for i = 1, 2 do
        local hand = player.hands[i]
        if hand then
            local obj = hobj(hand, reg)
            if obj and matches_keyword(obj, kw) then
                return obj, "hand", nil, nil
            end
        end
    end
end

-- Sub-search: contents of containers held in hands
local function _fv_bags(kw, reg, player, hobj)
    for i = 1, 2 do
        local hand = player.hands[i]
        if hand then
            local obj = hobj(hand, reg)
            if obj and obj.container and obj.contents then
                for _, item_id in ipairs(obj.contents) do
                    local item = reg:get(item_id)
                    if item and matches_keyword(item, kw) then
                        return item, "bag", obj, nil
                    end
                end
            end
        end
    end
end

-- Sub-search: worn items and contents of worn containers
local function _fv_worn(kw, reg, player)
    for _, worn_id in ipairs(player.worn or {}) do
        local obj = reg:get(worn_id)
        if obj and matches_keyword(obj, kw) then
            return obj, "worn", nil, nil
        end
        if obj and obj.container and obj.contents then
            for _, item_id in ipairs(obj.contents) do
                local item = reg:get(item_id)
                if item and matches_keyword(item, kw) then
                    return item, "bag", obj, nil
                end
            end
        end
    end
end

local function find_visible(ctx, keyword)
    if not keyword or keyword == "" then return nil end
    local room = ctx.current_room
    local reg = ctx.registry
    local hobj = core.hobj
    if not hobj then
        hobj = function(hand, registry)
            if type(hand) == "table" then return hand end
            if type(hand) == "string" then return registry:get(hand) end
            return nil
        end
    end
    local kw = keyword:lower()
        :gsub("^the%s+", "")
        :gsub("^a%s+", "")
        :gsub("^an%s+", "")

    local verb = ctx.current_verb or ""
    local obj, loc, parent, surface

    if interaction_verbs[verb] then
        -- Interaction: acting on held objects → Hands → Bags → Worn → Room → Surfaces → Parts
        obj, loc, parent, surface = _fv_hands(kw, reg, ctx.player, hobj)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _fv_bags(kw, reg, ctx.player, hobj)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _fv_worn(kw, reg, ctx.player)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _try_room_scored(kw, reg, room, ctx)
        if obj then return obj, loc, parent, surface end
        if ctx.disambiguation_prompt then return nil end
        obj, loc, parent, surface = _fv_surfaces(kw, reg, room)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _fv_parts(kw, reg, room)
        if obj then return obj, loc, parent, surface end
    else
        -- Acquisition / default: reaching for world objects → Room → Surfaces → Parts → Hands → Bags → Worn
        obj, loc, parent, surface = _try_room_scored(kw, reg, room, ctx)
        if obj then return obj, loc, parent, surface end
        if ctx.disambiguation_prompt then return nil end
        obj, loc, parent, surface = _fv_surfaces(kw, reg, room)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _fv_parts(kw, reg, room)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _fv_hands(kw, reg, ctx.player, hobj)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _fv_bags(kw, reg, ctx.player, hobj)
        if obj then return obj, loc, parent, surface end
        obj, loc, parent, surface = _fv_worn(kw, reg, ctx.player)
        if obj then return obj, loc, parent, surface end
    end

    return nil
end

-- Wrap find_visible with pronoun resolution ("it", "one", "that", "this") and
-- last-object tracking for compound command support.
-- Tier 4: Also resolves "the thing I found" from search discoveries,
-- and pushes found objects to the context window stack.
do
    local _find_visible = find_visible
    find_visible = function(ctx, keyword)
        if not keyword or keyword == "" then return nil end
        local kw = keyword:lower()
            :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
        -- Tier 4: try context window resolution first (pronouns + discovery refs)
        if core.context_window then
            local cw_obj = core.context_window.resolve(kw)
            if cw_obj then
                ctx.last_object = cw_obj
                return cw_obj, ctx.last_object_loc or "room",
                       ctx.last_object_parent, ctx.last_object_surface
            end
        end
        -- Legacy pronoun fallback (in case context_window not loaded)
        if (kw == "it" or kw == "one" or kw == "that" or kw == "this") and ctx.last_object then
            return ctx.last_object, ctx.last_object_loc or "room",
                   ctx.last_object_parent, ctx.last_object_surface
        end
        local obj, loc, parent, surface = _find_visible(ctx, keyword)
        if obj then
            ctx.last_object = obj
            ctx.last_object_loc = loc
            ctx.last_object_parent = parent
            ctx.last_object_surface = surface
            ctx.known_objects = ctx.known_objects or {}
            ctx.known_objects[obj.id] = true
            -- Tier 4: push to context window stack
            if core.context_window then
                core.context_window.push(obj)
            end
            return obj, loc, parent, surface
        end

        -- BUG-115: Spatial reference — "thing on X" / "something on X" etc.
        -- Resolves vague references to the first object on a named surface.
        local spatial_surface = kw:match("^thing%s+on%s+(.+)$")
            or kw:match("^something%s+on%s+(.+)$")
            or kw:match("^item%s+on%s+(.+)$")
            or kw:match("^object%s+on%s+(.+)$")
            or kw:match("^stuff%s+on%s+(.+)$")
        if spatial_surface then
            local surface_obj = _find_visible(ctx, spatial_surface)
            if surface_obj and surface_obj.surfaces then
                -- Prefer "top" surface, then any accessible surface
                local check_order = {}
                for zone_name, zone in pairs(surface_obj.surfaces) do
                    if zone_name == "top" then
                        table.insert(check_order, 1, { name = zone_name, zone = zone })
                    elseif zone.accessible ~= false then
                        check_order[#check_order + 1] = { name = zone_name, zone = zone }
                    end
                end
                for _, entry in ipairs(check_order) do
                    if entry.zone.contents and #entry.zone.contents > 0 then
                        if #entry.zone.contents == 1 then
                            local item = ctx.registry:get(entry.zone.contents[1])
                            if item then
                                ctx.last_object = item
                                ctx.last_object_loc = "surface"
                                ctx.last_object_parent = surface_obj
                                ctx.last_object_surface = entry.name
                                ctx.known_objects = ctx.known_objects or {}
                                ctx.known_objects[item.id] = true
                                if core.context_window then
                                    core.context_window.push(item)
                                end
                                return item, "surface", surface_obj, entry.name
                            end
                        else
                            -- Multiple items: disambiguate
                            local names = {}
                            for _, id in ipairs(entry.zone.contents) do
                                local item = ctx.registry:get(id)
                                names[#names + 1] = item and item.name or id
                            end
                            print("Which thing on " .. (surface_obj.name or spatial_surface)
                                .. "? You see: " .. table.concat(names, ", ") .. ".")
                            return nil
                        end
                    end
                end
            end
        end

        -- Tier 5: Fuzzy noun resolution fallback (only when exact match fails)
        -- BUG-146 (#46): Skip fuzzy when caller needs exact-only (e.g., search
        -- scope detection). Fuzzy "match"→"mat" causes search to target the rug
        -- instead of doing a room-wide search for "match".
        -- #309: Skip fuzzy if disambiguation prompt already set (preserves
        -- direction-qualified prompt from _try_room_scored).
        if core.fuzzy and not ctx._exact_only and not ctx.disambiguation_prompt then
            local fobj, floc, fparent, fsurface, prompt = core.fuzzy.resolve(ctx, keyword)
            if fobj then
                ctx.last_object = fobj
                ctx.last_object_loc = floc
                ctx.last_object_parent = fparent
                ctx.last_object_surface = fsurface
                ctx.known_objects = ctx.known_objects or {}
                ctx.known_objects[fobj.id] = true
                if core.context_window then
                    core.context_window.push(fobj)
                end
                return fobj, floc, fparent, fsurface
            end
            if prompt then
                -- Store disambiguation prompt for caller to display
                ctx.disambiguation_prompt = prompt
                return nil
            end
        end

        return nil
    end
end

---------------------------------------------------------------------------
-- Helper: find object in player's carried items (hands + bags + worn)
---------------------------------------------------------------------------
local function find_in_inventory(ctx, keyword)
    if not keyword or keyword == "" then return nil end
    local kw = keyword:lower()
        :gsub("^the%s+", "")
        :gsub("^a%s+", "")
        :gsub("^an%s+", "")
    local reg = ctx.registry
    local hobj = core.hobj
    if not hobj then
        hobj = function(hand, registry)
            if type(hand) == "table" then return hand end
            if type(hand) == "string" then return registry:get(hand) end
            return nil
        end
    end
    -- Hands
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local obj = hobj(hand, reg)
            if obj and matches_keyword(obj, kw) then return obj end
        end
    end
    -- Held bag contents
    for i = 1, 2 do
        local hand = ctx.player.hands[i]
        if hand then
            local bag = hobj(hand, reg)
            if bag and bag.container and bag.contents then
                for _, item_id in ipairs(bag.contents) do
                    local item = reg:get(item_id)
                    if item and matches_keyword(item, kw) then return item end
                end
            end
        end
    end
    -- Worn items
    for _, worn_id in ipairs(ctx.player.worn or {}) do
        local obj = reg:get(worn_id)
        if obj and matches_keyword(obj, kw) then return obj end
    end
    -- Worn bag contents
    for _, worn_id in ipairs(ctx.player.worn or {}) do
        local bag = reg:get(worn_id)
        if bag and bag.container and bag.contents then
            for _, item_id in ipairs(bag.contents) do
                local item = reg:get(item_id)
                if item and matches_keyword(item, kw) then return item end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Helper: find an exit door in room.exits by keyword, name, or direction.
-- Returns (exit_table, direction_key) or (nil, nil).
---------------------------------------------------------------------------
local function find_exit_by_keyword(ctx, keyword)
    if not keyword or keyword == "" then return nil, nil end
    local room = ctx.current_room
    if not room or not room.exits then return nil, nil end
    local kw = keyword:lower()
        :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")

    -- Match by direction name first
    if room.exits[kw] and type(room.exits[kw]) == "table" then
        return room.exits[kw], kw
    end

    -- Search by keywords, name, or target
    for dir, exit in pairs(room.exits) do
        if type(exit) == "table" then
            if type(exit.keywords) == "table" then
                for _, k in ipairs(exit.keywords) do
                    if k:lower() == kw then return exit, dir end
                end
            end
            if exit.name then
                local padded = " " .. exit.name:lower() .. " "
                if padded:find(" " .. kw .. " ", 1, true) then return exit, dir end
            end
            -- Match by target room id (for "enter closet")
            if exit.target and exit.target:lower() == kw then return exit, dir end
        end
    end

    return nil, nil
end

M.matches_keyword = matches_keyword
M._score_adjective_match = _score_adjective_match
M.interaction_verbs = interaction_verbs
M._fv_room = _fv_room
M._fv_surfaces = _fv_surfaces
M._fv_parts = _fv_parts
M._fv_hands = _fv_hands
M._fv_bags = _fv_bags
M._fv_worn = _fv_worn
M.find_visible = find_visible
M.find_in_inventory = find_in_inventory
M.find_exit_by_keyword = find_exit_by_keyword

return M

end

package.preload["engine.verbs.helpers.tools"] = function()
-- engine/verbs/helpers/tools.lua
-- Tool capability resolution helpers.

local core = require("engine.verbs.helpers.core")

local M = {}

---------------------------------------------------------------------------
-- Helper: find a tool in carried items that provides a given capability.
-- Also checks blood as writing instrument when player has bloody state.
---------------------------------------------------------------------------
local function find_tool_in_inventory(ctx, required_capability)
    local reg = ctx.registry
    local all_ids = core.get_all_carried_ids(ctx)
    for _, obj_id in ipairs(all_ids) do
        local obj = reg:get(obj_id)
        if obj and obj.provides_tool then
            local provides = obj.provides_tool
            if type(provides) == "string" and provides == required_capability then
                return obj
            elseif type(provides) == "table" then
                for _, cap in ipairs(provides) do
                    if cap == required_capability then
                        return obj
                    end
                end
            end
        end
    end
    -- Blood as writing instrument when player is injured
    if required_capability == "writing_instrument" then
        local state = ctx.player.state or {}
        if state.bloody then
            return {
                id = "blood", name = "your blood",
                provides_tool = "writing_instrument",
                _is_blood = true,
                on_tool_use = {
                    consumes_charge = false,
                    use_message = "You press your bleeding finger to the surface, leaving dark crimson marks.",
                },
            }
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Helper: check if an object provides a specific tool capability
---------------------------------------------------------------------------
local function provides_capability(obj, capability)
    if not obj or not obj.provides_tool then return false end
    local provides = obj.provides_tool
    if type(provides) == "string" then return provides == capability end
    if type(provides) == "table" then
        for _, cap in ipairs(provides) do
            if cap == capability then return true end
        end
    end
    return false
end

---------------------------------------------------------------------------
-- Helper: find a tool that is visible (in room/surfaces) but not carried
---------------------------------------------------------------------------
local function find_visible_tool(ctx, required_capability)
    local room = ctx.current_room
    local reg = ctx.registry
    -- Room contents
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.provides_tool then
            if provides_capability(obj, required_capability) then
                return obj
            end
        end
    end
    -- Surface contents
    for _, obj_id in ipairs(room.contents or {}) do
        local obj = reg:get(obj_id)
        if obj and obj.surfaces then
            for _, zone in pairs(obj.surfaces) do
                if zone.accessible ~= false then
                    for _, item_id in ipairs(zone.contents or {}) do
                        local item = reg:get(item_id)
                        if item and provides_capability(item, required_capability) then
                            return item
                        end
                    end
                end
            end
        end
    end
    return nil
end

---------------------------------------------------------------------------
-- Helper: consume a charge from a tool, mutate to depleted if empty
---------------------------------------------------------------------------
local function consume_tool_charge(ctx, tool)
    if not tool or not tool.on_tool_use or not tool.on_tool_use.consumes_charge then
        return
    end
    if not tool.charges then return end
    tool.charges = tool.charges - 1
    if tool.charges <= 0 and tool.on_tool_use.when_depleted then
        if tool.on_tool_use.depleted_message then
            print(tool.on_tool_use.depleted_message)
        end
        local source = ctx.object_sources[tool.on_tool_use.when_depleted]
        if source then
            ctx.mutation.mutate(ctx.registry, ctx.loader, tool.id, source, ctx.templates, ctx)
        end
    end
end

M.find_tool_in_inventory = find_tool_in_inventory
M.provides_capability = provides_capability
M.find_visible_tool = find_visible_tool
M.consume_tool_charge = consume_tool_charge

return M

end

package.preload["engine.verbs"] = function()
-- engine/verbs/init.lua
-- Registry for verb handlers.

local verbs = {}

function verbs.create()
    local handlers = {}

    local sensory = require("engine.verbs.sensory")
    local acquisition = require("engine.verbs.acquisition")
    local containers = require("engine.verbs.containers")
    local destruction = require("engine.verbs.destruction")
    local fire = require("engine.verbs.fire")
    local combat = require("engine.verbs.combat")
    local crafting = require("engine.verbs.crafting")
    local equipment = require("engine.verbs.equipment")
    local survival = require("engine.verbs.survival")
    local movement = require("engine.verbs.movement")
    local meta = require("engine.verbs.meta")
    local traps = require("engine.verbs.traps")

    sensory.register(handlers)
    acquisition.register(handlers)
    containers.register(handlers)
    destruction.register(handlers)
    fire.register(handlers)
    combat.register(handlers)
    crafting.register(handlers)
    equipment.register(handlers)
    survival.register(handlers)
    movement.register(handlers)
    meta.register(handlers)
    traps.register(handlers)

    ---------------------------------------------------------------------------
    -- WAVE-3: CATCH / GRAB / SNATCH — creature interaction verb
    ---------------------------------------------------------------------------
    do
        local cr_ok, cr_mod = pcall(require, "engine.creatures")
        local inj_ok, injury_mod = pcall(require, "engine.injuries")

        local CATCHABLE_SIZES = { tiny = true, small = true }

        local function keyword_matches(obj, kw)
            if obj.id and obj.id:lower() == kw then return true end
            if type(obj.keywords) == "table" then
                for _, k in ipairs(obj.keywords) do
                    if k:lower() == kw then return true end
                end
            end
            if obj.name then
                local padded = " " .. obj.name:lower() .. " "
                if padded:find(" " .. kw .. " ", 1, true) then return true end
            end
            return false
        end

        local function find_creature_by_keyword(ctx, keyword)
            if not cr_ok or not cr_mod then return nil end
            local kw = keyword:lower()
                :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
            local room_id = type(ctx.current_room) == "table"
                and ctx.current_room.id or ctx.current_room
            local room_creatures = cr_mod.get_creatures_in_room(ctx.registry, room_id)
            for _, c in ipairs(room_creatures) do
                if keyword_matches(c, kw) then return c end
            end
            return nil
        end

        local function find_room_object_by_keyword(ctx, keyword)
            local kw = keyword:lower()
                :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
            local room = ctx.current_room
            for _, obj_id in ipairs(room.contents or {}) do
                local obj = ctx.registry:get(obj_id)
                if obj and keyword_matches(obj, kw) then return obj end
            end
            return nil
        end

        handlers["catch"] = function(ctx, noun)
            if noun == "" then
                print("Catch what?")
                return
            end

            local creature = find_creature_by_keyword(ctx, noun)

            if not creature then
                local obj = find_room_object_by_keyword(ctx, noun)
                if obj then
                    if obj._state == "dead" or obj.alive == false then
                        print("It's dead. You could try to take it.")
                    else
                        print("You can't grab that.")
                    end
                else
                    print("You don't see that here.")
                end
                return
            end

            if ctx.player.hands then
                if ctx.player.hands[1] ~= nil and ctx.player.hands[2] ~= nil then
                    print("Your hands are full.")
                    return
                end
            elseif ctx.player.left_hand ~= nil and ctx.player.right_hand ~= nil then
                print("Your hands are full.")
                return
            end

            if not CATCHABLE_SIZES[creature.size or "medium"] then
                print("You can't grab that.")
                return
            end

            -- Success: creature panics, player gets bitten
            print("You grab " .. (creature.name or "it") .. "! It squirms and bites!")

            if creature.drives and creature.drives.fear then
                creature.drives.fear.value = creature.drives.fear.max or 100
            end

            if cr_ok and cr_mod then
                local room_id = type(ctx.current_room) == "table"
                    and ctx.current_room.id or ctx.current_room
                cr_mod.emit_stimulus(room_id, "player_attacks", { target = creature.id })
            end

            -- Inflict bite injury (D-COMBAT-NPC-PHASE-SEQUENCING: simple direct call)
            if inj_ok and injury_mod then
                injury_mod.inflict(ctx.player, "minor-cut", creature.id or "creature", "arms", 2)
            end
        end
        local original_take = handlers["take"]
        handlers["take"] = function(ctx, noun)
            if noun ~= "" then
                local creature = find_creature_by_keyword(ctx, noun)
                if creature then
                    return handlers["catch"](ctx, noun)
                end
            end
            if original_take then
                return original_take(ctx, noun)
            end
            return handlers["catch"](ctx, noun)
        end
        handlers["grab"] = handlers["take"]
        handlers["snatch"] = handlers["catch"]
    end

    ---------------------------------------------------------------------------
    -- WAVE-6: ATTACK verb → combat FSM trigger + stance prompt + flee
    -- Wires combat engine (Bart's src/engine/combat/init.lua) into verb layer.
    ---------------------------------------------------------------------------
    do
        local combat_ok, combat_mod = pcall(require, "engine.combat")
        local cr_ok, cr_mod = pcall(require, "engine.creatures")
        local inj_ok, injury_mod = pcall(require, "engine.injuries")
        local pres_ok, pres_mod = pcall(require, "engine.ui.presentation")

        local function kw_match(obj, kw)
            if obj.id and obj.id:lower() == kw then return true end
            if type(obj.keywords) == "table" then
                for _, k in ipairs(obj.keywords) do
                    if k:lower() == kw then return true end
                end
            end
            if obj.name then
                local padded = " " .. obj.name:lower() .. " "
                if padded:find(" " .. kw .. " ", 1, true) then return true end
            end
            return false
        end

        local function find_creature(ctx, keyword)
            if not cr_ok or not cr_mod then return nil end
            local kw = keyword:lower()
                :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
            local room_id = type(ctx.current_room) == "table"
                and ctx.current_room.id or ctx.current_room
            local creatures = cr_mod.get_creatures_in_room(ctx.registry, room_id)
            -- #344: Collect all matching creatures for disambiguation
            local matches = {}
            for _, c in ipairs(creatures) do
                if kw_match(c, kw) then matches[#matches + 1] = c end
            end
            if #matches == 0 then return nil end
            if #matches == 1 then return matches[1] end
            -- All same base id → fungible, return first
            local all_same = true
            for i = 2, #matches do
                if matches[i].id ~= matches[1].id then
                    all_same = false; break
                end
            end
            if all_same then return matches[1] end
            -- Different creatures: prompt disambiguation (#344 fix: standard format)
            local names = {}
            for _, c in ipairs(matches) do
                names[#names + 1] = c.name or c.id
            end
            local prompt
            if #names == 2 then
                prompt = "Which do you mean: " .. names[1] .. " or " .. names[2] .. "?"
            else
                local parts = {}
                for i, n in ipairs(names) do
                    if i == #names then
                        parts[#parts + 1] = "or " .. n
                    else
                        parts[#parts + 1] = n
                    end
                end
                prompt = "Which do you mean: " .. table.concat(parts, ", ") .. "?"
            end
            print(prompt)
            ctx.disambiguation_prompt = prompt
            return nil
        end

        local function emit_combat_stimulus(ctx, target_id)
            local room_id = ctx.current_room and ctx.current_room.id
                or ctx.player and ctx.player.location
            if not room_id then return end
            if cr_ok and cr_mod and cr_mod.emit_stimulus then
                cr_mod.emit_stimulus(room_id, "player_attacks", {
                    source = "player", target = target_id,
                })
            end
        end

        local function find_held_weapon(ctx)
            if not ctx.player or not ctx.player.hands then return nil end
            for i = 1, 2 do
                local hand = ctx.player.hands[i]
                if hand then
                    local obj = type(hand) == "table" and hand
                        or (ctx.registry and ctx.registry.get and ctx.registry:get(hand))
                    if obj and obj.combat then return obj end
                end
            end
            return nil
        end

        local function get_traversable_exits(ctx)
            local exits = {}
            local room = ctx.current_room
            if not room or not room.exits then return exits end
            for dir, exit_data in pairs(room.exits) do
                local portal_obj = nil
                if type(exit_data) == "table" and exit_data.portal then
                    portal_obj = ctx.registry:get(exit_data.portal)
                end
                if portal_obj and portal_obj.portal then
                    local state = portal_obj.states and portal_obj.states[portal_obj._state]
                    if state and state.traversable then
                        exits[#exits + 1] = dir
                    end
                else
                    exits[#exits + 1] = dir
                end
            end
            return exits
        end

        local function has_light(ctx)
            if pres_ok and pres_mod and pres_mod.has_some_light then
                return pres_mod.has_some_light(ctx)
            end
            return true
        end

        local INTERRUPT_MSG = {
            weapon_break = "Your weapon cracks!",
            armor_fail = "Your armor fails!",
            stance_ineffective = "Your stance isn't working!",
        }

        local function prompt_stance(ctx, is_interrupt, interrupt_reason)
            -- WAVE-3: Stress flee_bias — in headless mode, stress can auto-select flee
            if ctx.headless then
                local inj_ok, inj_mod = pcall(require, "engine.injuries")
                if inj_ok and inj_mod and inj_mod.get_stress_effects then
                    local effects = inj_mod.get_stress_effects(ctx.player)
                    local flee_bias = effects.flee_bias or 0
                    if flee_bias > 0 and math.random() < flee_bias then
                        return "flee"
                    end
                end
                return "balanced"
            end
            if is_interrupt and interrupt_reason then
                print("[INTERRUPT: " .. (INTERRUPT_MSG[interrupt_reason] or interrupt_reason) .. "]")
            end
            -- WAVE-3: Stress flee hint in interactive mode
            local stress_hint = ""
            local inj_ok2, inj_mod2 = pcall(require, "engine.injuries")
            if inj_ok2 and inj_mod2 and inj_mod2.get_stress_effects then
                local effects = inj_mod2.get_stress_effects(ctx.player)
                if effects.flee_bias and effects.flee_bias > 0 then
                    stress_hint = " (your instincts scream to flee!)"
                end
            end
            if is_interrupt then
                io.write("Combat stance? > aggressive | defensive | balanced | flee" .. stress_hint .. "\n> ")
            else
                io.write("Combat stance? > aggressive | defensive | balanced" .. stress_hint .. "\n> ")
            end
            io.flush()
            local input = io.read()
            if not input then return "balanced" end
            input = input:lower():gsub("^%s+", ""):gsub("%s+$", "")
            if input == "aggressive" or input == "defensive" or input == "balanced" then
                return input
            end
            if input == "flee" or input:match("^flee") or input == "run" then
                return "flee"
            end
            return "balanced"
        end

        -- Forward declarations
        local attempt_flee, run_combat_encounter

        attempt_flee = function(ctx, creature, light)
            local player = ctx.player
            local player_speed = player.combat and player.combat.speed or 3
            local creature_speed = creature.combat and creature.combat.speed or 3

            -- Leg injury modifier
            if player.injuries then
                for _, inj in ipairs(player.injuries) do
                    local z = inj.location or inj.zone or ""
                    if z:match("leg") or z:match("feet") or z:match("ankle") then
                        player_speed = player_speed * 0.7
                        break
                    end
                end
            end

            -- WAVE-3: Stress movement_penalty reduces flee speed
            local inj_ok3, inj_mod3 = pcall(require, "engine.injuries")
            if inj_ok3 and inj_mod3 and inj_mod3.get_stress_effects then
                local effects = inj_mod3.get_stress_effects(player)
                local penalty = effects.movement_penalty or 0
                if penalty > 0 then
                    player_speed = player_speed * (1.0 - penalty)
                end
            end

            local flee_chance = player_speed / (player_speed + creature_speed)
            if math.random() <= flee_chance then
                -- Success: partial damage (GRAZE via "flee" response)
                if combat_ok and combat_mod then
                    local graze = combat_mod.resolve_exchange(
                        creature, player, nil, nil, "flee",
                        { light = light, stance = "balanced" }
                    )
                    if graze.narration and graze.narration ~= "" then
                        print(graze.narration)
                    end
                end
                local exits = get_traversable_exits(ctx)
                if #exits > 0 then
                    local dir = exits[math.random(#exits)]
                    print("You break free and run " .. dir .. "!")
                    handlers["go"](ctx, dir)
                else
                    print("You break free but there's nowhere to run!")
                end
                return true
            else
                print("You try to flee but " .. (creature.name or "the creature") .. " blocks your escape!")
                return false
            end
        end

        run_combat_encounter = function(ctx, creature, target_zone)
            if not combat_ok or not combat_mod then
                print("Something goes wrong.")
                return
            end

            local player = ctx.player
            local light = has_light(ctx)

            if not light then
                print("You can't see well — attacks will be less accurate.")
            end

            local weapon = find_held_weapon(ctx)
            local weapon_name = weapon and (weapon.name or weapon.id) or "bare fists"
            print("You engage " .. (creature.name or "the creature") .. " with " .. weapon_name .. "!")

            local stance = prompt_stance(ctx, false, nil)
            if stance == "flee" then
                attempt_flee(ctx, creature, light)
                return
            end

            local combat_state = { deflect_streak = 0 }
            local MAX_ROUNDS = 20

            for round = 1, MAX_ROUNDS do
                -- Re-check weapon each round (may have broken)
                local round_weapon = find_held_weapon(ctx) or weapon

                -- Creature defensive behavior
                local creature_response = "dodge"
                if creature.combat and creature.combat.defense then
                    creature_response = creature.combat.defense
                end

                -- Player attacks creature
                local result = combat_mod.resolve_exchange(
                    player, creature, round_weapon, target_zone,
                    creature_response,
                    { light = light, stance = stance }
                )

                if result.narration and result.narration ~= "" then
                    print(result.narration)
                end

                -- Creature death
                if result.defender_dead or (creature.health and creature.health <= 0) then
                    local cr_ok2, cr_mod = pcall(require, "engine.creatures")
                    local room = type(ctx.current_room) == "table" and ctx.current_room or nil
                    if not (cr_ok2 and cr_mod.handle_creature_death
                            and cr_mod.handle_creature_death(creature, ctx, room)) then
                        creature._state = "dead"
                        creature.animate = false
                        creature.portable = true
                        creature.alive = false
                    end
                    -- #345/#370: Use "The" + id for death message (capitalized, definite article)
                    local death_id = creature.id or "creature"
                    print("The " .. death_id .. " is dead!")
                    return
                end

                -- Creature counter-attack
                if creature.combat and creature.combat.natural_weapons then
                    local player_response = "dodge"
                    if stance == "defensive" then
                        player_response = "block"
                    end

                    local counter = combat_mod.resolve_exchange(
                        creature, player, nil, nil, player_response,
                        { light = light, stance = stance }
                    )
                    if counter.narration and counter.narration ~= "" then
                        print(counter.narration)
                    end

                    if player.health and player.health <= 0 then
                        print("You collapse from your wounds!")
                        return
                    end
                end

                -- Interrupt check (headless: never interrupt, run to completion)
                if not ctx.headless then
                    local interrupt = combat_mod.interrupt_check(result, combat_state)
                    if interrupt then
                        stance = prompt_stance(ctx, true, interrupt)
                        if stance == "flee" then
                            if attempt_flee(ctx, creature, light) then return end
                            print("You fail to escape! The creature presses its attack!")
                            stance = "balanced"
                        end
                        combat_state.deflect_streak = 0
                    end
                end

                -- Creature morale break / flee threshold
                local flee_threshold = creature.combat and creature.combat.behavior
                    and creature.combat.behavior.flee_threshold
                if flee_threshold then
                    local max_hp = creature.max_health or creature.health or 10
                    local hp_pct = (creature.health or 10) / max_hp
                    if hp_pct <= flee_threshold then
                        print((creature.name or "The creature") .. " turns and flees!")
                        creature._state = "fled"
                        if cr_ok and cr_mod and cr_mod.emit_stimulus then
                            local room_id = type(ctx.current_room) == "table"
                                and ctx.current_room.id or ctx.current_room
                            cr_mod.emit_stimulus(room_id, "creature_fled", {
                                creature = creature.id,
                            })
                        end
                        return
                    end
                end
            end

            print("The combat reaches a stalemate. Both combatants back off, wary.")
        end

        -- Save original hit handler (self-infliction from combat.lua)
        local original_hit = handlers["hit"]

        handlers["attack"] = function(ctx, noun)
            if noun == "" then
                print("Attack what?")
                return
            end

            -- Parse "attack <creature> <zone>"
            local words = {}
            for w in noun:gmatch("%S+") do words[#words + 1] = w end

            local creature_word = words[1]
            local target_zone = words[2]

            local creature = find_creature(ctx, creature_word)
            if not creature and not ctx.disambiguation_prompt then
                -- Try full noun as creature name (multi-word: "giant rat")
                creature = find_creature(ctx, noun)
                target_zone = nil
            end

            -- #344: If disambiguation was triggered, return early
            if ctx.disambiguation_prompt then
                return
            end

            if creature then
                if creature._state == "dead" or creature.alive == false then
                    print("It's already dead.")
                    return
                end
                emit_combat_stimulus(ctx, creature.id)
                run_combat_encounter(ctx, creature, target_zone)
                return
            end

            -- #331: Check for dead creatures matching keyword before "don't see" message
            local room_id = type(ctx.current_room) == "table"
                and ctx.current_room.id or ctx.current_room
            local room = type(ctx.current_room) == "table" and ctx.current_room or nil
            if room and room.contents then
                local kw = noun:lower()
                    :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
                for _, obj_id in ipairs(room.contents) do
                    local obj = ctx.registry and ctx.registry.get and ctx.registry:get(obj_id)
                    if obj and (obj._state == "dead" or obj.alive == false) and kw_match(obj, kw) then
                        print("It's already dead.")
                        return
                    end
                end
            end

            print("You don't see that here to attack.")
        end
        handlers["fight"]  = handlers["attack"]
        handlers["kill"]   = handlers["attack"]
        handlers["slay"]   = handlers["attack"]
        handlers["murder"] = handlers["attack"]

        -- #331: Helper to check for dead creatures in room contents
        local function check_dead_creature(ctx, keyword)
            local room = type(ctx.current_room) == "table" and ctx.current_room or nil
            if not room or not room.contents then return false end
            local kw = keyword:lower()
                :gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
            for _, obj_id in ipairs(room.contents) do
                local obj = ctx.registry and ctx.registry.get and ctx.registry:get(obj_id)
                if obj and (obj._state == "dead" or obj.alive == false) and kw_match(obj, kw) then
                    return true
                end
            end
            return false
        end

        -- #358: Extend stab/jab/pierce: try creature combat first, fall through to self-infliction
        local original_stab = handlers["stab"]
        handlers["stab"] = function(ctx, noun)
            if noun ~= "" then
                local first_word = noun:match("^(%S+)")
                local creature = find_creature(ctx, first_word)
                if creature and creature.alive ~= false and creature._state ~= "dead" then
                    return handlers["attack"](ctx, noun)
                end
                -- #331: dead creature check before falling through
                if check_dead_creature(ctx, first_word) then
                    print("It's already dead.")
                    return
                end
            end
            if original_stab then return original_stab(ctx, noun) end
            print("Stab what?")
        end
        handlers["jab"]    = handlers["stab"]
        handlers["pierce"] = handlers["stab"]
        handlers["stick"]  = handlers["stab"]

        -- Extend hit/strike/swing: try creature combat first, fall through
        handlers["hit"] = function(ctx, noun)
            if noun ~= "" then
                local first_word = noun:match("^(%S+)")
                local creature = find_creature(ctx, first_word)
                if creature and creature.alive ~= false and creature._state ~= "dead" then
                    return handlers["attack"](ctx, noun)
                end
                -- #331: dead creature check before falling through
                if check_dead_creature(ctx, first_word) then
                    print("It's already dead.")
                    return
                end
            end
            if original_hit then return original_hit(ctx, noun) end
            print("Hit what?")
        end
        -- Re-sync aliases set by combat.lua so identity checks pass
        handlers["punch"]    = handlers["hit"]
        handlers["bash"]     = handlers["hit"]
        handlers["bonk"]     = handlers["hit"]
        handlers["thump"]    = handlers["hit"]
        handlers["smack"]    = handlers["hit"]
        handlers["bang"]     = handlers["hit"]
        handlers["slap"]     = handlers["hit"]
        handlers["whack"]    = handlers["hit"]
        handlers["headbutt"] = handlers["hit"]
        handlers["kick"]     = handlers["hit"]
        handlers["stomp"]    = handlers["hit"]
        handlers["trample"]  = handlers["hit"]
        handlers["stamp"]    = handlers["hit"]
        handlers["squash"]   = handlers["hit"]
        handlers["crush"]    = handlers["hit"]
        handlers["squish"]   = handlers["hit"]

        -- strike: preserve fire.lua match-striking, add creature combat fallback
        local original_strike = handlers["strike"]
        handlers["strike"] = function(ctx, noun)
            if noun ~= "" then
                local first_word = noun:match("^(%S+)")
                local creature = find_creature(ctx, first_word)
                if creature and creature.alive ~= false and creature._state ~= "dead" then
                    return handlers["attack"](ctx, noun)
                end
                -- #331: dead creature check before falling through
                if check_dead_creature(ctx, first_word) then
                    print("It's already dead.")
                    return
                end
            end
            if original_strike then return original_strike(ctx, noun) end
            print("Strike what?")
        end

        handlers["swing"] = function(ctx, noun)
            if noun ~= "" then
                local first_word = noun:match("^(%S+)")
                local creature = find_creature(ctx, first_word)
                if creature and creature.alive ~= false and creature._state ~= "dead" then
                    return handlers["attack"](ctx, noun)
                end
                -- #331: dead creature check before falling through
                if check_dead_creature(ctx, first_word) then
                    print("It's already dead.")
                    return
                end
            end
            print("Swing at what?")
        end

        -- FLEE verb (standalone — works in and out of combat)
        handlers["flee"] = function(ctx, noun)
            -- Strip "away" — "flee away" / "run away" are just flee
            if noun == "away" then noun = "" end

            if not cr_ok or not cr_mod then
                print("There's nothing to flee from.")
                return
            end
            local room_id = type(ctx.current_room) == "table"
                and ctx.current_room.id or ctx.current_room
            local room_creatures = cr_mod.get_creatures_in_room(ctx.registry, room_id)
            local threat = nil
            for _, c in ipairs(room_creatures) do
                if c.alive ~= false and c._state ~= "dead" and c._state ~= "fled" then
                    threat = c
                    break
                end
            end
            if not threat then
                if noun ~= "" then
                    handlers["go"](ctx, noun)
                else
                    print("There's nothing to flee from.")
                end
                return
            end
            local light = has_light(ctx)
            if not attempt_flee(ctx, threat, light) then
                print("You're still here, facing " .. (threat.name or "the creature") .. ".")
            end
        end

        -- #330: "run" checks for threats first (flee), falls back to movement
        handlers["run"] = handlers["flee"]
        handlers["escape"] = handlers["flee"]
    end

    -- Consciousness gate: block all verbs while the player is unconscious.
    -- Cache wrappers by original function to preserve alias identity
    -- (e.g., handlers["i"] == handlers["inventory"]).
    local raw = {}
    for k, v in pairs(handlers) do raw[k] = v end
    local wrapper_cache = {}
    for verb, fn in pairs(raw) do
        if not wrapper_cache[fn] then
            wrapper_cache[fn] = function(ctx, noun)
                if ctx.player and ctx.player.consciousness
                   and ctx.player.consciousness.state == "unconscious" then
                    print("You are unconscious.")
                    return
                end
                return fn(ctx, noun)
            end
        end
        handlers[verb] = wrapper_cache[fn]
    end

    return handlers
end

return verbs

end

package.preload["engine.verbs.meta"] = function()
-- engine/verbs/meta.lua
local H = require("engine.verbs.helpers")

local fsm_mod = H.fsm_mod
local presentation = H.presentation
local preprocess = H.preprocess
local traverse_effects = H.traverse_effects
local effects = H.effects
local materials = H.materials
local context_window = H.context_window
local fuzzy = H.fuzzy

local GAME_SECONDS_PER_REAL_SECOND = H.GAME_SECONDS_PER_REAL_SECOND
local GAME_START_HOUR = H.GAME_START_HOUR
local DAYTIME_START = H.DAYTIME_START
local DAYTIME_END = H.DAYTIME_END

local next_instance_id = H.next_instance_id
local _hid = H._hid
local _hobj = H._hobj
local err_not_found = H.err_not_found
local err_cant_do_that = H.err_cant_do_that
local err_nothing_happens = H.err_nothing_happens
local matches_keyword = H.matches_keyword
local interaction_verbs = H.interaction_verbs
local hands_full = H.hands_full
local first_empty_hand = H.first_empty_hand
local which_hand = H.which_hand
local get_all_carried_ids = H.get_all_carried_ids
local count_hands_used = H.count_hands_used
local find_part = H.find_part
local detach_part = H.detach_part
local reattach_part = H.reattach_part
local _fv_room = H._fv_room
local _fv_surfaces = H._fv_surfaces
local _fv_parts = H._fv_parts
local _fv_hands = H._fv_hands
local _fv_bags = H._fv_bags
local _fv_worn = H._fv_worn
local find_visible = H.find_visible
local find_in_inventory = H.find_in_inventory
local find_tool_in_inventory = H.find_tool_in_inventory
local provides_capability = H.provides_capability
local find_visible_tool = H.find_visible_tool
local consume_tool_charge = H.consume_tool_charge
local remove_from_location = H.remove_from_location
local container_contents_accessible = H.container_contents_accessible
local find_mutation = H.find_mutation
local spawn_objects = H.spawn_objects
local perform_mutation = H.perform_mutation
local inventory_weight = H.inventory_weight
local move_spatial_object = H.move_spatial_object

local get_game_time = H.get_game_time
local is_daytime = H.is_daytime
local format_time = H.format_time
local time_of_day_desc = H.time_of_day_desc
local get_light_level = H.get_light_level
local has_some_light = H.has_some_light
local vision_blocked_by_worn = H.vision_blocked_by_worn

local M = {}

function M.register(handlers)
    ---------------------------------------------------------------------------
    -- INVENTORY -- shows hands, worn items, and bag contents
    ---------------------------------------------------------------------------
    handlers["inventory"] = function(ctx, noun)
        local reg = ctx.registry

        -- Hands
        for i = 1, 2 do
            local hand = ctx.player.hands[i]
            if hand then
                local obj = _hobj(hand, reg)
                local label = (i == 1) and "Left hand" or "Right hand"
                print("  " .. label .. ": " .. (obj and obj.name or _hid(hand)))
                -- Show bag contents
                if obj and obj.container and obj.contents and #obj.contents > 0 then
                    print("    (contains:)")
                    for _, item_id in ipairs(obj.contents) do
                        local item = reg:get(item_id)
                        print("      " .. (item and item.name or item_id))
                    end
                end
            else
                local label = (i == 1) and "Left hand" or "Right hand"
                print("  " .. label .. ": (empty)")
            end
        end

        -- Worn items (grouped by slot when wear metadata is available)
        if #(ctx.player.worn or {}) > 0 then
            print("  Worn:")
            for _, worn_id in ipairs(ctx.player.worn) do
                local obj = reg:get(worn_id)
                local label = obj and obj.name or worn_id
                if obj and obj.wear and obj.wear.slot then
                    label = label .. " (" .. obj.wear.slot .. ")"
                end
                print("    " .. label)
                if obj and obj.container and obj.contents and #obj.contents > 0 then
                    print("    (contains:)")
                    for _, item_id in ipairs(obj.contents) do
                        local item = reg:get(item_id)
                        print("      " .. (item and item.name or item_id))
                    end
                end
            end
        end

        -- Flame status
        if ctx.player.state.has_flame and ctx.player.state.has_flame > 0 then
            print("")
            print("  You hold a flickering match flame.")
        end
    end

    handlers["i"] = handlers["inventory"]

    -- TIME
    ---------------------------------------------------------------------------
    handlers["time"] = function(ctx, noun)
        local hour, minute = get_game_time(ctx)
        local sky = ctx.current_room and ctx.current_room.sky_visible
        local desc = time_of_day_desc(hour, sky)
        if desc then print(desc) end
        print("It is " .. format_time(hour, minute) .. ".")
    end

    ---------------------------------------------------------------------------
    -- SET / ADJUST — advance adjustable clocks (puzzle mechanic)
    ---------------------------------------------------------------------------
    handlers["set"] = function(ctx, noun)
        if noun == "" then print("Set what?") return end

        -- Find the target object (room or inventory)
        local obj = find_visible(ctx, noun)
        if not obj then obj = find_in_inventory(ctx, noun) end
        if not obj then
            print("You don't see any " .. noun .. " to set.")
            return
        end

        -- Only adjustable clocks respond to SET
        if not obj.adjustable then
            print("You can't set that.")
            return
        end

        -- Must have light to fiddle with clock hands
        if not has_some_light(ctx) then
            print("It is too dark to see the clock face.")
            return
        end

        -- Extract current hour from state name (hour_N)
        local cur_hour = obj._state and tonumber(obj._state:match("hour_(%d+)"))
        if not cur_hour then
            print("You can't figure out how to set that.")
            return
        end

        -- Advance to next hour
        local next_hour = (cur_hour % 24) + 1
        local next_state = "hour_" .. next_hour

        -- Apply the state change directly (manual adjustment, not timed)
        local fsm_set = require("engine.fsm")
        fsm_set.stop_timer(obj.id or "wall-clock")
        local old_state = obj._state
        if obj.states and obj.states[next_state] then
            -- Apply new state properties
            if obj.states[old_state] then
                for k in pairs(obj.states[old_state]) do
                    if k ~= "on_tick" and k ~= "terminal" and k ~= "timed_events" then
                        obj[k] = nil
                    end
                end
            end
            for k, v in pairs(obj.states[next_state]) do
                if k ~= "on_tick" and k ~= "terminal" and k ~= "timed_events" then
                    obj[k] = v
                end
            end
            obj._state = next_state
        end

        -- Restart the hourly timer for the new state
        fsm_set.start_timer(ctx.registry, obj.id or "wall-clock")

        -- Display the new hour
        local display_h = ((next_hour - 1) % 12) + 1
        local number_words = {
            "one", "two", "three", "four", "five", "six",
            "seven", "eight", "nine", "ten", "eleven", "twelve",
        }
        print("You turn the clock hands. The clock now reads " .. number_words[display_h] .. " o'clock.")

        -- Check if puzzle target_hour is reached
        if obj.target_hour and next_hour == obj.target_hour then
            if obj.on_correct_time then
                obj.on_correct_time(obj, ctx)
            end
        end
    end
    handlers["adjust"] = handlers["set"]

    ---------------------------------------------------------------------------
    -- REPORT BUG — opens a pre-filled GitHub issue URL
    ---------------------------------------------------------------------------
    handlers["report_bug"] = function(ctx, noun)
        -- Build transcript text from recent output (last 100 exchanges)
        local transcript = ctx.transcript or {}
        local lines = {}
        for _, entry in ipairs(transcript) do
            lines[#lines + 1] = "> " .. entry.input
            lines[#lines + 1] = entry.output
            lines[#lines + 1] = ""
        end
        local transcript_text = table.concat(lines, "\n")

        -- Level name (stored on room object as level = { number, name })
        local level_name = "Unknown"
        if ctx.current_room and ctx.current_room.level then
            local lv = ctx.current_room.level
            if lv.number and lv.name then
                level_name = "Level " .. lv.number .. ": " .. lv.name
            elseif lv.name then
                level_name = lv.name
            end
        end

        -- Room name
        local room_name = "Unknown"
        if ctx.current_room then
            room_name = ctx.current_room.name or ctx.current_room.id or "Unknown"
        end

        -- Build timestamp (read from src/.build-timestamp if available)
        local build_timestamp = "dev"
        local ts_file = io.open("src/.build-timestamp", "r")
        if ts_file then
            local content = ts_file:read("*a")
            ts_file:close()
            if content and #content > 0 then
                build_timestamp = content:match("^%s*(.-)%s*$") or "dev"
            end
        end

        -- URL-encode helper
        local function url_encode(str)
            str = str:gsub("\r\n", "\n")
            str = str:gsub("([^%w%-%.%_%~ ])", function(c)
                return string.format("%%%02X", string.byte(c))
            end)
            str = str:gsub(" ", "+")
            return str
        end

        local timestamp = os.date and os.date("%Y-%m-%d %H:%M") or "unknown"
        local title = "[Bug Report] " .. room_name .. " - " .. timestamp
        -- GitHub issue body limit is 65535 chars; truncate transcript if needed
        local MAX_BODY = 65535
        local header = "## Bug Report\n\n"
            .. "**Level:** " .. level_name .. "\n"
            .. "**Room:** " .. room_name .. "\n"
            .. "**Build:** " .. build_timestamp .. "\n\n"
            .. "### What happened?\n"
            .. "_[Please describe the bug here]_\n\n"
            .. "### Session Transcript (last " .. #transcript .. " exchanges)\n\n"
        local footer = "```\n"
        local budget = MAX_BODY - #header - #footer - 10
        if #transcript_text > budget then
            transcript_text = "...(truncated)\n" .. transcript_text:sub(-budget)
        end
        local body = header .. "```\n" .. transcript_text .. footer

        local url = "https://github.com/WayneWalterBerry/MMO/issues/new"
            .. "?title=" .. url_encode(title)
            .. "&body=" .. url_encode(body)

        -- Try web bridge first (opens in new tab), fall back to printing URL
        if ctx.open_url then
            ctx.open_url(url)
            print("Opening bug report in a new tab...")
        else
            print("To report a bug, open this URL:")
            print(url)
        end
        print("Thank you for helping improve the game!")
    end
    ---------------------------------------------------------------------------
    -- HELP
    ---------------------------------------------------------------------------
    handlers["help"] = function(ctx, noun)
        print("== Movement ==")
        print("  north/south/east/west    Move in a direction (n/s/e/w)")
        print("  up/down                  Move up or down (u/d)")
        print("  go <direction>           Move (go north, go through door)")
        print("  enter <thing>            Enter through an exit")
        print("  climb up/down            Climb stairs or ladders")
        print("")
        print("== Observation ==")
        print("  look                     Look around the room (vision only, needs light)")
        print("  look at <thing>          Examine something closely (needs light)")
        print("  look in/on/under         Inspect a surface (needs light)")
        print("  search                   Search around (all senses, works in darkness)")
        print("  search <thing>           Search for something (all senses)")
        print("  find <thing>             Find something (all senses, works in darkness)")
        print("  read <thing>             Read text on an object (may teach skills)")
        print("  feel                     Grope around (works in darkness)")
        print("  feel <thing>             Feel an object by touch")
        print("  smell                    Smell the air (works in darkness)")
        print("  smell <thing>            Smell a specific object")
        print("  taste <thing>            Taste something (risky! works in darkness)")
        print("  listen                   Listen to ambient sounds (works in darkness)")
        print("  listen to <thing>        Listen closely to something")
        print("")
        print("== Item Interaction ==")
        print("  take <thing>             Pick something up (needs a free hand)")
        print("  get <x> from <y>         Take something from a bag or container")
        print("  drop <thing>             Drop something you're holding")
        print("  put <x> in <y>           Put something in a container")
        print("  put <x> on <y>           Put something on a surface")
        print("  open <thing>             Open a container or door")
        print("  close <thing>            Close something")
        print("  unlock <thing>           Unlock a locked door")
        print("  pull <thing>             Pull a part free (drawer, cork, etc.)")
        print("")
        print("== Equipment ==")
        print("  wear <thing>             Put on a wearable item (cloak, hat, armor)")
        print("  remove <thing>           Take off a worn item")
        print("  inventory (i)            See what you're carrying / wearing")
        print("")
        print("== Tools & Crafting ==")
        print("  break <thing>            Break something breakable")
        print("  tear <thing>             Tear fabric apart")
        print("  cut <thing> with <tool>  Cut something (or 'cut self' for blood)")
        print("  prick self with <tool>   Prick yourself with something sharp")
        print("  strike match on <x>      Strike a match")
        print("  light <thing>            Light a candle or torch (needs fire)")
        print("  extinguish <thing>       Put out a flame")
        print("  write <text> on <thing>  Write on a writable surface")
        print("  sew <thing> with <tool>  Sew materials together (requires skill)")
        print("")
        print("== Combat ==")
        print("  stab <target>            Attack with a stabbing weapon")
        print("  slash <target>           Attack with a slashing weapon")
        print("")
        print("== Health & Survival ==")
        print("  health                   Check your injuries and health")
        print("  injuries                 List your injuries")
        print("  apply <item>             Apply a healing item to an injury")
        print("  eat <thing>              Eat something edible")
        print("  drink <thing>            Drink from a container")
        print("  pour <thing>             Pour out a liquid")
        print("  burn <thing>             Set something flammable on fire")
        print("  sleep                    Sleep for 1 hour (or: sleep for 2 hours)")
        print("")
        print("== Information ==")
        print("  time                     Check the time of day")
        print("  help                     Show this list")
        print("  report bug               Report a bug (opens GitHub issue)")
        print("  quit                     Leave the game")
    end
    ---------------------------------------------------------------------------
    -- INJURIES -- examine active injuries and derived health
    ---------------------------------------------------------------------------
    handlers["injuries"] = function(ctx, noun)
        local inj_ok, injury_mod = pcall(require, "engine.injuries")
        if not inj_ok then
            print("You feel fine.")
            return
        end

        injury_mod.list(ctx.player)

        -- Show derived health
        local health = injury_mod.compute_health(ctx.player)
        local max = ctx.player.max_health or 100
        if ctx.player.injuries and #ctx.player.injuries > 0 then
            print("")
            print("Health: " .. health .. "/" .. max)
        end
    end
    handlers["injury"] = handlers["injuries"]
    handlers["wounds"] = handlers["injuries"]
    handlers["health"] = handlers["injuries"]

    ---------------------------------------------------------------------------
    -- APPLY -- apply a healing item to an injury ("apply bandage", "apply bandage to wound")
    -- Supports bandage dual-binding via injury_targeting + injury_treatment
    ---------------------------------------------------------------------------
    handlers["apply"] = function(ctx, noun)
        if noun == "" then
            print("Apply what? Try 'examine' to check what you're carrying.")
            return
        end

        local inj_ok, injury_mod = pcall(require, "engine.injuries")
        if not inj_ok then
            err_cant_do_that()
            return
        end

        if not ctx.player.injuries or #ctx.player.injuries == 0 then
            print("You don't have any injuries to treat.")
            return
        end

        -- Parse "apply X to Y" or just "apply X"
        -- #109: prefer context.apply_target (extracted by game loop)
        local item_kw = noun
        local target_kw = ctx.apply_target or nil
        if not target_kw then
            local to_match = noun:match("^(.-)%s+to%s+(.+)$")
            if to_match then
                item_kw = noun:match("^(.-)%s+to%s+")
                target_kw = noun:match("%s+to%s+(.+)$")
            end
        end

        -- Strip articles
        item_kw = item_kw:lower():gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", "")
        if target_kw then
            target_kw = target_kw:lower():gsub("^the%s+", ""):gsub("^a%s+", ""):gsub("^an%s+", ""):gsub("^my%s+", "")
        end

        -- Find healing item in inventory (hands, worn, etc.)
        local obj = find_in_inventory(ctx, item_kw)
        if not obj then
            print("You don't have " .. item_kw .. ".")
            return
        end

        -- Check if this is a bandage-type item with cures list and FSM
        if obj.cures and obj._state then
            -- Bandage-style treatment: use dual-binding system
            if obj.applied_to then
                print((obj.name or "That") .. " is already applied to a wound.")
                return
            end

            -- Resolve which injury to target
            local injury, err = injury_mod.resolve_target(ctx.player, target_kw, obj.cures)
            if not injury then
                print(err)
                return
            end

            -- Apply the treatment (dual binding)
            injury_mod.apply_treatment(ctx.player, obj, injury)

            -- Find and print the transition message from the bandage's transitions
            local msg = nil
            if obj.transitions then
                for _, t in ipairs(obj.transitions) do
                    if t.verb == "apply" and t.to == "applied" then
                        msg = t.message
                        break
                    end
                end
            end
            if not msg then
                msg = "You apply " .. (obj.name or item_kw) .. " to the wound."
            end
            print(msg)
            return
        end

        -- Fallback: legacy healing via on_apply/on_use/on_drink
        local healing_effect = nil
        local healing_verb = nil
        for _, v in ipairs({"apply", "use", "drink"}) do
            local eff = obj["on_" .. v]
            if eff and eff.cures then
                healing_effect = eff
                healing_verb = v
                break
            end
        end

        if not healing_effect then
            print("You can't use " .. (obj.name or item_kw) .. " to treat injuries.")
            return
        end

        -- Attempt healing
        local healed = injury_mod.try_heal(ctx.player, obj, healing_verb)
        if healed and healing_effect.consumable then
            -- Consume the item from hands
            for i = 1, 2 do
                local hand = ctx.player.hands[i]
                if hand then
                    local hand_id = type(hand) == "table" and hand.id or hand
                    if hand_id == obj.id then
                        ctx.player.hands[i] = nil
                        break
                    end
                end
            end
        end
    end
    handlers["treat"] = handlers["apply"]

    ---------------------------------------------------------------------------
    -- USE -- generic "use X" handler (#102)
    ---------------------------------------------------------------------------
    handlers["use"] = function(ctx, noun)
        if noun == "" then
            print("Use what? Try 'use [item]'.")
            return
        end

        local obj = find_in_inventory(ctx, noun)
        if not obj then
            obj = find_visible(ctx, noun)
        end
        if not obj then
            err_not_found(ctx)
            return
        end

        -- #329: If item has cures (healing item), block use when player has no injuries
        if obj.cures then
            if not ctx.player.injuries or #ctx.player.injuries == 0 then
                print("You don't have any injuries to treat.")
                return
            end
        end

        -- #305: If item has cures (bandage-type), delegate to apply handler
        if obj.cures and handlers["apply"] then
            handlers["apply"](ctx, noun)
            return
        end

        -- FSM path: check for a "use" transition
        if obj.states then
            local transitions = fsm_mod.get_transitions(obj)
            local target_trans
            for _, t in ipairs(transitions) do
                if t.verb == "use" then target_trans = t; break end
                if t.aliases then
                    for _, alias in ipairs(t.aliases) do
                        if alias == "use" then target_trans = t; break end
                    end
                    if target_trans then break end
                end
            end
            if target_trans then
                local trans = fsm_mod.transition(ctx.registry, obj.id, target_trans.to, {}, "use")
                if trans then
                    print(trans.message or ("You use " .. (obj.name or obj.id) .. "."))
                    -- on_use hook: fire callback if object declares one
                    if obj.on_use and type(obj.on_use) == "function" then
                        obj.on_use(obj, ctx)
                    end
                    -- event_output: one-shot flavor text for on_use
                    if obj.event_output and obj.event_output["on_use"] then
                        print(obj.event_output["on_use"])
                        obj.event_output["on_use"] = nil
                    end
                end
                return
            end
        end

        -- Non-FSM path: fire callback if object declares one
        if obj.on_use and type(obj.on_use) == "function" then
            obj.on_use(obj, ctx)
            -- event_output: one-shot flavor text for on_use
            if obj.event_output and obj.event_output["on_use"] then
                print(obj.event_output["on_use"])
                obj.event_output["on_use"] = nil
            end
            return
        end

        -- event_output only (DATA pattern, no callback)
        if obj.event_output and obj.event_output["on_use"] then
            print(obj.event_output["on_use"])
            obj.event_output["on_use"] = nil
            return
        end

        print("You don't know how to use " .. (obj.name or "that") .. ".")
    end
    handlers["utilize"] = handlers["use"]

    -- #39: "wait" — pass a turn without acting (BUG-131)
    -- Post-command injury tick and time advance happen automatically in the loop.
    handlers["wait"] = function(ctx, noun)
        print("Time passes.")
    end
    handlers["pass"] = handlers["wait"]

    -- #39/#37: "appearance" — show player appearance description (BUG-131/BUG-129)
    handlers["appearance"] = function(ctx, noun)
        local app_ok, app_mod = pcall(require, "engine.player.appearance")
        if app_ok and app_mod then
            print(app_mod.describe(ctx.player, ctx.registry))
        else
            print("You can't see yourself without a mirror.")
        end
    end
end

return M

end

