                source_id = obj.id,
            })
        end
    end
    handlers["lick"] = handlers["taste"]

    ---------------------------------------------------------------------------
end


return M

end

package.preload["engine.verbs.sensory.touch"] = function()
-- Auto-split from sensory.lua
local H = require("engine.verbs.helpers")

local find_visible = H.find_visible
local container_contents_accessible = H.container_contents_accessible

local M = {}

function M.register(handlers)
    -- FEEL / TOUCH / GROPE -- works even in total darkness
    ---------------------------------------------------------------------------
    handlers["feel"] = function(ctx, noun)
        -- Treat "around", "room", "here" the same as bare feel (room sweep)
        local sweep_words = { [""] = true, ["around"] = true, ["room"] = true, ["here"] = true,
                              ["around me"] = true, ["surroundings"] = true }
        if sweep_words[noun] then
            -- Feel around the room
            local room = ctx.current_room
            local found = {}
            for _, obj_id in ipairs(room.contents or {}) do
                local obj = ctx.registry:get(obj_id)
                if obj and not obj.hidden then
                    local desc = obj.name or obj.id
                    found[#found + 1] = desc
                end
            end
            if #found > 0 then
                print("You reach out in the darkness, feeling around you...")
                for _, entry in ipairs(found) do
                    print("  " .. entry)
                end
            else
                print("You feel around but find nothing within reach.")
            end
            return
        end

        -- Handle "feel in/inside/under/underneath/beneath {target}" prepositional phrases
        -- BUG-089: Track the preposition so "feel inside X" limits to interior only
        local container_noun = nil
        local surface_prep = nil
        local in_match = noun:match("^in%s+(.+)") or noun:match("^inside%s+(.+)")
        if in_match then
            container_noun = in_match
            surface_prep = "inside"
        end
        if not container_noun then
            local p, t = noun:match("^(under)%s+(.+)")
            if not p then p, t = noun:match("^(underneath)%s+(.+)") end
            if not p then p, t = noun:match("^(beneath)%s+(.+)") end
            if p then
                surface_prep = "underneath"
                container_noun = t
            end
        end
        -- Bare "feel inside" / "feel in" ΓåÆ use last-interacted container
        if not container_noun and (noun == "inside" or noun == "in") then
            if ctx.last_object and (ctx.last_object.surfaces or (ctx.last_object.container and ctx.last_object.contents)) then
                container_noun = ctx.last_object.id
            else
                print("Feel inside what? Try 'feel' to explore your surroundings by touch.")
                return
            end
        end
        if container_noun then
            local cobj, loc_type, parent_obj = find_visible(ctx, container_noun)
            if not cobj then
                print("You can't feel anything like that nearby. Try 'feel' to explore what's around you.")
                return
            end
            -- BUG-058: If we found a part, redirect to the parent for surface access
            -- BUG-096: Preserve the target name for gating messages
            -- #88: Don't redirect when the part itself is a container (e.g., drawer)
            local target_name = cobj.name or "that"
            if loc_type == "part" and parent_obj and not cobj.container then
                cobj = parent_obj
            end
            local found_anything = false
            -- BUG-089: If a specific surface prep was given, check only that surface
            if surface_prep and cobj.surfaces and cobj.surfaces[surface_prep] then
                local zone = cobj.surfaces[surface_prep]
                if zone.accessible == false then
                    print("You can't reach " .. noun:match("^(%S+)") .. " " .. target_name .. ".")
                    return
                end
                if #(zone.contents or {}) > 0 then
                    print("Your fingers find " .. surface_prep .. " " .. (cobj.name or "that") .. ":")
                    for _, id in ipairs(zone.contents) do
                        local item = ctx.registry:get(id)
                        print("  " .. (item and item.name or id))
                    end
                    found_anything = true
                else
                    print("You feel " .. noun:match("^(%S+)") .. " " .. (cobj.name or "that") .. " but find nothing.")
                end
                -- Also check simple container contents for "inside" prep
                -- Sensory gating: only show contents if container is open
                if surface_prep == "inside" and cobj.container and cobj.contents and #cobj.contents > 0
                    and container_contents_accessible(cobj, "tactile") then
                    local items = {}
                    for _, id in ipairs(cobj.contents) do
                        local item = ctx.registry:get(id)
                        items[#items + 1] = item and item.name or id
                    end
                    print("Inside you feel:")
                    for _, item_name in ipairs(items) do
                        print("  " .. item_name)
                    end
                    found_anything = true
                end
                if not found_anything then
                    print("You feel " .. noun:match("^(%S+)") .. " " .. (cobj.name or "that") .. " but find nothing.")
                end
                return
            end
            -- When surface_prep is set but the specific surface doesn't exist,
            -- only check simple container contents (don't show unrelated surfaces)
            if surface_prep then
                if cobj.container and cobj.contents and #cobj.contents > 0
                    and container_contents_accessible(cobj, "tactile") then
                    local items = {}
                    for _, id in ipairs(cobj.contents) do
                        local item = ctx.registry:get(id)
                        items[#items + 1] = item and item.name or id
                    end
                    print("Inside you feel:")
                    for _, item_name in ipairs(items) do
                        print("  " .. item_name)
                    end
                    found_anything = true
                end
                if not found_anything then
                    -- Issue #100: Explicit "closed" message for closed containers
                    if (cobj.container or cobj.is_container)
                        and not container_contents_accessible(cobj, "tactile") then
                        local cname = (cobj.name or "that"):gsub("^a ", "the "):gsub("^an ", "the ")
                        print(cname:sub(1,1):upper() .. cname:sub(2) .. " is closed.")
                    else
                        print("You can't feel inside " .. (cobj.name or "that") .. ".")
                    end
                end
                return
            end
            -- Check surface contents (e.g., nightstand "inside" zone)
            if cobj.surfaces then
                for zone_name, zone in pairs(cobj.surfaces) do
                    if zone.accessible ~= false and #(zone.contents or {}) > 0 then
                        local items = {}
                        for _, id in ipairs(zone.contents) do
                            local item = ctx.registry:get(id)
                            items[#items + 1] = item and item.name or id
                        end
                        print("Your fingers find " .. zone_name .. ":")
                        for _, item_name in ipairs(items) do
                            print("  " .. item_name)
                        end
                        found_anything = true
                    end
                end
            end
            -- Check simple container contents
            -- Sensory gating: only show contents if container is open
            if cobj.container and cobj.contents and #cobj.contents > 0
                and container_contents_accessible(cobj, "tactile") then
                local items = {}
                for _, id in ipairs(cobj.contents) do
                    local item = ctx.registry:get(id)
                    items[#items + 1] = item and item.name or id
                end
                print("Inside you feel:")
                for _, item_name in ipairs(items) do
                    print("  " .. item_name)
                end
                found_anything = true
            end
            if not found_anything then
                if cobj.surfaces then
                    local any_inaccessible = false
                    for _, zone in pairs(cobj.surfaces) do
                        if zone.accessible == false then any_inaccessible = true; break end
                    end
                    if any_inaccessible then
                        print("You can't reach inside " .. (cobj.name or "that") .. ". It seems closed.")
                    else
                        print("You feel around inside " .. (cobj.name or "that") .. " but find nothing.")
                    end
                elseif (cobj.container or cobj.is_container)
                    and not container_contents_accessible(cobj, "tactile") then
                    local cname = (cobj.name or "that"):gsub("^a ", "the "):gsub("^an ", "the ")
                    print(cname:sub(1,1):upper() .. cname:sub(2) .. " is closed.")
                else
                    print("You can't feel inside " .. (cobj.name or "that") .. ".")
                end
            end
            return
        end

        local obj, loc_type, parent_obj, surface_key = find_visible(ctx, noun)
        if not obj then
            print("You can't feel anything like that nearby. Try 'feel' to explore what's around you.")
            return
        end

        -- Prefer on_feel (rich sensory), fall back to touch_description, then generic
        if obj.on_feel then
            local feel_text = type(obj.on_feel) == "function" and obj.on_feel(obj) or obj.on_feel
            print(feel_text)
        elseif obj.touch_description then
            print(obj.touch_description)
        else
            print("You run your hands over " .. (obj.name or "it") ..
                ". " .. (obj.description or "It feels ordinary."))
        end

        -- BUG-065: If feeling a part that carries contents, check parent's surfaces
        local check_obj = obj
        local check_inside_only = false
        if loc_type == "part" and parent_obj and obj.carries_contents then
            check_obj = parent_obj
            check_inside_only = true
        end

        -- Enumerate accessible surface contents by touch
        if check_obj.surfaces then
            for zone_name, zone in pairs(check_obj.surfaces) do
                -- For parts with carries_contents, only show "inside" surface
                if (not check_inside_only or zone_name == "inside") then
                    if zone.accessible ~= false and #(zone.contents or {}) > 0 then
                        local items = {}
                        for _, id in ipairs(zone.contents) do
                            local item = ctx.registry:get(id)
                            items[#items + 1] = item and item.name or id
                        end
                        print("Your fingers find " .. zone_name .. ":")
                        for _, item_name in ipairs(items) do
                            print("  " .. item_name)
                        end
                    end
                end
            end
        end

        -- Enumerate simple container contents by touch
        -- Sensory gating: only show contents if container is open
        if check_obj.container and check_obj.contents and #check_obj.contents > 0
            and container_contents_accessible(check_obj, "tactile") then
            local items = {}
            for _, id in ipairs(check_obj.contents) do
                local item = ctx.registry:get(id)
                items[#items + 1] = item and item.name or id
            end
            print("Inside you feel:")
            for _, item_name in ipairs(items) do
                print("  " .. item_name)
            end
        end
    end
    handlers["touch"] = handlers["feel"]
    handlers["grope"] = handlers["feel"]

    ---------------------------------------------------------------------------
end


return M

end

package.preload["engine.verbs.survival"] = function()
-- engine/verbs/survival.lua
-- Retains: pour, dump/empty, wash handlers.
-- Eat/drink moved to consumption.lua; sleep/rest moved to rest.lua (Phase 3 WAVE-0).
local H = require("engine.verbs.helpers")

local fsm_mod = H.fsm_mod
local effects = H.effects

local err_not_found = H.err_not_found
local find_visible = H.find_visible
local find_in_inventory = H.find_in_inventory
local find_tool_in_inventory = H.find_tool_in_inventory
local provides_capability = H.provides_capability
local find_visible_tool = H.find_visible_tool
local remove_from_location = H.remove_from_location

local M = {}

function M.register(handlers)
    -- Delegate eat/drink to consumption module
    local consumption = require("engine.verbs.consumption")
    consumption.register(handlers)

    -- Delegate sleep/rest/nap to rest module
    local rest = require("engine.verbs.rest")
    rest.register(handlers)

    ---------------------------------------------------------------------------
    -- POUR -- pour out a liquid (FSM or generic)
    ---------------------------------------------------------------------------
    handlers["pour"] = function(ctx, noun)
        if noun == "" then print("Pour what?") return end

        local obj = find_in_inventory(ctx, noun)
        if not obj then obj = find_visible(ctx, noun) end
        if not obj then
            err_not_found(ctx)
            return
        end

        -- #108: "pour X into Y" — transfer liquid to target container
        local pour_target_noun = ctx.pour_target
        if pour_target_noun then
            local target_obj = find_in_inventory(ctx, pour_target_noun)
            if not target_obj then target_obj = find_visible(ctx, pour_target_noun) end
            if not target_obj then
                print("You don't see any " .. pour_target_noun .. " to pour into.")
                return
            end

            -- Check source has a "pour" FSM transition with target support
            if obj.states then
                local transitions = fsm_mod.get_transitions(obj)
                local target_trans
                for _, t in ipairs(transitions) do
                    if t.verb == "pour" then target_trans = t; break end
                    if t.aliases then
                        for _, alias in ipairs(t.aliases) do
                            if alias == "pour" then target_trans = t; break end
                        end
                        if target_trans then break end
                    end
                end
                if target_trans then
                    local trans = fsm_mod.transition(ctx.registry, obj.id, target_trans.to, {}, "pour")
                    if trans then
                        print(trans.message or ("You pour " .. (obj.name or obj.id) .. " into " .. (target_obj.name or target_obj.id) .. "."))
                    else
                        print("You can't pour " .. (obj.name or "that") .. ".")
                    end
                    return
                end
            end

            -- #118: Check target has a "pour" FSM transition (e.g. lantern needing oil)
            if target_obj.states then
                local transitions = fsm_mod.get_transitions(target_obj)
                local found_trans
                for _, t in ipairs(transitions) do
                    if t.verb == "pour" then found_trans = t; break end
                    if t.aliases then
                        for _, alias in ipairs(t.aliases) do
                            if alias == "pour" then found_trans = t; break end
                        end
                        if found_trans then break end
                    end
                end
                if found_trans then
                    if found_trans.requires_tool then
                        if not provides_capability(obj, found_trans.requires_tool) then
                            local tool = find_tool_in_inventory(ctx, found_trans.requires_tool)
                            if not tool then
                                print(found_trans.fail_message or ("You can't pour " .. (obj.name or "that") .. " into " .. (target_obj.name or "that") .. "."))
                                return
                            end
                        end
                    end
                    local trans = fsm_mod.transition(ctx.registry, target_obj.id, found_trans.to, {}, "pour")
                    if trans then
                        print(trans.message or ("You pour " .. (obj.name or obj.id) .. " into " .. (target_obj.name or target_obj.id) .. "."))
                    else
                        print("You can't pour " .. (obj.name or "that") .. " into " .. (target_obj.name or "that") .. ".")
                    end
                    return
                end
            end

            -- Generic liquid transfer message
            print("You pour " .. (obj.name or obj.id) .. " into " .. (target_obj.name or target_obj.id) .. ".")
            return
        end

        -- FSM path: check for "pour" transition (bare pour, no target)
        if obj.states then
            local transitions = fsm_mod.get_transitions(obj)
            local target_trans
            for _, t in ipairs(transitions) do
                if t.verb == "pour" then target_trans = t; break end
                if t.aliases then
                    for _, alias in ipairs(t.aliases) do
                        if alias == "pour" then target_trans = t; break end
                    end
                    if target_trans then break end
                end
            end
            if target_trans then
                local trans = fsm_mod.transition(ctx.registry, obj.id, target_trans.to, {}, "pour")
                if trans then
                    print(trans.message or ("You pour out " .. (obj.name or obj.id) .. "."))
                else
                    print("You can't pour " .. (obj.name or "that") .. ".")
                end
                return
            end
        end

        print("You can't pour " .. (obj.name or "that") .. ".")
    end

    handlers["spill"] = handlers["pour"]
    handlers["fill"] = handlers["pour"]
    handlers["fuel"] = handlers["pour"]     -- #398: "fuel lantern" routes to pour
    handlers["refuel"] = handlers["pour"]   -- #398: "refuel lantern" routes to pour

    ---------------------------------------------------------------------------
    -- DUMP / EMPTY — container-aware pour (#182)
    -- If target is a dry container with item contents, spill them into the
    -- room.  Otherwise fall through to pour behavior for liquids.
    ---------------------------------------------------------------------------
    local function dump_container(ctx, noun)
        if noun == "" then print("Dump what?") return end

        local obj = find_in_inventory(ctx, noun)
        if not obj then obj = find_visible(ctx, noun) end
        if not obj then err_not_found(ctx) return end

        -- Container with direct item contents
        if obj.container and obj.contents and #obj.contents > 0 then
            local room = ctx.current_room
            local dumped = {}
            for _, item_id in ipairs(obj.contents) do
                local item = ctx.registry:get(item_id)
                if item then
                    room.contents[#room.contents + 1] = item_id
                    item.location = room.id
                    dumped[#dumped + 1] = item.name or item.id
                end
            end
            obj.contents = {}
            if #dumped == 1 then
                print("You dump " .. dumped[1] .. " out of " .. (obj.name or "that") .. ".")
            else
                print("You dump the contents of " .. (obj.name or "that") .. " onto the floor.")
            end
            return
        end

        -- Container with surface.inside contents
        if obj.surfaces and obj.surfaces.inside then
            local inside = obj.surfaces.inside
            if inside.contents and #inside.contents > 0 then
                if inside.accessible ~= false then
                    local room = ctx.current_room
                    for _, item_id in ipairs(inside.contents) do
                        local item = ctx.registry:get(item_id)
                        if item then
                            room.contents[#room.contents + 1] = item_id
                            item.location = room.id
                        end
                    end
                    inside.contents = {}
                    print("You dump the contents of " .. (obj.name or "that") .. " onto the floor.")
                else
                    print("You turn " .. (obj.name or "that") .. " upside down but nothing falls out.")
                end
                return
            end
        end

        -- Empty container
        if obj.container then
            print("You turn " .. (obj.name or "that") .. " upside down but nothing falls out.")
            return
        end

        -- Not a container — fall through to pour for liquids
        handlers["pour"](ctx, noun)
    end

    handlers["dump"] = dump_container
    handlers["empty"] = dump_container

    ---------------------------------------------------------------------------
    -- WASH -- clean soiled objects using a water source (#112)
    ---------------------------------------------------------------------------
    handlers["wash"] = function(ctx, noun)
        if noun == "" then
            print("Wash what?")
            return
        end

        -- "wash hands" / "wash my hands"
        local hand_noun = noun:gsub("^my%s+", "")
        if hand_noun == "hands" or hand_noun == "hand" then
            -- Find water source nearby
            local water = find_tool_in_inventory(ctx, "water_source")
            if not water then water = find_visible_tool(ctx, "water_source") end
            if not water or (water._state and water._state:match("empty")) then
                print("You need water to wash your hands.")
                return
            end
            print("You plunge your hands into the water and scrub them clean.")
            if ctx.player.state then
                ctx.player.state.bloody = nil
                ctx.player.state.dirty = nil
            end
            return
        end

        local obj = find_in_inventory(ctx, noun)
        if not obj then obj = find_visible(ctx, noun) end
        if not obj then
            err_not_found(ctx)
            return
        end

        -- FSM path: check for "wash" transition
        if obj.states then
            local transitions = fsm_mod.get_transitions(obj)
            local found_trans
            for _, t in ipairs(transitions) do
                if t.verb == "wash" then found_trans = t; break end
                if t.aliases then
                    for _, alias in ipairs(t.aliases) do
                        if alias == "wash" then found_trans = t; break end
                    end
                    if found_trans then break end
                end
            end

            if found_trans then
                if found_trans.requires_tool then
                    -- If player specified "wash X in Y", check the target
                    local water
                    if ctx.wash_target then
                        water = find_in_inventory(ctx, ctx.wash_target)
                        if not water then water = find_visible(ctx, ctx.wash_target) end
                        if water and not provides_capability(water, found_trans.requires_tool) then
                            print((water.name or ctx.wash_target) .. " isn't a water source.")
                            return
                        end
                    end
                    -- Auto-find water source
                    if not water then
                        water = find_tool_in_inventory(ctx, found_trans.requires_tool)
                    end
                    if not water then
                        water = find_visible_tool(ctx, found_trans.requires_tool)
                    end
                    -- Reject empty water sources
                    if water and water._state and water._state:match("empty") then
                        water = nil
                    end
                    if not water then
                        print(found_trans.fail_message or "You need water to wash that.")
                        return
                    end
                end

                local trans = fsm_mod.transition(ctx.registry, obj.id, found_trans.to, {}, "wash")
                if trans then
                    print(trans.message or ("You wash " .. (obj.name or obj.id) .. "."))
                else
                    print("You can't wash " .. (obj.name or "that") .. ".")
                end
                return
            end
        end

        print("You can't wash " .. (obj.name or "that") .. ".")
    end
end

return M

end

package.preload["engine.verbs.traps"] = function()
-- engine/verbs/traps.lua
-- Verb handlers for environmental trap interactions (#162).
-- Handles: breathe, trigger, step, unbar, bar — verbs used by
-- unconsciousness triggers and FSM-only door/portal interactions.
--
-- Ownership: Smithers (UI Engineer) — verb registration + dispatch
--            Flanders (Object Designer) — trigger object definitions
local H = require("engine.verbs.helpers")

local fsm_mod = H.fsm_mod
local effects = H.effects
local find_visible = H.find_visible
local try_fsm_verb = H.try_fsm_verb
local err_not_found = H.err_not_found
local err_nothing_happens = H.err_nothing_happens

local M = {}

---------------------------------------------------------------------------
-- Shared: find an object by noun, trying find_visible then registry
---------------------------------------------------------------------------
local function find_target(ctx, noun)
    local obj = find_visible(ctx, noun)
    if not obj and ctx.registry and ctx.registry.find_by_keyword then
        obj = ctx.registry:find_by_keyword(noun)
    end
    return obj
end

---------------------------------------------------------------------------
-- Shared: generic FSM interaction verb
-- #402: Uses fsm.transition() to actually apply state changes, keyword
-- mutations, and bidirectional portal sync — not just try_fsm_verb which
-- only prints the message without mutating state.
---------------------------------------------------------------------------
local function fsm_interact(ctx, noun, verb, prompt)
    if not noun or noun == "" then
        print(prompt)
        return
    end

    local target = noun:gsub("^on%s+", ""):gsub("^at%s+", ""):gsub("^into%s+", "")
    local obj = find_target(ctx, target)
    if not obj then
        err_not_found(ctx)
        return
    end

    -- #402: Proper FSM transition path — find matching transition and
    -- call fsm.transition() to apply state change + mutations
    if obj.states and obj.transitions then
        local transitions = fsm_mod.get_transitions(obj)
        local target_trans
        for _, t in ipairs(transitions) do
            if t.verb == verb then target_trans = t; break end
            if t.aliases then
                for _, a in ipairs(t.aliases) do
                    if a == verb then target_trans = t; break end
                end
                if target_trans then break end
            end
        end
        if target_trans then
            local trans, err = fsm_mod.transition(
                ctx.registry, obj.id, target_trans.to, {}, verb)
            if trans then
                print(trans.message or ("You " .. verb .. " " .. (obj.name or obj.id) .. "."))
                -- Process pipeline effects (injuries, unconsciousness, etc.)
                local fx = trans.pipeline_effects or trans.effect
                if fx and effects and ctx.player then
                    effects.process(fx, {
                        player = ctx.player,
                        source = obj,
                        source_id = obj.id,
                        registry = ctx.registry,
                        time_offset = ctx.time_offset or 0,
                    })
                end
                return
            end
        end
    end

    -- Fallback: try_fsm_verb for effect-only transitions (traps, unconsciousness)
    if try_fsm_verb(ctx, obj, verb) then return end

    err_nothing_happens(obj)
end

---------------------------------------------------------------------------
-- Register verb handlers
---------------------------------------------------------------------------
function M.register(handlers)

    handlers["breathe"] = function(ctx, noun)
        fsm_interact(ctx, noun, "breathe", "Breathe what?")
    end
    handlers["inhale"] = handlers["breathe"]

    handlers["trigger"] = function(ctx, noun)
        fsm_interact(ctx, noun, "trigger", "Trigger what?")
    end
    handlers["activate"] = handlers["trigger"]

    handlers["step"] = function(ctx, noun)
        fsm_interact(ctx, noun, "step", "Step on what?")
    end

    -- #322: unbar/bar verb handlers for door FSM transitions
    handlers["unbar"] = function(ctx, noun)
        fsm_interact(ctx, noun, "unbar", "Unbar what?")
    end
    handlers["lift bar"] = handlers["unbar"]
    handlers["remove bar"] = handlers["unbar"]

    handlers["bar"] = function(ctx, noun)
        fsm_interact(ctx, noun, "bar", "Bar what?")
    end

end

return M

end

package.preload["engine.world"] = function()
-- engine/world/init.lua
-- World loader: discovers, loads, validates, and selects worlds.
-- Follows dependency injection — zero require() calls.
-- World is metadata (context.world), NOT a game entity.
-- See: docs/design/worlds.md, D-WORLDS-CONCEPT

local M = {}

-- Required fields every world must have
local REQUIRED_FIELDS = { "guid", "id", "name", "levels", "starting_room", "theme" }

--- discover(worlds_dir, list_lua_files, read_file, load_source)
-- Scan worlds_dir for .lua files, load each via sandbox.
-- Returns array of world tables (may be empty).
function M.discover(worlds_dir, list_lua_files, read_file, load_source)
    local files = list_lua_files(worlds_dir)
    local worlds = {}
    for _, filename in ipairs(files) do
        local sep = package.config:sub(1, 1)
        local path = worlds_dir .. sep .. filename
        local source = read_file(path)
        if source then
            local tbl, err = load_source(source)
            if tbl then
                worlds[#worlds + 1] = tbl
            end
        end
    end
    return worlds
end

--- validate(world)
-- Check that a world table has all required fields.
-- Returns true or false, error_message.
function M.validate(world)
    if type(world) ~= "table" then
        return false, "world is not a table"
    end
    for _, field in ipairs(REQUIRED_FIELDS) do
        if world[field] == nil then
            return false, "missing required field: " .. field
        end
    end
    if type(world.levels) ~= "table" or #world.levels == 0 then
        return false, "levels must be a non-empty array"
    end
    if type(world.starting_room) ~= "string" or world.starting_room == "" then
        return false, "starting_room must be a non-empty string"
    end
    return true
end

--- select(worlds)
-- Single-world auto-select (Phase 1).
-- 0 worlds = FATAL. 2+ worlds = not implemented.
function M.select(worlds)
    if #worlds == 0 then
        return nil, "FATAL: no worlds found"
    end
    if #worlds > 1 then
        return nil, "world selection not implemented (multiple worlds found)"
    end
    return worlds[1], nil
end

--- get_starting_room(world)
-- Returns the world's starting room ID.
function M.get_starting_room(world)
    return world.starting_room
end

--- load(worlds_dir, list_lua_files, read_file, load_source)
-- Orchestrator: discover → validate each → select.
-- Returns selected world or nil, error.
function M.load(worlds_dir, list_lua_files, read_file, load_source)
    local worlds = M.discover(worlds_dir, list_lua_files, read_file, load_source)
    -- Validate each discovered world
    local valid = {}
    for _, world in ipairs(worlds) do
        local ok, err = M.validate(world)
        if ok then
            valid[#valid + 1] = world
        end
    end
    return M.select(valid)
end

return M

end

